import React, { useState, useEffect } from 'react';
import { SettingsProvider } from './contexts/SettingsContext';
import { HeaderProvider } from './contexts/HeaderContext';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { tools } from './data/tools';

function App() {
  const [currentTool, setCurrentTool] = useState(() => {
    const params = new URLSearchParams(window.location.search);
    const toolParam = params.get('tool');
    if (toolParam) return toolParam;
    return localStorage.getItem('teacherToolsCurrentTool') || 'home';
  });

  const [activeTab, setActiveTab] = useState(() => {
    const params = new URLSearchParams(window.location.search);
    const tabParam = params.get('tab');
    if (tabParam) return tabParam;

    // If we have a tool param but no tab param, find the correct tab for the tool
    const toolParam = params.get('tool');
    if (toolParam) {
      const tool = tools.find(t => t.id === toolParam);
      if (tool) return tool.mainSection;
    }

    return localStorage.getItem('teacherToolsActiveTab') || 'Teacher Tools';
  });

  useEffect(() => {
    const handlePopState = () => {
      const params = new URLSearchParams(window.location.search);
      const toolParam = params.get('tool') || 'home';
      const tabParam = params.get('tab');

      setCurrentTool(toolParam);
      if (tabParam) {
        setActiveTab(tabParam);
      } else if (toolParam !== 'home') {
        const tool = tools.find(t => t.id === toolParam);
        if (tool) setActiveTab(tool.mainSection);
      }
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  useEffect(() => {
    const url = new URL(window.location.href);
    const prevTool = url.searchParams.get('tool') || 'home';
    const prevTab = url.searchParams.get('tab') || 'Teacher Tools';

    let changed = false;

    if (currentTool !== 'home') {
      if (url.searchParams.get('tool') !== currentTool) {
        url.searchParams.set('tool', currentTool);
        changed = true;
      }
    } else if (url.searchParams.has('tool')) {
      url.searchParams.delete('tool');
      changed = true;
    }

    if (activeTab !== 'Teacher Tools') {
      if (url.searchParams.get('tab') !== activeTab) {
        url.searchParams.set('tab', activeTab);
        changed = true;
      }
    } else if (url.searchParams.has('tab')) {
      url.searchParams.delete('tab');
      changed = true;
    }

    if (changed) {
      // Use pushState if the tool changed to allow back button
      if (currentTool !== prevTool) {
        window.history.pushState({}, '', url);
      } else {
        window.history.replaceState({}, '', url);
      }
    }

    localStorage.setItem('teacherToolsCurrentTool', currentTool);
    localStorage.setItem('teacherToolsActiveTab', activeTab);
  }, [currentTool, activeTab]);

  const handleTabChange = (tab) => {
    setActiveTab(tab);
    setCurrentTool('home');
  };

  const renderTool = () => {
    if (currentTool === 'home') {
      return <Dashboard onNavigate={setCurrentTool} activeTab={activeTab} />;
    }

    const tool = tools.find(t => t.id === currentTool);

    if (tool && tool.component) {
      const ToolComponent = tool.component;
      return <ToolComponent />;
    }

    return (
      <div className="flex flex-col items-center justify-center h-full">
        <h2 className="text-3xl font-bold mb-4 text-primary">Tool Not Found</h2>
        <button
          onClick={() => setCurrentTool('home')}
          className="px-6 py-2 bg-primary text-white rounded-lg hover:bg-primary/90 transition-colors"
        >
          Back to Dashboard
        </button>
      </div>
    );
  };









  return (
    <SettingsProvider>
      <HeaderProvider>
        <div className="theme-nature-bg">
          <div className="nature-sun" />
          <div className="nature-cloud cloud-1" />
          <div className="nature-cloud cloud-2" />
        </div>
        <div className="theme-early-years-bg" />
        <div className="theme-dark-bg" />
        <Layout onNavigate={setCurrentTool} activeTab={activeTab} onTabChange={handleTabChange} currentTool={currentTool}>
          {renderTool()}
        </Layout>
      </HeaderProvider>
    </SettingsProvider>
  );
}

export default App;

