import React, { useState, useEffect } from 'react';
import { 
  ListOrdered, 
  Download, 
  Trash2, 
  TimerReset, 
  ChevronUp, 
  ChevronDown 
} from 'lucide-react';
import { AnimatePresence } from 'framer-motion';

/**
 * A reusable history sidebar component with pagination, download, and clear actions.
 * Used for displaying logs, lap history, or other lists in a tool's sidebar.
 */
const HistoryPanel = ({ 
  title = "History",
  items = [],
  onClear,
  onDownload,
  renderItem,
  emptyMessage = "No Data",
  itemsPerPage = 7,
  badgeValue,
  icon: Icon = ListOrdered
}) => {
  const [currentPage, setCurrentPage] = useState(1);
  const totalPages = Math.ceil(items.length / itemsPerPage);

  // Clamp page number to valid range during render
  const safeCurrentPage = Math.min(currentPage, Math.max(1, totalPages));
  const displayItems = items.slice((safeCurrentPage - 1) * itemsPerPage, safeCurrentPage * itemsPerPage);

  return (
    <div className="tool-sidebar-card-flush flex-1 flex flex-col overflow-hidden">
      <div className="tool-history-header">
        <div className="flex items-center gap-2">
          <Icon size={16} className="text-indigo-400" />
          <h4 className="mb-0">{title}</h4>
        </div>
        <div className="flex items-center gap-2">
          {onDownload && (
            <button onClick={onDownload} disabled={items.length === 0} className="tool-history-button" title="Download">
              <Download size={14} />
            </button>
          )}
          {onClear && (
            <button onClick={onClear} disabled={items.length === 0} className="tool-history-button-danger" title="Clear All">
              <Trash2 size={14} />
            </button>
          )}
          {(badgeValue !== undefined || items.length > 0) && (
            <div className="tool-history-badge ml-1">{badgeValue ?? items.length}</div>
          )}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-3 custom-scrollbar no-scrollbar italic flex flex-col">
        <div className="flex-1">
          <AnimatePresence initial={false} mode="popLayout">
            {items.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center py-8 bg-slate-50/50 border-2 border-slate-100 border-dashed rounded-[2rem]">
                <TimerReset size={32} strokeWidth={1} className="mb-3 text-slate-200" />
                <p className="text-[8px] font-black uppercase tracking-widest text-slate-300 text-center px-4">{emptyMessage}</p>
              </div>
            ) : (
              <div className="space-y-2">
                {displayItems.map((item, index) => renderItem(item, (safeCurrentPage - 1) * itemsPerPage + index))}
              </div>
            )}
          </AnimatePresence>
        </div>

        {/* Pagination Controls */}
        {totalPages > 1 && (
          <div className="flex items-center justify-center gap-4 mt-4 pt-4 border-t border-slate-100 shrink-0">
            <button 
              onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
              disabled={safeCurrentPage === 1}
              className="p-2 rounded-xl bg-white border border-slate-100 text-slate-400 disabled:opacity-30 transition-all hover:bg-slate-50"
            >
              <ChevronUp size={16} className="-rotate-90" />
            </button>
            <span className="text-[10px] font-black text-slate-400 tabular-nums uppercase tracking-widest">
              Page {safeCurrentPage} of {totalPages}
            </span>
            <button 
              onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
              disabled={safeCurrentPage === totalPages}
              className="p-2 rounded-xl bg-white border border-slate-100 text-slate-400 disabled:opacity-30 transition-all hover:bg-slate-50"
            >
              <ChevronDown size={16} className="-rotate-90" />
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default HistoryPanel;

