  const { settings } = useSettings();
  const [time, setTime] = useState(new Date());
  const [isEditing, setIsEditing] = useState(false);
  const [showSidebar, setShowSidebar] = useState(false);
  const [analogueStyle, setAnalogueStyle] = useState('Default');
  const [digitalStyle, setDigitalStyle] = useState('Default');
  const svgRef = useRef(null);
  const isDragging = useRef(false);

  useEffect(() => {
    if (!isEditing && !isDragging.current) {
      const timer = setInterval(() => setTime(new Date()), 1000);
      return () => clearInterval(timer);
    }
  }, [isEditing]);

  const reset = () => {
    setAnalogueStyle('Default');
    setDigitalStyle('Default');
    setIsEditing(false);
    setTime(new Date());
    setShowSidebar(false);
    setIsConfigOpen(false);
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    setHasConfig(true);
    setOnReset(() => reset);
    setOnConfigToggle(() => () => {
      setShowSidebar(prev => !prev);
      setIsConfigOpen(prev => !prev);
    });
    setIsConfigOpen(false);
    setHeaderActions(null);
    setHelpContent([
      "Modes: Toggle between 'Real Time' (current time) and 'Edit Mode' (manual adjustment).",
      "Adjusting Time: In Edit Mode, you can drag the clock hands directly or use the arrows on the digital display.",
      "Hands: The black hand shows hours, the blue hand shows minutes, and the red hand (active in Real Time) shows seconds.",
      "Styles: Use the configuration panel to select different visual styles for both clocks."
    ]);

    return () => clearHeader();
  }, [clearHeader, setHasConfig, setOnReset, setOnConfigToggle, setIsConfigOpen, setHeaderActions, setHelpContent, isEditing, settings.soundTheme]);

  const getAngle = (e) => {
    if (!svgRef.current) return 0;
    const rect = svgRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const x = e.clientX - centerX;
    const y = e.clientY - centerY;
    let angle = Math.atan2(y, x) * (180 / Math.PI) + 90;
    if (angle < 0) angle += 360;
    return angle;
  };

  const dragType = useRef(null);

  const handlePointerDown = (e, type) => {
    e.preventDefault();
    isDragging.current = true;
    dragType.current = type;
    setIsEditing(true);
    audioEngine.playTick(settings.soundTheme);
  };

  const handlePointerMove = (e) => {
    if (!isDragging.current || !dragType.current) return;
    const angle = getAngle(e);

    setTime(prevTime => {
      const newTime = new Date(prevTime);
      if (dragType.current === 'minute') {
        const minutes = Math.round((angle / 360) * 60) % 60;
        if (newTime.getMinutes() !== minutes) {
          newTime.setMinutes(minutes);
          return newTime;
        }
      } else if (dragType.current === 'hour') {
        const hours = Math.round((angle / 360) * 12) % 12;
        const isCurrentlyPM = newTime.getHours() >= 12;
        newTime.setHours(isCurrentlyPM ? hours + 12 : hours);
        if (prevTime.getHours() !== newTime.getHours()) {
          return newTime;
        }
      }
      return prevTime;
    });
  };

  const handlePointerUp = () => {
    isDragging.current = false;
    dragType.current = null;
  };

  useEffect(() => {
    window.addEventListener('pointermove', handlePointerMove);
    window.addEventListener('pointerup', handlePointerUp);
    return () => {
      window.removeEventListener('pointermove', handlePointerMove);
      window.removeEventListener('pointerup', handlePointerUp);
    };
  }, []);

  const adjustHours = (delta) => {
    setTime(prev => {
      const newTime = new Date(prev);
      newTime.setHours((newTime.getHours() + delta + 24) % 24);
      return newTime;
    });
    audioEngine.playTick(settings.soundTheme);
  };

  const adjustMinutes = (delta) => {
    setTime(prev => {
      const newTime = new Date(prev);
      newTime.setMinutes((newTime.getMinutes() + delta + 60) % 60);
      return newTime;
    });
    audioEngine.playTick(settings.soundTheme);
  };

  const toggleAMPM = () => {
    setTime(prev => {
      const newTime = new Date(prev);
      newTime.setHours((newTime.getHours() + 12) % 24);
      return newTime;
    });
    audioEngine.playTick(settings.soundTheme);
  };

  return (
    <div className="tool-container w-full mx-auto space-y-8 h-full flex flex-col font-['Outfit'] select-none">

      <div className="flex flex-col lg:flex-row-reverse gap-8 flex-1 min-h-[600px] overflow-hidden">
        {/* Configuration Sidebar */}
        <AnimatePresence>
          {showSidebar && (
            <motion.div 
              initial={{ x: 460, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              exit={{ x: 460, opacity: 0 }}
              className="w-full lg:w-[320px] flex flex-col gap-4 shrink-0 h-full overflow-hidden"
            >
              <div className="tool-sidebar-card-flush flex-1 flex flex-col overflow-hidden">
                <div className="tool-history-header">
                  <div className="flex items-center gap-2">
                    <Settings2 size={16} className="text-indigo-400" />
                    <h4 className="mb-0">Clock Config</h4>
                  </div>
                </div>

                <div className="flex-1 p-6 space-y-8 overflow-y-auto custom-scrollbar no-scrollbar italic">
                  {/* Analogue Theme */}
                  <div className="space-y-4">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] ml-1">Analogue Theme</label>
                    <div className="grid grid-cols-1 gap-2">
                      {['Default', 'Minimal', 'Technical', 'Classic'].map(style => (
                        <button
                          key={style}
                          onClick={() => { setAnalogueStyle(style); audioEngine.playTick(settings.soundTheme); }}
                          className={`flex items-center justify-between p-3.5 rounded-2xl transition-all border-2 italic ${analogueStyle === style ? 'bg-slate-900 border-slate-900 text-white shadow-lg' : 'bg-slate-50 border-transparent text-slate-500 hover:bg-white hover:border-indigo-100 hover:shadow-md'}`}
                        >
                          <span className="text-[10px] font-black uppercase tracking-wider">{style}</span>
                          {analogueStyle === style && <Check size={14} className="text-indigo-400" />}
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Digital Theme */}
                  <div className="space-y-4">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] ml-1">Digital Theme</label>
                    <div className="grid grid-cols-1 gap-2">
                      {['Default', 'Cyber', 'Monospace', 'LED'].map(style => (
                        <button
                          key={style}
                          onClick={() => { setDigitalStyle(style); audioEngine.playTick(settings.soundTheme); }}
                          className={`flex items-center justify-between p-3.5 rounded-2xl transition-all border-2 italic ${digitalStyle === style ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-slate-50 border-transparent text-slate-500 hover:bg-white hover:border-rose-100 hover:shadow-md'}`}
                        >
                          <span className="text-[10px] font-black uppercase tracking-wider">{style}</span>
                          {digitalStyle === style && <Check size={14} className="text-white" />}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        <div className="flex-1 flex flex-col gap-8 min-h-0 min-w-0">
          <div className="tool-stage flex-1 flex flex-col items-stretch relative bg-white overflow-hidden p-0">
            <div className="tool-grid-bg opacity-30" />

            {/* Analogue Clock Section (50%) */}
            <div className="flex-[0.5] relative flex flex-col items-center justify-center min-h-0 p-4">

              <div className="relative h-full aspect-square flex items-center justify-center">
                <div className="relative w-full h-full max-h-[480px] max-w-[480px] rounded-full bg-white shadow-[0_20px_50px_-10px_rgba(0,0,0,0.1)] flex items-center justify-center shrink-0">
                  <div className="absolute -inset-10 border-4 border-dashed border-slate-100 rounded-full animate-spin-slow opacity-30 pointer-events-none" />

                  <svg
                    ref={svgRef}
                    viewBox="0 0 100 100"
                    className="w-full h-full p-8"
                    style={{ touchAction: 'none' }}
                  >
                    <defs>
                      <filter id="shadow-large">
                        <feDropShadow dx="0" dy="2" stdDeviation="2" floodOpacity="0.3"/>
                      </filter>
                    </defs>

                    {/* Ticks */}
                    {[...Array(60)].map((_, i) => {
                      const isMajor = i % 5 === 0;
                      const isTechnical = analogueStyle === 'Technical';
                      const isMinimal = analogueStyle === 'Minimal';

                      if (isMinimal && !isMajor) return null;

                      return (
                        <line
                          key={i}
                          x1="50" y1="2" x2="50" y2={isMajor ? "10" : (isTechnical ? "6" : "5")}
                          stroke={isMajor ? "#1e293b" : (isTechnical ? "#94a3b8" : "#cbd5e1")}
                          strokeWidth={isMajor ? (isTechnical ? "2.5" : "2") : "1"}
                          transform={`rotate(${i * 6} 50 50)`}
                        />
                      );
                    })}

                    {/* Numbers */}
                    {analogueStyle !== 'Minimal' && [...Array(12)].map((_, i) => {
                      const romanNumerals = ["I", "II", "III", "IV", "V", "VI", "VII", "VIII", "IX", "X", "XI", "XII"];
                      const isClassic = analogueStyle === 'Classic';
                      const isTechnical = analogueStyle === 'Technical';

                      return (
                        <text
                          key={i}
                          x="50"
                          y={isClassic ? "18" : "22"}
                          fill="#1e293b"
                          fontSize={isTechnical ? "8" : (isClassic ? "10" : "11")}
                          fontWeight={isClassic ? "400" : "900"}
                          textAnchor="middle"
                          alignmentBaseline="middle"
                          transform={`rotate(${(i + 1) * 30} 50 50) rotate(${-(i + 1) * 30} 50 ${isClassic ? 18 : 22})`}
                          className={`${isClassic ? 'font-serif' : "font-['Outfit']"} select-none pointer-events-none italic tracking-tighter`}
                        >
