                      className={isEditing ? "cursor-grab active:cursor-grabbing" : ""}
                    >
                      <line
                        x1="50" y1="50" x2="50" y2="28"
                        stroke="#1e293b"
                        strokeWidth="4"
                        strokeLinecap="round"
                      />
                      <path 
                        d="M 50 28 L 48 32 L 52 32 Z" 
                        fill="#1e293b"
                      />
                      {isEditing && (
                        <circle cx="50" cy="28" r="12" fill="transparent" />
                      )}
                    </g>

                    {/* Minute Hand */}
                    <g 
                      transform={`rotate(${time.getMinutes() * 6} 50 50)`}
                      onPointerDown={(e) => handlePointerDown(e, 'minute')}
                      className={isEditing ? "cursor-grab active:cursor-grabbing" : ""}
                    >
                      <line
                        x1="50" y1="50" x2="50" y2="12"
                        stroke="#2563eb"
                        strokeWidth="3"
                        strokeLinecap="round"
                      />
                      <path 
                        d="M 50 12 L 48.5 17 L 51.5 17 Z" 
                        fill="#2563eb"
                      />
                      {isEditing && (
                        <circle cx="50" cy="12" r="12" fill="transparent" />
