                    {/* Second Hand */}
                    {!isEditing && (
                      <g transform={`rotate(${time.getSeconds() * 6} 50 50)`}>
                        <line
                          x1="50" y1="55" x2="50" y2="10"
                          stroke="#ef4444"
                          strokeWidth="1"
                          strokeLinecap="round"
                        />
                        <circle cx="50" cy="50" r="2" fill="#ef4444" />
                      </g>
                    )}

                    <circle cx="50" cy="50" r={analogueStyle === 'Technical' ? "2" : "3"} fill="#1e293b" stroke="#ffffff" strokeWidth="1" />
                  </svg>
                </div>
