                </button>
                <button 
                  onClick={() => {
                    setIsEditing(true);
                    audioEngine.playTick(settings.soundTheme);
                  }} 
                  className={`px-6 py-2 text-[10px] font-black transition-all uppercase tracking-[0.2em] rounded-xl italic ${isEditing ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                >
                  Edit Mode
                </button>
              </div>
            </div>

            {/* Digital Clock Section (30%) */}
            <div className="flex-[0.3] flex items-center justify-center p-4">
              <div className={`w-full max-w-none px-12 h-full max-h-[160px] rounded-[3rem] border-4 transition-all duration-500 relative group overflow-hidden flex items-center justify-center shadow-xl ${settings.theme === 'dark' ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-50'}`}>
                <div className={`tool-grid-bg${settings.theme === 'dark' ? '-dark' : ''} opacity-10`} />
