                <div className="relative z-10 flex items-center gap-8">
                  <div className="flex items-center gap-4">
                    <div className="relative flex flex-col items-center">
                      {isEditing && (
                        <div className="absolute -inset-y-12 flex flex-col justify-between items-center w-full z-50">
                          <button onClick={() => adjustHours(1)} className={`p-1 transition-all transform hover:scale-150 active:scale-95 ${settings.theme === 'dark' ? 'text-white hover:text-indigo-400' : 'text-slate-300 hover:text-indigo-500'}`}><ChevronUp size={32} /></button>
                          <button onClick={() => adjustHours(-1)} className={`p-1 transition-all transform hover:scale-150 active:scale-95 ${settings.theme === 'dark' ? 'text-white hover:text-indigo-400' : 'text-slate-300 hover:text-indigo-500'}`}><ChevronDown size={32} /></button>
                        </div>
                      )}
                      <div className={`text-7xl font-black tabular-nums tracking-tighter leading-none italic ${digitalStyle === 'Cyber' ? 'text-slate-900 drop-shadow-[0_0_20px_rgba(30,41,59,0.3)]' : (digitalStyle === 'LED' ? 'text-slate-900' : (settings.theme === 'dark' ? 'text-slate-100' : 'text-slate-900'))} ${digitalStyle === 'Monospace' || digitalStyle === 'LED' ? 'font-mono' : ''}`}>
                        {(time.getHours() % 12 || 12).toString().padStart(2, '0')}
                      </div>
                    </div>

                    <div className={`flex flex-col gap-2 ${settings.theme === 'dark' ? 'opacity-20' : 'opacity-10'}`}>
                      <div className={`w-2 h-2 rounded-full ${settings.theme === 'dark' ? 'bg-white' : 'bg-slate-900'}`} />
                      <div className={`w-2 h-2 rounded-full ${settings.theme === 'dark' ? 'bg-white' : 'bg-slate-900'}`} />
                    </div>

                    <div className="relative flex flex-col items-center">
                      {isEditing && (
                        <div className="absolute -inset-y-12 flex flex-col justify-between items-center w-full z-50">
                          <button onClick={() => adjustMinutes(1)} className={`p-1 transition-all transform hover:scale-150 active:scale-95 ${settings.theme === 'dark' ? 'text-white hover:text-indigo-400' : 'text-slate-300 hover:text-indigo-500'}`}><ChevronUp size={32} /></button>
                          <button onClick={() => adjustMinutes(-1)} className={`p-1 transition-all transform hover:scale-150 active:scale-95 ${settings.theme === 'dark' ? 'text-white hover:text-indigo-400' : 'text-slate-300 hover:text-indigo-500'}`}><ChevronDown size={32} /></button>
                        </div>
                      )}
                      <div className={`text-7xl font-black tabular-nums tracking-tighter leading-none italic ${digitalStyle === 'Cyber' ? 'text-blue-600 drop-shadow-[0_0_20px_rgba(37,99,235,0.4)]' : (digitalStyle === 'LED' ? 'text-blue-600' : (settings.theme === 'dark' ? 'text-blue-400' : 'text-blue-600'))} ${digitalStyle === 'Monospace' || digitalStyle === 'LED' ? 'font-mono' : ''}`}>
                        {time.getMinutes().toString().padStart(2, '0')}
                      </div>
                    </div>
                  </div>

                  <button 
                    onClick={isEditing ? toggleAMPM : undefined}
                    className={`px-4 py-1.5 rounded-xl border-2 font-black text-lg tracking-tighter transition-all italic ${isEditing ? 'border-indigo-600 text-indigo-400 hover:bg-indigo-600/10' : (settings.theme === 'dark' ? 'border-slate-800 text-slate-700 cursor-default' : 'border-slate-100 text-slate-300 cursor-default')}`}
                  >
                    {time.getHours() >= 12 ? 'PM' : 'AM'}
                  </button>

                  <div className={`text-6xl font-black tabular-nums tracking-tighter leading-none italic ${digitalStyle === 'Cyber' ? 'text-red-500 drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]' : (digitalStyle === 'LED' ? 'text-red-500' : (settings.theme === 'dark' ? 'text-red-400' : 'text-red-500'))} ${digitalStyle === 'Monospace' || digitalStyle === 'LED' ? 'font-mono' : ''}`}>
                    {time.getSeconds().toString().padStart(2, '0')}
                  </div>
                </div>
              </div>
            </div>

            <div className="flex-[0.15] flex flex-col items-center justify-center px-8 py-2">
              <h2 className="text-xl sm:text-2xl md:text-3xl lg:text-4xl font-medium text-slate-800 tracking-tight italic capitalize leading-tight text-center max-w-4xl">
                {getTimeInWords(time)}
              </h2>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

