import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Grid3X3, 
  RotateCcw, 
  Play, 
  Trash2, 
  Plus, 
  ChevronRight, 
  Trophy, 
  Clock, 
  Settings2, 
  Zap, 
  Target, 
  Sparkles,
  Info,
  Monitor,
  MousePointer2,
  Terminal,
  Database,
  Activity,
  History,
  Award,
  ShieldCheck,
  Search,
  BookOpen
} from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';

const GRID_SIZE = 4;
const LETTERS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
const DIE_FACES = [
  "AAEEGN", "ELRTTY", "AOOTTW", "ABBJOO",
  "EHRTVW", "CIMOTU", "DISTTY", "EIOSST",
  "DELRVY", "ACHOPS", "HIMNQU", "EEINSU",
  "EEGHNW", "AFFKPS", "HLNNRZ", "DEILRX"
];

export const Boggle = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [grid, setGrid] = useState([]);
  const [foundWords, setFoundWords] = useState([]);
  const [currentWord, setCurrentWord] = useState('');
  const [timer, setTimer] = useState(120);
  const [gameState, setGameState] = useState('menu'); // menu, playing, finished
  const [selection, setSelection] = useState([]); // [{r, c}]
  const timerRef = useRef(null);

  const generateGrid = () => {
    const shuffledDice = [...DIE_FACES].sort(() => Math.random() - 0.5);
    const newGrid = [];
    for (let i = 0; i < GRID_SIZE; i++) {
      const row = [];
      for (let j = 0; j < GRID_SIZE; j++) {
        const face = shuffledDice[i * GRID_SIZE + j];
        row.push(face[Math.floor(Math.random() * face.length)]);
      }
      newGrid.push(row);
    }
    setGrid(newGrid);
  };

  const startGame = () => {
    generateGrid();
    setFoundWords([]);
    setCurrentWord('');
    setSelection([]);
    setTimer(120);
    setGameState('playing');
    audioEngine.playTick(settings.soundTheme);
  };

  const handleCellClick = (r, c) => {
    if (gameState !== 'playing') return;

    const last = selection[selection.length - 1];
    if (last && last.r === r && last.c === c) {
      // Remove last letter
      setSelection(prev => prev.slice(0, -1));
      setCurrentWord(prev => prev.slice(0, -1));
    } else {
      // Check if adjacent and not already selected
      const isSelected = selection.some(s => s.r === r && s.c === c);
      if (isSelected) return;

      if (last) {
        const dr = Math.abs(last.r - r);
        const dc = Math.abs(last.c - c);
        if (dr > 1 || dc > 1) return;
      }

      setSelection(prev => [...prev, { r, c }]);
      setCurrentWord(prev => prev + grid[r][c]);
    }
    audioEngine.playTick(settings.soundTheme);
  };

  const submitWord = () => {
    if (currentWord.length >= 3 && !foundWords.includes(currentWord)) {
      setFoundWords(prev => [currentWord, ...prev]);
      audioEngine.playTick(settings.soundTheme);
    }
    setCurrentWord('');
    setSelection([]);
  };

  useEffect(() => {
    if (gameState === 'playing' && timer > 0) {
      timerRef.current = setInterval(() => {
        setTimer(prev => prev - 1);
      }, 1000);
    } else if (timer === 0) {
      setGameState('finished');
      clearInterval(timerRef.current);
    }
    return () => clearInterval(timerRef.current);
  }, [gameState, timer]);

  useEffect(() => {
    setOnReset(() => () => setGameState('menu'));
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        {gameState === 'playing' && (
           <div className="flex items-center bg-white/40 backdrop-blur-xl p-1 rounded-2xl border-4 border-slate-50 shadow-inner w-fit shrink-0">
              <div className="px-6 py-2 flex items-center gap-6">
                 <div className="flex flex-col gap-0.5">
                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none">Temporal Decay</span>
                    <span className={`text-[12px] font-black uppercase tracking-tighter italic leading-none tabular-nums ${timer < 10 ? 'text-rose-500 animate-pulse' : 'text-indigo-600'}`}>
                       {Math.floor(timer / 60)}:{(timer % 60).toString().padStart(2, '0')} REremaining
                    </span>
                 </div>
                 <div className="w-px h-6 bg-slate-200" />
                 <div className="flex flex-col gap-0.5">
                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none">Lexis Yield</span>
                    <span className="text-[12px] font-black text-slate-800 uppercase tracking-tighter italic leading-none">{foundWords.length} Detected</span>
                 </div>
              </div>
           </div>
        )}
        <button
          onClick={() => { setGameState('menu'); audioEngine.playTick(settings.soundTheme); }}
          className="flex items-center gap-2 px-8 py-2 bg-white text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-rose-50 hover:text-rose-600 transition-all active:scale-95 border-2 border-slate-100 hover:border-rose-100 shadow-sm italic"
        >
          <RotateCcw size={14} /> Exit Labyrinth
        </button>
      </div>
    );
  }, [gameState, timer, foundWords, settings.soundTheme, setHeaderActions]);

  return (
    <div className="tool-container flex flex-col gap-8 h-full font-['Outfit'] select-none">
      {gameState === 'menu' && (
        <div className="tool-stage flex-1 p-12 lg:p-24 bg-slate-50 relative overflow-hidden flex flex-col items-center justify-center rounded-[4rem]">
           <div className="tool-grid-bg opacity-40" />

           <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-center mb-20 space-y-8 relative z-10"
           >
              <div className="relative mx-auto w-40 h-40 mb-12">
                 <div className="absolute inset-0 bg-indigo-500 blur-[100px] opacity-20 animate-pulse" />
                 <div className="relative z-10 w-full h-full bg-slate-950 rounded-[4rem] shadow-2xl flex items-center justify-center text-white border-4 border-white/20 rotate-3 group-hover:rotate-0 transition-transform">
                    <BookOpen size={80} strokeWidth={1} className="text-indigo-400" />
                 </div>
                 <div className="absolute -top-4 -right-4 w-16 h-16 bg-white rounded-full flex items-center justify-center text-rose-500 shadow-2xl border-4 border-slate-50 animate-bounce">
                    <Sparkles size={32} />
                 </div>
              </div>
              <div className="space-y-3">
                 <h1 className="text-8xl font-black text-slate-900 tracking-tighter italic uppercase leading-none">Lexis Labyrinth</h1>
                 <p className="text-[12px] font-black text-slate-400 uppercase tracking-[0.8em] italic">Lexical Extraction Protocol v3.4</p>
              </div>
           </motion.div>

           <div className="flex flex-col items-center gap-8 relative z-10">
              <button
                onClick={startGame}
                className="group flex items-center gap-6 px-16 py-8 bg-indigo-600 text-white rounded-[3rem] font-black uppercase tracking-[0.4em] italic text-xl hover:bg-indigo-500 hover:scale-[1.02] active:scale-95 transition-all shadow-[0_48px_96px_-24px_rgba(79,70,229,0.5)] border-4 border-indigo-400/50"
              >
                Initiate Grid <ChevronRight size={32} />
              </button>
              <div className="flex items-center gap-8 opacity-40">
                 <div className="flex items-center gap-3">
                    <Clock size={18} className="text-slate-400" />
                    <span className="text-[11px] font-black uppercase tracking-widest">120s Limit</span>
                 </div>
                 <div className="w-1.5 h-1.5 rounded-full bg-slate-300" />
                 <div className="flex items-center gap-3">
                    <Grid3X3 size={18} className="text-slate-400" />
                    <span className="text-[11px] font-black uppercase tracking-widest">4x4 Matrix</span>
                 </div>
              </div>
           </div>
        </div>
      )}

      {gameState === 'finished' && (
        <div className="tool-overlay-container bg-slate-950/98 backdrop-blur-3xl p-10">
           <motion.div 
            initial={{ scale: 0.8, opacity: 0, y: 50 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            className="tool-overlay-card bg-transparent border-none text-white max-w-4xl"
           >
              <div className="relative mb-16">
                 <div className="absolute -inset-20 bg-amber-400/20 rounded-full blur-[100px] animate-pulse" />
                 <div className="w-40 h-40 bg-gradient-to-br from-amber-400 to-orange-600 shadow-[0_48px_96px_-12px_rgba(251,191,36,0.6)] border-[12px] border-white/20 mx-auto rounded-[4rem] flex items-center justify-center text-white drop-shadow-2xl relative z-10 rotate-3">
                    <Award size={100} strokeWidth={1} />
                 </div>
                 <div className="absolute -top-6 -right-6 w-16 h-16 bg-white rounded-full flex items-center justify-center text-amber-500 shadow-2xl animate-bounce">
                    <Sparkles size={32} />
                 </div>
              </div>

              <div className="space-y-6 text-center">
                 <div className="space-y-2">
                    <h2 className="text-7xl font-black tracking-tighter uppercase italic text-white drop-shadow-2xl">Labyrinth Concluded</h2>
                    <p className="text-[12px] font-black text-white/30 uppercase tracking-[0.5em] italic">Extraction Efficiency Report</p>
                 </div>
                 <div className="flex flex-col gap-2 items-center bg-white/5 p-12 rounded-[4rem] border border-white/10 shadow-inner">
                    <span className="text-[12px] font-black text-indigo-400 uppercase tracking-widest italic mb-2">Total Discoveries</span>
                    <div className="flex items-baseline gap-4">
                       <span className="text-9xl font-black tabular-nums tracking-tighter text-white italic drop-shadow-md">{foundWords.length}</span>
                       <span className="text-4xl font-black text-white/20 uppercase italic">Words Extracted</span>
                    </div>
                 </div>
              </div>

              <div className="flex flex-col sm:flex-row gap-6 w-full max-w-2xl mt-12">
                 <button
                   onClick={() => setGameState('menu')}
                   className="flex-1 py-8 bg-white/10 hover:bg-white/20 text-white font-black text-[12px] uppercase tracking-[0.3em] rounded-[3rem] transition-all active:scale-95 border-2 border-white/10 italic shadow-xl"
                 >
                   Archive Session
                 </button>
                 <button
                   onClick={startGame}
                   className="flex-1 py-8 bg-indigo-600 text-white font-black text-[12px] uppercase tracking-[0.3em] rounded-[3rem] hover:bg-indigo-500 transition-all active:scale-95 shadow-[0_32px_64px_-12px_rgba(79,70,229,0.5)] border-2 border-indigo-400/50 italic"
                 >
                   New Manifest
                 </button>
              </div>
           </motion.div>
        </div>
      )}

      {gameState === 'playing' && (
        <div className="flex-1 flex flex-col lg:flex-row gap-8 min-h-0">
          {/* Labyrinth Grid Area */}
          <div className="tool-stage flex-1 p-12 lg:p-24 relative overflow-hidden bg-white border-none rounded-[4rem] group/stage flex flex-col items-center justify-center">
             <div className="tool-grid-bg opacity-30" />

             {/* HUD Elements */}
             <div className="absolute top-12 left-12 flex flex-col gap-6 z-20 pointer-events-none italic">
                <div className="flex items-center gap-4 px-8 py-4 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border-4 border-white/60 shadow-xl group/hud hover:border-indigo-100 transition-all">
                   <div className="w-3 h-3 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_20px_rgba(79,70,229,1)]" />
                   <div className="flex flex-col">
                      <span className="text-[11px] font-black text-slate-800 uppercase tracking-[0.6em] leading-none mb-1">Matrix Observation</span>
                      <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.4em] leading-none">Dynamic Field Active</span>
                   </div>
                </div>
             </div>

             <div className="flex flex-col items-center gap-16 lg:gap-24 w-full justify-center relative z-10">
                <div className="grid grid-cols-4 gap-6 lg:gap-10 p-10 bg-slate-900 rounded-[4.5rem] shadow-[0_80px_160px_-30px_rgba(0,0,0,0.3)] border-[12px] border-slate-800 relative group/grid">
                   <div className="tool-grid-bg-dark opacity-10" />
                   {grid.map((row, r) => (
                     row.map((letter, c) => {
                       const isSelected = selection.some(s => s.r === r && s.c === c);
                       const isLast = selection[selection.length - 1]?.r === r && selection[selection.length - 1]?.c === c;

                       return (
                         <motion.button
                           key={`${r}-${c}`}
                           whileHover={{ scale: 1.05 }}
                           whileTap={{ scale: 0.95 }}
                           onClick={() => handleCellClick(r, c)}
                           className={`w-28 h-28 lg:w-36 lg:h-36 rounded-[2.5rem] text-5xl lg:text-7xl font-black italic border-8 transition-all flex items-center justify-center relative overflow-hidden ${
                             isSelected 
                               ? 'bg-indigo-600 border-indigo-400 text-white shadow-[0_20px_40px_-10px_rgba(79,70,229,0.5)] scale-110 z-20' 
                               : 'bg-white border-slate-50 text-slate-800 hover:border-indigo-100 hover:shadow-xl'
                           } ${isLast ? 'ring-4 ring-white animate-pulse' : ''}`}
                         >
                            <div className="absolute inset-0 bg-gradient-to-tr from-black/5 via-transparent to-white/10" />
                            <span className="relative z-10 drop-shadow-sm">{letter}</span>
                            {/* Glass FX */}
                            <div className="absolute inset-x-4 top-4 h-3 bg-white/20 rounded-full blur-[1px] opacity-40" />
                         </motion.button>
                       );
                     })
                   ))}
                </div>

                <div className="text-center space-y-6">
                   <span className="text-[14px] font-black text-indigo-400 uppercase tracking-[1em] italic leading-none block mb-4">Discovery Stream</span>
                   <AnimatePresence mode="wait">
                      <motion.div
                        key={currentWord}
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="text-8xl lg:text-[10rem] font-black text-slate-800 italic tracking-tighter leading-none min-h-[1.2em]"
                      >
                        {currentWord || <span className="opacity-10">SEARCHING</span>}
                      </motion.div>
                   </AnimatePresence>
                </div>
             </div>

             {/* Interaction Guide */}
             <div className="absolute bottom-12 right-12 flex items-center gap-6 z-20 pointer-events-none opacity-40 italic">
                <div className="text-right">
                   <p className="text-[11px] font-black uppercase tracking-[0.6em]">Extraction Interface</p>
                   <p className="text-[11px] font-black uppercase tracking-[0.4em] mt-1">Trace word patterns to resolve</p>
                </div>
                <div className="w-12 h-12 rounded-2xl bg-white/50 border-2 border-white flex items-center justify-center shadow-inner">
                   <MousePointer2 size={24} className="text-slate-400" />
                </div>
             </div>
          </div>

          {/* Lexical Sidebar */}
          <div className="w-full lg:w-[420px] flex flex-col gap-6 shrink-0 h-full overflow-hidden">
             <div className="tool-sidebar-card flex-1 p-10 flex flex-col bg-slate-950 border-none relative overflow-hidden group shadow-2xl">
                <div className="tool-grid-bg-dark opacity-10" />
                <div className="absolute inset-0 bg-indigo-500/5 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                <div className="flex items-center justify-between border-b border-white/10 pb-10 relative z-10 shrink-0">
                   <div className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-2xl bg-white/5 flex items-center justify-center text-indigo-400 border border-white/10 shadow-inner">
                         <Terminal size={24} />
                      </div>
                      <div className="flex flex-col">
                         <h4 className="text-lg font-black text-indigo-400 uppercase tracking-tight italic">Lexical Console</h4>
                         <span className="text-[10px] font-black text-white/20 uppercase tracking-[0.4em] italic leading-none">Extraction Node v3.4</span>
                      </div>
                   </div>
                   <div className="flex flex-col items-end">
                      <span className="text-[10px] font-black text-white/30 uppercase tracking-widest leading-none mb-1">Yield</span>
                      <span className="text-2xl font-black text-white italic tabular-nums leading-none">{foundWords.length}</span>
                   </div>
                </div>

                <div className="flex-1 space-y-8 my-10 overflow-y-auto pr-2 custom-scrollbar no-scrollbar relative z-10">
                   <div className="grid grid-cols-1 gap-3">
                      {foundWords.map((word, i) => (
                        <motion.div 
                          key={i}
                          initial={{ opacity: 0, x: 20 }}
                          animate={{ opacity: 1, x: 0 }}
                          className="flex items-center justify-between p-6 bg-white/5 rounded-[2.5rem] border-2 border-white/10 shadow-sm group/item hover:bg-white/10 hover:border-indigo-500/50 transition-all"
                        >
                           <div className="flex items-center gap-5">
                              <div className="w-10 h-10 rounded-xl bg-indigo-500 flex items-center justify-center text-white font-black italic shadow-lg group-hover/item:scale-110 transition-transform">
                                 {word.length}
                              </div>
                              <span className="text-3xl font-black text-white tracking-tighter uppercase italic">{word}</span>
                           </div>
                           <div className="flex flex-col items-end">
                              <span className="text-[9px] font-black text-indigo-400 uppercase tracking-widest leading-none mb-1">Score</span>
                              <span className="text-lg font-black text-white/40 tabular-nums italic">{word.length > 7 ? 11 : word.length === 7 ? 5 : word.length === 6 ? 3 : word.length === 5 ? 2 : 1}</span>
                           </div>
                        </motion.div>
                      ))}
                      {foundWords.length === 0 && (
                        <div className="py-24 flex flex-col items-center justify-center opacity-20 text-center gap-8 bg-white/5 rounded-[4rem] border-4 border-dashed border-white/10">
                           <Search size={64} strokeWidth={1} className="text-slate-400" />
                           <p className="text-[11px] font-black uppercase tracking-[0.5em] italic">No lexical patterns extracted</p>
                        </div>
                      )}
                   </div>
                </div>

                <button
                  onClick={submitWord}
                  disabled={currentWord.length < 3 || gameState !== 'playing'}
                  className={`w-full py-10 rounded-[3.5rem] text-[12px] font-black transition-all flex items-center justify-center gap-6 shadow-[0_48px_96px_-24px_rgba(0,0,0,0.5)] uppercase tracking-[0.4em] italic border-4 relative z-10 ${
                    currentWord.length < 3 ? 'bg-white/5 text-white/10 border-white/5 grayscale pointer-events-none' :
                    'bg-indigo-600 text-white border-indigo-400/50 hover:bg-indigo-500 hover:scale-[1.02] active:scale-95 shadow-indigo-500/40'
                  }`}
                >
                  Resolve Pattern <Zap size={32} fill="currentColor" />
                </button>

                <div className="mt-auto pt-10 border-t border-white/10 shrink-0 relative z-10">
                   <div className="p-8 bg-white/5 rounded-[3rem] text-white flex flex-col gap-4 shadow-2xl overflow-hidden relative group/stab">
                       <div className="tool-grid-bg-dark opacity-10" />
                       <div className="flex items-center gap-3 relative z-10">
                          <ShieldCheck size={18} className="text-indigo-400" />
                          <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] italic">Stability Protocol</span>
                       </div>
                       <p className="text-[11px] font-black text-white/40 leading-relaxed relative z-10 italic uppercase tracking-tighter">
                          Lexical synchronization ensures grid stability. Patterns of 3+ units required for resolution.
                       </p>
                   </div>
                </div>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Boggle;

