source:
import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Beaker, 
  Sparkles, 
  Trash2, 
  Info, 
  Zap, 
  Flame, 
  FlaskConical, 
  X, 
  Activity, 
  Wind,
  Settings2,
  Layout,
  MousePointer2,
  ChevronRight,
  TrendingUp,
  Microscope,
  Cpu,
  Monitor,
  Database,
  Terminal,
  ShieldCheck,
  ZapOff
} from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';
import { CHEMICALS } from './ChemicalFireworks/chemicalData';
import { formatFormula } from '../../utils/format';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';

export const ChemicalFireworks = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const canvasRef = useRef(null);
  const containerRef = useRef(null);
  const [activeChemicalIds, setActiveChemicalIds] = useState([]);
  const [showInfo, setShowInfo] = useState(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [speed, setSpeed] = useState('normal');
  const particles = useRef([]);
  const rockets = useRef([]);
  const requestRef = useRef();
  const timers = useRef({});

  const speedSettings = {
    slow: { base: 1500, range: 1500 },
    normal: { base: 500, range: 1000 },
    fast: { base: 100, range: 300 }
  };

  class Particle {
    constructor(x, y, color, secondary, isSpark = false) {
      this.x = x;
      this.y = y;
      this.color = color;
      this.secondary = secondary;
      this.isSpark = isSpark;
      const angle = Math.random() * Math.PI * 2;
      const velocity = Math.random() * 8 + 3;
      this.vx = Math.cos(angle) * velocity;
      this.vy = Math.sin(angle) * velocity;
      this.alpha = 1;
      this.decay = Math.random() * 0.012 + 0.005;
      this.gravity = 0.18;
      this.friction = 0.95;
      this.size = Math.random() * 4 + 1.5;
    }

    draw(ctx) {
      ctx.save();
      ctx.globalAlpha = this.alpha;
      ctx.beginPath();
      ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
      ctx.fillStyle = this.isSpark ? '#FFD700' : this.color;
      ctx.shadowBlur = 25;
      ctx.shadowColor = this.color;
      ctx.fill();
      ctx.restore();
    }

    update() {
      this.vx *= this.friction;
      this.vy *= this.friction;
      this.vy += this.gravity;
      this.x += this.vx;
      this.y += this.vy;
      this.alpha -= this.decay;
    }
  }

  class RocketObj {
    constructor(targetX, targetY, chemical, startX, startY) {
      this.x = startX || (targetX + (Math.random() - 0.5) * 100);
      this.y = startY || (containerRef.current?.clientHeight || 600);
      this.targetY = targetY;
      this.chemical = chemical;
      this.vx = (targetX - this.x) / 35;
      this.vy = (targetY - this.y) / 35;
      this.exploded = false;
    }

    update() {
      this.x += this.vx;
      this.y += this.vy;
      if (Math.abs(this.y - this.targetY) < 5 || this.y <= this.targetY) {
        this.explode();
        return true;
      }
      return false;
    }

    draw(ctx) {
      ctx.save();
      ctx.beginPath();
      ctx.arc(this.x, this.y, 3, 0, Math.PI * 2);
      ctx.fillStyle = '#FFFFFF';
      ctx.shadowBlur = 10;
      ctx.shadowColor = '#FFFFFF';
      ctx.fill();

      ctx.beginPath();
      ctx.moveTo(this.x, this.y);
      ctx.lineTo(this.x - this.vx * 4, this.y - this.vy * 4);
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.4)';
      ctx.lineWidth = 2;
      ctx.stroke();
      ctx.restore();
    }

    explode() {
      const count = 120;
      for (let i = 0; i < count; i++) {
        particles.current.push(new Particle(this.x, this.y, this.chemical.color, this.chemical.secondary));
      }
    }
  }

  const animate = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = 'rgba(5, 5, 16, 0.15)'; // Slightly darker trails
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    rockets.current = rockets.current.filter(rocket => {
      const exploded = rocket.update();
      if (!exploded) rocket.draw(ctx);
      return !exploded;
    });
    particles.current = particles.current.filter(p => {
      p.update();
      p.draw(ctx);
      return p.alpha > 0;
    });
    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    const updateSize = () => {
      if (containerRef.current) {
        canvas.width = containerRef.current.clientWidth;
        canvas.height = containerRef.current.clientHeight;
      }
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    requestRef.current = requestAnimationFrame(animate);
    return () => {
      cancelAnimationFrame(requestRef.current);
      window.removeEventListener('resize', updateSize);
    };
  }, []);

  const launchFirework = (chemical, startX, startY) => {
    if (!containerRef.current) return;
    const width = containerRef.current.clientWidth;
    const height = containerRef.current.clientHeight;
    const targetX = Math.random() * (width * 0.8) + (width * 0.1);
    const targetY = Math.random() * (height * 0.4) + (height * 0.1);
    rockets.current.push(new RocketObj(targetX, targetY, chemical, startX, startY));
  };

  const toggleChemical = (id) => {
    setActiveChemicalIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    if (activeChemicalIds.length === 0) return;
    const scheduleNext = () => {
      const currentSpeed = speedSettings[speed];
      const delay = Math.random() * currentSpeed.range + currentSpeed.base;
      timers.current.global = setTimeout(() => {
        const randomId = activeChemicalIds[Math.floor(Math.random() * activeChemicalIds.length)];
        const chem = CHEMICALS.find(c => c.id === randomId);
        const el = document.getElementById(`chem-btn-${randomId}`);
        let sx, sy;
        if (el && containerRef.current) {
          const rect = el.getBoundingClientRect();
          const containerRect = containerRef.current.getBoundingClientRect();
          sx = rect.left - containerRect.left + rect.width / 2;
          sy = rect.top - containerRect.top;
        }
        launchFirework(chem, sx, sy);
        scheduleNext();
      }, delay);
    };
    scheduleNext();
    return () => clearTimeout(timers.current.global);
  }, [activeChemicalIds, speed]);

  useEffect(() => {
    setOnReset(() => () => {
      setActiveChemicalIds([]);
      audioEngine.playTick(settings.soundTheme);
    });
    return () => {
      clearHeader();
      cancelAnimationFrame(requestRef.current);
    };
  }, [clearHeader, setOnReset, settings.soundTheme]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <div className="flex bg-slate-100 p-1 rounded-2xl border-2 border-slate-200/50 shadow-inner w-fit shrink-0">
          {['slow', 'normal', 'fast'].map(s => (
            <button 
              key={s} 
              onClick={() => { setSpeed(s); audioEngine.playTick(settings.soundTheme); }} 
              className={`px-8 py-2 rounded-xl transition-all font-black text-[10px] uppercase tracking-[0.2em] italic ${speed === s ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              {s}
            </button>
          ))}
        </div>
        <div className="w-px h-6 bg-slate-200" />
        <button
          onClick={() => { setShowExplanation(true); audioEngine.playTick(settings.soundTheme); }}
          className="flex items-center gap-2 px-8 py-2 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-slate-800 transition-all active:scale-95 shadow-xl italic"
        >
          <Microscope size={14} className="text-indigo-400" /> Theory Lab
        </button>
      </div>
    );
  }, [speed, setHeaderActions, settings.soundTheme]);

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      {/* Reagent Sidebar */}
      <div className="w-full lg:w-[420px] flex flex-col gap-6 shrink-0 h-full overflow-hidden">
        <div className="tool-sidebar-card flex-1 p-10 flex flex-col">
           <div className="flex items-center justify-between mb-10 shrink-0">
              <div className="flex items-center gap-4">
                 <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 border-4 border-white shadow-inner">
                    <FlaskConical size={24} />
                 </div>
                 <div className="flex flex-col">
                    <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Reactive Reagents</h4>
                    <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic">Molecular Synthesis v4.2</span>
                 </div>
              </div>
              <button 
                onClick={() => { setActiveChemicalIds([]); audioEngine.playTick(settings.soundTheme); }} 
                className="p-3 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-all"
              >
                <Trash2 size={20} />
              </button>
           </div>

           <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar no-scrollbar space-y-3 italic">
              {CHEMICALS.map(chem => {
                const isActive = activeChemicalIds.includes(chem.id);
                return (
                  <button
                    key={chem.id}
                    id={`chem-btn-${chem.id}`}
                    onMouseEnter={() => setShowInfo(chem)}
                    onMouseLeave={() => setShowInfo(null)}
                    onClick={() => toggleChemical(chem.id)}
                    className={`w-full p-6 rounded-[2.5rem] border-4 transition-all flex items-center justify-between group ${isActive ? 'bg-slate-900 border-slate-900 text-white shadow-2xl translate-x-3' : 'bg-slate-50 border-transparent text-slate-600 hover:bg-white hover:border-indigo-100 hover:shadow-xl'}`}
                  >
                    <div className="flex items-center gap-6">
                       <div className={`w-14 h-14 rounded-3xl flex items-center justify-center font-black text-lg italic shadow-inner ${isActive ? 'bg-white/10' : 'bg-white text-indigo-500 border-2 border-slate-100'}`}>
                          {formatFormula(chem.formula)}
                       </div>
                       <div className="text-left">
                          <p className="text-[12px] font-black uppercase tracking-[0.2em] leading-tight">{chem.name}</p>
                          <p className={`text-[9px] font-black uppercase tracking-widest mt-1 italic ${isActive ? 'text-indigo-400' : 'text-slate-400'}`}>Flame: {chem.description.split(' ')[0]}</p>
                       </div>
                    </div>
                    <div className={`w-5 h-5 rounded-full shadow-lg transition-transform ${isActive ? 'scale-125' : ''}`} style={{ backgroundColor: chem.color, boxShadow: isActive ? `0 0 20px ${chem.color}` : 'none' }} />
                  </button>
                );
              })}
           </div>

           <div className="mt-10 pt-10 border-t border-slate-50 shrink-0">
              <div className="p-8 bg-slate-900 rounded-[3rem] text-white relative overflow-hidden group shadow-2xl border border-slate-800">
                 <div className="tool-grid-bg-dark opacity-10" />
                 <div className="absolute inset-0 bg-indigo-500/5 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                 <div className="relative z-10 space-y-6">
                    <div className="flex items-center gap-3">
                       <div className="w-2.5 h-2.5 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_12px_rgba(99,102,241,1)]" />
                       <span className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.3em] italic mb-0">Spectral Analysis</span>
                    </div>
                    <div className="flex items-center justify-between">
                       <div className="flex flex-col">
                          <span className="text-[10px] font-black text-white/30 uppercase tracking-[0.4em] italic mb-1">Active Nodes</span>
                          <span className="text-4xl font-black text-white italic tabular-nums tracking-tighter">{activeChemicalIds.length}</span>
                       </div>
                       <div className="text-right flex flex-col">
                          <span className="text-[10px] font-black text-white/30 uppercase tracking-[0.4em] italic mb-1">Tempo</span>
                          <span className="text-2xl font-black text-indigo-400 uppercase italic tracking-tighter tabular-nums">{speed}</span>
                       </div>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      </div>

      {/* Observation Stage */}
      <div ref={containerRef} className="flex-1 tool-stage bg-[#050510] p-0 relative overflow-hidden border-none rounded-[4rem] group/stage">
        <canvas ref={canvasRef} className="absolute inset-0 z-0 pointer-events-none" />

        {/* HUD Overlay */}
        <div className="absolute top-12 left-12 z-20 pointer-events-none italic">
           <AnimatePresence mode="wait">
            {showInfo ? (
              <motion.div 
                key={showInfo.id}
                initial={{ opacity: 0, x: -30, scale: 0.9 }} 
                animate={{ opacity: 1, x: 0, scale: 1 }} 
                exit={{ opacity: 0, x: -30, scale: 0.9 }} 
                className="bg-white/10 backdrop-blur-3xl px-12 py-10 rounded-[4rem] border-4 border-white/10 shadow-[0_80px_160px_-40px_rgba(0,0,0,0.8)] flex items-center gap-10"
              >
                 <div className="w-20 h-20 rounded-[2.5rem] bg-white/5 flex items-center justify-center text-white/60 shadow-inner border border-white/10">
                    <FlaskConical size={32} strokeWidth={1.5} />
                 </div>
                 <div className="space-y-3">
                    <h4 className="text-5xl font-black text-white tracking-tighter uppercase italic drop-shadow-2xl leading-none">{showInfo.name}</h4>
                    <div className="flex items-center gap-6">
                       <span className="text-[16px] font-black text-indigo-400 uppercase tracking-[0.3em] italic leading-none">{formatFormula(showInfo.infoFormula || showInfo.formula)}</span>
                       <div className="w-3 h-3 rounded-full shadow-[0_0_20px_#fff]" style={{ backgroundColor: showInfo.color }} />
                       <span className="text-[14px] font-black text-white/40 uppercase tracking-[0.2em] italic leading-none">{showInfo.description}</span>
                    </div>
                 </div>
              </motion.div>
            ) : (
              <div className="flex items-center gap-6 px-10 py-5 bg-white/5 backdrop-blur-2xl rounded-[3rem] border-4 border-white/5 group/hud hover:border-white/10 transition-all cursor-default">
                 <div className="w-3 h-3 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_20px_rgba(79,70,229,1)]" />
                 <div className="flex flex-col">
                    <span className="text-[11px] font-black text-white/60 uppercase tracking-[0.6em] italic leading-none mb-1">Live Spectrum Simulation</span>
                    <span className="text-[9px] font-black text-white/20 uppercase tracking-[0.4em] italic leading-none">Atomic Phase Sync Active</span>
                 </div>
              </div>
            )}
           </AnimatePresence>
        </div>

        {/* Interaction Guide */}
        <div className="absolute bottom-12 right-12 z-20 flex items-center gap-6 text-white/10 italic pointer-events-none">
           <div className="text-right">
              <p className="text-[11px] font-black uppercase tracking-[0.6em]">Spectral Manifest</p>
              <p className="text-[11px] font-black uppercase tracking-[0.4em] mt-1">Select reagent to trigger reaction</p>
           </div>
           <div className="w-12 h-12 rounded-2xl bg-white/5 flex items-center justify-center border border-white/10">
              <MousePointer2 size={24} />
           </div>
        </div>
      </div>

      {/* Explanation Modal */}
      <AnimatePresence>
        {showExplanation && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-8 bg-slate-950/95 backdrop-blur-3xl">
            <motion.div 
              initial={{ scale: 0.8, opacity: 0, y: 50 }} 
              animate={{ scale: 1, opacity: 1, y: 0 }} 
              exit={{ scale: 0.8, opacity: 0, y: 50 }} 
              className="bg-white p-12 lg:p-20 rounded-[6rem] shadow-[0_120px_240px_-40px_rgba(0,0,0,0.8)] max-w-6xl w-full space-y-16 relative overflow-hidden italic"
            >
              <div className="absolute -right-60 -top-60 w-[500px] h-[500px] bg-indigo-50 rounded-full blur-[150px] opacity-60" />

              <button 
                onClick={() => setShowExplanation(false)} 
                className="absolute top-16 right-16 p-6 text-slate-400 hover:text-slate-900 hover:bg-slate-50 rounded-[3rem] transition-all z-10 border-4 border-transparent hover:border-slate-100"
              >
                <X size={36} />
              </button>

              <div className="flex items-center gap-12 text-indigo-600 relative z-10">
                <div className="w-32 h-32 rounded-[4rem] bg-indigo-50 flex items-center justify-center shadow-inner border-4 border-white">
                  <Flame size={64} strokeWidth={1} />
                </div>
                <div className="space-y-3">
                  <h2 className="text-7xl font-black tracking-tighter uppercase italic leading-none text-slate-900">Photon Dynamics</h2>
                  <p className="text-[14px] font-black text-indigo-400 uppercase tracking-[0.6em] italic">The Atomic Physics of Color Synthesis</p>
                </div>
              </div>

              <div className="space-y-12 text-slate-600 leading-relaxed relative z-10">
                <p className="text-4xl italic font-black text-slate-800 tracking-tighter leading-tight max-w-4xl">"Each color is a mathematical signature of the atomic structure."</p>
                <p className="text-2xl font-medium">When chemical elements are heated, their valence electrons absorb thermal energy and jump to higher "excited" states. This simulation visualizes the specific photons released during relaxation back to the ground state.</p>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="bg-slate-50 p-12 rounded-[4.5rem] border-4 border-slate-100/50 space-y-6 group hover:border-indigo-100 transition-all">
                    <div className="flex items-center gap-5 text-indigo-500">
                      <div className="w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center group-hover:scale-110 transition-transform"><Zap size={28} fill="currentColor" /></div>
                      <h4 className="text-[14px] font-black uppercase tracking-[0.4em] italic">Excitation</h4>
                    </div>
                    <p className="text-xl leading-relaxed text-slate-500 italic font-black uppercase tracking-tight opacity-60">Thermal energy forces valence electrons into unstable high-energy orbitals.</p>
                  </div>
                  <div className="bg-indigo-50 p-12 rounded-[4.5rem] border-4 border-indigo-100/50 space-y-6 group hover:border-indigo-200 transition-all shadow-inner">
                    <div className="flex items-center gap-5 text-indigo-600">
                      <div className="w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center group-hover:scale-110 transition-transform"><Sparkles size={28} fill="currentColor" /></div>
                      <h4 className="text-[14px] font-black uppercase tracking-[0.4em] italic">Relaxation</h4>
                    </div>
                    <p className="text-xl leading-relaxed text-indigo-700/60 italic font-black uppercase tracking-tight opacity-80">As electrons drop back, they eject specific photons—creating distinct chromatic bands.</p>
                  </div>
                </div>

                <div className="p-12 bg-slate-900 rounded-[4.5rem] text-white/90 border-l-[20px] border-indigo-500 italic text-3xl font-black tracking-tighter leading-tight shadow-[0_50px_100px_-20px_rgba(0,0,0,0.3)] relative group">
                  <div className="tool-grid-bg-dark opacity-10" />
                  <span className="relative z-10">"The wavelength (λ) is determined exactly by the energy gap—a unique quantum fingerprint of the element."</span>
                </div>
              </div>

              <div className="flex gap-10 pt-10 relative z-10">
                <div className="flex-1 p-10 bg-slate-50 rounded-[3rem] border-4 border-slate-100 flex items-center gap-8 group hover:border-indigo-100 transition-all">
                   <div className="w-20 h-20 rounded-[2.5rem] bg-white shadow-md flex items-center justify-center text-indigo-500 font-mono font-black italic text-3xl group-hover:scale-110 transition-transform">ΔE</div>
                   <div>
                      <p className="text-[11px] font-black uppercase text-slate-400 tracking-[0.4em] mb-2">Energy Delta</p>
                      <p className="text-3xl font-black text-slate-900 uppercase italic tracking-tighter">h * (c / λ)</p>
                   </div>
                </div>
                <div className="flex-1 p-10 bg-slate-50 rounded-[3rem] border-4 border-slate-100 flex items-center gap-8 group hover:border-indigo-100 transition-all">
                   <div className="w-20 h-20 rounded-[2.5rem] bg-white shadow-md flex items-center justify-center text-indigo-500 group-hover:rotate-12 transition-transform"><TrendingUp size={40} /></div>
                   <div>
                      <p className="text-[11px] font-black uppercase text-slate-400 tracking-[0.4em] mb-2">Application</p>
                      <p className="text-3xl font-black text-slate-900 uppercase italic tracking-tighter">Emission Spectroscopy</p>
                   </div>
                </div>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default ChemicalFireworks;

