source:
import React, { useEffect, useRef, useState } from 'react';
import { 
  Gamepad2, 
  RotateCcw, 
  Trophy, 
  Play, 
  Settings2, 
  Info, 
  Sparkles,
  Zap,
  Activity,
  Award,
  ChevronRight,
  MousePointer2,
  Clock,
  Layout,
  Timer,
  Terminal,
  Database,
  History,
  Monitor,
  ShieldCheck,
  ChevronLeft
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';

export const ClassRex = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const canvasRef = useRef(null);
  const containerRef = useRef(null);
  const [gameState, setGameState] = useState('START'); // START, PLAYING, GAMEOVER
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(parseInt(localStorage.getItem('classrex-highscore') || '0'));
  const requestRef = useRef();

  // Game Constants
  const CANVAS_WIDTH = 800;
  const CANVAS_HEIGHT = 400;
  const GROUND_Y = 350;
  const GRAVITY = 0.6;
  const JUMP_FORCE = -12;
  const INITIAL_SPEED = 5;
  const SPEED_INCREMENT = 0.001;

  // Game Objects
  const rex = useRef({
    x: 50,
    y: GROUND_Y - 50,
    width: 50,
    height: 50,
    vy: 0,
    isJumping: false,
    frame: 0,
    frameCounter: 0
  });

  const obstacles = useRef([]);
  const clouds = useRef([]);
  const particles = useRef([]);
  const stars = useRef([]);
  const shakeFrames = useRef(0);
  const gameSpeed = useRef(INITIAL_SPEED);
  const frameCount = useRef(0);
  const scoreRef = useRef(0);

  const spawnObstacle = () => {
    const types = ['small', 'large', 'group'];
    const type = types[Math.floor(Math.random() * types.length)];
    let width = 30;
    let height = 50;

    if (type === 'large') height = 70;
    if (type === 'group') width = 70;

    obstacles.current.push({
      x: CANVAS_WIDTH,
      y: GROUND_Y - height,
      width,
      height,
      type
    });
  };

  const spawnCloud = () => {
    clouds.current.push({
      x: CANVAS_WIDTH,
      y: 50 + Math.random() * 100,
      width: 60,
      height: 30,
      speed: 0.5 + Math.random() * 1
    });
  };

  const spawnDust = (x, y, count) => {
    for (let i = 0; i < count; i++) {
      particles.current.push({
        x: x + (Math.random() - 0.5) * 20,
        y: y + (Math.random() - 0.5) * 5,
        vx: (Math.random() - 0.5) * 2 - gameSpeed.current * 0.2,
        vy: (Math.random() - 1) * 2,
        life: 1.0,
        decay: 0.02 + Math.random() * 0.03,
        size: 3 + Math.random() * 4
      });
    }
  };

  const drawRex = (ctx, x, y, width, height, frame, isJumping, vy) => {
    const p = height / 20;
    ctx.save();
    ctx.translate(x + width/2, y + height/2);
    if (isJumping) {
      const rot = Math.min(Math.max(vy * 0.03, -0.2), 0.2);
      ctx.rotate(rot);
    }
    ctx.translate(-width/2, -height/2);

    const primary = '#10b981';
    const secondary = '#059669';
    const dark = '#064e3b';
    const capColor = '#1e293b';
    const tasselColor = '#fbbf24';

    ctx.fillStyle = primary;
    ctx.fillRect(11*p, 0, 9*p, 8*p);
    ctx.fillRect(20*p, 2*p, 1*p, 5*p);

    ctx.fillStyle = capColor;
    ctx.fillRect(9*p, -3*p, 13*p, 2*p);
    ctx.fillRect(12*p, -1*p, 7*p, 1*p);
    ctx.fillStyle = tasselColor;
    ctx.fillRect(21*p, -1*p, 1*p, 3*p);
    ctx.fillRect(21*p, 2*p, 2*p, 2*p);

    ctx.fillStyle = 'white';
    ctx.fillRect(13*p, 1.5*p, 2*p, 2*p);
    ctx.fillStyle = 'black';
    ctx.fillRect(14.5*p, 1.5*p, 1*p, 1.5*p);

    ctx.fillStyle = primary;
    ctx.fillRect(11*p, 8*p, 4*p, 3*p);
    ctx.fillRect(2*p, 10*p, 11*p, 6*p);
    ctx.fillRect(4*p, 16*p, 7*p, 1*p);
    ctx.fillRect(0, 10*p, 2*p, 4*p);
    ctx.fillRect(2*p, 10*p, 1*p, 2*p);
    ctx.fillRect(13*p, 11*p, 2*p, 1*p);
    ctx.fillRect(14*p, 12*p, 1*p, 1*p);

    ctx.fillStyle = secondary;
    ctx.fillRect(2*p, 9*p, 2*p, 1*p);
    ctx.fillRect(5*p, 9*p, 2*p, 1*p);
    ctx.fillRect(8*p, 9*p, 2*p, 1*p);

    ctx.fillStyle = dark;
    if (isJumping) {
      ctx.fillRect(5*p, 17*p, 2*p, 3*p);
      ctx.fillRect(9*p, 17*p, 2*p, 3*p);
    } else {
      if (frame === 0) {
        ctx.fillRect(5*p, 17*p, 2*p, 3*p); 
        ctx.fillRect(9*p, 16*p, 2*p, 2*p); 
      } else {
        ctx.fillRect(5*p, 16*p, 2*p, 2*p); 
        ctx.fillRect(9*p, 17*p, 2*p, 3*p); 
      }
    }
    ctx.restore();
  };

  const drawCactus = (ctx, x, y, width, height, type) => {
    const p = height / 20;
    ctx.save();
    ctx.translate(x, y);
    ctx.fillStyle = '#065f46';

    const drawSingleCactus = (ox, oy, w, h) => {
      const pw = w / 6;
      ctx.fillRect(ox + 2*pw, oy, 2*pw, h);
      ctx.fillRect(ox, oy + 4*p, pw, 6*p);
      ctx.fillRect(ox, oy + 9*p, 2*pw, pw);
      ctx.fillRect(ox + 5*pw, oy + 2*p, pw, 5*p);
      ctx.fillRect(ox + 4*pw, oy + 6*p, 2*pw, pw);
    };

    if (type === 'group') {
      drawSingleCactus(0, 4*p, width/2.5, height - 4*p);
      drawSingleCactus(width/1.8, 0, width/2, height);
    } else if (type === 'large') {
      drawSingleCactus(0, 0, width, height);
    } else {
      drawSingleCactus(width/4, 4*p, width/2, height - 4*p);
    }
    ctx.restore();
  };

  const drawCloud = (ctx, x, y, width, height) => {
    const p = width / 12;
    ctx.save();
    ctx.fillStyle = 'rgba(209, 213, 219, 0.5)';
    ctx.fillRect(x + 2*p, y + 2*p, 8*p, 4*p);
    ctx.fillRect(x + 4*p, y, 6*p, 2*p);
    ctx.fillRect(x, y + 3*p, 2*p, 2*p);
    ctx.fillRect(x + 10*p, y + 3*p, 2*p, 2*p);
    ctx.restore();
  };

  const update = () => {
    if (gameState !== 'PLAYING') return;

    rex.current.vy += GRAVITY;
    rex.current.y += rex.current.vy;

    if (rex.current.y >= GROUND_Y - rex.current.height) {
      if (rex.current.isJumping) {
        spawnDust(rex.current.x + rex.current.width / 2, GROUND_Y, 8);
      }
      rex.current.y = GROUND_Y - rex.current.height;
      rex.current.vy = 0;
      rex.current.isJumping = false;
    }

    rex.current.frameCounter++;
    if (rex.current.frameCounter > 5) {
      rex.current.frame = (rex.current.frame + 1) % 2;
      rex.current.frameCounter = 0;
    }

    if (!rex.current.isJumping && frameCount.current % 6 === 0) {
      spawnDust(rex.current.x, GROUND_Y, 2);
    }

    gameSpeed.current += SPEED_INCREMENT;

    particles.current.forEach(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.life -= p.decay;
    });
    particles.current = particles.current.filter(p => p.life > 0);

    obstacles.current.forEach(obs => {
      obs.x -= gameSpeed.current;
    });

    obstacles.current.forEach(obs => {
      const hitboxPadding = 12;
      if (
        rex.current.x + hitboxPadding < obs.x + obs.width - hitboxPadding &&
        rex.current.x + rex.current.width - hitboxPadding > obs.x + hitboxPadding &&
        rex.current.y + hitboxPadding < obs.y + obs.height - hitboxPadding &&
        rex.current.y + rex.current.height - hitboxPadding > obs.y + hitboxPadding
      ) {
        gameOver();
      }
    });

    obstacles.current = obstacles.current.filter(obs => obs.x + obs.width > 0);

    const spawnRate = Math.floor(100 / (gameSpeed.current / INITIAL_SPEED));
    if (frameCount.current % spawnRate === 0) {
      if (Math.random() > 0.6) spawnObstacle();
    }

    clouds.current.forEach(cloud => {
      cloud.x -= cloud.speed + (gameSpeed.current * 0.1);
    });
    clouds.current = clouds.current.filter(cloud => cloud.x + cloud.width > 0);
    if (frameCount.current % 150 === 0) spawnCloud();

    if (stars.current.length === 0) {
      for (let i = 0; i < 60; i++) {
        stars.current.push({
          x: Math.random() * CANVAS_WIDTH,
          y: Math.random() * (CANVAS_HEIGHT * 0.6),
          size: Math.random() * 1.5,
          opacity: Math.random(),
          speed: 0.1 + Math.random() * 0.3
        });
      }
    }
    stars.current.forEach(star => {
      star.x -= star.speed + (gameSpeed.current * 0.05);
      if (star.x < 0) {
        star.x = CANVAS_WIDTH;
        star.y = Math.random() * (CANVAS_HEIGHT * 0.6);
      }
    });

    scoreRef.current++;
    if (scoreRef.current % 10 === 0) {
      setScore(Math.floor(scoreRef.current / 10));
    }
    frameCount.current++;
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');

    ctx.save();
    if (shakeFrames.current > 0) {
      const intensity = shakeFrames.current;
      ctx.translate((Math.random() - 0.5) * intensity, (Math.random() - 0.5) * intensity);
      if (gameState === 'GAMEOVER') {
        shakeFrames.current *= 0.9;
        if (shakeFrames.current < 0.5) shakeFrames.current = 0;
      }
    }

    ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    const cycleDuration = 1000;
    const currentCycle = scoreRef.current % cycleDuration;
    let nightFactor = 0;
    if (currentCycle > 500) nightFactor = Math.min(1, (currentCycle - 500) / 100);
    else if (currentCycle < 100) nightFactor = 1 - Math.min(1, currentCycle / 100);

    const skyGradient = ctx.createLinearGradient(0, 0, 0, CANVAS_HEIGHT);
    skyGradient.addColorStop(0, '#e0f2fe');
    skyGradient.addColorStop(1, '#ffffff');
    ctx.fillStyle = skyGradient;
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    if (nightFactor > 0) {
      ctx.fillStyle = `rgba(15, 23, 42, ${nightFactor * 0.9})`;
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      stars.current.forEach(star => {
        ctx.fillStyle = `rgba(255, 255, 255, ${star.opacity * nightFactor})`;
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
        ctx.fill();
      });
    }

    if (nightFactor > 0) {
      ctx.fillStyle = `rgba(253, 224, 71, ${nightFactor})`;
      ctx.beginPath();
      ctx.arc(CANVAS_WIDTH - 150, 100, 30, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = `rgba(15, 23, 42, ${nightFactor * 0.9})`;
      ctx.beginPath();
      ctx.arc(CANVAS_WIDTH - 160, 95, 25, 0, Math.PI * 2);
      ctx.fill();
    }

    clouds.current.forEach(cloud => {
      drawCloud(ctx, cloud.x, cloud.y, cloud.width, cloud.height);
    });

    ctx.strokeStyle = nightFactor > 0.5 ? '#334155' : '#94a3b8';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(0, GROUND_Y);
    ctx.lineTo(CANVAS_WIDTH, GROUND_Y);
    ctx.stroke();

    ctx.fillStyle = nightFactor > 0.5 ? '#475569' : '#cbd5e1';
    for (let i = 0; i < CANVAS_WIDTH + 100; i += 50) {
      const offset = (frameCount.current * gameSpeed.current + i) % (CANVAS_WIDTH + 100);
      ctx.fillRect(CANVAS_WIDTH - offset, GROUND_Y + 5, 4, 2);
      ctx.fillRect(CANVAS_WIDTH - offset + 20, GROUND_Y + 12, 2, 2);
    }

    particles.current.forEach(p => {
      ctx.fillStyle = `rgba(148, 163, 184, ${p.life * (1 - nightFactor * 0.5)})`;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fill();
    });

    obstacles.current.forEach(obs => {
      drawCactus(ctx, obs.x, obs.y, obs.width, obs.height, obs.type);
    });

    drawRex(ctx, rex.current.x, rex.current.y, rex.current.width, rex.current.height, rex.current.frame, rex.current.isJumping, rex.current.vy);

    ctx.restore();

    requestRef.current = requestAnimationFrame(() => {
      update();
      draw();
    });
  };

  const jump = () => {
    if (gameState === 'PLAYING' && !rex.current.isJumping) {
      rex.current.vy = JUMP_FORCE;
      rex.current.isJumping = true;
      spawnDust(rex.current.x + rex.current.width / 2, GROUND_Y, 12);
      audioEngine.playTick(settings.soundTheme);
    } else if (gameState === 'START' || gameState === 'GAMEOVER') {
      startGame();
    }
  };

  const startGame = () => {
    setGameState('PLAYING');
    setScore(0);
    obstacles.current = [];
    clouds.current = [];
    particles.current = [];
    gameSpeed.current = INITIAL_SPEED;
    frameCount.current = 0;
    shakeFrames.current = 0;
    rex.current.y = GROUND_Y - rex.current.height;
    rex.current.vy = 0;
    scoreRef.current = 0;
    audioEngine.playTick(settings.soundTheme);
  };

  const gameOver = () => {
    setGameState('GAMEOVER');
    shakeFrames.current = 15;
    spawnDust(rex.current.x + rex.current.width, rex.current.y + rex.current.height / 2, 20);
    if (Math.floor(scoreRef.current / 10) > Math.floor(highScore / 10)) {
      setHighScore(scoreRef.current);
      localStorage.setItem('classrex-highscore', scoreRef.current.toString());
    }
    audioEngine.playAlarm(settings.soundTheme);
  };

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.code === 'Space' || e.code === 'ArrowUp') {
        e.preventDefault();
        jump();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    requestRef.current = requestAnimationFrame(draw);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      cancelAnimationFrame(requestRef.current);
    };
  }, [gameState]);

  useEffect(() => {
    setOnReset(() => () => setGameState('START'));
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-6">
        <div className="flex flex-col items-end gap-0.5">
           <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Peak Distance</span>
           <span className="text-xl font-black text-amber-500 tabular-nums italic">{Math.floor(highScore / 10)}</span>
        </div>
        <div className="w-px h-8 bg-slate-200" />
        <button 
          onClick={() => { setGameState('START'); audioEngine.playTick(settings.soundTheme); }}
          className="flex items-center gap-2 px-8 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:border-indigo-100 hover:text-indigo-600 transition-all active:scale-95 shadow-sm italic"
        >
          <RotateCcw size={14} /> Reset Rex
        </button>
      </div>
    );
  }, [highScore, settings.soundTheme, setHeaderActions]);

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      {/* Statistics Sidebar */}
      <div className="w-full lg:w-[420px] flex flex-col gap-6 shrink-0 h-full overflow-hidden">
        <div className="tool-sidebar-card flex-1 p-10 flex flex-col">
           <div className="flex items-center justify-between mb-10 shrink-0">
              <div className="flex items-center gap-4">
                 <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 border-4 border-white shadow-inner">
                    <Activity size={24} />
                 </div>
                 <div className="flex flex-col">
                    <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Engagement Log</h4>
                    <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic">Adaptive Stimulus v4.2</span>
                 </div>
              </div>
           </div>

           <div className="flex-1 space-y-10 overflow-y-auto pr-2 custom-scrollbar no-scrollbar italic">
              <div className="tool-hero-stat-card p-12 bg-slate-950 shadow-2xl border-none relative group overflow-hidden rounded-[3.5rem]">
                 <div className="tool-grid-bg-dark opacity-10" />
                 <div className="absolute inset-0 bg-indigo-500/10 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                 <div className="relative z-10 flex flex-col">
                    <span className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.6em] italic mb-4 leading-none">Current Magnitude</span>
                    <AnimatePresence mode="wait">
                       <motion.div
                         key={score}
                         initial={{ opacity: 0, scale: 0.9, y: 10 }}
                         animate={{ opacity: 1, scale: 1, y: 0 }}
                         className="text-8xl font-black text-white italic tracking-tighter tabular-nums drop-shadow-2xl leading-tight"
                       >
                         {score}
                       </motion.div>
                    </AnimatePresence>
                    <div className="w-full h-1.5 bg-white/5 mt-10 rounded-full overflow-hidden border border-white/5 p-0.5">
                       <motion.div 
                         className="h-full bg-indigo-500 shadow-[0_0_20px_rgba(99,102,241,1)] rounded-full"
                         initial={false}
                         animate={{ width: `${Math.min((gameSpeed.current - INITIAL_SPEED) * 100, 100)}%` }}
                       />
                    </div>
                 </div>
              </div>

              <div className="space-y-6">
                 <div className="flex items-center gap-3">
                    <Timer size={18} className="text-slate-300" />
                    <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest leading-none">Dynamics Telemetry</h4>
                 </div>
                 <div className="grid grid-cols-1 gap-4">
                    <div className="p-8 bg-slate-50 rounded-[3rem] border-4 border-white shadow-sm flex items-center justify-between group hover:border-indigo-100 transition-all">
                       <div className="flex flex-col gap-1">
                          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Velocity Vector</span>
                          <span className="text-3xl font-black text-slate-800 italic leading-none">{gameSpeed.current.toFixed(2)} units/s</span>
