                      <div className="absolute inset-0 bg-indigo-500 blur-[100px] opacity-40 animate-pulse" />
                      <div className="relative z-10 w-full h-full bg-slate-900 rounded-[3.5rem] shadow-2xl flex items-center justify-center text-white border-4 border-white/20 rotate-3">
                         <Gamepad2 size={80} strokeWidth={1} className="text-indigo-400" />
                      </div>
