                   <div className="space-y-4">
                      <h1 className="text-8xl font-black text-white tracking-tighter uppercase leading-none drop-shadow-2xl">Class-Rex</h1>
                      <p className="text-[12px] font-black text-indigo-400 uppercase tracking-[0.8em] leading-none">Adaptive Learning Stimulus v4.2</p>
