                      <div className="relative z-10 w-full h-full bg-rose-50 rounded-[2.5rem] shadow-inner flex items-center justify-center text-rose-500 border-4 border-white rotate-3">
                         <Trophy size={64} strokeWidth={1.5} />
                      </div>
                   </div>
                   <div className="space-y-4">
                      <h1 className="text-6xl font-black text-slate-900 tracking-tighter uppercase leading-none italic">Sequence Terminated</h1>
                      <div className="flex gap-6 justify-center">
                         <div className="p-6 bg-slate-50 rounded-3xl border-2 border-slate-100 flex flex-col items-center">
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-2">Magnitude</span>
                            <span className="text-4xl font-black text-slate-800 tabular-nums italic">{score}</span>
                         </div>
                         <div className="p-6 bg-amber-50 rounded-3xl border-2 border-amber-100 flex flex-col items-center">
                            <span className="text-[10px] font-black text-amber-500 uppercase tracking-widest leading-none mb-2">Peak</span>
                            <span className="text-4xl font-black text-amber-600 tabular-nums italic">{Math.floor(highScore / 10)}</span>
                         </div>
                      </div>
                   </div>
                   <button
                     onClick={startGame}
                     className="group flex items-center gap-6 px-12 py-6 bg-slate-950 text-white rounded-[2.5rem] font-black uppercase tracking-[0.4em] italic text-lg hover:bg-rose-600 hover:scale-[1.02] active:scale-95 transition-all shadow-2xl"
                   >
                     Reboot Node <RotateCcw size={24} />
                   </button>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {/* Interaction Guide */}
        <div className="absolute bottom-12 right-12 flex items-center gap-6 z-20 pointer-events-none opacity-40 italic">
           <div className="text-right">
              <p className="text-[11px] font-black uppercase tracking-[0.6em]">Dynamics Manifest</p>
              <p className="text-[11px] font-black uppercase tracking-[0.4em] mt-1">Tap kinetic field to elevate Rex</p>
           </div>
           <div className="w-12 h-12 rounded-2xl bg-white/50 border-2 border-white flex items-center justify-center shadow-inner">
              <MousePointer2 size={24} className="text-slate-400" />
