                 <span className="text-[9px] font-black text-indigo-400 uppercase tracking-widest leading-none mb-1">Jump Control</span>
                 <span className="text-sm font-black text-slate-800 uppercase italic">Elevate Rex</span>
              </div>
           </div>
           <div className="p-6 bg-white rounded-[2.5rem] border-4 border-slate-50 shadow-sm flex items-center gap-6 group hover:border-emerald-100 transition-all">
              <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-3xl shadow-inner group-hover:scale-110 transition-transform">🦖</div>
              <div className="flex flex-col">
                 <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Character</span>
                 <span className="text-sm font-black text-slate-800 uppercase italic">ClassRex v1.2</span>
              </div>
           </div>
           <div className="p-6 bg-white rounded-[2.5rem] border-4 border-slate-50 shadow-sm flex items-center gap-6 group hover:border-indigo-100 transition-all">
              <div className="w-14 h-14 bg-slate-50 rounded-2xl flex items-center justify-center text-indigo-500 shadow-inner group-hover:scale-110 transition-transform">
                 <Sparkles size={28} />
              </div>
              <div className="flex flex-col">
                 <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Dynamics</span>
                 <span className="text-sm font-black text-slate-800 uppercase italic">Adaptive Sync</span>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default ClassRex;

