import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Trophy, 
  RotateCcw, 
  Search, 
  CheckCircle2, 
  Clock, 
  Zap, 
  Target, 
  Sparkles,
  Info,
  Timer,
  Layout,
  MousePointer2,
  Activity,
  Award,
  ChevronRight,
  Monitor,
  Flame,
  ZapOff,
  Terminal,
  Database,
  ShieldCheck,
  Eye,
  Activity as PulseIcon
} from 'lucide-react';
import confetti from 'canvas-confetti';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';

const COLORS = [
  { name: 'Red', hex: '#ef4444', text: 'text-white' },
  { name: 'Blue', hex: '#3b82f6', text: 'text-white' },
  { name: 'Green', hex: '#22c55e', text: 'text-white' },
  { name: 'Yellow', hex: '#eab308', text: 'text-slate-900' },
  { name: 'Pink', hex: '#ec4899', text: 'text-white' },
  { name: 'Orange', hex: '#f97316', text: 'text-white' },
  { name: 'Purple', hex: '#a855f7', text: 'text-white' },
  { name: 'Teal', hex: '#14b8a6', text: 'text-white' },
];

export const ColourHunt = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [gameState, setGameState] = useState('menu'); // menu, playing, finished
  const [targetColor, setTargetColor] = useState(null);
  const [score, setScore] = useState(0);
  const [timer, setTimer] = useState(60);
  const [highScore, setHighScore] = useState(() => parseInt(localStorage.getItem('colour_hunt_highscore') || '0'));
  const [options, setOptions] = useState([]);

  const timerRef = useRef(null);

  const generateOptions = useCallback((correct) => {
    const shuffled = [...COLORS].sort(() => Math.random() - 0.5);
    const result = [correct];
    let i = 0;
    while (result.length < 4) {
      if (shuffled[i].name !== correct.name) {
        result.push(shuffled[i]);
      }
      i++;
    }
    return result.sort(() => Math.random() - 0.5);
  }, []);

  const nextRound = useCallback(() => {
    const randomColor = COLORS[Math.floor(Math.random() * COLORS.length)];
    setTargetColor(randomColor);
    setOptions(generateOptions(randomColor));
  }, [generateOptions]);

  const startGame = () => {
    setScore(0);
    setTimer(60);
    setGameState('playing');
    nextRound();
    audioEngine.playTick(settings.soundTheme);
  };

  const handleChoice = (choice) => {
    if (gameState !== 'playing') return;

    if (choice.name === targetColor.name) {
      setScore(prev => prev + 1);
      audioEngine.playTick(settings.soundTheme);
      confetti({
        particleCount: 40,
        spread: 50,
        origin: { y: 0.7 },
        colors: [choice.hex]
      });
      nextRound();
    } else {
      audioEngine.playTick(settings.soundTheme);
    }
  };

  useEffect(() => {
    if (gameState === 'playing' && timer > 0) {
      timerRef.current = setInterval(() => {
        setTimer(prev => prev - 1);
      }, 1000);
    } else if (timer === 0) {
      setGameState('finished');
      if (score > highScore) {
        setHighScore(score);
        localStorage.setItem('colour_hunt_highscore', score.toString());
      }
      clearInterval(timerRef.current);
    }
    return () => clearInterval(timerRef.current);
  }, [gameState, timer, score, highScore]);

  useEffect(() => {
    setOnReset(() => () => setGameState('menu'));
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-6">
        <div className="flex flex-col items-end shrink-0">
           <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Peak Score</span>
           <span className="text-xl font-black text-amber-500 tabular-nums italic">{highScore}</span>
        </div>
        <div className="w-px h-8 bg-slate-200" />
        <button
          onClick={() => { setGameState('menu'); audioEngine.playTick(settings.soundTheme); }}
          className="flex items-center gap-2 px-8 py-2 bg-white text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-rose-50 hover:text-rose-600 transition-all active:scale-95 border-2 border-slate-100 hover:border-rose-100 shadow-sm italic"
        >
          <RotateCcw size={14} /> Exit Quest
        </button>
      </div>
    );
  }, [highScore, settings.soundTheme, setHeaderActions]);

  return (
    <div className="tool-container flex flex-col gap-8 h-full font-['Outfit'] select-none">

      {gameState === 'menu' && (
        <div className="tool-stage flex-1 p-12 lg:p-24 bg-slate-50 relative overflow-hidden flex flex-col items-center justify-center rounded-[4rem]">
           <div className="tool-grid-bg opacity-40" />

           <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-center mb-20 space-y-8 relative z-10"
           >
              <div className="relative mx-auto w-40 h-40 mb-12">
                 <div className="absolute inset-0 bg-indigo-500 blur-[100px] opacity-20 animate-pulse" />
                 <div className="relative z-10 w-full h-full bg-slate-950 rounded-[4rem] shadow-2xl flex items-center justify-center text-white border-4 border-white/20 rotate-3 group-hover:rotate-0 transition-transform">
                    <Search size={80} strokeWidth={1} className="text-indigo-400" />
                 </div>
                 <div className="absolute -top-4 -right-4 w-16 h-16 bg-white rounded-full flex items-center justify-center text-rose-500 shadow-2xl border-4 border-slate-50 animate-bounce">
                    <Sparkles size={32} />
                 </div>
              </div>
              <div className="space-y-3">
                 <h1 className="text-8xl font-black text-slate-900 tracking-tighter italic uppercase leading-none">Chromatic Hunt</h1>
                 <p className="text-[12px] font-black text-slate-400 uppercase tracking-[0.8em] italic">High-Speed Visual Processing v4.2</p>
              </div>
           </motion.div>

           <div className="flex flex-col items-center gap-8 relative z-10">
              <button
                onClick={startGame}
                className="group flex items-center gap-6 px-16 py-8 bg-indigo-600 text-white rounded-[3rem] font-black uppercase tracking-[0.4em] italic text-xl hover:bg-indigo-500 hover:scale-[1.02] active:scale-95 transition-all shadow-[0_48px_96px_-24px_rgba(79,70,229,0.5)] border-4 border-indigo-400/50"
              >
                Engage Target <ChevronRight size={32} />
              </button>
              <div className="flex items-center gap-8 opacity-40">
                 <div className="flex items-center gap-3">
                    <Clock size={18} className="text-slate-400" />
                    <span className="text-[11px] font-black uppercase tracking-widest">60s Sprint</span>
                 </div>
                 <div className="w-1.5 h-1.5 rounded-full bg-slate-300" />
                 <div className="flex items-center gap-3">
                    <Target size={18} className="text-slate-400" />
                    <span className="text-[11px] font-black uppercase tracking-widest">Infinite Iterations</span>
                 </div>
              </div>
           </div>
        </div>
      )}

      {gameState === 'playing' && (
        <div className="flex-1 flex flex-col lg:flex-row gap-8 min-h-0">
          {/* Sidebar Stats */}
          <div className="w-full lg:w-[420px] flex flex-col gap-6 shrink-0 h-full overflow-hidden">
             <div className="tool-sidebar-card flex-1 p-10 flex flex-col">
                <div className="flex items-center justify-between mb-10 shrink-0">
                   <div className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 border-4 border-white shadow-inner">
                         <PulseIcon size={24} />
                      </div>
                      <div className="flex flex-col">
                         <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Quest Metrics</h4>
                         <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic">Node Active v4.2</span>
                      </div>
                   </div>
                   <div className="px-3 py-1 bg-emerald-50 rounded-lg text-[10px] font-black text-emerald-500 uppercase tracking-widest italic border border-emerald-100">Live Sync</div>
                </div>

                <div className="space-y-8 flex-1 flex flex-col justify-center italic">
                   <div className="tool-hero-stat-card p-12 bg-slate-950 shadow-2xl border-none relative group overflow-hidden rounded-[3.5rem]">
                      <div className="tool-grid-bg-dark opacity-10" />
                      <div className="absolute inset-0 bg-rose-500/10 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                      <div className="relative z-10 flex flex-col items-center">
                         <span className="text-[11px] font-black text-rose-400 uppercase tracking-[0.4em] italic mb-4 leading-none">Temporal Decay</span>
                         <span className={`text-9xl font-black italic tracking-tighter tabular-nums leading-none ${timer < 10 ? 'text-rose-500 animate-pulse' : 'text-white'}`}>
                            {timer}
                         </span>
                         <div className="w-full h-1.5 bg-white/10 mt-10 rounded-full overflow-hidden p-0.5 border border-white/5">
                            <motion.div 
                              className={`h-full rounded-full ${timer < 10 ? 'bg-rose-500 shadow-[0_0_20px_rgba(244,63,94,0.8)]' : 'bg-indigo-500 shadow-[0_0_15px_rgba(99,102,241,1)]'}`}
                              animate={{ width: `${(timer / 60) * 100}%` }}
                            />
                         </div>
                      </div>
                   </div>

                   <div className="p-10 bg-white rounded-[4rem] border-4 border-slate-100 shadow-inner flex items-center justify-between group hover:border-indigo-100 transition-all">
                      <div className="flex flex-col gap-1">
                         <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest leading-none">Resolved</span>
                         <span className="text-5xl font-black text-slate-900 italic tracking-tighter tabular-nums leading-none group-hover:text-indigo-600 transition-colors">{score}</span>
                      </div>
                      <div className="w-20 h-20 rounded-[2.5rem] bg-indigo-50 flex items-center justify-center text-indigo-500 border-4 border-white shadow-lg group-hover:scale-110 transition-transform">
                         <Target size={36} strokeWidth={1.5} />
                      </div>
                   </div>
                </div>

                <div className="mt-10 pt-10 border-t border-slate-50 shrink-0">
                   <div className="p-8 bg-slate-900 rounded-[3rem] text-white relative overflow-hidden group shadow-2xl border border-slate-800">
                      <div className="tool-grid-bg-dark opacity-10" />
                      <div className="absolute inset-0 bg-indigo-500/5 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                      <div className="relative z-10 flex items-center justify-between">
                         <div className="flex flex-col gap-2">
                            <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] italic leading-none mb-1">Compute Stability</span>
                            <span className="text-4xl font-black italic tracking-tighter leading-none">Optimal<span className="text-xl text-white/20 ml-2">Sync</span></span>
                         </div>
                         <div className="w-14 h-14 rounded-[1.25rem] bg-white/5 border border-white/10 flex items-center justify-center text-indigo-400">
                            <ShieldCheck size={28} />
                         </div>
                      </div>
                   </div>
                </div>
             </div>
          </div>

          {/* Main Hunt Stage */}
          <div className="flex-1 tool-stage p-12 lg:p-24 relative overflow-hidden bg-white border-none rounded-[4rem] group/stage flex flex-col items-center justify-center">
             <div className="tool-grid-bg opacity-30" />

             {/* HUD Elements */}
             <div className="absolute top-12 left-12 flex flex-col gap-6 z-20 pointer-events-none italic">
                <div className="flex items-center gap-4 px-8 py-4 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border-4 border-white/60 shadow-xl group/hud hover:border-indigo-100 transition-all">
                   <div className="w-3 h-3 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_20px_rgba(79,70,229,1)]" />
                   <div className="flex flex-col">
                      <span className="text-[11px] font-black text-slate-800 uppercase tracking-[0.6em] leading-none mb-1">Chromatic Extraction</span>
                      <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.4em] leading-none">Visual Field Active</span>
                   </div>
                </div>
             </div>

             <div className="h-full flex flex-col items-center justify-center gap-16 lg:gap-24 relative z-10 w-full">
                {/* Target Prompt */}
                <div className="text-center space-y-6">
                   <span className="text-[14px] font-black text-slate-400 uppercase tracking-[1em] italic leading-none">Extract Target Spectrum</span>
                   <AnimatePresence mode="wait">
                      <motion.div
                        key={targetColor?.name}
                        initial={{ scale: 0.8, opacity: 0, y: 20 }}
                        animate={{ scale: 1, opacity: 1, y: 0 }}
                        exit={{ scale: 1.2, opacity: 0 }}
                        className="text-9xl lg:text-[14rem] font-black uppercase italic tracking-tighter leading-none drop-shadow-2xl"
                        style={{ color: targetColor?.hex }}
                      >
                        {targetColor?.name}
                      </motion.div>
                   </AnimatePresence>
                </div>

                {/* Hunt Matrix */}
                <div className="grid grid-cols-2 gap-8 lg:gap-12 w-full max-w-5xl">
                   {options.map((option, i) => (
                     <motion.button
                       key={`${option.name}-${i}`}
                       whileHover={{ scale: 1.05, rotate: i % 2 === 0 ? 1 : -1 }}
                       whileTap={{ scale: 0.95 }}
                       onClick={() => handleChoice(option)}
                       className="aspect-[2/1] rounded-[4rem] shadow-[0_48px_96px_-16px_rgba(0,0,0,0.15)] border-[12px] border-white relative overflow-hidden group/opt transition-all"
                       style={{ backgroundColor: option.hex }}
                     >
                        <div className="absolute inset-0 bg-white/20 opacity-0 group-hover/opt:opacity-100 transition-opacity" />
                        <div className="absolute inset-0 flex items-center justify-center">
                           <span className={`text-4xl lg:text-5xl font-black uppercase italic tracking-tighter opacity-0 group-hover/opt:opacity-100 transition-all translate-y-4 group-hover/opt:translate-y-0 ${option.text}`}>
