import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Copy, 
  Check, 
  RotateCcw, 
  Hash, 
  Palette, 
  Info, 
  Sparkles,
  Zap,
  Activity,
  Award,
  Layers,
  Monitor,
  MousePointer2,
  ChevronRight,
  Eye,
  Sliders,
  History,
  Terminal,
  Database,
  ShieldCheck
} from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';

const generateRandomHex = () => {
  return '#' + Math.floor(Math.random()*16777215).toString(16).padStart(6, '0').toUpperCase();
};

const hexToRgb = (hex) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : null;
};

const getLuminance = (r, g, b) => {
  const a = [r, g, b].map(v => {
    v /= 255;
    return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
  });
  return a[0] * 0.2126 + a[1] * 0.7152 + a[2] * 0.0722;
};

export const ColourPicker = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const [currentColor, setCurrentColor] = useState('#6366F1');
  const [history, setHistory] = useState([]);
  const [copied, setCopied] = useState(false);
  const [palette, setPalette] = useState([]);

  const generateNewColor = () => {
    const newColor = generateRandomHex();
    setCurrentColor(newColor);
    setHistory(prev => [newColor, ...prev].slice(0, 12));
    generatePalette(newColor);
    audioEngine.playTick(settings.soundTheme);
  };

  const generatePalette = (hex) => {
    const rgb = hexToRgb(hex);
    if (!rgb) return;

    // Simple palette generation
    const newPalette = [
      hex,
      `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.8)`,
      `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.6)`,
      `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.4)`,
      `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.2)`,
    ];
    setPalette(newPalette);
  };

  const copyToClipboard = (text) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    generateNewColor();
    setOnReset(() => generateNewColor);
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <button
          onClick={generateNewColor}
          className="flex items-center gap-2 px-8 py-2 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-slate-800 transition-all active:scale-95 shadow-xl italic"
        >
          <RotateCcw size={14} className="text-indigo-400" /> New Chromatic
        </button>
      </div>
    );
  }, [settings.soundTheme, setHeaderActions]);

  const rgb = hexToRgb(currentColor);
  const isDark = rgb ? getLuminance(rgb.r, rgb.g, rgb.b) < 0.5 : false;

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      {/* Main Color Stage */}
      <div className="flex-1 tool-stage p-0 relative overflow-hidden bg-slate-900 border-none rounded-[4rem] group/stage">
         <motion.div 
          key={currentColor}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="absolute inset-0 transition-colors duration-1000"
          style={{ backgroundColor: currentColor }}
         />
         <div className="tool-grid-bg-dark opacity-10" />

         {/* Decorative Center Element */}
         <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-[0.05]">
            <Palette size={600} className="text-white animate-pulse" strokeWidth={0.05} />
         </div>

         <div className="relative h-full flex flex-col items-center justify-center p-12 lg:p-24 z-10">
            {/* HUD Elements */}
            <div className="absolute top-12 left-12 flex flex-col gap-6 z-20 pointer-events-none italic">
               <div className={`flex items-center gap-4 px-8 py-4 backdrop-blur-3xl rounded-[2.5rem] border-4 shadow-2xl transition-all duration-1000 ${isDark ? 'bg-white/5 border-white/10 text-white/60' : 'bg-slate-900/5 border-slate-900/10 text-slate-900/60'}`}>
                  <div className={`w-3 h-3 rounded-full animate-pulse shadow-[0_0_20px_rgba(255,255,255,1)] ${isDark ? 'bg-white' : 'bg-slate-900'}`} />
                  <div className="flex flex-col">
                     <span className="text-[11px] font-black uppercase tracking-[0.6em] leading-none mb-1">Chromatic Extraction</span>
                     <span className="text-[9px] font-black uppercase tracking-[0.4em] leading-none opacity-40">Precision Sync Active</span>
                  </div>
               </div>
            </div>

            <div className={`space-y-12 text-center transition-colors duration-1000 ${isDark ? 'text-white' : 'text-slate-900'}`}>
               <div className="space-y-4">
                  <span className={`text-[14px] font-black uppercase tracking-[0.8em] italic leading-none opacity-40`}>Extracted Spectrum</span>
                  <motion.h1 
                    key={currentColor}
                    initial={{ scale: 0.8, opacity: 0, y: 20 }}
                    animate={{ scale: 1, opacity: 1, y: 0 }}
                    className="text-8xl lg:text-[12rem] font-black italic tracking-tighter leading-none drop-shadow-2xl"
                  >
                    {currentColor}
                  </motion.h1>
               </div>

               <div className="flex flex-wrap items-center justify-center gap-6">
                  <button
                    onClick={() => copyToClipboard(currentColor)}
                    className={`flex items-center gap-4 px-12 py-6 rounded-[3rem] font-black uppercase tracking-[0.3em] italic text-sm transition-all active:scale-95 border-4 shadow-2xl ${isDark ? 'bg-white/10 border-white/20 hover:bg-white/20 text-white' : 'bg-slate-900/5 border-slate-900/10 hover:bg-slate-900/10 text-slate-900'}`}
                  >
                    {copied ? <Check size={24} className="text-emerald-400" /> : <Copy size={24} />}
                    {copied ? 'Copied' : 'Extract Hex'}
                  </button>
                  <button
                    onClick={() => copyToClipboard(`rgb(${rgb?.r}, ${rgb?.g}, ${rgb?.b})`)}
                    className={`flex items-center gap-4 px-12 py-6 rounded-[3rem] font-black uppercase tracking-[0.3em] italic text-sm transition-all active:scale-95 border-4 shadow-2xl ${isDark ? 'bg-white/10 border-white/20 hover:bg-white/20 text-white' : 'bg-slate-900/5 border-slate-900/10 hover:bg-slate-900/10 text-slate-900'}`}
                  >
                    <Sliders size={24} />
                    RGB Matrix
                  </button>
               </div>
            </div>

            {/* Interaction Guide */}
            <div className={`absolute bottom-12 right-12 flex items-center gap-6 z-20 pointer-events-none opacity-40 italic transition-colors duration-1000 ${isDark ? 'text-white' : 'text-slate-900'}`}>
               <div className="text-right">
                  <p className="text-[11px] font-black uppercase tracking-[0.6em]">Chromatic Manifest</p>
                  <p className="text-[11px] font-black uppercase tracking-[0.4em] mt-1">Capture hex pattern for export</p>
               </div>
               <div className={`w-12 h-12 rounded-2xl flex items-center justify-center shadow-inner border-2 ${isDark ? 'bg-white/5 border-white/10' : 'bg-slate-900/5 border-slate-900/10'}`}>
                  <MousePointer2 size={24} />
               </div>
            </div>

            {/* Stage Footer Info */}
            <div className="absolute bottom-12 left-12 flex flex-col gap-3">
               <span className={`text-[10px] font-black uppercase tracking-[0.6em] italic transition-colors duration-1000 ${isDark ? 'text-white/40' : 'text-slate-900/40'}`}>Chromatic Legend</span>
               <div className="flex gap-2">
                  {palette.map((c, i) => (
                    <motion.div 
                      key={`${currentColor}-${i}`}
                      initial={{ scale: 0 }}
                      animate={{ scale: 1 }}
                      transition={{ delay: i * 0.1 }}
                      className="w-10 h-2 rounded-full border border-white/10 shadow-lg" 
                      style={{ backgroundColor: c }} 
                    />
                  ))}
               </div>
            </div>
         </div>
      </div>

      {/* History Sidebar */}
      <div className="w-full lg:w-[420px] flex flex-col gap-6 shrink-0 h-full overflow-hidden">
        <div className="tool-sidebar-card flex-1 p-10 flex flex-col">
           <div className="flex items-center justify-between mb-10 shrink-0">
              <div className="flex items-center gap-4">
                 <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 border-4 border-white shadow-inner">
                    <History size={24} />
                 </div>
                 <div className="flex flex-col">
                    <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Chromatic Log</h4>
                    <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic">Spectral Data v9.2</span>
                 </div>
              </div>
              <div className="px-3 py-1 bg-indigo-50 rounded-lg text-[10px] font-black text-indigo-500 uppercase tracking-widest italic border border-indigo-100">Live Feed</div>
           </div>

           <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar no-scrollbar italic">
              <AnimatePresence mode="popLayout">
                {history.map((hex, i) => (
                  <motion.button
                    key={`${hex}-${i}`}
                    layout
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    onClick={() => { setCurrentColor(hex); audioEngine.playTick(settings.soundTheme); }}
                    className="w-full p-6 rounded-[2.5rem] border-4 border-transparent hover:border-indigo-100 hover:bg-slate-50 transition-all flex items-center justify-between group mb-4"
                  >
                     <div className="flex items-center gap-6">
                        <div className="w-16 h-16 rounded-3xl shadow-xl border-4 border-white group-hover:scale-110 transition-transform" style={{ backgroundColor: hex }} />
                        <div className="text-left">
                           <span className="text-2xl font-black text-slate-800 tracking-tighter uppercase tabular-nums leading-none">{hex}</span>
                        </div>
                     </div>
                     <ChevronRight size={24} className="text-slate-300 group-hover:translate-x-1 transition-transform" />
                  </motion.button>
                ))}
                {history.length === 0 && (
                  <div className="py-24 flex flex-col items-center justify-center opacity-20 text-center gap-8 bg-slate-50 rounded-[4rem] border-4 border-dashed border-white">
                     <Layers size={64} strokeWidth={1} className="text-slate-400" />
                     <p className="text-[11px] font-black uppercase tracking-[0.5em] italic">No spectral data logged</p>
                  </div>
                )}
              </AnimatePresence>
           </div>

           <div className="mt-10 pt-10 border-t border-slate-50 shrink-0">
              <div className="p-8 bg-slate-900 rounded-[3rem] text-white relative overflow-hidden group shadow-2xl border border-slate-800">
                 <div className="tool-grid-bg-dark opacity-10" />
                 <div className="absolute inset-0 bg-indigo-500/5 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                 <div className="relative z-10 flex items-center justify-between">
                    <div className="flex flex-col gap-2">
                       <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] italic leading-none mb-1">Optical Stability</span>
                       <span className="text-4xl font-black italic tracking-tighter leading-none">Optimal<span className="text-xl text-white/20 ml-2">Sync</span></span>
                    </div>
                    <div className="w-14 h-14 rounded-[1.25rem] bg-white/5 border border-white/10 flex items-center justify-center text-indigo-400">
                       <ShieldCheck size={28} />
                    </div>
                 </div>
              </div>
           </div>
        </div>
      </div>

    </div>
  );
};

export default ColourPicker;

