source:
import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Circle, 
  LayoutGrid, 
  Hourglass, 
  Timer,
  TimerReset, 
  ChevronUp, 
  ChevronDown,
  Volume2,
  Settings2,
  Clock,
  Sparkles,
  Zap,
  Activity,
  Layers,
  Bell,
  Waves,
  Music,
  VolumeX,
  RefreshCw
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';

export const CountDown = () => {
  const [initialMinutes, setInitialMinutes] = useState(5);
  const [initialSeconds, setInitialSeconds] = useState(0);
  const [timeLeft, setTimeLeft] = useState(300);
  const [totalTime, setTotalTime] = useState(300);
  const [isRunning, setIsRunning] = useState(false);
  const [isFinished, setIsFinished] = useState(false);
  const [visualMode, setVisualMode] = useState('circle'); // circle, progress, sand, rainbow
  const [soundOverride, setSoundOverride] = useState('default');

  const { settings } = useSettings();
  const { setHasConfig, isConfigOpen, setIsConfigOpen, setOnConfigToggle, setOnReset, clearHeader } = useHeader();

  useEffect(() => {
    setHasConfig(true);
    setOnConfigToggle(() => () => setIsConfigOpen(prev => !prev));
    setOnReset(() => reset);
    return () => clearHeader();
  }, [clearHeader, setHasConfig, setOnReset, setOnConfigToggle, setIsConfigOpen]);

  useEffect(() => {
    let intervalId;
    if (isRunning && timeLeft > 0) {
      intervalId = setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            setIsRunning(false);
            setIsFinished(true);
            const activeTheme = soundOverride === 'default' ? settings.soundTheme : soundOverride;
            audioEngine.playAlarm(activeTheme);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(intervalId);
  }, [isRunning, timeLeft, settings.soundTheme, soundOverride]);

  useEffect(() => {
    const timeout = setTimeout(() => {
      if (!isRunning && !isFinished) {
        const newTotal = initialMinutes * 60 + initialSeconds;
        setTimeLeft(prev => prev !== newTotal ? newTotal : prev);
        setTotalTime(prev => prev !== newTotal ? newTotal : prev);
      }
    }, 0);
    return () => clearTimeout(timeout);
  }, [initialMinutes, initialSeconds, isRunning, isFinished]);

  const toggle = () => {
    if (isFinished) {
      setIsFinished(false);
      const newTotal = initialMinutes * 60 + initialSeconds;
      setTimeLeft(newTotal);
      setTotalTime(newTotal);
    }
    if (timeLeft > 0) {
      setIsRunning(!isRunning);
      audioEngine.playTick(settings.soundTheme);
    }
  };

  const reset = () => {
    setIsRunning(false);
    setIsFinished(false);
    const newTotal = initialMinutes * 60 + initialSeconds;
    setTimeLeft(newTotal);
    setTotalTime(newTotal);
    setVisualMode('circle');
    setSoundOverride('default');
    audioEngine.playTick(settings.soundTheme);
  };

  const soundOptions = [
    { id: 'default', name: 'DEFAULT' },
    { id: 'none', name: 'NONE' },
    { id: 'classic', name: 'CLASSIC' },
    { id: 'digital', name: 'DIGITAL' },
    { id: 'soft', name: 'SOFT' },
    { id: 'bubbly', name: 'BUBBLY' },
    { id: 'chime', name: 'CHIME' },
    { id: 'synth', name: 'SYNTH' },
    { id: 'beep', name: 'BEEP' },
    { id: 'siren', name: 'SIREN' }
  ];

  const visualModes = [
    { id: 'circle', icon: Circle },
    { id: 'grid', icon: LayoutGrid },
    { id: 'sand', icon: Hourglass },
    { id: 'rainbow', icon: TimerReset }
  ];

  const renderVisualization = () => {
    const progress = totalTime > 0 ? ((totalTime - timeLeft) / totalTime) * 100 : 100;
    const remainingProgress = 100 - progress;

    if (visualMode === 'grid') {
      return (
        <div className="grid grid-cols-10 gap-1.5 w-full max-w-sm aspect-square bg-slate-50/50 p-6 rounded-[2.5rem] border-2 border-slate-50 shadow-inner group-hover:scale-105 transition-transform">
          {[...Array(100)].map((_, i) => (
            <motion.div
              key={i}
              initial={{ scale: 1, opacity: 1 }}
              animate={{ 
                scale: (100 - i) <= (remainingProgress) ? 1 : 0,
                opacity: (100 - i) <= (remainingProgress) ? 1 : 0
              }}
              className="bg-indigo-500 rounded-sm"
            />
          ))}
        </div>
      );
    }

    if (visualMode === 'circle') {
      const radius = 60;
      const circumference = 2 * Math.PI * radius;
      const strokeDashoffset = (remainingProgress / 100) * circumference;

      return (
        <div className="relative flex items-center justify-center bg-slate-50/50 p-12 rounded-full border-2 border-slate-50 shadow-inner group-hover:scale-105 transition-transform">
          <svg viewBox="0 0 160 160" className="transform -rotate-90 w-48 h-48 md:w-64 md:h-64">
            <circle cx="80" cy="80" r="60" stroke="#f1f5f9" strokeWidth="8" fill="transparent" />
            <motion.circle
              cx="80" cy="80" r="60"
              stroke={isFinished ? "#f43f5e" : "#6366f1"}
              strokeWidth="8"
              fill="transparent"
              strokeDasharray={circumference}
              strokeLinecap="round"
              initial={{ strokeDashoffset: circumference }}
              animate={{ strokeDashoffset }}
              transition={{ ease: "linear", duration: 1 }}
            />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
            {isRunning ? <Pause size={48} className="text-indigo-600/20" /> : <Play size={48} className="text-emerald-600/20 ml-2" />}
          </div>
        </div>
      );
    }

    if (visualMode === 'sand') {
      return (
        <div className="relative w-32 h-56 border-8 border-slate-50 rounded-3xl flex flex-col items-center overflow-hidden bg-white shadow-inner group-hover:scale-105 transition-transform">
           <div className="w-full h-1/2 border-b-2 border-slate-50 relative overflow-hidden flex items-end">
              <motion.div
                className="w-full bg-amber-400/20"
                initial={{ height: '100%' }}
                animate={{ height: `${remainingProgress}%` }}
                transition={{ ease: "linear", duration: 1 }}
              />
           </div>
           <div className="w-full h-1/2 relative overflow-hidden">
              <motion.div
                className="w-full bg-amber-400 absolute bottom-0"
                initial={{ height: '0%' }}
                animate={{ height: `${progress}%` }}
                transition={{ ease: "linear", duration: 1 }}
              />
           </div>
           {isRunning && !isFinished && (
             <div className="absolute top-1/2 left-1/2 w-1 h-full bg-amber-400/40 transform -translate-x-1/2 animate-pulse" />
           )}
        </div>
      );
    }

    if (visualMode === 'rainbow') {
      const radius = 40;
      const circumference = 2 * Math.PI * radius;
      const strokeDashoffset = (progress / 100) * circumference;
      const hue = (remainingProgress / 100) * 360;

      return (
        <div className="relative flex items-center justify-center bg-slate-50/50 p-12 rounded-full border-2 border-slate-50 shadow-inner group-hover:scale-105 transition-transform">
          <svg viewBox="0 0 160 160" className="transform -rotate-90 w-48 h-48 md:w-64 md:h-64">
            <circle cx="80" cy="80" r={radius} stroke="#f1f5f9" strokeWidth="40" fill="transparent" />
            <motion.circle
              cx="80" cy="80" r={radius}
              stroke="currentColor"
              strokeWidth="40"
              fill="transparent"
              strokeDasharray={circumference}
              initial={{ strokeDashoffset: 0 }}
              animate={{ strokeDashoffset }}
              transition={{ ease: "linear", duration: 1 }}
              style={{
                color: isFinished ? '#f43f5e' : `hsl(${hue}, 80%, 55%)`
              }}
            />
          </svg>
        </div>
      );
    }

    return null;
  };

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none overflow-hidden">

      {/* Main Temporal Stage */}
      <div className="flex-1 tool-stage p-0 relative overflow-hidden bg-white border-none rounded-[4rem] group/stage flex flex-col items-center justify-center shadow-xl">
        <div className="tool-grid-bg opacity-30" />

        <div className="relative z-10 flex flex-col items-center justify-center gap-12 w-full h-full py-12 px-8 overflow-y-auto no-scrollbar">

          {/* Digit Cluster - Now ABOVE the visualization */}
          <div className="flex items-center gap-8 md:gap-16 shrink-0">
            {/* Minutes */}
            <div className="flex flex-col items-center gap-2">
              <button 
                onClick={(e) => { e.stopPropagation(); setInitialMinutes(m => Math.min(99, m + 1)); audioEngine.playTick(settings.soundTheme); }}
                className={`p-2 text-slate-200 hover:text-indigo-500 transition-all ${isRunning ? 'opacity-0 pointer-events-none' : ''}`}
              >
                <ChevronUp size={64} strokeWidth={3} />
              </button>
              <div className="text-8xl md:text-[10rem] font-black tabular-nums tracking-tighter leading-none text-slate-900">
                {Math.floor(timeLeft / 60).toString().padStart(2, '0')}
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); setInitialMinutes(m => Math.max(0, m - 1)); audioEngine.playTick(settings.soundTheme); }}
                className={`p-2 text-slate-200 hover:text-indigo-500 transition-all ${isRunning ? 'opacity-0 pointer-events-none' : ''}`}
              >
                <ChevronDown size={64} strokeWidth={3} />
              </button>
            </div>

            <div className="text-8xl md:text-[10rem] font-black text-slate-100 leading-none pb-8">:</div>

            {/* Seconds */}
            <div className="flex flex-col items-center gap-2">
              <button 
                onClick={(e) => { e.stopPropagation(); setInitialSeconds(s => (s + 1) % 60); audioEngine.playTick(settings.soundTheme); }}
                className={`p-2 text-slate-200 hover:text-indigo-500 transition-all ${isRunning ? 'opacity-0 pointer-events-none' : ''}`}
              >
                <ChevronUp size={64} strokeWidth={3} />
              </button>
              <div className="text-8xl md:text-[10rem] font-black tabular-nums tracking-tighter leading-none text-slate-900">
                {(timeLeft % 60).toString().padStart(2, '0')}
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); setInitialSeconds(s => (s - 1 + 60) % 60); audioEngine.playTick(settings.soundTheme); }}
                className={`p-2 text-slate-200 hover:text-indigo-500 transition-all ${isRunning ? 'opacity-0 pointer-events-none' : ''}`}
              >
                <ChevronDown size={64} strokeWidth={3} />
              </button>
            </div>
          </div>

          {/* Visualization - Click to Start */}
          <div 
            onClick={toggle}
            className="flex items-center justify-center min-h-[320px] w-full shrink-0 cursor-pointer group active:scale-95 transition-all"
          >
            {renderVisualization() || (
               <div className="w-32 h-32 rounded-full border-8 border-slate-50 flex items-center justify-center">
                <div className="w-24 h-24 rounded-full bg-slate-50 opacity-50" />
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Configuration Sidebar */}
      <AnimatePresence>
        {isConfigOpen && (
          <motion.div 
            initial={{ width: 0, opacity: 0 }}
            animate={{ width: 320, opacity: 1 }}
            exit={{ width: 0, opacity: 0 }}
            className="shrink-0 h-full overflow-hidden"
          >
            <div className="tool-sidebar-card-flush flex-1 flex flex-col overflow-hidden italic">
              <div className="tool-history-header">
                <div className="flex items-center gap-2">
                  <Settings2 size={16} className="text-indigo-400" />
                  <h4 className="mb-0">Configuration</h4>
                </div>
              </div>

              <div className="flex-1 p-8 space-y-12 overflow-y-auto custom-scrollbar no-scrollbar italic">
                {/* Visual Mode Section */}
                <div className="space-y-6">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Visual Mode</span>
                  <div className="grid grid-cols-2 gap-3">
                    {visualModes.map(mode => (
                      <button
                        key={mode.id}
                        onClick={() => { setVisualMode(mode.id); audioEngine.playTick(settings.soundTheme); }}
                        className={`p-4 rounded-2xl transition-all border-4 flex items-center justify-center ${
                          visualMode === mode.id 
                            ? 'border-indigo-100 bg-white text-indigo-600 shadow-sm' 
                            : 'border-transparent text-slate-300 hover:text-slate-400 bg-slate-50'
                        }`}
                      >
                        <mode.icon size={20} />
                      </button>
                    ))}
                  </div>
                </div>

                {/* Sound Effect Section */}
                <div className="space-y-6">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Sound Effect</span>
                  <div className="grid grid-cols-2 gap-2">
                    {soundOptions.map(opt => (
                      <button
                        key={opt.id}
                        onClick={() => {
                          setSoundOverride(opt.id);
                          if (opt.id !== 'none') {
                            audioEngine.playAlarm(opt.id === 'default' ? settings.soundTheme : opt.id);
                          }
                        }}
                        className={`py-3 px-2 rounded-xl border-2 transition-all text-[9px] font-black tracking-tighter ${
                          soundOverride === opt.id 
                            ? 'border-orange-400 bg-white text-orange-600 shadow-sm' 
                            : 'border-slate-50 bg-slate-50 text-slate-400 hover:bg-slate-100'
                        }`}
                      >
                        {opt.name}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};
export default CountDown;

