import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Grid3X3, BookOpen, Volume2, RotateCcw, 
  ChevronRight, CheckCircle2, XCircle, Sparkles, Lightbulb,
  ArrowRight, ArrowDown, ListFilter, Play, Trash2,
  Info, Activity, Zap, Layers, Trophy, Clock,
  MousePointer2, Terminal, Settings2, ShieldCheck, Database,
  Search, Award, Monitor, ChevronLeft
} from 'lucide-react';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';

const INITIAL_GRID_SIZE = 40;
const MAX_CELL_SIZE = 48;
const MIN_CELL_SIZE = 24;

export const Crossword = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const [status, setStatus] = useState('setup'); // setup, playing, finished
  const [lists, setLists] = useState([]);
  const [selectedList, setSelectedList] = useState(null);
  const [grid, setGrid] = useState([]);
  const [clues, setClues] = useState([]);
  const [gridSize, setGridSize] = useState({ rows: 0, cols: 0 });
  const [direction, setDirection] = useState('across'); // across, down
  const containerRef = useRef(null);
  const [cellSize, setCellSize] = useState(40);
  const [userGrid, setUserGrid] = useState({});
  const [focusedCell, setFocusedCell] = useState(null);

  useEffect(() => {
    const saved = localStorage.getItem('spelling_lists');
    if (saved) {
      setLists(JSON.parse(saved));
    }
  }, []);

  const generateCrossword = useCallback((words) => {
    const cleanWords = words.map(w => w.toUpperCase().trim()).filter(w => w.length > 1);
    if (cleanWords.length === 0) return;

    const canPlace = (word, x, y, isAcross, currentGrid) => {
      if (isAcross) {
        if (x < 0 || x + word.length > INITIAL_GRID_SIZE || y < 0 || y >= INITIAL_GRID_SIZE) return false;
        for (let i = 0; i < word.length; i++) {
          const cell = currentGrid[y][x + i];
          if (cell !== null && cell !== word[i]) return false;
          if (cell === null) {
            if (y > 0 && currentGrid[y - 1][x + i]) return false;
            if (y < INITIAL_GRID_SIZE - 1 && currentGrid[y + 1][x + i]) return false;
          }
        }
        if (x > 0 && currentGrid[y][x - 1]) return false;
        if (x + word.length < INITIAL_GRID_SIZE && currentGrid[y][x + word.length]) return false;
      } else {
        if (y < 0 || y + word.length > INITIAL_GRID_SIZE || x < 0 || x >= INITIAL_GRID_SIZE) return false;
        for (let i = 0; i < word.length; i++) {
          const cell = currentGrid[y + i][x];
          if (cell !== null && cell !== word[i]) return false;
          if (cell === null) {
            if (x > 0 && currentGrid[y + i][x - 1]) return false;
            if (x < INITIAL_GRID_SIZE - 1 && currentGrid[y + i][x + 1]) return false;
          }
        }
        if (y > 0 && currentGrid[y - 1][x]) return false;
        if (y + word.length < INITIAL_GRID_SIZE && currentGrid[y + word.length][x]) return false;
      }
      return true;
    };

    const attemptGeneration = () => {
      let tempGrid = Array(INITIAL_GRID_SIZE).fill(null).map(() => Array(INITIAL_GRID_SIZE).fill(null));
      let placedWords = [];
      let remainingWords = [...cleanWords].sort((a, b) => b.length - a.length);

      const placeWordInternal = (word, x, y, isAcross) => {
        let num;
        const existing = placedWords.find(p => p.x === x && p.y === y);
        if (existing) num = existing.num;
        else {
          const maxNum = placedWords.length === 0 ? 0 : Math.max(...placedWords.map(p => p.num));
          num = maxNum + 1;
        }

        for (let i = 0; i < word.length; i++) {
          if (isAcross) tempGrid[y][x + i] = word[i];
          else tempGrid[y + i][x] = word[i];
        }
        placedWords.push({ word, x, y, isAcross, num });
      };

      const first = remainingWords.shift();
      placeWordInternal(first, Math.floor((INITIAL_GRID_SIZE - first.length) / 2), Math.floor(INITIAL_GRID_SIZE / 2), true);

      let iterations = 0;
      while (remainingWords.length > 0 && iterations < 1000) {
        iterations++;
        let placedAny = false;
        const currentRemaining = [...remainingWords];
        for (let i = 0; i < currentRemaining.length; i++) {
          const word = currentRemaining[i];
          const shuffledPlaced = [...placedWords].sort(() => Math.random() - 0.5);
          for (const p of shuffledPlaced) {
            for (let j = 0; j < p.word.length; j++) {
              for (let k = 0; k < word.length; k++) {
                if (p.word[j] === word[k]) {
                  const nx = p.isAcross ? p.x + j : p.x - k;
                  const ny = p.isAcross ? p.y - k : p.y + j;
                  const nIsAcross = !p.isAcross;
                  if (canPlace(word, nx, ny, nIsAcross, tempGrid)) {
                    placeWordInternal(word, nx, ny, nIsAcross);
                    remainingWords = remainingWords.filter(w => w !== word);
                    placedAny = true;
                    break;
                  }
                }
              }
              if (placedAny) break;
            }
            if (placedAny) break;
          }
          if (placedAny) break;
        }

        if (!placedAny && remainingWords.length > 0) {
          const word = remainingWords[0];
          let islandPlaced = false;
          const centerX = Math.floor(placedWords.reduce((acc, p) => acc + p.x, 0) / placedWords.length);
          const centerY = Math.floor(placedWords.reduce((acc, p) => acc + p.y, 0) / placedWords.length);
          for (let radius = 2; radius < 15 && !islandPlaced; radius++) {
            for (let attempt = 0; attempt < 20; attempt++) {
              const rx = centerX + Math.floor((Math.random() - 0.5) * radius * 2);
              const ry = centerY + Math.floor((Math.random() - 0.5) * radius * 2);
              const rIsAcross = Math.random() > 0.5;
              if (canPlace(word, rx, ry, rIsAcross, tempGrid)) {
                placeWordInternal(word, rx, ry, rIsAcross);
                remainingWords.shift();
                islandPlaced = true;
                placedAny = true;
                break;
              }
            }
          }
          if (!islandPlaced) remainingWords.shift();
        }
      }

      let minX = INITIAL_GRID_SIZE, maxX = 0, minY = INITIAL_GRID_SIZE, maxY = 0;
      let hasPlaced = false;
      for (let y = 0; y < INITIAL_GRID_SIZE; y++) {
        for (let x = 0; x < INITIAL_GRID_SIZE; x++) {
          if (tempGrid[y][x]) {
            minX = Math.min(minX, x);
            maxX = Math.max(maxX, x);
            minY = Math.min(minY, y);
            maxY = Math.max(maxY, y);
            hasPlaced = true;
          }
        }
      }

      if (!hasPlaced) return null;
      minX = Math.max(0, minX - 1);
      minY = Math.max(0, minY - 1);
      maxX = Math.min(INITIAL_GRID_SIZE - 1, maxX + 1);
      maxY = Math.min(INITIAL_GRID_SIZE - 1, maxY + 1);

      const rows = maxY - minY + 1;
      const cols = maxX - minX + 1;
      const trimmedGrid = Array(rows).fill(null).map(() => Array(cols).fill(null));
      for (let y = minY; y <= maxY; y++) {
        for (let x = minX; x <= maxX; x++) {
          trimmedGrid[y - minY][x - minX] = tempGrid[y][x];
        }
      }
      const trimmedClues = placedWords.map(clue => ({
        ...clue,
        x: clue.x - minX,
        y: clue.y - minY
      }));
      return { grid: trimmedGrid, clues: trimmedClues, rows, cols, area: rows * cols };
    };

    let best = null;
    for (let i = 0; i < 5; i++) {
      const result = attemptGeneration();
      if (!best || (result && result.area < best.area)) best = result;
    }

    if (best) {
      setGrid(best.grid);
      setClues(best.clues);
      setGridSize({ rows: best.rows, cols: best.cols });
      setUserGrid({});
      setStatus('playing');
      audioEngine.playTick(settings.soundTheme);
    }
  }, [settings.soundTheme]);

  useEffect(() => {
    if (status !== 'playing' || !containerRef.current) return;
    const updateSize = () => {
      const container = containerRef.current;
      if (!container) return;
      const { width, height } = container.getBoundingClientRect();
      const padding = 80;
      const availableW = width - padding;
      const availableH = height - padding;
      const sizeW = availableW / gridSize.cols;
      const sizeH = availableH / gridSize.rows;
      let newSize = Math.min(sizeW, sizeH);
      newSize = Math.max(MIN_CELL_SIZE, Math.min(MAX_CELL_SIZE, newSize));
      setCellSize(newSize);
    };
    updateSize();
    const resizeObserver = new ResizeObserver(updateSize);
    if (containerRef.current) resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, [status, gridSize]);

  const startGame = (list) => {
    setSelectedList(list);
    generateCrossword(list.words);
  };

  const handleCellInput = (x, y, val) => {
    const char = val.toUpperCase().slice(-1);
    if (!char.match(/[A-Z]/) && char !== "") return;
    const key = `${x}-${y}`;
    setUserGrid(prev => ({ ...prev, [key]: char }));
    if (char !== "") {
      const nextX = direction === 'across' ? x + 1 : x;
      const nextY = direction === 'down' ? y + 1 : y;
      if (nextY < gridSize.rows && nextX < gridSize.cols && grid[nextY][nextX]) {
        setFocusedCell({ x: nextX, y: nextY });
      }
    }
    audioEngine.playTick(settings.soundTheme);
  };

  const speak = (text) => {
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
    audioEngine.playTick(settings.soundTheme);
  };

  const checkWin = useCallback(() => {
    const isComplete = clues.every(clue => {
      for (let i = 0; i < clue.word.length; i++) {
        const cx = clue.isAcross ? clue.x + i : clue.x;
        const cy = clue.isAcross ? clue.y : clue.y + i;
        if (userGrid[`${cx}-${cy}`] !== clue.word[i]) return false;
      }
      return true;
    });
    if (isComplete) {
      setStatus('finished');
      audioEngine.playAlarm(settings.soundTheme);
    }
  }, [clues, userGrid, settings.soundTheme]);

  useEffect(() => {
    if (status === 'playing') checkWin();
  }, [checkWin, status]);

  useEffect(() => {
    setOnReset(() => () => setStatus('setup'));
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        {status === 'playing' && (
          <>
            <div className="flex bg-slate-100 p-0.5 rounded-xl border-2 border-slate-200/50 shadow-inner w-fit shrink-0">
              <button 
                onClick={() => { setDirection('across'); audioEngine.playTick(settings.soundTheme); }} 
                className={`flex items-center gap-2 px-5 py-1.5 rounded-lg font-black text-[10px] uppercase tracking-[0.2em] transition-all ${direction === 'across' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <ArrowRight size={14} /> Across
              </button>
              <button 
                onClick={() => { setDirection('down'); audioEngine.playTick(settings.soundTheme); }} 
                className={`flex items-center gap-2 px-5 py-1.5 rounded-lg font-black text-[10px] uppercase tracking-[0.2em] transition-all ${direction === 'down' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <ArrowDown size={14} /> Down
              </button>
            </div>
            <div className="w-px h-6 bg-slate-200" />
            <button
              onClick={() => { setStatus('setup'); audioEngine.playTick(settings.soundTheme); }}
              className="flex items-center gap-2 px-6 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:border-rose-100 hover:text-rose-600 transition-all active:scale-95 shadow-sm italic"
            >
              <RotateCcw size={14} /> Exit Lab
            </button>
          </>
        )}
      </div>
    );
  }, [status, direction, settings.soundTheme, setHeaderActions]);

  return (
    <div className="tool-container flex flex-col gap-8 h-full font-['Outfit'] select-none">
      <AnimatePresence mode="wait">
        {status === 'setup' ? (
          <motion.div
            key="setup"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className="tool-stage flex-1 p-12 lg:p-24 bg-slate-50 relative overflow-hidden flex flex-col items-center justify-center rounded-[4rem]"
          >
            <div className="tool-grid-bg opacity-40" />

            <motion.div 
             initial={{ opacity: 0, y: 20 }}
             animate={{ opacity: 1, y: 0 }}
             className="text-center mb-16 space-y-8 relative z-10"
            >
               <div className="relative mx-auto w-40 h-40 mb-12">
                  <div className="absolute inset-0 bg-indigo-500 blur-[100px] opacity-20 animate-pulse" />
                  <div className="relative z-10 w-full h-full bg-slate-950 rounded-[4rem] shadow-2xl flex items-center justify-center text-white border-4 border-white/20 rotate-3 group-hover:rotate-0 transition-transform">
                     <Terminal size={80} strokeWidth={1} className="text-indigo-400" />
                  </div>
                  <div className="absolute -top-4 -right-4 w-16 h-16 bg-white rounded-full flex items-center justify-center text-rose-500 shadow-2xl border-4 border-slate-50 animate-bounce">
                     <Sparkles size={32} />
                  </div>
               </div>
               <div className="space-y-3">
                  <h1 className="text-8xl font-black text-slate-900 tracking-tighter italic uppercase leading-none">Grid Guardian</h1>
                  <p className="text-[12px] font-black text-slate-400 uppercase tracking-[0.8em] italic">Pattern Decryption Protocol v5.1</p>
               </div>
            </motion.div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8 w-full max-w-7xl relative z-10 px-8">
              {lists.map(list => (
                <button
                  key={list.id}
                  onClick={() => startGame(list)}
                  className="group relative p-10 bg-white border-4 border-slate-200 rounded-[3.5rem] hover:border-indigo-600 hover:shadow-[0_40px_80px_-20px_rgba(99,102,241,0.2)] transition-all text-left flex flex-col gap-8 active:scale-95 shadow-sm italic"
                >
