import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Plus,
  Trash2,
  RotateCcw,
  ChevronRight,
  Settings2,
  Clock,
  Calendar,
  X,
  Trash,
  ChevronDown,
  Layout,
  Info
} from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';
import { defaultSchedules, DAYS, SCHOOL_EMOJIS } from './DailySchedule/scheduleData';

export const DailySchedule = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [currentDay, setCurrentDay] = useState('Monday');
  const [allSchedules, setAllSchedules] = useState(defaultSchedules);
  const [isEditing, setIsEditing] = useState(false);
  const [editingItem, setEditingItem] = useState(null);
  const [showEmojiPicker, setShowEmojiPicker] = useState(null);
  const [currentTime, setCurrentTime] = useState('');

  const scrollRef = useRef(null);

  useEffect(() => {
    const updateTime = () => {
      const now = new Date();
      const timeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`;
      setCurrentTime(timeStr);
    };
    updateTime();
    const interval = setInterval(updateTime, 10000); // Check every 10 seconds for better responsiveness
    return () => clearInterval(interval);
  }, []);

  const getEventStatus = (item) => {
    if (!currentTime) return 'future';
    if (currentTime < item.startTime) return 'future';
    if (currentTime >= item.startTime && currentTime < item.endTime) return 'current';
    return 'past';
  };

  const currentSchedule = allSchedules[currentDay] || [];

  useEffect(() => {
    const saved = localStorage.getItem('daily_schedules_v2');
    if (saved) {
      try {
        setAllSchedules(JSON.parse(saved));
      } catch (e) {
        console.error('Failed to parse saved schedules', e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('daily_schedules_v2', JSON.stringify(allSchedules));
  }, [allSchedules]);

  const resetSchedule = () => {
    setAllSchedules(prev => ({
      ...prev,
      [currentDay]: defaultSchedules[currentDay]
    }));
    audioEngine.playTick(settings.soundTheme);
  };

  const clearDay = () => {
    setAllSchedules(prev => ({
      ...prev,
      [currentDay]: []
    }));
    audioEngine.playTick(settings.soundTheme);
  };

  const updateSchedule = (newSchedule) => {
    setAllSchedules(prev => ({
      ...prev,
      [currentDay]: newSchedule.sort((a, b) => a.startTime.localeCompare(b.startTime))
    }));
  };

  const addItem = (startTime = '09:00', endTime = '10:00') => {
    const newItem = {
      id: Date.now().toString(),
      startTime,
      endTime,
      activity: 'New Activity',
      emoji: '⭐'
    };
    updateSchedule([...currentSchedule, newItem]);
    audioEngine.playTick(settings.soundTheme);
  };

  const removeItem = (id) => {
    updateSchedule(currentSchedule.filter(item => item.id !== id));
    audioEngine.playTick(settings.soundTheme);
  };

  const updateItem = (id, updates) => {
    updateSchedule(currentSchedule.map(item => item.id === id ? { ...item, ...updates } : item));
  };

  const fillGap = (index) => {
    const prevItem = currentSchedule[index - 1];
    const nextItem = currentSchedule[index];
    if (!prevItem || !nextItem) return;

    const newItem = {
      id: Date.now().toString(),
      startTime: prevItem.endTime,
      endTime: nextItem.startTime,
      activity: 'New Activity',
      emoji: '➕'
    };
    updateSchedule([...currentSchedule, newItem]);
    audioEngine.playTick(settings.soundTheme);
  };

  const formatTime = (time24) => {
    if (!time24) return '';
    const [hours, minutes] = time24.split(':');
    const h = parseInt(hours);
    const ampm = h >= 12 ? 'PM' : 'AM';
    const h12 = h % 12 || 12;
    return `${h12.toString().padStart(2, '0')}:${minutes} ${ampm}`;
  };

  useEffect(() => {
    setOnReset(() => resetSchedule);

    // Auto scroll to current activity on mount or day change
    if (currentTime && currentSchedule.length > 0) {
      const currentIdx = currentSchedule.findIndex(item => getEventStatus(item) === 'current');
      if (currentIdx !== -1) {
        setTimeout(() => {
          const element = document.getElementById(`schedule-item-${currentSchedule[currentIdx].id}`);
          if (element) {
            element.scrollIntoView({ behavior: 'smooth', block: 'center' });
          }
        }, 500);
      }
    }

    return () => clearHeader();
  }, [clearHeader, setOnReset, currentDay]);

  return (
    <div className="tool-container flex flex-col h-full font-['Outfit'] select-none bg-[#f8fafc] p-4 lg:p-8 overflow-hidden">
      <div className="max-w-5xl mx-auto w-full flex flex-col h-full bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">

        {/* Internal Header / Tools Area */}
        <div className="px-6 py-4 border-b border-slate-100 flex flex-wrap items-center justify-between gap-4 shrink-0 bg-white/50 backdrop-blur-sm">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl">
              <Calendar size={20} />
            </div>
            <div>
              <h2 className="text-xl font-black text-slate-900 leading-none uppercase tracking-tight">{currentDay}</h2>
              <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mt-1">Schedule</p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200/50">
              {DAYS.map(day => (
                <button
                  key={day}
                  onClick={() => {
                    setCurrentDay(day);
                    audioEngine.playTick(settings.soundTheme);
                  }}
                  className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-tighter transition-all ${currentDay === day
                      ? 'bg-white text-indigo-600 shadow-sm'
                      : 'text-slate-500 hover:text-slate-700 hover:bg-white/50'
                    }`}
                >
                  {day.slice(0, 3)}
                </button>
              ))}
            </div>

            <div className="w-px h-6 bg-slate-200 mx-1 hidden sm:block" />

            <div className="flex items-center gap-2">
              <button
                onClick={resetSchedule}
                className="flex items-center gap-2 px-4 py-2 bg-slate-50 text-slate-600 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-100 border border-slate-100 transition-all active:scale-95 shadow-sm"
                title="Reset to default"
              >
                <RotateCcw size={14} /> Reset
              </button>
              <button
                onClick={clearDay}
                className="flex items-center gap-2 px-4 py-2 bg-slate-50 text-rose-500 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-rose-50 border border-rose-100/50 transition-all active:scale-95 shadow-sm"
                title="Clear current day"
              >
                <Trash size={14} /> Clear
              </button>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 lg:p-6 no-scrollbar" ref={scrollRef}>
          <div className="flex flex-col items-center gap-2 max-w-4xl mx-auto">

            <AnimatePresence mode="popLayout">
              <motion.div
                key={currentDay}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                className="w-full relative bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-sm"
              >
                {/* Table Header */}
                <div className="grid grid-cols-[180px_48px_1fr_48px] gap-4 px-6 py-2 bg-slate-50 border-b border-slate-100 shrink-0">
                  <div className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Time Interval</div>
                  <div className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] text-center">Icon</div>
                  <div className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Activity Name</div>
                  <div className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] text-right">Edit</div>
                </div>

                {/* Add Top Button Row */}
                <div className="p-2 flex justify-center bg-slate-50/30 border-b border-slate-50">
                  <button 
                    onClick={() => addItem('08:00', '09:00')}
                    className="flex items-center gap-2 px-4 py-1.5 bg-white text-slate-400 hover:text-indigo-600 hover:border-indigo-100 border border-slate-200 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all shadow-sm"
                  >
                    <Plus size={14} /> Add Activity
                  </button>
                </div>

                <div className="divide-y divide-slate-50">
                  {currentSchedule.map((item, index) => {
                    const status = getEventStatus(item);
                    return (
                      <React.Fragment key={item.id}>
                        {/* Schedule Item / Row */}
                        <motion.div
                          layout
                          id={`schedule-item-${item.id}`}
                          className={`group relative grid grid-cols-[180px_48px_1fr_48px] items-center gap-4 px-6 py-1.5 transition-all ${status === 'current'
                              ? 'bg-indigo-50/50 z-10'
                              : status === 'past'
                                ? 'bg-slate-50/30 opacity-60'
                                : 'bg-white hover:bg-slate-50/30'
                            }`}
                        >
                          {/* Status Side Indicator */}
                          {status === 'current' && (
                            <div className="absolute left-0 top-0 bottom-0 w-1 bg-indigo-500" />
                          )}

                          {/* Time Controls */}
                          <div className="flex items-center gap-1.5 shrink-0">
                            <input
                              type="time"
                              value={item.startTime}
                              onChange={(e) => updateItem(item.id, { startTime: e.target.value })}
                              className="text-sm font-bold text-slate-700 bg-slate-50/50 px-2 py-1 rounded-lg outline-none w-[95px] border border-transparent focus:border-indigo-200 focus:bg-white transition-all"
                            />
                            <span className="text-[8px] font-black text-slate-300">TO</span>
                            <input
                              type="time"
                              value={item.endTime}
                              onChange={(e) => updateItem(item.id, { endTime: e.target.value })}
                              className="text-sm font-bold text-slate-700 bg-slate-50/50 px-2 py-1 rounded-lg outline-none w-[95px] border border-transparent focus:border-indigo-200 focus:bg-white transition-all"
                            />
                          </div>

                          {/* Emoji Selector */}
                          <div className="relative flex justify-center">
                            <button
                              onClick={() => {
                                setShowEmojiPicker(showEmojiPicker === item.id ? null : item.id);
                                audioEngine.playTick(settings.soundTheme);
                              }}
                              className={`w-9 h-9 rounded-lg flex items-center justify-center text-xl transition-all border ${status === 'current'
                                  ? 'bg-white border-indigo-200 shadow-sm'
                                  : 'bg-white border-slate-100 hover:border-slate-200'
                                }`}
                            >
                              {item.emoji}
                            </button>

                            <AnimatePresence>
                              {showEmojiPicker === item.id && (
                                <motion.div
                                  initial={{ opacity: 0, scale: 0.9, y: 10 }}
                                  animate={{ opacity: 1, scale: 1, y: 0 }}
                                  exit={{ opacity: 0, scale: 0.9, y: 10 }}
                                  className="absolute top-full mt-2 left-0 z-30 bg-white p-2 rounded-2xl shadow-2xl border border-slate-100 grid grid-cols-4 gap-1 w-44"
                                >
                                  {SCHOOL_EMOJIS.map(emoji => (
                                    <button
                                      key={emoji}
                                      onClick={() => {
                                        updateItem(item.id, { emoji });
                                        setShowEmojiPicker(null);
                                        audioEngine.playTick(settings.soundTheme);
                                      }}
                                      className="w-9 h-9 flex items-center justify-center text-xl hover:bg-slate-50 rounded-lg transition-all"
                                    >
                                      {emoji}
                                    </button>
                                  ))}
                                </motion.div>
                              )}
                            </AnimatePresence>
                          </div>

                          {/* Activity Name */}
                          <div className="flex-1 min-w-0 flex items-center gap-3">
                            <input
                              type="text"
                              value={item.activity}
                              onChange={(e) => updateItem(item.id, { activity: e.target.value })}
                              placeholder="Activity Name..."
                              className={`w-full text-base font-bold bg-transparent border-none outline-none focus:placeholder:opacity-0 truncate ${status === 'current' ? 'text-indigo-900' : 'text-slate-700'
                                }`}
                            />
                            {status === 'current' && (
                              <div className="flex items-center gap-1.5 shrink-0 px-2 py-0.5 bg-indigo-100 text-indigo-600 rounded-full">
                                <div className="w-1.5 h-1.5 rounded-full bg-indigo-600 animate-ping" />
                                <span className="text-[8px] font-black uppercase tracking-tighter">NOW</span>
                              </div>
                            )}
                          </div>

                          {/* Remove Button */}
                          <div className="flex justify-end">
                            <button
                              onClick={() => removeItem(item.id)}
                              className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                            >
                              <Trash2 size={16} />
                            </button>
                          </div>
                        </motion.div>

                        {/* Subtle Gap Filler / Add Between Row */}
                        {index < currentSchedule.length - 1 && currentSchedule[index].endTime < currentSchedule[index + 1].startTime && (
                          <div className="relative h-6 flex items-center justify-center group/gap">
                            <div className="absolute left-[200px] right-6 h-px bg-slate-50" />
                            <button
                              onClick={() => fillGap(index + 1)}
                              className="relative z-10 flex items-center gap-1.5 px-3 py-0.5 bg-white text-slate-300 hover:text-indigo-600 hover:border-indigo-200 border border-slate-100 rounded-full text-[8px] font-black uppercase tracking-tighter transition-all opacity-0 group-hover/gap:opacity-100"
                            >
                              <Plus size={8} /> Fill Gap
                            </button>
                          </div>
                        )}
                      </React.Fragment>
                    );
                  })}

                  {/* Add Bottom Button Row */}
                  <div className="p-2 flex justify-center bg-slate-50/30">
                    <button
                      onClick={() => {
                        if (currentSchedule.length > 0) {
                          const lastItem = currentSchedule[currentSchedule.length - 1];
                          addItem(lastItem.endTime, lastItem.endTime);
                        } else {
                          addItem();
                        }
                      }}
                      className="flex items-center gap-2 px-4 py-1.5 bg-white text-slate-400 hover:text-indigo-600 hover:border-indigo-100 border border-slate-200 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all shadow-sm"
                    >
                      <Plus size={14} /> Add Activity
                    </button>
                  </div>
                </div>

                {currentSchedule.length === 0 && (
                  <div className="py-20 flex flex-col items-center justify-center text-slate-300 gap-4">
                    <Calendar size={64} strokeWidth={1} />
                    <p className="text-sm font-bold uppercase tracking-[0.2em]">Empty Schedule</p>
                    <button
                      onClick={() => addItem()}
                      className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-500 transition-all shadow-lg"
                    >
                      Add First Activity
                    </button>
                  </div>
                )}
              </motion.div>
            </AnimatePresence>
          </div>
        </div>
      </div>

      {/* Backdrop for Emoji Picker */}
      {showEmojiPicker && (
        <div
          className="fixed inset-0 z-20"
          onClick={() => setShowEmojiPicker(null)}
        />
      )}
    </div>
  );
};

export default DailySchedule;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Dices, 
  RotateCcw, 
  BarChart3, 
  Trash2, 
  Download, 
  Play, 
  Info, 
  Settings2, 
  Hash, 
  Layers, 
  Monitor, 
  Database, 
  Terminal, 
  Target, 
  Zap, 
  Star, 
  Sparkles, 
  ListFilter, 
  Plus, 
  BookOpen, 
  Clock, 
  Trophy,
  History,
  Timer,
  ShieldCheck,
  Activity,
  Pencil
} from 'lucide-react';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';

const DICE_TYPES = [
  { sides: 4, label: 'D4', icon: '🔺', color: '#f43f5e' },
  { sides: 6, label: 'D6', icon: '🎲', color: '#6366f1' },
  { sides: 8, label: 'D8', icon: '💎', color: '#10b981' },
  { sides: 10, label: 'D10', icon: '🌀', color: '#f59e0b' },
  { sides: 12, label: 'D12', icon: '🔮', color: '#a855f7' },
  { sides: 20, label: 'D20', icon: '🌌', color: '#06b6d4' },
];

export const DiceRoller = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const [selectedDice, setSelectedDice] = useState(6);
  const [rolls, setRolls] = useState([]);
  const [isRolling, setIsRolling] = useState(false);
  const [history, setHistory] = useState(() => {
    const saved = localStorage.getItem('teacherToolsDiceHistory');
    return saved ? JSON.parse(saved) : [];
  });
  const [showStats, setShowStats] = useState(true);

  useEffect(() => {
    localStorage.setItem('teacherToolsDiceHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    setOnReset(() => () => {
      setHistory([]);
      setRolls([]);
      audioEngine.playTick(settings.soundTheme);
    });
    return () => clearHeader();
  }, [clearHeader, setOnReset, settings.soundTheme]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <button
          onClick={() => { setShowStats(!showStats); audioEngine.playTick(settings.soundTheme); }}
          className={`flex items-center gap-2 px-8 py-2 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all active:scale-95 border-2 italic ${
            showStats 
              ? 'bg-slate-950 text-white border-slate-950 shadow-xl shadow-indigo-100' 
              : 'bg-white text-slate-400 hover:text-indigo-600 hover:bg-slate-50 border-slate-100 hover:border-indigo-100 shadow-sm'
          }`}
        >
          {showStats ? <BarChart3 size={14} className="text-indigo-400" /> : <BarChart3 size={14} className="opacity-40" />}
          Stats: {showStats ? 'ON' : 'OFF'}
        </button>
        <div className="w-px h-6 bg-slate-200" />
        <button
          onClick={() => { setHistory([]); setRolls([]); audioEngine.playTick(settings.soundTheme); }}
          className="flex items-center gap-2 px-8 py-2 bg-white text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-rose-50 hover:text-rose-600 transition-all active:scale-95 border-2 border-slate-100 hover:border-rose-100 shadow-sm italic"
        >
          <RotateCcw size={14} /> Clear Stream
        </button>
      </div>
    );
  }, [showStats, settings.soundTheme, setHeaderActions]);

  const rollDice = () => {
    if (isRolling) return;
    setIsRolling(true);
    audioEngine.playTick(settings.soundTheme);

    setTimeout(() => {
      const newValue = Math.floor(Math.random() * selectedDice) + 1;
      const newRoll = {
        id: Date.now(),
        value: newValue,
        sides: selectedDice,
        timestamp: new Date().toLocaleTimeString(),
        color: DICE_TYPES.find(d => d.sides === selectedDice).color
      };
      setRolls([newRoll, ...rolls].slice(0, 5));
      setHistory([newRoll, ...history]);
      setIsRolling(false);
      audioEngine.playSuccess(settings.soundTheme);
    }, 600);
  };

  const stats_data = useMemo(() => {
    if (history.length === 0) return null;
    const currentDiceHistory = history.filter(h => h.sides === selectedDice);
    if (currentDiceHistory.length === 0) return null;

    const counts = {};
    for (let i = 1; i <= selectedDice; i++) counts[i] = 0;
    currentDiceHistory.forEach(h => counts[h.value]++);

    const max = Math.max(...Object.values(counts));
    return { counts, max, total: currentDiceHistory.length };
  }, [history, selectedDice]);

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      {/* Simulation Stage */}
      <div className="flex-1 flex flex-col gap-8">
        <div className="flex-1 tool-stage p-12 lg:p-24 relative overflow-hidden bg-white border-none rounded-[4rem] group/stage flex flex-col items-center justify-center">
          <div className="tool-grid-bg opacity-30" />

          {/* HUD Elements */}
          <div className="absolute top-12 left-12 flex flex-col gap-6 z-20 pointer-events-none italic">
             <div className="flex items-center gap-4 px-8 py-4 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border-4 border-white/60 shadow-xl group/hud hover:border-indigo-100 transition-all">
                <div className="w-3 h-3 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_20px_rgba(79,70,229,1)]" />
                <div className="flex flex-col">
                   <span className="text-[11px] font-black text-slate-800 uppercase tracking-[0.6em] leading-none mb-1">Probability Core</span>
                   <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.4em] leading-none">Status: Entropy Nominal</span>
                </div>
             </div>
          </div>

          {/* Dice Display Area */}
          <div className="relative z-10 flex flex-col items-center gap-20 w-full">
            <AnimatePresence mode="wait">
              {isRolling ? (
                <motion.div
                  key="rolling"
                  initial={{ scale: 0.8, opacity: 0, rotate: -20 }}
                  animate={{ scale: 1, opacity: 1, rotate: 0 }}
                  exit={{ scale: 1.2, opacity: 0, rotate: 20 }}
                  className="w-64 h-64 rounded-[3.5rem] bg-slate-900 flex items-center justify-center shadow-[0_64px_128px_-24px_rgba(0,0,0,0.4)] border-8 border-slate-800"
                >
                  <motion.div
                    animate={{ rotate: 360, scale: [1, 1.1, 1] }}
                    transition={{ duration: 0.5, repeat: Infinity, ease: "linear" }}
                  >
                    <Dices size={100} className="text-indigo-400 opacity-20" />
                  </motion.div>
                </motion.div>
              ) : (
                <motion.div
                  key={rolls[0]?.id || 'empty'}
                  initial={{ y: 40, opacity: 0, rotateX: 45 }}
                  animate={{ y: 0, opacity: 1, rotateX: 0 }}
                  className="relative group/dice"
                >
                  {rolls[0] ? (
                    <div 
                      className="w-64 h-64 rounded-[4rem] flex flex-col items-center justify-center shadow-[0_80px_120px_-20px_rgba(0,0,0,0.3)] border-[12px] border-white relative overflow-hidden transition-transform duration-700 group-hover/dice:scale-105"
                      style={{ backgroundColor: rolls[0].color }}
                    >
                      <div className="absolute inset-0 bg-gradient-to-tr from-black/20 via-transparent to-white/30" />
                      <span className="text-[11px] font-black text-white/40 uppercase tracking-[0.8em] mb-4 relative z-10 italic">Result</span>
                      <span className="text-9xl font-black text-white tabular-nums tracking-tighter drop-shadow-2xl relative z-10 italic">
                        {rolls[0].value}
                      </span>
                      <div className="absolute -bottom-4 -right-4 opacity-10 group-hover/dice:rotate-12 transition-transform duration-1000">
                         <Dices size={160} />
                      </div>
                    </div>
                  ) : (
                    <div className="w-64 h-64 rounded-[4rem] bg-slate-50 border-8 border-dashed border-slate-100 flex flex-col items-center justify-center text-slate-200 gap-6">
                       <Dices size={80} strokeWidth={1} />
                       <span className="text-[10px] font-black uppercase tracking-[0.4em] italic">Initialize Roll</span>
                    </div>
                  )}
                </motion.div>
              )}
            </AnimatePresence>

            {/* Selector Grid */}
            <div className="flex flex-wrap justify-center gap-4 p-4 bg-slate-50/50 backdrop-blur-xl rounded-[3rem] border-4 border-white shadow-xl">
              {DICE_TYPES.map((dice) => (
                <button
                  key={dice.sides}
                  onClick={() => { setSelectedDice(dice.sides); audioEngine.playTick(settings.soundTheme); }}
                  className={`group relative flex flex-col items-center gap-2 px-8 py-5 rounded-[2rem] transition-all duration-500 border-4 ${
                    selectedDice === dice.sides 
                      ? 'bg-white border-indigo-600 shadow-2xl -translate-y-2 scale-110 z-10' 
                      : 'bg-white/40 border-transparent hover:bg-white hover:border-slate-100 text-slate-400 opacity-60 hover:opacity-100'
                  }`}
                >
                  <span className="text-2xl mb-1 group-hover:scale-125 transition-transform duration-500">{dice.icon}</span>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedDice === dice.sides ? 'text-indigo-600' : 'text-slate-400'}`}>
                    {dice.label}
                  </span>
                  {selectedDice === dice.sides && (
                    <motion.div layoutId="dice-glow" className="absolute inset-0 rounded-[1.8rem] bg-indigo-500/5 -z-10" />
                  )}
                </button>
              ))}
            </div>

            <button
              onClick={rollDice}
              disabled={isRolling}
              className="px-16 py-8 bg-slate-950 text-white rounded-[3rem] font-black text-xs uppercase tracking-[0.8em] shadow-[0_48px_96px_-16px_rgba(0,0,0,0.6)] hover:bg-indigo-600 hover:-translate-y-2 active:scale-95 transition-all duration-500 border-8 border-slate-800 italic"
            >
              Execute Roll
            </button>
          </div>
        </div>
      </div>

      {/* Probability Analytics Sidebar */}
      <div className="w-full lg:w-[460px] shrink-0 flex flex-col gap-8 h-full overflow-hidden">
        <div className="tool-sidebar-card flex-1 p-12 flex flex-col gap-10">
           <div className="flex items-center justify-between shrink-0 mb-2">
              <div className="flex items-center gap-5">
                 <div className="w-14 h-14 rounded-2xl bg-slate-900 flex items-center justify-center text-indigo-400 border-4 border-slate-800 shadow-2xl">
                    <Database size={28} />
                 </div>
                 <div className="flex flex-col">
                    <h4 className="text-xl font-black text-slate-800 uppercase tracking-tight">Signal Analysis</h4>
                    <span className="text-[10px] font-black text-slate-300 uppercase tracking-[0.4em] italic">Temporal Data Stream</span>
                 </div>
              </div>
           </div>

           <div className="flex-1 flex flex-col gap-12 min-h-0">
              {/* Statistical Distribution */}
              {showStats && stats_data ? (
                <div className="space-y-8 shrink-0">
                  <div className="flex items-center justify-between italic">
                     <h3 className="text-[12px] font-black text-slate-400 uppercase tracking-[0.4em] leading-none">Distribution Curve</h3>
                     <span className="text-[10px] font-black text-indigo-400 uppercase bg-indigo-50 px-3 py-1 rounded-full">{stats_data.total} Iterations</span>
                  </div>
                  <div className="h-[280px] w-full bg-slate-50 rounded-[3rem] border-4 border-white shadow-inner p-10 flex items-end justify-between gap-3 relative overflow-hidden">
                    <div className="tool-grid-bg opacity-10" />
                    {Object.entries(stats_data.counts).map(([val, count]) => {
                      const height = stats_data.max > 0 ? (count / stats_data.max) * 100 : 0;
                      return (
                        <div key={val} className="flex-1 flex flex-col items-center gap-4 group/bar h-full justify-end relative z-10">
                          <div className="w-full relative flex flex-col justify-end h-full">
                            <motion.div 
                              initial={{ height: 0 }}
                              animate={{ height: `${height}%` }}
                              className="w-full bg-slate-950 rounded-2xl relative group-hover/bar:bg-indigo-600 transition-colors shadow-2xl overflow-hidden"
                            >
                               <div className="absolute inset-x-0 top-0 h-1/2 bg-white/10" />
                               {count > 0 && (
                                 <span className="absolute -top-8 left-1/2 -translate-x-1/2 text-[10px] font-black text-indigo-500 tabular-nums">
                                   {count}
                                 </span>
                               )}
                            </motion.div>
                          </div>
                          <span className="text-xs font-black text-slate-400 tabular-nums italic group-hover/bar:text-slate-900">{val}</span>
                        </div>
                      );
                    })}
                  </div>
                </div>
              ) : (
                <div className="h-[280px] w-full bg-slate-50 rounded-[3rem] border-4 border-dashed border-slate-100 flex flex-col items-center justify-center text-slate-300 gap-6 opacity-40 shrink-0 italic">
                   <Activity size={48} strokeWidth={1} />
                   <p className="text-[10px] font-black uppercase tracking-[0.4em]">Awaiting Sufficient Entropy</p>
                </div>
              )}

              {/* Recent Activity Log */}
              <div className="flex-1 flex flex-col min-h-0">
                <div className="flex items-center justify-between mb-8 shrink-0 italic">
                   <h3 className="text-[12px] font-black text-slate-400 uppercase tracking-[0.4em] leading-none">Telemetry Log</h3>
                   <Terminal size={18} className="text-slate-300" />
                </div>
                <div className="flex-1 overflow-y-auto space-y-4 pr-4 custom-scrollbar no-scrollbar italic">
                  <AnimatePresence initial={false}>
                    {history.length === 0 ? (
                      <div className="h-full flex items-center justify-center text-slate-300 italic text-[11px] font-black uppercase tracking-[0.6em] p-12 text-center">
                        Initializing Data Capture Protocol...
                      </div>
                    ) : (
                      history.slice(0, 50).map((h) => (
                        <motion.div 
                          key={h.id}
                          initial={{ opacity: 0, x: -20 }}
                          animate={{ opacity: 1, x: 0 }}
                          className="flex justify-between items-center p-8 rounded-[2.5rem] bg-slate-50 border-4 border-white hover:border-indigo-100 hover:bg-white transition-all group shadow-sm hover:shadow-xl"
                        >
                          <div className="flex items-center gap-6">
                             <div className="w-14 h-14 rounded-3xl bg-white shadow-inner flex items-center justify-center border-2 border-slate-100 group-hover:scale-110 transition-transform">
                                <div className="w-6 h-6 rounded-full shadow-lg" style={{ backgroundColor: h.color }} />
                             </div>
                             <div className="flex flex-col">
                                <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest group-hover:text-indigo-400 transition-colors">Vector: D{h.sides}</span>
                                <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">{h.timestamp}</span>
                             </div>
                          </div>
                          <span className="text-4xl font-black text-slate-800 italic tracking-tighter leading-none">{h.value}</span>
                        </motion.div>
                      ))
                    )}
                  </AnimatePresence>
                </div>
              </div>

              {/* Status Footer */}
              <div className="mt-auto pt-10 border-t border-slate-50 shrink-0">
                 <div className="p-8 bg-slate-900 rounded-[3rem] text-white relative overflow-hidden group shadow-2xl border border-slate-800 italic">
                    <div className="tool-grid-bg-dark opacity-10" />
                    <div className="absolute -right-12 -top-12 opacity-5 group-hover:rotate-12 transition-transform duration-1000">
                       <Activity size={180} />
                    </div>
                    <div className="relative z-10 flex items-center justify-between">
                       <div className="flex flex-col gap-2">
                          <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] leading-none">Stability Vector</span>
                          <span className="text-4xl font-black italic tracking-tighter leading-none">Optimal<span className="text-xl text-white/20 ml-2">Sync</span></span>
                       </div>
                       <div className="w-14 h-14 rounded-[1.25rem] bg-white/5 border border-white/10 flex items-center justify-center text-indigo-400">
                          <ShieldCheck size={28} />
                       </div>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default DiceRoller;

