  '🎨', '🎭', '🎪', '🎫', '🎬', '🎤', '🎧', '🎷'
];

const LEVELS = {
  easy: { rows: 2, cols: 4, name: 'Standard', color: '#10b981', icon: Star, label: 'Node Primary' },
  medium: { rows: 4, cols: 4, name: 'Complex', color: '#6366f1', icon: Zap, label: 'Node Advanced' },
  hard: { rows: 6, cols: 6, name: 'Quantum', color: '#f43f5e', icon: Brain, label: 'Node Elite' }
};

export const EmojiMatch = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const [status, setStatus] = useState('setup'); // 'setup', 'playing', 'finished'
  const [level, setLevel] = useState('easy');
  const [cards, setCards] = useState([]);
  const [flipped, setFlipped] = useState([]); // indices
  const [matched, setMatched] = useState([]); // indices
  const [moves, setMoves] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [startTime, setStartTime] = useState(null);
  const [elapsed, setElapsed] = useState(0);

  const initGame = useCallback((lvlKey) => {
    const lvl = LEVELS[lvlKey];
    const totalCards = lvl.rows * lvl.cols;
    const numPairs = totalCards / 2;

    const selectedEmojis = [...EMOJIS].sort(() => Math.random() - 0.5).slice(0, numPairs);
    const deck = [...selectedEmojis, ...selectedEmojis]
      .sort(() => Math.random() - 0.5)
      .map((emoji, idx) => ({ id: idx, emoji }));

    setCards(deck);
    setFlipped([]);
    setMatched([]);
    setMoves(0);
    setElapsed(0);
    setStartTime(Date.now());
    setStatus('playing');
    setIsProcessing(false);
  }, []);

  const handleCardClick = (idx) => {
    if (isProcessing || flipped.includes(idx) || matched.includes(idx)) return;

    const newFlipped = [...flipped, idx];
    setFlipped(newFlipped);
    audioEngine.playTick(settings.soundTheme);

    if (newFlipped.length === 2) {
      setMoves(m => m + 1);
      setIsProcessing(true);

      const [firstIdx, secondIdx] = newFlipped;
      if (cards[firstIdx].emoji === cards[secondIdx].emoji) {
        setTimeout(() => {
          const newMatched = [...matched, firstIdx, secondIdx];
          setMatched(newMatched);
          setFlipped([]);
          setIsProcessing(false);
          audioEngine.playSuccess(settings.soundTheme);

          if (newMatched.length === cards.length) {
            confetti({ 
               particleCount: 150, 
               spread: 100, 
               origin: { y: 0.6 },
               colors: ['#6366f1', '#10b981', '#f59e0b', '#f43f5e']
            });
            audioEngine.playAlarm(settings.soundTheme);
            setTimeout(() => setStatus('finished'), 1000);
          }
        }, 600);
      } else {
        setTimeout(() => {
          setFlipped([]);
          setIsProcessing(false);
        }, 800);
      }
    }
  };

  useEffect(() => {
    let interval;
    if (status === 'playing') {
      interval = setInterval(() => {
        setElapsed(Math.floor((Date.now() - startTime) / 1000));
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [status, startTime]);

  useEffect(() => {
    setOnReset(() => () => setStatus('setup'));
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
