export const EventCalendar = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const [view, setView] = useState('countdowns'); // 'calendar' or 'countdowns'
  const [countdownFormat, setCountdownFormat] = useState('grid'); // 'grid' or 'list'
  const [showCountdownAddModal, setShowCountdownAddModal] = useState(false);

  // Events state
  const [events, setEvents] = useState(() => {
    const saved = localStorage.getItem('teacherToolsEventCountdowns');
    return saved ? JSON.parse(saved) : [];
  });

  const containerRef = useRef(null);
  const contentRef = useRef(null);
  const [scale, setScale] = useState(1);

  useEffect(() => {
    if (!containerRef.current || !contentRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (let entry of entries) {
        const containerHeight = entry.contentRect.height;
        const contentHeight = contentRef.current.scrollHeight;
        if (contentHeight > containerHeight && containerHeight > 0) {
          setScale(Math.max(0.5, containerHeight / (contentHeight + 20)));
        } else {
          setScale(1);
        }
      }
    });
    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, [view, events.length]);

  // Countdown specific state
  const [newEventName, setNewEventName] = useState('');
  const [newEventDate, setNewEventDate] = useState('');
  const [now, setNow] = useState(new Date());

  // Calendar specific state
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [showAddModal, setShowAddModal] = useState(false);
  const [modalEventTime, setModalEventTime] = useState('12:00');

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  useEffect(() => {
    localStorage.setItem('teacherToolsEventCountdowns', JSON.stringify(events));
  }, [events]);

  useEffect(() => {
    if (view === 'countdowns') {
      const timer = setInterval(() => setNow(new Date()), 1000);
      return () => clearInterval(timer);
    }
  }, [view]);

  useEffect(() => {
    setOnReset(() => () => {
      setEvents([]);
      audioEngine.playTick(settings.soundTheme);
    });
    return () => clearHeader();
  }, [clearHeader, setOnReset, settings.soundTheme]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-2">
        <div className="flex bg-slate-100 p-1 rounded-xl">
          <button
            onClick={() => { setView('calendar'); audioEngine.playTick(settings.soundTheme); }}
            className={`px-4 py-1.5 text-xs font-bold transition-all rounded-lg ${view === 'calendar' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Calendar
          </button>
          <button
            onClick={() => { setView('countdowns'); audioEngine.playTick(settings.soundTheme); }}
            className={`px-4 py-1.5 text-xs font-bold transition-all rounded-lg ${view === 'countdowns' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Countdowns
          </button>
        </div>
        <button
          onClick={() => { setEvents([]); audioEngine.playTick(settings.soundTheme); }}
          className="p-2 text-slate-400 hover:text-rose-500 transition-all"
          title="Clear All Events"
        >
          <Trash2 size={18} />
        </button>
      </div>
    );
  }, [view, setHeaderActions, settings.soundTheme, events.length]);

  // --- Shared Event Actions ---
  const addEvent = (name, dateStr) => {
    if (!name.trim() || !dateStr) return;
    const newEvent = {
      id: Date.now().toString(),
      name: name.trim(),
      date: dateStr
    };
    setEvents([...events, newEvent]);
    audioEngine.playSuccess(settings.soundTheme);
  };

  const removeEvent = (id) => {
    setEvents(events.filter(event => event.id !== id));
    audioEngine.playTick(settings.soundTheme);
  };

  // --- Countdowns Handlers ---
  const handleAddCountdown = (e) => {
    e.preventDefault();
    addEvent(newEventName, newEventDate);
    setNewEventName('');
    setNewEventDate('');
    setShowCountdownAddModal(false);
  };

  const calculateTimeLeft = (targetDateString) => {
    const target = new Date(targetDateString);
    const difference = target - now;
    if (difference <= 0) return { days: 0, hours: 0, minutes: 0, seconds: 0, passed: true };
    const days = Math.floor(difference / (1000 * 60 * 60 * 24));
    const hours = Math.floor((difference / (1000 * 60 * 60)) % 24);
    const minutes = Math.floor((difference / 1000 / 60) % 60);
    const seconds = Math.floor((difference / 1000) % 60);
    return { days, hours, minutes, seconds, passed: false };
  };

  // --- Calendar Handlers ---
  const viewMonth = currentDate.getMonth();
  const viewYear = currentDate.getFullYear();
  const daysInMonth = new Date(viewYear, viewMonth + 1, 0).getDate();
  const firstDayOfMonth = new Date(viewYear, viewMonth, 1).getDay();
  const firstDayIndex = firstDayOfMonth === 0 ? 6 : firstDayOfMonth - 1; // Mon to Sun

  const monthNames = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December"
  ];
  const dayNames = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

  const prevMonth = () => { setCurrentDate(new Date(viewYear, viewMonth - 1, 1)); audioEngine.playTick(settings.soundTheme); };
  const nextMonth = () => { setCurrentDate(new Date(viewYear, viewMonth + 1, 1)); audioEngine.playTick(settings.soundTheme); };
  const goToToday = () => {
    const t = new Date();
    setCurrentDate(t);
    setSelectedDate(t);
    audioEngine.playTick(settings.soundTheme);
  };

  const calendarDays = [];
  const prevMonthLastDay = new Date(viewYear, viewMonth, 0).getDate();
  for (let i = firstDayIndex - 1; i >= 0; i--) {
    calendarDays.push({ day: prevMonthLastDay - i, month: viewMonth - 1, year: viewYear, isCurrentMonth: false });
  }
  for (let i = 1; i <= daysInMonth; i++) {
    calendarDays.push({ day: i, month: viewMonth, year: viewYear, isCurrentMonth: true });
  }
  const remainingSlots = 42 - calendarDays.length;
  for (let i = 1; i <= remainingSlots; i++) {
    calendarDays.push({ day: i, month: viewMonth + 1, year: viewYear, isCurrentMonth: false });
  }

  const isToday = (d, month, y) => {
    const date = new Date(y, month, d);
    date.setHours(0, 0, 0, 0);
    return date.getTime() === today.getTime();
  };

  const isSelected = (d, month, y) => {
    const date = new Date(y, month, d);
    date.setHours(0, 0, 0, 0);
    const sel = new Date(selectedDate);
    sel.setHours(0, 0, 0, 0);
    return date.getTime() === sel.getTime();
  };

  const getEventsForDate = (d, month, y) => {
    const dateStr = new Date(y, month, d).toLocaleDateString();
    return events.filter(e => new Date(e.date).toLocaleDateString() === dateStr);
  };

  const handleCalendarAddEvent = (e) => {
    e.preventDefault();
    const formattedDate = new Date(selectedDate);
    const [hours, minutes] = modalEventTime.split(':');
    formattedDate.setHours(parseInt(hours, 10), parseInt(minutes, 10), 0, 0);
    const tzoffset = (new Date()).getTimezoneOffset() * 60000;
    const localISOTime = (new Date(formattedDate - tzoffset)).toISOString().slice(0, 16);
    addEvent(newEventName, localISOTime);
    setNewEventName('');
    setShowAddModal(false);
  };

  return (
