                    </AnimatePresence>
                  </div>
                </div>

                {/* Footer Controls */}
                <div className="px-6 py-3 border-t-2 border-slate-50 bg-white flex items-center justify-between shrink-0 relative z-10">
                   <div className="flex items-center gap-4">
