import React, { useState, useEffect } from 'react';
import { 
  Play, 
  RotateCcw, 
  BookOpen, 
  Activity,
  Pause,
  Clock,
  Settings2
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';

export const ExamClock = () => {
  const [readingTime, setReadingTime] = useState(5); // minutes
  const [examTime, setExamTime] = useState(60); // minutes
  const [warningTime, setWarningTime] = useState(5); // minutes
  const [examName, setExamName] = useState('Final Examination');
  const [phase, setPhase] = useState('setup'); // 'setup', 'reading', 'paused', 'exam', 'finished'
  const [timeLeft, setTimeLeft] = useState(0);

  const { settings } = useSettings();
  const { setHasConfig, clearHeader } = useHeader();

  useEffect(() => {
    setHasConfig(false);
    return () => clearHeader();
  }, [clearHeader, setHasConfig]);

  useEffect(() => {
    let interval;
    if ((phase === 'reading' || phase === 'exam') && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            audioEngine.playAlarm(settings.soundTheme);
            if (phase === 'reading') {
              setPhase('paused');
              setTimeLeft(examTime * 60);
            } else {
              setPhase('finished');
            }
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [phase, timeLeft, examTime, settings.soundTheme]);

  const startReading = () => {
    if (readingTime > 0) {
      setTimeLeft(readingTime * 60);
      setPhase('reading');
    } else {
      startExam();
    }
    audioEngine.playTick(settings.soundTheme);
  };

  const startExam = () => {
    setTimeLeft(examTime * 60);
    setPhase('exam');
    audioEngine.playTick(settings.soundTheme);
  };

  const reset = () => {
    setPhase('setup');
    setTimeLeft(0);
    audioEngine.playTick(settings.soundTheme);
  };

  const formatTime = (seconds) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    if (h > 0) {
      return `${h}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
    }
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getPhaseLabel = () => {
    switch(phase) {
      case 'reading': return 'READING TIME';
      case 'paused': return 'WAITING TO START EXAM';
      case 'exam': return timeLeft <= warningTime * 60 ? 'FINAL WARNING' : 'EXAMINATION ACTIVE';
      case 'finished': return 'EXAMINATION FINISHED';
      default: return '';
    }
  };

  return (
    <div className="tool-container w-full mx-auto h-full flex flex-col font-['Outfit'] select-none bg-slate-50/30 overflow-hidden">

      <AnimatePresence mode="wait">
        {phase === 'setup' ? (
          <motion.div 
            key="setup"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className="flex-1 flex flex-col items-center justify-center p-6 md:p-12 max-w-4xl mx-auto w-full"
          >
            <div className="w-full space-y-12 bg-white p-8 md:p-16 rounded-[3rem] shadow-xl border border-slate-100">
              <div className="text-center space-y-4">
                <h1 className="text-4xl md:text-5xl font-black text-slate-800 tracking-tight uppercase">Exam Configuration</h1>
                <div className="w-full h-px bg-slate-200" />
              </div>

              <div className="space-y-8">
                <div className="space-y-3 text-center">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Exam Name</label>
                  <input 
                    type="text" 
                    value={examName} 
                    onChange={(e) => setExamName(e.target.value)}
                    className="w-full p-6 bg-slate-50 border-none rounded-[1.5rem] font-bold text-2xl md:text-4xl text-slate-800 text-center focus:ring-4 focus:ring-blue-100 outline-none transition-all"
                    placeholder="Enter Exam Name..."
                  />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {[
                    { label: 'Reading Time (min)', val: readingTime, set: setReadingTime },
                    { label: 'Exam Time (min)', val: examTime, set: setExamTime },
                    { label: 'Warning Time (min)', val: warningTime, set: setWarningTime }
                  ].map((item, idx) => (
                    <div key={idx} className="space-y-3 text-center">
                      <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block h-8 flex items-center justify-center">{item.label}</label>
                      <input 
                        type="number" 
                        value={item.val} 
                        onChange={(e) => item.set(Math.max(0, parseInt(e.target.value) || 0))}
                        className="w-full p-6 bg-slate-50 border-none rounded-[1.5rem] font-black text-4xl text-slate-800 text-center focus:ring-4 focus:ring-blue-100 outline-none transition-all tabular-nums"
                      />
                    </div>
                  ))}
                </div>
              </div>

              <div className="flex flex-col sm:flex-row gap-4 pt-4">
                <button 
                  onClick={startReading}
                  className="flex-1 py-6 bg-blue-600 hover:bg-blue-700 text-white rounded-[1.5rem] font-black text-lg md:text-xl uppercase tracking-tighter transition-all shadow-lg shadow-blue-200 flex items-center justify-center gap-3 active:scale-95"
                >
                  Start Reading Time
                </button>
                <button 
                  onClick={startExam}
                  className="flex-1 py-6 bg-emerald-500 hover:bg-emerald-600 text-white rounded-[1.5rem] font-black text-lg md:text-xl uppercase tracking-tighter transition-all shadow-lg shadow-emerald-200 flex items-center justify-center gap-3 active:scale-95"
                >
                  Skip to Exam
                </button>
              </div>
            </div>
          </motion.div>
        ) : (
          <motion.div 
            key="active"
            initial={{ opacity: 0, scale: 1.05 }}
            animate={{ opacity: 1, scale: 1 }}
            className="flex-1 flex flex-col items-center justify-center p-4 md:p-8 space-y-12"
          >
            {/* Main Timer Display Box */}
            <div className="w-full max-w-5xl bg-white rounded-[4rem] border-[6px] border-blue-500 shadow-2xl p-12 md:p-20 flex flex-col items-center justify-center relative overflow-hidden">

               <div className="text-center space-y-2 mb-8">
                  <h2 className="text-3xl md:text-5xl font-black text-blue-600 uppercase tracking-tight">{examName}</h2>
                  <div className="flex flex-col items-center">
                    <span className="text-sm md:text-lg font-bold text-blue-400 uppercase tracking-[0.2em]">{getPhaseLabel()}</span>
                    <div className="w-24 h-0.5 bg-blue-300 mt-1" />
                  </div>
               </div>

               <div className={`text-[11rem] md:text-[18rem] font-medium tabular-nums tracking-tighter leading-none text-blue-600 drop-shadow-sm select-all transition-colors duration-500 ${phase === 'exam' && timeLeft <= warningTime * 60 ? 'text-rose-600' : ''}`}>
                  {formatTime(timeLeft)}
               </div>
            </div>

               <div className="flex items-center gap-6">
                 {phase === 'reading' && (
                   <button 
                     onClick={() => { setPhase('paused'); setTimeLeft(examTime * 60); audioEngine.playTick(settings.soundTheme); }}
                     className="px-12 py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-[1.5rem] font-black text-xl uppercase tracking-tight flex items-center gap-3 shadow-lg shadow-orange-100 transition-all active:scale-95"
                   >
                     <Pause size={24} fill="white" /> Skip Reading
                   </button>
                 )}
                 {phase === 'paused' && (
                   <button 
                     onClick={() => { startExam(); audioEngine.playTick(settings.soundTheme); }}
                     className="px-12 py-5 bg-emerald-500 hover:bg-emerald-600 text-white rounded-[1.5rem] font-black text-xl uppercase tracking-tight flex items-center gap-3 shadow-lg shadow-emerald-100 transition-all active:scale-95 animate-pulse"
                   >
                     <Play size={24} fill="white" /> Start Exam
                   </button>
                 )}
               </div>

          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default ExamClock;

