                {/* The Marker */}
                <motion.div 
                  className="absolute -top-10 w-24 h-24 rounded-[2.5rem] border-[8px] border-white shadow-2xl cursor-grab active:cursor-grabbing z-20 flex items-center justify-center transition-transform hover:scale-110 active:scale-95 group/marker"
                  style={{ 
                    x: pointerX,
                    backgroundColor: activeColor,
                    boxShadow: `0 48px 96px -16px ${activeColor}99`
                  }}
                  drag="x"
                  dragConstraints={lineRef}
                  dragElastic={0}
                  dragMomentum={false}
                  onDrag={(e, info) => {
                    const rect = lineRef.current.getBoundingClientRect();
                    if (!rect) return;
                    const x = info.point.x - rect.left;
                    const percent = x / rect.width;
                    const closestNum = Math.round(percent * denominator);
                    const newVal = Math.max(0, Math.min(denominator, closestNum));
                    if (newVal !== numerator) {
                      setNumerator(newVal);
                      audioEngine.playTick(settings.soundTheme);
                    }
                    pointerX.set(0);
                  }}
                  onDragEnd={() => pointerX.set(0)}
                  animate={{ left: `calc(${(numerator / denominator) * 100}% - 3rem)` }}
                  transition={{ type: 'spring', damping: 30, stiffness: 500 }}
                >
                  <div className="flex gap-2">
                    <div className="w-2.5 h-10 bg-white/30 rounded-full group-hover/marker:h-12 transition-all" />
                    <div className="w-2.5 h-10 bg-white/30 rounded-full group-hover/marker:h-12 transition-all" />
                  </div>
                </motion.div>
              </div>
            </div>
          </div>
        </div>
      </div>

    </div>
  );
};

