  Layers
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';
import { shuffle } from '../../utils/random';

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ec4899', '#8b5cf6', '#ef4444', '#06b6d4', '#f97316'];

export const GroupMaker = () => {
  const { settings } = useSettings();
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const [selectedClassId, setSelectedClassId] = useState(settings.classes[0]?.id || '');
  const [mode, setMode] = useState('groups'); // 'groups' or 'students'
  const [count, setCount] = useState(4);
  const [groups, setGroups] = useState([]);
  const [isGenerating, setIsGenerating] = useState(false);

  const selectedClass = settings.classes.find(c => c.id === selectedClassId);
  const students = selectedClass?.students || [];

  const makeGroups = () => {
    if (!students.length) return;
    setIsGenerating(true);
    setGroups([]);
    audioEngine.playTick(settings.soundTheme);

    setTimeout(() => {
      const shuffled = shuffle([...students]);
      let newGroups = [];

      if (mode === 'groups') {
        newGroups = Array.from({ length: count }, () => []);
        shuffled.forEach((student, index) => {
          newGroups[index % count].push(student);
        });
      } else {
        const numGroups = Math.ceil(students.length / count);
        newGroups = Array.from({ length: numGroups }, () => []);
        shuffled.forEach((student, index) => {
          newGroups[Math.floor(index / count)].push(student);
        });
      }

      setGroups(newGroups);
      setIsGenerating(false);
      audioEngine.playSuccess(settings.soundTheme);
    }, 800);
  };

  useEffect(() => {
    setOnReset(() => () => { setGroups([]); audioEngine.playTick(settings.soundTheme); });
    return () => clearHeader();
  }, [clearHeader, setOnReset, settings.soundTheme]);

  useEffect(() => {
    setHeaderActions(null);
  }, [setHeaderActions]);

  return (
    <div className="tool-container flex flex-col gap-8 h-full font-['Outfit'] select-none">

      {/* Control Bar */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-wrap items-end gap-8">
        {/* Class Selection */}
        <div className="flex flex-col gap-2">
          <label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider ml-1">Select Class</label>
          <div className="relative">
            <select 
              value={selectedClassId} 
              onChange={(e) => { setSelectedClassId(e.target.value); audioEngine.playTick(settings.soundTheme); }} 
              className="appearance-none pl-4 pr-10 py-2 bg-slate-50 border border-slate-200 text-slate-900 rounded-xl text-sm font-medium outline-none transition-all cursor-pointer hover:border-indigo-300 min-w-[160px]"
            >
              {settings.classes.map(c => (
                <option key={c.id} value={c.id}>{c.name} ({c.students.length})</option>
              ))}
            </select>
            <ChevronDown size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
          </div>
        </div>

        {/* Mode Toggle */}
        <div className="bg-slate-100 p-1 rounded-xl flex items-center h-[42px]">
          <button 
            onClick={() => { setMode('groups'); audioEngine.playTick(settings.soundTheme); }}
            className={`px-4 py-1.5 rounded-lg text-[11px] font-bold uppercase tracking-wider transition-all ${mode === 'groups' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Number of Groups
          </button>
          <button 
            onClick={() => { setMode('students'); audioEngine.playTick(settings.soundTheme); }}
            className={`px-4 py-1.5 rounded-lg text-[11px] font-bold uppercase tracking-wider transition-all ${mode === 'students' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Students per Group
          </button>
        </div>

        {/* Count Input */}
        <div className="flex items-center gap-2 h-[42px]">
          <input 
            type="number"
            value={count}
            min={1}
            max={students.length || 100}
            onChange={(e) => { setCount(parseInt(e.target.value) || 1); audioEngine.playTick(settings.soundTheme); }}
            className="w-16 h-full bg-white border border-slate-200 rounded-xl text-center font-bold text-lg focus:border-indigo-500 outline-none transition-all"
          />
        </div>

        {/* Generate Button */}
        <button
          onClick={makeGroups}
          disabled={isGenerating || !students.length}
          className={`h-[42px] ml-auto flex items-center gap-3 px-8 rounded-xl font-bold text-sm text-white transition-all active:scale-95 shadow-md ${isGenerating ? 'bg-slate-300 cursor-not-allowed' : 'bg-[#6366f1] hover:bg-[#5558e3] hover:shadow-indigo-200'}`}
        >
          {isGenerating ? <RotateCcw size={18} className="animate-spin" /> : <Shuffle size={18} />}
          <span>Generate</span>
        </button>
      </div>

      {/* Main Display Area */}
      <div className="flex-1 overflow-y-auto no-scrollbar">
        <AnimatePresence mode="wait">
          {groups.length > 0 ? (
            <motion.div 
              key="groups-grid"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-8"
            >
              {groups.map((members, idx) => (
                <motion.div
                  key={idx}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: idx * 0.05 }}
                  className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden flex flex-col h-fit"
                >
                  <div className="px-6 py-4 flex items-center justify-between border-b border-slate-50">
                    <h3 className="font-bold text-indigo-600 text-sm">Group {idx + 1}</h3>
                    <span className="w-6 h-6 rounded-md bg-indigo-50 text-indigo-600 flex items-center justify-center text-[10px] font-bold">
                      {members.length}
                    </span>
                  </div>

                  <div className="p-5 flex flex-col gap-3">
                    {members.map((member, mIdx) => (
                      <div key={mIdx} className="flex items-center gap-3">
                        <div className="w-2 h-2 rounded-full bg-orange-400" />
                        <span className="text-sm font-medium text-slate-700">{member}</span>
                      </div>
                    ))}
                  </div>
                </motion.div>
              ))}
            </motion.div>
          ) : isGenerating ? (
            <div className="h-full flex flex-col items-center justify-center py-20">
              <RotateCcw size={48} className="text-indigo-500 animate-spin mb-4" />
              <p className="text-slate-400 font-medium animate-pulse">Generating groups...</p>
            </div>
          ) : (
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className="h-full flex flex-col items-center justify-center py-20 text-slate-300"
            >
              <Users size={80} strokeWidth={1} className="mb-4 opacity-20" />
              <p className="text-lg font-medium">Ready to shuffle!</p>
              <p className="text-sm opacity-60">Select your class and click Generate.</p>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

