      { emoji: '🍑', name: 'Peach' }, { emoji: '🍊', name: 'Orange' }, { emoji: '🍋', name: 'Lemon' },
      { emoji: '🍈', name: 'Melon' }, { emoji: '🍏', name: 'Green Apple' }, { emoji: '🍐', name: 'Pear' }
    ]
  },
  space: {
