    if (guess === target) {
      result = 'Correct';
      setStatus('won');
      audioEngine.playAlarm(settings.soundTheme);

      const end = Date.now() + 3 * 1000;
      const colors = ['#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];

      (function frame() {
        confetti({
          particleCount: 15,
          angle: 60,
          spread: 55,
          origin: { x: 0 },
          colors: colors
        });
        confetti({
          particleCount: 15,
          angle: 120,
          spread: 55,
          origin: { x: 1 },
          colors: colors
