  return (
    <motion.button
      onClick={() => onClick(num)}
      animate={{
        backgroundColor: isCurrentlyVisible && highlightColor ? `${highlightColor}33` : (isCurrentlyVisible ? '#ffffff' : '#f8fafc'),
