};

export const HundredsChart = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [hiddenNumbers, setHiddenNumbers] = useState(new Set());
  const [highlighted, setHighlighted] = useState({});
  const [activeMode, setActiveMode] = useState(0); // 0 for Hide, 1+ for colors
  const [animSpeed, setAnimSpeed] = useState(4000);
  const [isPatternAnimating, setIsPatternAnimating] = useState(false);

  const colors = [
    '#6366f1', // indigo
    '#f43f5e', // rose
    '#10b981', // emerald
    '#f59e0b', // amber
    '#0ea5e9', // sky
    '#8b5cf6', // violet
  ];

  const speeds = [
    { label: 'Slow', value: 4000 },
    { label: 'Fast', value: 2000 },
    { label: 'Instant', value: 5 },
  ];

  const hideAll = () => {
    const all = new Set();
    for (let i = 1; i <= 100; i++) all.add(i);
    setHiddenNumbers(all);
    audioEngine.playTick(settings.soundTheme);
  };

  const revealAll = () => {
    setHiddenNumbers(new Set());
    audioEngine.playTick(settings.soundTheme);
  };

  const clearAll = () => {
    setHiddenNumbers(new Set());
    setHighlighted({});
    setIsPatternAnimating(false);
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    setOnReset(() => clearAll);
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <div className="flex bg-slate-100 p-0.5 rounded-xl border-2 border-slate-200/50 shadow-inner w-fit shrink-0">
           <button 
             onClick={hideAll} 
             className="px-4 py-1.5 text-[10px] font-black text-slate-400 hover:text-slate-600 transition-all uppercase tracking-[0.2em] rounded-lg"
           >
             Hide All
           </button>
           <button 
             onClick={revealAll} 
             className="px-4 py-1.5 text-[10px] font-black text-slate-400 hover:text-slate-600 transition-all uppercase tracking-[0.2em] rounded-lg"
           >
             Reveal All
           </button>
        </div>
        <div className="w-px h-8 bg-slate-200" />
        <button
          onClick={clearAll}
          className="flex items-center gap-2 px-6 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:border-rose-100 hover:text-rose-600 transition-all active:scale-95 shadow-sm italic"
        >
          <RotateCcw size={14} /> Clear Board
        </button>
      </div>
    );
  }, [hiddenNumbers, highlighted, settings.soundTheme]);

  const handleCellClick = (num) => {
    audioEngine.playTick(settings.soundTheme);
    if (activeMode === 0) {
      setHiddenNumbers(prev => {
        const next = new Set(prev);
        if (next.has(num)) next.delete(num);
        else next.add(num);
        return next;
      });
    } else {
      setHighlighted(prev => {
        const next = { ...prev };
        const colorIndex = activeMode - 1;
        if (next[num] === colorIndex) delete next[num];
        else next[num] = colorIndex;
        return next;
      });
    }
  };

  const highlightMultiples = (multiple) => {
    audioEngine.playTick(settings.soundTheme);
    setIsPatternAnimating(true);
    const newHighlights = { ...highlighted };
    const colorIndex = activeMode === 0 ? 0 : activeMode - 1;

    for (let i = multiple; i <= 100; i += multiple) {
      newHighlights[i] = colorIndex;
    }
    setHighlighted(newHighlights);

    setTimeout(() => setIsPatternAnimating(false), 100 * (animSpeed / 1000) + 400);
  };

  const rows = useMemo(() => {
    const r = [];
    for (let i = 0; i < 10; i++) {
      const row = [];
      for (let j = 1; j <= 10; j++) row.push(i * 10 + j);
      r.push(row);
    }
    return r;
  }, []);

  return (
    <div className="tool-container w-full mx-auto space-y-8 h-full flex flex-col font-['Outfit'] select-none">

      <div className="flex flex-col lg:flex-row gap-8 flex-1 min-h-[600px] overflow-hidden">

        {/* Interaction Sidebar */}
        <div className="w-full lg:w-80 flex flex-col gap-6 shrink-0 h-full overflow-hidden">
          <div className="tool-sidebar-card flex-1 p-10">
            <div className="flex-1 space-y-10 overflow-y-auto pr-2 custom-scrollbar no-scrollbar">
               <div className="space-y-8">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400">
                        <Sliders size={18} />
                    </div>
                    <h4 className="tool-sub-label mb-0">Logic Cascade</h4>
                  </div>

                  <div className="space-y-4">
                    <span className="tool-sub-label-indigo border-b-0 pb-0 ml-1">Synthesis Speed</span>
                    <div className="flex bg-slate-100 p-1 rounded-2xl border-2 border-slate-200/50 shadow-inner">
                      {speeds.map(s => (
                        <button
                          key={s.label}
                          onClick={() => { setAnimSpeed(s.value); audioEngine.playTick(settings.soundTheme); }}
