             <Sparkles size={24} className="text-indigo-400 animate-pulse" />
             <span className="text-[10px] font-black uppercase tracking-[0.6em] italic text-slate-800">Grid Array Synthesis v2.0</span>
          </div>

          <div className="w-full max-w-5xl aspect-square relative z-10">
            <div className="bg-slate-900 shadow-[0_80px_160px_-40px_rgba(0,0,0,0.4)] rounded-[4rem] border-4 border-slate-800 p-4 relative overflow-hidden group/chart">
              <div className="tool-grid-bg-dark opacity-[0.05]" />
              <div className="grid grid-cols-10 border-2 border-slate-800/50 bg-white rounded-[3.5rem] overflow-hidden shadow-inner relative z-10">
                {rows.flat().map(num => (
                  <div key={num} className="aspect-square">
                    <ChartCell
                      num={num}
                      isHidden={hiddenNumbers.has(num)}
                      highlightColor={highlighted[num] !== undefined ? colors[highlighted[num]] : null}
                      animDelay={isPatternAnimating ? (num * animSpeed) / 50000 : 0}
                      isPatternAnimating={isPatternAnimating}
                      onClick={handleCellClick}
                      settings={settings}
                    />
                  </div>
                ))}
              </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

export default HundredsChart;

