import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Image as ImageIcon, 
  Upload, 
  Play, 
  Pause,
  RotateCcw, 
  ChevronLeft, 
  ChevronRight, 
  Eye, 
  Zap, 
  Settings, 
  X,
  Maximize2, 
  Grid, 
  Layers, 
  Sparkles,
  Activity,
  History,
  Layout,
  MousePointer2,
  Settings2,
  Trash2,
  Info,
  Timer,
  Target
} from 'lucide-react';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';

const REVEAL_EFFECTS = [
  { id: 'blur', label: 'Diffusion Blur', icon: Sparkles, desc: 'Gaussian interference' },
  { id: 'grid', label: 'Mosaic Matrix', icon: Grid, desc: 'Cellular reveal' },
  { id: 'pixel', label: 'Bit Synthesis', icon: Layers, desc: 'Quantum upscaling' }
];

export const ImageReveal = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const [images, setImages] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [mode, setMode] = useState('reveal'); // 'reveal' or 'lightsOut'
  const [revealEffect, setRevealEffect] = useState('blur');
  const [progress, setProgress] = useState(0);
  const [isRevealing, setIsRevealing] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 50, y: 50 });
  const [gridState, setGridState] = useState([]);

  const containerRef = useRef(null);
  const revealTimerRef = useRef(null);

  const handleUpload = (e) => {
    const files = Array.from(e.target.files);
    const newImages = files.map(file => URL.createObjectURL(file));
    setImages(prev => [...prev, ...newImages]);
    if (images.length === 0) setCurrentIndex(0);
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    if (revealEffect === 'grid') {
      const size = 10;
      setGridState(Array(size * size).fill(true));
    }
  }, [revealEffect, currentIndex]);

  useEffect(() => {
    if (isRevealing && mode === 'reveal') {
      const duration = 20000;
      const intervalTime = 100;
      const step = (intervalTime / duration) * 100;

      revealTimerRef.current = setInterval(() => {
        setProgress(prev => {
          if (prev >= 100) {
            setIsRevealing(false);
            clearInterval(revealTimerRef.current);
            return 100;
          }
          return prev + step;
        });

        if (revealEffect === 'grid') {
          setGridState(prev => {
            const next = [...prev];
            const hiddenIndices = next.map((v, i) => v ? i : -1).filter(i => i !== -1);
            if (hiddenIndices.length > 0) {
              const toReveal = Math.ceil(hiddenIndices.length * (step / (100 - progress || 1)));
              for (let i = 0; i < toReveal; i++) {
                const rand = Math.floor(Math.random() * hiddenIndices.length);
                next[hiddenIndices[rand]] = false;
                hiddenIndices.splice(rand, 1);
              }
            }
            return next;
          });
        }
      }, intervalTime);
    } else {
      clearInterval(revealTimerRef.current);
    }
    return () => clearInterval(revealTimerRef.current);
  }, [isRevealing, mode, revealEffect]);

  const toggleReveal = () => {
    if (progress >= 100) {
      resetReveal();
    } else {
      setIsRevealing(!isRevealing);
      audioEngine.playTick(settings.soundTheme);
    }
  };

  const resetReveal = () => {
    setIsRevealing(false);
    setProgress(0);
    if (revealEffect === 'grid') {
      setGridState(Array(100).fill(true));
    }
    audioEngine.playTick(settings.soundTheme);
  };

  const handleMouseMove = (e) => {
    if (mode !== 'lightsOut' || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;
    setMousePos({ x, y });
  };

  const removeImage = (idx) => {
    setImages(prev => prev.filter((_, i) => i !== idx));
    if (currentIndex >= images.length - 1) setCurrentIndex(Math.max(0, images.length - 2));
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    setOnReset(() => resetReveal);
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <div className="flex bg-slate-100 p-0.5 rounded-xl border-2 border-slate-200/50 shadow-inner w-fit shrink-0">
           {[
             { id: 'reveal', label: 'Reveal', icon: Zap },
             { id: 'lightsOut', label: 'Lights Out', icon: Maximize2 }
           ].map(m => (
             <button
               key={m.id}
               onClick={() => { setMode(m.id); resetReveal(); audioEngine.playTick(settings.soundTheme); }}
               className={`px-5 py-1.5 rounded-lg font-black text-[10px] uppercase tracking-[0.2em] transition-all flex items-center gap-2 ${mode === m.id ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
             >
               <m.icon size={14} /> {m.label}
             </button>
           ))}
        </div>
        <div className="w-px h-8 bg-slate-200" />
        <button 
          onClick={resetReveal}
          className="flex items-center gap-2 px-6 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:border-rose-100 hover:text-rose-600 transition-all active:scale-95 shadow-sm italic"
        >
          <RotateCcw size={14} /> Reset Stage
        </button>
      </div>
    );
  }, [mode, settings.soundTheme]);

  return (
    <div className="tool-container w-full mx-auto space-y-8 h-full flex flex-col font-['Outfit'] select-none">
      <div className="flex flex-col lg:flex-row gap-8 flex-1 min-h-[600px] overflow-hidden">

        {/* Playlist & Control Sidebar */}
        <div className="w-full lg:w-96 flex flex-col gap-6 shrink-0 h-full overflow-hidden">
          <div className="tool-sidebar-card flex-1 p-10">
             <div className="flex items-center justify-between mb-10">
                <div className="flex items-center gap-3">
                   <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400">
                      <Settings2 size={18} />
                   </div>
                   <h4 className="tool-sub-label mb-0">Unveil Terminal</h4>
                </div>
                <label className="p-3 bg-indigo-50 text-indigo-600 border-2 border-indigo-100 rounded-xl hover:bg-indigo-100 transition-all cursor-pointer shadow-sm active:scale-95">
                   <input type="file" multiple accept="image/*" onChange={handleUpload} className="hidden" />
                   <Upload size={18} />
                </label>
             </div>

             <div className="flex-1 space-y-10 overflow-y-auto pr-2 custom-scrollbar no-scrollbar">
                {/* Synthesis Mode Selection */}
                {mode === 'reveal' && (
                  <div className="space-y-4">
                     <span className="tool-sub-label-indigo border-b-0 pb-0 ml-1">Synthesis Logic</span>
                     <div className="grid grid-cols-1 gap-3">
                       {REVEAL_EFFECTS.map(effect => (
                         <button
                           key={effect.id}
                           onClick={() => { setRevealEffect(effect.id); resetReveal(); audioEngine.playTick(settings.soundTheme); }}
                           className={`p-6 rounded-[2.5rem] border-4 transition-all text-left flex items-center gap-4 ${revealEffect === effect.id ? 'bg-white border-indigo-600 text-indigo-600 shadow-2xl translate-x-2' : 'bg-slate-50 border-transparent text-slate-600 hover:border-indigo-100'}`}
                         >
                            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center shadow-inner ${revealEffect === effect.id ? 'bg-indigo-50 text-indigo-600' : 'bg-white text-slate-300'}`}>
                               <effect.icon size={20} />
                            </div>
                            <div className="flex-1">
                               <p className="text-[11px] font-black uppercase tracking-widest leading-none mb-1 italic">{effect.label}</p>
                               <p className={`text-[9px] font-bold uppercase tracking-widest opacity-40`}>{effect.desc}</p>
                            </div>
                         </button>
                       ))}
                     </div>
                  </div>
                )}

                {/* Playlist Grid */}
                <div className="space-y-4">
                   <div className="flex items-center justify-between ml-1">
                      <span className="tool-sub-label-indigo border-b-0 pb-0">Active Playlist</span>
                      <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest tabular-nums italic">{images.length} Units</span>
                   </div>
                   <div className="grid grid-cols-2 gap-3">
                      {images.map((img, idx) => (
                        <div 
                          key={idx}
                          onClick={() => { setCurrentIndex(idx); resetReveal(); audioEngine.playTick(settings.soundTheme); }}
                          className={`group relative aspect-video rounded-3xl overflow-hidden cursor-pointer border-4 transition-all ${currentIndex === idx ? 'border-indigo-600 scale-95 shadow-2xl' : 'border-white bg-slate-50 hover:border-indigo-100 hover:shadow-lg'}`}
                        >
                          <img src={img} className="w-full h-full object-cover" alt={`Preview ${idx}`} />
                          <div className={`absolute inset-0 bg-black/40 flex items-center justify-center transition-opacity ${currentIndex === idx ? 'opacity-0' : 'opacity-0 group-hover:opacity-100'}`}>
                             <Eye size={20} className="text-white" />
                          </div>
                          <button 
                            onClick={(e) => { e.stopPropagation(); removeImage(idx); }}
                            className="absolute top-2 right-2 p-2 bg-rose-500 text-white rounded-xl opacity-0 group-hover:opacity-100 transition-all hover:scale-110 shadow-lg"
                          >
                            <Trash2 size={12} />
                          </button>
                        </div>
                      ))}
                      <label className="flex flex-col items-center justify-center aspect-video rounded-3xl border-4 border-dashed border-slate-50 hover:border-indigo-100 hover:bg-indigo-50/30 transition-all cursor-pointer text-slate-300 hover:text-indigo-400 group">
                        <input type="file" multiple accept="image/*" onChange={handleUpload} className="hidden" />
                        <Upload size={20} className="group-hover:scale-110 transition-transform" />
                        <span className="text-[9px] font-black uppercase mt-2 italic tracking-widest">Append</span>
                      </label>
                   </div>
                </div>
             </div>

             <div className="mt-10 pt-10 border-t border-slate-50">
                <div className="p-8 bg-slate-900 rounded-[2.5rem] text-white flex items-start gap-4 relative overflow-hidden group shadow-2xl border border-slate-800">
                   <div className="tool-grid-bg-dark opacity-10" />
                   <div className="w-10 h-10 bg-white/5 rounded-2xl flex items-center justify-center text-indigo-400 shrink-0 relative z-10">
                      <Info size={18} />
                   </div>
                   <div className="space-y-1 relative z-10">
                      <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest italic">Protocol Tip</p>
                      <p className="text-[10px] font-black text-white/40 leading-relaxed uppercase tracking-tighter italic">
                        {mode === 'reveal' ? 'Gradual entropy reduction allows for multi-phase hypothesis testing.' : 'Restricted visual field forces attention on specific anatomical segments.'}
                      </p>
                   </div>
                </div>
             </div>
          </div>
        </div>

        {/* Main Canvas Stage */}
        <div className="flex-1 tool-stage bg-[#050510] p-12 relative overflow-hidden flex flex-col items-center justify-center h-auto">
           <div className="tool-grid-bg-dark opacity-20" />

           <div className="relative w-full h-full flex flex-col gap-10 z-10">
              <div 
                ref={containerRef}
                onMouseMove={handleMouseMove}
                className="flex-1 bg-black rounded-[4rem] shadow-[0_80px_160px_-40px_rgba(0,0,0,0.8)] overflow-hidden relative border-[12px] border-white/5 cursor-crosshair group/canvas"
              >
                {images.length > 0 ? (
                  <>
                    <img 
                      src={images[currentIndex]} 
                      alt="Mystery" 
                      className="w-full h-full object-contain select-none"
                    />

                    <AnimatePresence>
                      {mode === 'lightsOut' ? (
                        <motion.div 
                          initial={{ opacity: 0 }}
                          animate={{ opacity: 1 }}
                          exit={{ opacity: 0 }}
                          className="absolute inset-0 z-10 pointer-events-none"
                          style={{
                            background: `radial-gradient(circle 160px at ${mousePos.x}% ${mousePos.y}%, transparent 0%, rgba(0,0,0,0.98) 100%)`
                          }}
                        />
                      ) : (
                        <motion.div className="absolute inset-0 z-10">
                          {revealEffect === 'blur' && (
                            <div 
                              className="absolute inset-0 backdrop-blur-3xl"
                              style={{ 
                                backdropFilter: `blur(${Math.pow(1 - progress / 100, 2) * 120}px)`,
                                opacity: progress >= 100 ? 0 : 1,
                                backgroundColor: `rgba(0, 0, 0, ${Math.max(0, 0.7 * (1 - progress/100))})`
                              }}
                            />
                          )}

                          {revealEffect === 'pixel' && (
                            <div className="absolute inset-0">
                              <PixelatedImage src={images[currentIndex]} progress={progress} />
                            </div>
                          )}

                          {revealEffect === 'grid' && (
                            <div className="absolute inset-0 grid grid-cols-10 grid-rows-10">
                              {gridState.map((active, i) => (
                                <motion.div
                                  key={i}
                                  initial={false}
                                  animate={{ opacity: active ? 1 : 0, scale: active ? 1 : 0.8 }}
                                  className="bg-[#050510] border-[0.5px] border-white/10"
                                />
                              ))}
                            </div>
                          )}
                        </motion.div>
                      )}
                    </AnimatePresence>
                  </>
                ) : (
                  <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-700 gap-8">
                    <div className="w-40 h-40 bg-white/5 rounded-[3.5rem] border-4 border-white/5 flex items-center justify-center animate-pulse shadow-2xl">
                       <ImageIcon size={80} strokeWidth={1} className="text-indigo-400/20" />
                    </div>
                    <div className="text-center space-y-3">
                       <p className="font-black uppercase tracking-[0.6em] text-xl opacity-30 italic">Canvas Depleted</p>
                       <p className="text-[11px] font-black text-indigo-400/40 uppercase tracking-[0.4em] italic">Awaiting Visual Payload</p>
                    </div>
                  </div>
                )}

                {/* Stage HUD Overlay */}
                <div className="absolute top-10 left-10 flex items-center gap-4 opacity-20 pointer-events-none">
                   <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_15px_rgba(99,102,241,1)]" />
                   <span className="text-[10px] font-black text-white uppercase tracking-[0.6em] italic">Unveil System v4.2 Active</span>
                </div>

                {/* Internal Nav Controls */}
                {images.length > 1 && (
                  <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-10 z-20">
                    <button 
                      onClick={() => { setCurrentIndex(prev => (prev - 1 + images.length) % images.length); resetReveal(); }}
                      className="p-6 bg-white/10 backdrop-blur-3xl text-white rounded-[2rem] hover:bg-white/20 transition-all border-2 border-white/10 shadow-2xl active:scale-90"
                    >
                      <ChevronLeft size={32} />
                    </button>
                    <div className="px-12 py-4 bg-white/10 backdrop-blur-3xl text-white rounded-[2.5rem] font-black text-2xl italic tracking-tighter border-2 border-white/10 shadow-2xl min-w-[140px] text-center tabular-nums">
                      {currentIndex + 1} <span className="text-white/20">/</span> {images.length}
                    </div>
                    <button 
                      onClick={() => { setCurrentIndex(prev => (prev + 1) % images.length); resetReveal(); }}
                      className="p-6 bg-white/10 backdrop-blur-3xl text-white rounded-[2rem] hover:bg-white/20 transition-all border-2 border-white/10 shadow-2xl active:scale-90"
                    >
                      <ChevronRight size={32} />
                    </button>
                  </div>
                )}

                {/* Primary Action Button */}
                {images.length > 0 && mode === 'reveal' && (
                  <div className="absolute bottom-12 right-12 z-30">
                     <button
                        onClick={toggleReveal}
                        className={`w-36 h-36 rounded-[4rem] transition-all active:scale-90 shadow-2xl flex flex-col items-center justify-center gap-2 border-4 ${
                          isRevealing 
                            ? 'bg-amber-500 border-amber-400 text-white shadow-amber-900/50 animate-pulse' 
                            : 'bg-indigo-600 border-indigo-500 text-white shadow-indigo-900/50 hover:scale-105'
                        }`}
                      >
                        {isRevealing ? <Pause size={48} fill="currentColor" strokeWidth={0} /> : <Play size={48} fill="currentColor" strokeWidth={0} className="ml-2" />}
                        <span className="text-[10px] font-black uppercase tracking-[0.2em] italic">{isRevealing ? 'Halt' : 'Start'}</span>
                      </button>
                  </div>
                )}
              </div>

              {/* Progress HUD at bottom */}
              {mode === 'reveal' && images.length > 0 && (
                <div className="flex flex-col gap-4">
                   <div className="flex justify-between items-center px-4">
                      <div className="flex items-center gap-4">
                         <Target size={18} className="text-indigo-400" />
                         <span className="text-[11px] font-black text-white/30 uppercase tracking-[0.5em] italic">De-Entropy Progress</span>
                      </div>
                      <span className="text-2xl font-black italic text-indigo-400 tabular-nums">{Math.round(progress)}%</span>
                   </div>
                   <div className="bg-white/5 rounded-full h-4 shadow-inner border-2 border-white/5 overflow-hidden p-1">
                      <motion.div 
                        className="h-full bg-gradient-to-r from-indigo-600 to-indigo-400 rounded-full shadow-[0_0_25px_rgba(99,102,241,0.6)]"
                        initial={{ width: 0 }}
                        animate={{ width: `${progress}%` }}
                        transition={{ ease: "linear", duration: 0.1 }}
                      />
                   </div>
                </div>
              )}
           </div>
        </div>
      </div>
    </div>
  );
};

const PixelatedImage = ({ src, progress }) => {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const img = new Image();

    img.onload = () => {
      const w = 1200;
      const h = 900;
      canvas.width = w;
      canvas.height = h;

      const pixelSize = Math.max(1, Math.floor(100 * Math.pow(1 - progress / 100, 2)));

      if (pixelSize <= 1) {
        ctx.drawImage(img, 0, 0, w, h);
        return;
      }

      const sw = Math.ceil(w / pixelSize);
      const sh = Math.ceil(h / pixelSize);

      const tempCanvas = document.createElement('canvas');
      tempCanvas.width = sw;
      tempCanvas.height = sh;
      const tCtx = tempCanvas.getContext('2d');
      tCtx.drawImage(img, 0, 0, sw, sh);

      ctx.imageSmoothingEnabled = false;
      ctx.clearRect(0, 0, w, h);
      ctx.drawImage(tempCanvas, 0, 0, sw, sh, 0, 0, w, h);
    };
    img.src = src;
  }, [src, progress]);

  return (
    <canvas ref={canvasRef} className="w-full h-full object-contain bg-black" />
  );
};

export default ImageReveal;

