      for (let i = 0; i < 200; i++) {
        newParticles.push({
          x: x + (Math.random() - 0.5) * 15,
          y: y + (Math.random() - 0.5) * 15,
          vx: (Math.random() - 0.5) * 0.3,
          vy: Math.random() * 0.6 + 0.3,
          size: Math.random() * 4 + 1.5,
          opacity: Math.random() * 0.6 + 0.4,
          color: color
        });
      }
      particles.current = [...particles.current, ...newParticles].slice(-3000);
    },
    reset: () => {
      particles.current = [];
    }
  }));

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');

    const update = () => {
      if (isPlaying && particles.current.length > 0) {
        const tempFactor = (temperature + 40) / 80; 
        const diffusionRate = 1.4 * tempFactor;
        const randomForce = 1.0 * tempFactor;

        particles.current.forEach(p => {
          p.vx += (Math.random() - 0.5) * randomForce;
          p.vy += (Math.random() - 0.5) * randomForce;
          p.vy += 0.012;
          p.vx *= 0.96;
          p.vy *= 0.96;
          p.x += p.vx * diffusionRate;
          p.y += p.vy * diffusionRate;

          const margin = 8;
          if (p.x < margin) { p.x = margin; p.vx *= -0.4; }
          if (p.x > BEAKER_WIDTH - margin) { p.x = BEAKER_WIDTH - margin; p.vx *= -0.4; }
          if (p.y < 85) { p.y = 85; p.vy *= -0.4; }
          if (p.y > BEAKER_HEIGHT - margin) { p.y = BEAKER_HEIGHT - margin; p.vy *= -0.4; }
        });
      }
      draw();
      animationRef.current = requestAnimationFrame(update);
    };

    const draw = () => {
      ctx.clearRect(0, 0, BEAKER_WIDTH, BEAKER_HEIGHT);

      const tintOpacity = Math.min(0.04, temperature / 1200);
      ctx.fillStyle = temperature > 30 ? `rgba(244, 63, 94, ${tintOpacity})` : `rgba(99, 102, 241, ${Math.min(0.04, (30 - temperature) / 1200)})`;
      ctx.fillRect(0, 85, BEAKER_WIDTH, BEAKER_HEIGHT - 85);

      particles.current.forEach(p => {
        ctx.beginPath();
        const grad = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size * 5);
        grad.addColorStop(0, p.color);
        grad.addColorStop(1, 'transparent');
        ctx.fillStyle = grad;
        ctx.globalAlpha = p.opacity;
        ctx.arc(p.x, p.y, p.size * 2.5, 0, Math.PI * 2);
        ctx.fill();
      });
      ctx.globalAlpha = 1.0;
    };

    animationRef.current = requestAnimationFrame(update);
    return () => cancelAnimationFrame(animationRef.current);
  }, [temperature, isPlaying]);

  return (
    <div className="relative flex flex-col items-center group/container">
      {/* Thermometer Overlay */}
      <div className="absolute -left-20 top-24 flex flex-col items-center gap-4 z-30">
        <div className="w-5 h-56 bg-slate-100 rounded-full border-4 border-white relative overflow-hidden shadow-[inset_0_4px_8px_rgba(0,0,0,0.1),0_8px_16px_rgba(0,0,0,0.05)] transition-all group-hover/container:border-indigo-100">
          <motion.div 
            initial={{ height: 0 }}
            animate={{ height: `${temperature}%` }}
            className={`absolute bottom-0 left-0 right-0 rounded-full transition-all duration-1000 shadow-[0_0_20px_rgba(0,0,0,0.1)] ${
              temperature > 60 ? 'bg-rose-500 shadow-[0_0_15px_rgba(244,63,94,0.5)]' : temperature > 25 ? 'bg-amber-400 shadow-[0_0_15px_rgba(251,191,36,0.5)]' : 'bg-indigo-400 shadow-[0_0_15px_rgba(99,102,241,0.5)]'
            }`}
          />
        </div>
        <div className="bg-white/95 backdrop-blur-xl px-4 py-2 rounded-2xl shadow-2xl border-2 border-white flex items-center gap-2 italic">
          <Thermometer size={14} className="text-slate-400" />
          <span className="text-[11px] font-black text-slate-800 tabular-nums uppercase leading-none mt-0.5">{temperature}°C</span>
        </div>
      </div>

      {/* Beaker Body */}
      <div className="relative w-[300px] h-[400px] bg-white/20 backdrop-blur-md rounded-b-[4.5rem] border-x-[12px] border-b-[12px] border-white/40 shadow-[0_64px_128px_-32px_rgba(0,0,0,0.15)] overflow-hidden group/beaker transition-all duration-700 hover:border-white/60 hover:scale-[1.02]">
        {/* Liquid Surface */}
        <div className="absolute top-0 left-0 right-0 h-8 bg-white/60 border-b-2 border-white/20 z-20 flex items-center justify-center overflow-hidden">
           <div className="w-24 h-1.5 bg-slate-200/50 rounded-full opacity-40 animate-pulse" />
           <div className="absolute top-0 left-0 right-0 bottom-0 bg-gradient-to-b from-white/40 to-transparent" />
        </div>

        {/* Measurement Marks */}
        <div className="absolute left-8 top-28 bottom-12 w-10 flex flex-col justify-between items-start opacity-10 z-10 pointer-events-none italic">
          {[500, 400, 300, 200, 100].map(m => (
            <div key={m} className="flex items-center gap-3">
              <div className="w-10 h-[2.5px] bg-slate-900 rounded-full" />
              <span className="text-[11px] font-black text-slate-900 leading-none">{m}</span>
            </div>
          ))}
        </div>

        {/* Refraction/Reflection Overlays */}
        <div className="absolute top-0 left-10 bottom-0 w-24 bg-gradient-to-r from-white/30 to-transparent pointer-events-none z-20" />
        <div className="absolute top-0 right-10 bottom-0 w-10 bg-gradient-to-l from-white/10 to-transparent pointer-events-none z-20" />

        <canvas 
          ref={canvasRef} 
          width={BEAKER_WIDTH} 
          height={BEAKER_HEIGHT} 
          className="relative z-10"
        />
      </div>

      <div className="mt-10 text-center flex flex-col items-center gap-3">
        <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.4em] italic leading-none mb-1">
           Matrix: {label}
        </h4>
        <div className="flex items-center gap-3 px-5 py-2 bg-white/60 backdrop-blur-md rounded-full border-2 border-white shadow-xl">
          <Activity size={14} className={temperature > 50 ? 'text-rose-500 animate-pulse' : 'text-indigo-500'} />
          <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest tabular-nums italic">
             Kinetic Vector: {temperature > 50 ? 'EXCITED' : 'STABLE'}
          </span>
        </div>
      </div>
    </div>
  );
});

