              className={`px-4 py-1.5 rounded-lg font-black text-[10px] transition-all uppercase tracking-widest ${charSet === set ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'text-slate-400 hover:text-indigo-600'}`}
            >
              {set === 'upper' ? 'Caps' : set === 'lower' ? 'Small' : 'Nums'}
            </button>
          ))}
        </div>

        <div className="flex items-center gap-2 bg-white p-1 rounded-xl border-2 border-slate-100 shadow-sm">
          <button onClick={prevLetter} className="p-1.5 hover:bg-slate-50 rounded-lg transition-all text-slate-400 hover:text-indigo-600">
            <ChevronLeft size={16} />
          </button>
          <div className="text-sm font-black w-8 text-center text-slate-700 italic">{currentLetter}</div>
          <button onClick={nextLetter} className="p-1.5 hover:bg-slate-50 rounded-lg transition-all text-slate-400 hover:text-indigo-600">
            <ChevronRight size={16} />
          </button>
        </div>

        <div className="w-px h-6 bg-slate-200" />

        <div className="flex items-center gap-2">
          <button
