        <div className="flex-1 flex flex-col">
           <div className="tool-stage p-12 flex-1 flex items-center justify-center relative overflow-hidden bg-white">
             <div className="tool-grid-bg" />

             <div className="absolute top-10 left-10 flex items-center gap-3">
