                   <PenTool size={20} />
                </div>
                <div>
                   <h3 className="tool-title-hero text-lg mb-0 border-b-0 pb-0">Tracing Canvas</h3>
                   <p className="tool-sub-label mb-0 border-b-0 pb-0">Phonic Formation Lab</p>
                </div>
             </div>

             <div className="relative w-[400px] h-[400px] shadow-2xl rounded-[3rem] border-[12px] border-white bg-slate-50/50">
               <canvas
