              <div className="w-3 h-3 rounded-full bg-slate-100" />
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Pending</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col gap-8 overflow-x-auto no-scrollbar pb-4 custom-scrollbar">
          {Object.entries(charSets).map(([setName, set]) => (
            <div key={setName} className="flex items-center gap-8 min-w-max">
              <span className="w-16 text-[10px] font-black text-slate-300 uppercase tracking-widest text-right italic">{setName === 'upper' ? 'Caps' : setName === 'lower' ? 'Small' : 'Nums'}</span>
              <div className="flex gap-2">
                {set.split('').map(char => {
                  const charScore = mastery[char] || 0;
                  const isCurrent = currentLetter === char && charSet === setName;
                  return (
                    <button
                      key={char}
                      onClick={() => { setCharSet(setName); setCurrentLetter(char); }}
                      className={`group relative w-12 h-12 rounded-2xl font-black text-lg transition-all border-4 flex items-center justify-center overflow-hidden ${
                        isCurrent ? 'border-indigo-600 bg-slate-900 text-white scale-110 z-10 shadow-2xl' : 'border-slate-50 bg-white hover:border-indigo-100'
                      }`}
                    >
                      <div 
                        className="absolute bottom-0 left-0 w-full transition-all duration-1000 bg-emerald-500/10 group-hover:bg-emerald-500/20" 
                        style={{ height: `${charScore}%` }} 
                      />
                      <span className={`relative z-10 italic ${charScore > 80 ? 'text-emerald-600' : isCurrent ? 'text-white' : 'text-slate-400'}`}>{char}</span>
                      {charScore > 0 && (
                        <div className="absolute bottom-0 left-0 w-full h-1.5 bg-emerald-500 shadow-[0_0_8px_#10b981]" style={{ width: `${charScore}%` }} />
                      )}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default LetterTracing;

