import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  RotateCcw, 
  Trash2, 
  Sparkles, 
  Zap, 
  Layout, 
  MousePointer2, 
  Activity, 
  Box, 
  Monitor,
  Info,
  Maximize2,
  ChevronRight,
  Hash,
  Square,
  BoxSelect,
  Grid
} from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';

const BLOCK_TYPES = [
  { id: 'unit', name: 'Unit', value: 1, color: '#f43f5e', size: 30, label: 'Single' },
  { id: 'long', name: 'Long', value: 10, color: '#0ea5e9', size: 30, label: 'Rod' },
  { id: 'flat', name: 'Flat', value: 100, color: '#10b981', size: 30, label: 'Plane' },
  { id: 'cube', name: 'Cube', value: 1000, color: '#f59e0b', size: 30, label: 'Volume' },
];

export const MABBlocks = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const [blocks, setBlocks] = useState([]);
  const [isDragging, setIsDragging] = useState(false);
  const containerRef = useRef(null);

  const addBlock = (type) => {
    const rect = containerRef.current.getBoundingClientRect();
    const newBlock = {
      id: Date.now(),
      typeId: type.id,
      x: rect.width / 2 + (Math.random() - 0.5) * 100,
      y: rect.height / 2 + (Math.random() - 0.5) * 100,
      color: type.color,
      value: type.value,
      rotation: Math.random() * 4 - 2
    };
    setBlocks(prev => [...prev, newBlock]);
    audioEngine.playTick(settings.soundTheme);
  };

  const removeBlock = (id) => {
    setBlocks(prev => prev.filter(b => b.id !== id));
    audioEngine.playTick(settings.soundTheme);
  };

  const resetBlocks = () => {
    setBlocks([]);
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    setOnReset(() => resetBlocks);
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(null);
  }, [setHeaderActions]);

  const totalValue = blocks.reduce((acc, b) => acc + b.value, 0);

  const renderBlockVisual = (typeId, color) => {
    if (typeId === 'unit') return (
      <div className="w-8 h-8 rounded-lg shadow-lg border-2 border-white/20 relative overflow-hidden" style={{ backgroundColor: color }}>
        <div className="absolute inset-0 bg-gradient-to-tr from-black/20 via-transparent to-white/30" />
      </div>
    );
    if (typeId === 'long') return (
      <div className="w-8 h-32 rounded-xl shadow-xl border-2 border-white/20 relative flex flex-col gap-1 p-1 overflow-hidden" style={{ backgroundColor: color }}>
        <div className="absolute inset-0 bg-gradient-to-tr from-black/20 via-transparent to-white/30" />
        {Array.from({ length: 10 }).map((_, i) => (
          <div key={i} className="flex-1 w-full bg-white/10 rounded-sm" />
        ))}
      </div>
    );
    if (typeId === 'flat') return (
      <div className="w-32 h-32 rounded-2xl shadow-2xl border-2 border-white/20 relative grid grid-cols-10 grid-rows-10 gap-0.5 p-1 overflow-hidden" style={{ backgroundColor: color }}>
        <div className="absolute inset-0 bg-gradient-to-tr from-black/20 via-transparent to-white/30" />
        {Array.from({ length: 100 }).map((_, i) => (
          <div key={i} className="bg-white/10 rounded-[1px]" />
        ))}
      </div>
    );
    if (typeId === 'cube') return (
      <div className="w-40 h-40 rounded-[2.5rem] shadow-[0_32px_64px_-12px_rgba(0,0,0,0.3)] border-2 border-white/20 relative flex items-center justify-center overflow-hidden" style={{ backgroundColor: color }}>
         <div className="absolute inset-0 bg-gradient-to-tr from-black/20 via-transparent to-white/30" />
         <div className="grid grid-cols-4 gap-2 opacity-20">
            <Box size={40} />
            <Box size={40} />
            <Box size={40} />
            <Box size={40} />
         </div>
         <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-4xl font-black text-white/40 italic tracking-tighter">1000</span>
         </div>
      </div>
    );
  };

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      {/* Block Resource Sidebar */}
      <div className="w-full lg:w-[420px] flex flex-col gap-6 shrink-0 h-full overflow-hidden">
        <div className="tool-sidebar-card flex-1 p-10 flex flex-col">
           <div className="flex items-center justify-between mb-10 shrink-0">
              <div className="flex items-center gap-3">
                 <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 border border-slate-100">
                    <Box size={18} />
                 </div>
                 <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Resource Bank</h4>
              </div>
              <div className="px-3 py-1 bg-indigo-50 rounded-lg text-[10px] font-black text-indigo-500 uppercase tracking-widest italic">Inventory</div>
           </div>

           <div className="grid grid-cols-1 gap-3 shrink-0">
              {BLOCK_TYPES.map(type => (
                <button
                  key={type.id}
                  onClick={() => addBlock(type)}
                  className="w-full p-6 bg-slate-50 rounded-[2.5rem] border-4 border-transparent hover:border-indigo-100 hover:bg-white transition-all flex items-center justify-between group italic shadow-sm hover:shadow-xl"
                >
                  <div className="flex items-center gap-6">
                     <div className="w-14 h-14 rounded-3xl flex items-center justify-center shadow-lg border-2 border-white group-hover:scale-110 transition-transform" style={{ backgroundColor: type.color }}>
                        {type.id === 'unit' && <Square size={24} className="text-white/60" />}
                        {type.id === 'long' && <BoxSelect size={24} className="text-white/60" />}
                        {type.id === 'flat' && <Grid size={24} className="text-white/60" />}
                        {type.id === 'cube' && <Box size={24} className="text-white/60" />}
                     </div>
                     <div className="text-left">
                        <p className="text-[12px] font-black uppercase tracking-[0.2em] leading-tight text-slate-400">{type.label}</p>
                        <p className="text-xl font-black uppercase tracking-tighter text-slate-800 leading-none mt-1">{type.name}</p>
                     </div>
                  </div>
                  <div className="flex items-center gap-3">
                     <span className="text-[10px] font-black text-indigo-500 bg-indigo-50 px-3 py-1.5 rounded-xl uppercase tracking-widest">+{type.value}</span>
                  </div>
                </button>
              ))}
           </div>

           <div className="mt-auto pt-10 border-t border-slate-50 space-y-6">
              <div className="tool-hero-stat-card p-10 bg-slate-900 shadow-2xl border-none relative group overflow-hidden">
                 <div className="tool-grid-bg-dark opacity-10" />
                 <div className="absolute inset-0 bg-indigo-500/10 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                 <div className="relative z-10 flex flex-col items-center">
                    <span className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.4em] italic mb-4 leading-none">Total Accumulated</span>
                    <AnimatePresence mode="wait">
                       <motion.div
                         key={totalValue}
                         initial={{ opacity: 0, scale: 0.9, y: 10 }}
                         animate={{ opacity: 1, scale: 1, y: 0 }}
                         className="text-7xl font-black text-white italic tracking-tighter tabular-nums leading-none drop-shadow-2xl"
                       >
                         {totalValue.toLocaleString()}
                       </motion.div>
                    </AnimatePresence>
                    <div className="w-full h-1 bg-white/5 mt-8 rounded-full overflow-hidden">
                       <motion.div 
                        className="h-full bg-indigo-500 shadow-[0_0_15px_rgba(99,102,241,1)]"
                        initial={false}
                        animate={{ width: totalValue > 0 ? '100%' : '0%' }}
                       />
                    </div>
                 </div>
              </div>

              <div className="flex items-center gap-4 group">
                 <div className="w-10 h-10 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-300 group-hover:bg-indigo-50 group-hover:text-indigo-400 transition-all shadow-sm">
                    <MousePointer2 size={18} />
                 </div>
                 <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Spatial Manipulation</span>
                    <span className="text-[11px] font-bold text-slate-300 italic uppercase">Drag to reorganize nodes</span>
