      <div 
        ref={containerRef}
        className="flex-1 tool-stage bg-slate-50 p-0 relative overflow-hidden group/stage cursor-grab active:cursor-grabbing border-none rounded-[4rem] h-auto"
      >
        <div className="tool-grid-bg opacity-30" />

        {/* Decorative Background */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-[0.03] group-hover/stage:opacity-[0.05] transition-opacity duration-1000">
           <Maximize2 size={600} className="text-slate-900" strokeWidth={0.05} />
        </div>

        {/* HUD Overlay */}
        <div className="absolute top-12 left-12 flex items-center gap-6 z-20">
           <div className="flex items-center gap-4 px-8 py-4 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border-4 border-white/60 shadow-xl">
              <div className="w-3 h-3 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_20px_rgba(79,70,229,1)]" />
              <div className="flex flex-col">
                 <span className="text-[11px] font-black text-slate-800 uppercase tracking-[0.6em] italic leading-none mb-1">Observation Stage</span>
