              </div>
           </div>
        </div>

        {/* Action Guide */}
        <div className="absolute bottom-12 right-12 flex items-center gap-6 z-20 pointer-events-none opacity-40 italic">
           <div className="text-right">
              <p className="text-[11px] font-black uppercase tracking-[0.6em]">Right-Click to extract</p>
              <p className="text-[11px] font-black uppercase tracking-[0.4em] mt-1">Freeform organization active</p>
           </div>
           <div className="w-12 h-12 rounded-2xl bg-white/50 border border-white flex items-center justify-center shadow-inner">
              <Activity size={24} className="text-slate-400" />
           </div>
        </div>

        <AnimatePresence>
          {blocks.map(block => (
            <motion.div
              key={block.id}
              drag
              dragMomentum={false}
              initial={{ scale: 0, rotate: -20 }}
              animate={{ scale: 1, rotate: block.rotation }}
              exit={{ scale: 0, opacity: 0 }}
              className="absolute cursor-move z-10 group/block"
              style={{ left: block.x, top: block.y }}
              onContextMenu={(e) => {
                e.preventDefault();
                removeBlock(block.id);
              }}
            >
              <div className="relative group/wrap">
                 {renderBlockVisual(block.typeId, block.color)}

                 {/* Delete Hover Control */}
                 <button 
                  onClick={() => removeBlock(block.id)}
                  className="absolute -top-3 -right-3 w-8 h-8 bg-rose-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover/wrap:opacity-100 transition-all shadow-xl hover:scale-110 active:scale-90 border-2 border-white z-20"
                 >
                    <Trash2 size={14} />
                 </button>
              </div>
            </motion.div>
          ))}
        </AnimatePresence>

        {blocks.length === 0 && (
          <div className="absolute inset-0 flex flex-center justify-center items-center pointer-events-none">
             <div className="text-center space-y-4 opacity-20">
                <Box size={120} strokeWidth={0.5} className="mx-auto text-slate-400" />
                <p className="text-[14px] font-black uppercase tracking-[1em] italic">Deploy Base-10 Modules</p>
             </div>
          </div>
        )}
      </div>

    </div>
  );
};

export default MABBlocks;

