import React, { useState, useEffect, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Trophy, Play, RotateCcw, ArrowLeft, Gamepad2, Circle, CheckCircle2, XCircle, Activity, Sparkles, Target, MousePointer2, Box, Database, Terminal } from 'lucide-react';
import confetti from 'canvas-confetti';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';

const MARBLE_TYPES = [
  { name: 'Red', colorClass: 'bg-red-500 shadow-[inset_-6px_-6px_12px_rgba(0,0,0,0.3),0_0_20px_rgba(239,68,68,0.3)]', textClass: 'text-red-500' },
  { name: 'Blue', colorClass: 'bg-indigo-500 shadow-[inset_-6px_-6px_12px_rgba(0,0,0,0.3),0_0_20px_rgba(79,70,229,0.3)]', textClass: 'text-indigo-500' },
  { name: 'Green', colorClass: 'bg-emerald-500 shadow-[inset_-6px_-6px_12px_rgba(0,0,0,0.3),0_0_20px_rgba(16,185,129,0.3)]', textClass: 'text-emerald-500' },
  { name: 'Yellow', colorClass: 'bg-amber-400 shadow-[inset_-6px_-6px_12px_rgba(0,0,0,0.3),0_0_20px_rgba(251,191,36,0.3)]', textClass: 'text-amber-500' },
  { name: 'Purple', colorClass: 'bg-purple-500 shadow-[inset_-6px_-6px_12px_rgba(0,0,0,0.3),0_0_20px_rgba(168,85,247,0.3)]', textClass: 'text-purple-500' },
  { name: 'Orange', colorClass: 'bg-orange-500 shadow-[inset_-6px_-6px_12px_rgba(0,0,0,0.3),0_0_20px_rgba(249,115,22,0.3)]', textClass: 'text-orange-500' },
  { name: 'Pink', colorClass: 'bg-rose-500 shadow-[inset_-6px_-6px_12px_rgba(0,0,0,0.3),0_0_20px_rgba(244,63,94,0.3)]', textClass: 'text-rose-500' },
  { name: 'Cyan', colorClass: 'bg-cyan-500 shadow-[inset_-6px_-6px_12px_rgba(0,0,0,0.3),0_0_20px_rgba(6,182,212,0.3)]', textClass: 'text-cyan-500' },
];

export const MarbleCounting = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [gameState, setGameState] = useState('menu'); // 'menu', 'playing', 'result'
  const [difficulty, setDifficulty] = useState('1-5');
  const [marbles, setMarbles] = useState([]);
  const [targetType, setTargetType] = useState(null);
  const [targetCount, setTargetCount] = useState(0);
  const [options, setOptions] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [feedback, setFeedback] = useState(null); // { isCorrect, selected }

  const containerRef = useRef(null);
  const requestRef = useRef();

  const resetGame = useCallback(() => {
    setGameState('menu');
    setMarbles([]);
    setFeedback(null);
    setCurrentIndex(0);
    setScore(0);
    audioEngine.playTick(settings.soundTheme);
  }, [settings.soundTheme]);

  useEffect(() => {
    setOnReset(() => resetGame);
    return () => clearHeader();
  }, [clearHeader, setOnReset, resetGame]);

  const generateMarbles = useCallback((range) => {
    const [min, max] = range.split('-').map(Number);
    const selectedTypes = [...MARBLE_TYPES].sort(() => 0.5 - Math.random()).slice(0, 3);
    const target = selectedTypes[Math.floor(Math.random() * selectedTypes.length)];

    const newMarbles = [];
    let tCount = 0;

    selectedTypes.forEach(type => {
      const count = Math.floor(Math.random() * (max - min + 1)) + min;
      if (type.name === target.name) tCount = count;

      for (let i = 0; i < count; i++) {
        newMarbles.push({
          id: `${type.name}-${i}-${Math.random()}`,
          name: type.name,
          x: Math.random() * 60 + 20,
          y: Math.random() * 60 + 20,
          vx: (Math.random() - 0.5) * 0.4,
          vy: (Math.random() - 0.5) * 0.4,
          color: type.colorClass,
          size: 64,
        });
      }
    });

    const opts = new Set([tCount]);
    while (opts.size < 4) {
      const offset = Math.floor(Math.random() * 5) - 2;
      const fake = Math.max(1, tCount + offset);
      opts.add(fake);
    }

    setTargetType(target);
    setTargetCount(tCount);
    setMarbles(newMarbles);
    setOptions(Array.from(opts).sort((a, b) => a - b));
  }, []);

  const updatePhysics = useCallback(() => {
    if (!containerRef.current) return;
    const width = containerRef.current.clientWidth;
    const height = containerRef.current.clientHeight;
    if (width === 0 || height === 0) return;

    const sizePx = 64;
    const sizeXPercent = (sizePx / width) * 100;
    const sizeYPercent = (sizePx / height) * 100;

    setMarbles(prev => {
      let next = prev.map(m => {
        let nx = m.x + m.vx;
        let ny = m.y + m.vy;
        let nvx = m.vx;
        let nvy = m.vy;

        if (nx <= sizeXPercent/2 || nx >= 100 - sizeXPercent/2) nvx *= -1;
        if (ny <= sizeYPercent/2 || ny >= 100 - sizeYPercent/2) nvy *= -1;

        nx = Math.max(sizeXPercent/2, Math.min(100 - sizeXPercent/2, nx));
        ny = Math.max(sizeYPercent/2, Math.min(100 - sizeYPercent/2, ny));

        return { ...m, x: nx, y: ny, vx: nvx, vy: nvy };
      });

      for (let i = 0; i < next.length; i++) {
        for (let j = i + 1; j < next.length; j++) {
          const m1 = next[i];
          const m2 = next[j];
          const dx = (m1.x - m2.x) * (width / 100);
          const dy = (m1.y - m2.y) * (height / 100);
          const distance = Math.sqrt(dx * dx + dy * dy);

          if (distance < sizePx) {
            const v1x = m1.vx;
            const v1y = m1.vy;
            m1.vx = m2.vx;
            m1.vy = m2.vy;
            m2.vx = v1x;
            m2.vy = v1y;
            const overlap = sizePx - distance;
            const nx = dx / distance;
            const ny = dy / distance;
            m1.x += (nx * overlap / 2) * (100 / width);
            m1.y += (ny * overlap / 2) * (100 / height);
            m2.x -= (nx * overlap / 2) * (100 / width);
            m2.y -= (ny * overlap / 2) * (100 / height);
          }
        }
      }
      return next;
    });
    requestRef.current = requestAnimationFrame(updatePhysics);
  }, []);

  useEffect(() => {
    if (gameState === 'playing' || gameState === 'feedback') {
      requestRef.current = requestAnimationFrame(updatePhysics);
    }
    return () => cancelAnimationFrame(requestRef.current);
  }, [gameState, updatePhysics]);

  const startGame = (diff) => {
    setDifficulty(diff);
    setCurrentIndex(0);
    setScore(0);
    setGameState('playing');
    generateMarbles(diff);
    audioEngine.playTick(settings.soundTheme);
  };

  const handleAnswer = (val) => {
    if (feedback) return;
    const isCorrect = val === targetCount;
    if (isCorrect) {
      setScore(s => s + 1);
      audioEngine.playSuccess(settings.soundTheme);
    } else {
      audioEngine.playError(settings.soundTheme);
    }
    setFeedback({ isCorrect, selected: val });
    setTimeout(() => {
      if (currentIndex < 9) {
        setCurrentIndex(i => i + 1);
        generateMarbles(difficulty);
        setFeedback(null);
      } else {
        setGameState('result');
        if (score >= 8) {
          confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 } });
        }
      }
    }, 2000);
  };

  const kickMarble = (id) => {
    audioEngine.playTick(settings.soundTheme);
    setMarbles(prev => prev.map(m => 
      m.id === id ? { ...m, vx: -m.vx * 1.8, vy: -m.vy * 1.8 } : m
    ));
  };

  useEffect(() => {
    if (gameState === 'playing' || gameState === 'feedback') {
      setHeaderActions(
        <div className="flex items-center gap-4">
          <button onClick={resetGame} className="flex items-center gap-2 px-8 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:border-rose-100 hover:text-rose-600 transition-all active:scale-95 shadow-sm italic">
            <RotateCcw size={14} /> Abort Cycle
          </button>
        </div>
      );
    } else {
      setHeaderActions(null);
    }
  }, [gameState, resetGame, setHeaderActions]);

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      <AnimatePresence mode="wait">
        {gameState === 'menu' ? (
          <motion.div 
            key="menu"
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 1.02 }}
            className="flex-1 tool-stage p-0 flex flex-col items-center justify-center relative overflow-hidden bg-white border-none rounded-[4rem]"
          >
            <div className="tool-grid-bg opacity-30" />
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-indigo-500/5 blur-[120px] rounded-full pointer-events-none" />

            <div className="relative z-10 w-full max-w-4xl px-12 py-24 flex flex-col items-center text-center gap-12">
               <div className="w-40 h-40 rounded-[3.5rem] bg-slate-900 flex items-center justify-center text-white border-8 border-white shadow-2xl rotate-3 group hover:rotate-0 transition-transform duration-500">
                  <Box size={80} strokeWidth={1} />
               </div>

               <div className="space-y-6">
                  <h2 className="text-8xl font-black text-slate-900 tracking-tighter uppercase italic leading-none">Kinetic Counting</h2>
                  <p className="text-[14px] font-black text-slate-400 uppercase tracking-[0.6em] italic">Advanced Optical Tracking Simulator v2.0</p>
                  <p className="text-xl text-slate-500 font-bold max-w-2xl mx-auto leading-relaxed italic">
                    Engage neural pathways to identify and isolate specific pigment spheres within a dynamic kinetic field. High-precision extraction required.
                  </p>
               </div>

               <div className="grid grid-cols-3 gap-8 w-full max-w-3xl">
                 {[
                   { id: '1-5', label: 'Tier 1', range: '1-5', color: 'hover:border-emerald-200 hover:bg-emerald-50 text-emerald-600', icon: <Target className="text-emerald-400" /> },
                   { id: '5-10', label: 'Tier 2', range: '5-10', color: 'hover:border-indigo-200 hover:bg-indigo-50 text-indigo-600', icon: <Activity className="text-indigo-400" /> },
                   { id: '1-20', label: 'Elite', range: '1-20', color: 'hover:border-rose-200 hover:bg-rose-50 text-rose-600', icon: <Sparkles className="text-rose-400" /> }
                 ].map((diff) => (
                   <button
                     key={diff.id}
                     onClick={() => startGame(diff.range)}
                     className={`group flex flex-col items-center gap-4 p-10 bg-white border-4 border-slate-50 rounded-[3rem] transition-all hover:scale-105 shadow-xl active:scale-95 italic ${diff.color}`}
                   >
                     <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center group-hover:scale-110 transition-transform mb-2 shadow-inner">
                        {diff.icon}
                     </div>
                     <span className="text-[11px] font-black uppercase tracking-[0.4em] opacity-60 leading-none">{diff.label}</span>
                     <span className="text-4xl font-black tabular-nums tracking-tighter leading-none">{diff.range}</span>
                   </button>
                 ))}
               </div>
            </div>
          </motion.div>
        ) : gameState === 'result' ? (
          <motion.div 
            key="result"
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0 }}
            className="flex-1 tool-stage p-0 flex flex-col items-center justify-center relative overflow-hidden bg-slate-950 border-none rounded-[4rem]"
          >
            <div className="tool-grid-bg-dark opacity-10" />
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-indigo-500/10 blur-[160px] rounded-full pointer-events-none" />

            <div className="relative z-10 w-full max-w-4xl px-12 py-24 flex flex-col items-center text-center gap-16">
               <div className="relative group">
                  <div className="absolute -inset-12 bg-amber-400/20 rounded-full blur-[80px] animate-pulse" />
                  <div className="w-48 h-48 rounded-[4rem] bg-gradient-to-br from-amber-300 to-amber-600 flex items-center justify-center mx-auto shadow-[0_64px_128px_-32px_rgba(245,158,11,0.5)] border-[12px] border-white/20 rotate-6 group-hover:rotate-0 transition-transform duration-700">
                    <Trophy size={96} className="text-white drop-shadow-2xl" strokeWidth={1.5} />
                  </div>
               </div>

               <div className="space-y-6">
                  <h2 className="text-8xl font-black text-white tracking-tighter uppercase italic leading-none">Simulation Log</h2>
                  <p className="text-[14px] font-black text-indigo-400 uppercase tracking-[0.6em] italic">Optical Synchronization Result</p>
                  <div className="flex flex-col items-center gap-4 mt-12">
                     <span className="text-[11px] font-black text-white/20 uppercase tracking-[0.8em] italic">Tracking Accuracy</span>
                     <div className="text-[12rem] font-black text-white italic tabular-nums tracking-tighter leading-none flex items-end">
                        {score}<span className="text-4xl text-white/20 mb-8 ml-4">/ 10</span>
                     </div>
                  </div>
               </div>

               <div className="flex gap-6 w-full max-w-2xl mt-8">
                 <button 
                   onClick={resetGame} 
                   className="flex-1 py-8 bg-white/5 hover:bg-white/10 text-white font-black text-[11px] uppercase tracking-[0.4em] rounded-[2.5rem] transition-all active:scale-95 border-4 border-white/10 italic flex items-center justify-center gap-4 group"
                 >
                   <ArrowLeft size={20} className="group-hover:-translate-x-2 transition-transform" /> Laboratory Home
                 </button>
                 <button 
                   onClick={() => startGame(difficulty)} 
                   className="flex-1 py-8 bg-indigo-600 text-white font-black text-[11px] uppercase tracking-[0.4em] rounded-[2.5rem] hover:bg-indigo-700 transition-all active:scale-95 shadow-[0_48px_96px_-24px_rgba(79,70,229,0.5)] border-4 border-indigo-400/50 italic flex items-center justify-center gap-4 group"
                 >
                   <RotateCcw size={20} className="group-hover:rotate-180 transition-transform duration-1000" /> New Cycle
                 </button>
               </div>
            </div>
          </motion.div>
        ) : (
          <div className="flex-1 flex flex-col lg:flex-row gap-8 overflow-hidden h-full">
            {/* Playing Field */}
            <div className="flex-1 tool-stage p-0 relative overflow-hidden bg-white border-none rounded-[4rem] group/stage flex items-center justify-center" ref={containerRef}>
              <div className="tool-grid-bg opacity-30" />

              {/* HUD Elements */}
              <div className="absolute top-12 left-12 flex flex-col gap-6 z-20">
                 <div className="flex items-center gap-4 px-8 py-4 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border-4 border-white/60 shadow-xl group/hud hover:border-indigo-100 transition-all italic">
                    <div className="w-3 h-3 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_20px_rgba(79,70,229,1)]" />
                    <div className="flex flex-col">
                       <span className="text-[11px] font-black text-slate-800 uppercase tracking-[0.6em] leading-none mb-1">Field Tracking</span>
                       <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.4em] leading-none">Status: Engaging Signal</span>
                    </div>
                 </div>
              </div>

              <div className="absolute top-12 right-12 flex flex-col gap-6 z-20">
                 <div className="flex items-center gap-6 px-10 py-6 bg-slate-900 rounded-[2.5rem] shadow-[0_32px_64px_-16px_rgba(0,0,0,0.5)] border-4 border-slate-800 italic group">
                    <div className="flex flex-col items-end">
                       <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.5em] leading-none mb-2">Sync: 60Hz</span>
                       <span className="text-2xl font-black text-white tabular-nums leading-none tracking-tighter">{currentIndex + 1}<span className="text-[12px] text-white/20 ml-1">/ 10</span></span>
                    </div>
                    <div className="w-px h-10 bg-white/10" />
                    <div className="flex flex-col items-start">
                       <span className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.5em] leading-none mb-2">Score</span>
                       <span className="text-2xl font-black text-white tabular-nums leading-none tracking-tighter">{score}</span>
                    </div>
                 </div>
              </div>

              {/* The Marbles */}
              <AnimatePresence>
                {marbles.map((m) => (
                  <motion.div
                    key={m.id}
                    onClick={() => kickMarble(m.id)}
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    exit={{ scale: 0 }}
                    className={`absolute rounded-full cursor-pointer pointer-events-auto transition-transform active:scale-75 ${m.color} z-10 group/marble`}
                    style={{
                      left: `${m.x}%`,
                      top: `${m.y}%`,
                      width: `${m.size}px`,
                      height: `${m.size}px`,
                      transform: 'translate(-50%, -50%)',
                    }}
                  >
                    <div className="absolute inset-0 rounded-full bg-white/30 blur-[2px] opacity-0 group-hover/marble:opacity-100 transition-opacity" />
                    <div className="absolute inset-2 rounded-full border-2 border-white/20" />
                    {/* Chrome Highlight */}
                    <div className="absolute top-2 left-2 w-4 h-4 bg-white/40 rounded-full blur-[1px]" />
                  </motion.div>
                ))}
              </AnimatePresence>

              {/* Question Overlay */}
              <div className="absolute bottom-12 left-0 right-0 flex flex-col items-center pointer-events-none z-30">
                <div className="bg-white/80 backdrop-blur-3xl px-16 py-10 rounded-[4rem] shadow-[0_64px_128px_-32px_rgba(0,0,0,0.2)] border-8 border-white mb-12 text-center max-w-4xl mx-4 relative overflow-hidden group">
                  <div className="absolute inset-0 bg-indigo-500/5 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />
                  <h2 className="text-5xl font-black text-slate-900 tracking-tighter uppercase italic leading-tight relative z-10">
                    Extract <span className={`${targetType?.textClass} brightness-125 px-4`}>{targetType?.name}</span> Units
                  </h2>
                </div>

                <div className="flex gap-6 pointer-events-auto">
                  {options.map((opt) => (
                    <button
                      key={opt}
                      onClick={() => handleAnswer(opt)}
                      disabled={!!feedback}
                      className={`w-28 h-28 rounded-[3rem] text-5xl font-black transition-all transform active:scale-90 shadow-2xl border-4 tabular-nums italic ${
                        feedback 
                          ? opt === targetCount ? 'bg-emerald-500 border-emerald-400 text-white shadow-[0_32px_64px_-16px_rgba(16,185,129,0.5)]' : 
                            feedback.selected === opt ? 'bg-rose-500 border-rose-400 text-white shadow-[0_32px_64px_-16px_rgba(244,63,94,0.5)]' : 'bg-slate-900 border-slate-800 text-slate-600 opacity-20'
                          : 'bg-white border-slate-100 text-slate-800 hover:border-indigo-500 hover:text-indigo-600 hover:-translate-y-2'
                      }`}
                    >
                      {opt}
                    </button>
                  ))}
                </div>
              </div>

              {/* Feedback Overlay */}
              <AnimatePresence>
                {feedback && (
                  <motion.div
                    initial={{ opacity: 0, scale: 0.8, backdropFilter: 'blur(0px)' }}
                    animate={{ opacity: 1, scale: 1, backdropFilter: 'blur(12px)' }}
                    exit={{ opacity: 0, scale: 1.2, backdropFilter: 'blur(0px)' }}
                    className="absolute inset-0 flex items-center justify-center pointer-events-none z-40 bg-white/20"
                  >
                    <div className={`flex flex-col items-center gap-10 px-24 py-16 rounded-[6rem] shadow-[0_120px_240px_-40px_rgba(0,0,0,0.5)] border-8 italic ${feedback.isCorrect ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-rose-500 text-white border-rose-400'}`}>
                      {feedback.isCorrect ? <CheckCircle2 size={120} strokeWidth={1} /> : <XCircle size={120} strokeWidth={1} />}
                      <div className="text-center">
                        <span className="text-7xl font-black tracking-tighter uppercase leading-none block mb-2">{feedback.isCorrect ? 'SYNCHRONIZED' : 'ABORTED'}</span>
                        <span className="text-[14px] font-black uppercase tracking-[0.8em] opacity-60 leading-none">Target Resolution: {targetCount} Nodes</span>
                      </div>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>

              {/* Interaction Guide */}
              <div className="absolute bottom-12 right-12 flex items-center gap-6 z-20 pointer-events-none opacity-40 italic">
                <div className="text-right">
