import React, { useState, useEffect, useRef } from 'react';
import { Plus, Minus, RotateCcw, Sparkles, Trophy, Settings, X, Target, Layout } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import confetti from 'canvas-confetti';
import Matter from 'matter-js';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';
import { useHeader } from '../../contexts/HeaderContext';

const MARBLE_COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ec4899', '#8b5cf6', '#ef4444', '#06b6d4'];
const MARBLE_RADIUS = 20;

const JAR_STYLES = [
  { id: 'small-classic', name: 'Petite Jar', width: 220, height: 280 },
  { id: 'large-classic', name: 'Grande Jar', width: 280, height: 380 },
  { id: 'large-tall', name: 'Cylinder', width: 240, height: 450 },
];

export const MarbleJar = () => {
  const { settings } = useSettings();
  const { setHeaderActions, setHasConfig, setOnConfigToggle, setOnReset, clearHeader } = useHeader();

  const [marbleCount, setMarbleCount] = useState(() => {
    const saved = localStorage.getItem('teacherToolsMarbleJarCount');
    return saved ? JSON.parse(saved) : 0;
  });

  const [target, setTarget] = useState(() => {
    const saved = localStorage.getItem('teacherToolsMarbleJarTarget');
    return saved ? JSON.parse(saved) : 10;
  });

  const [jarStyleId, setJarStyleId] = useState(() => {
    const saved = localStorage.getItem('teacherToolsMarbleJarStyle');
    return saved ? JSON.parse(saved) : 'large-classic';
  });

  const currentJarStyle = JAR_STYLES.find(s => s.id === jarStyleId) || JAR_STYLES[1];
  const { width: JAR_WIDTH, height: JAR_HEIGHT } = currentJarStyle;

  const [isRewarding, setIsRewarding] = useState(false);
  const [hoverX, setHoverX] = useState(null);

  const engineRef = useRef(null);
  const runnerRef = useRef(null);
  const canvasRef = useRef(null);
  const jarContainerRef = useRef(null);
  const marbleBodiesRef = useRef([]);

  useEffect(() => {
    const engine = Matter.Engine.create();
    engineRef.current = engine;

    const ground = Matter.Bodies.rectangle(JAR_WIDTH / 2, JAR_HEIGHT + 20, JAR_WIDTH, 40, { isStatic: true, friction: 0.1, restitution: 0.5 });
    const leftWall = Matter.Bodies.rectangle(-10, JAR_HEIGHT / 2, 20, JAR_HEIGHT * 2, { isStatic: true, friction: 0.1 });
    const rightWall = Matter.Bodies.rectangle(JAR_WIDTH + 10, JAR_HEIGHT / 2, 20, JAR_HEIGHT * 2, { isStatic: true, friction: 0.1 });

    Matter.World.add(engine.world, [ground, leftWall, rightWall]);

    const runner = Matter.Runner.create();
    Matter.Runner.run(runner, engine);
    runnerRef.current = runner;

    let animationFrameId;
    const renderLoop = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      ctx.clearRect(0, 0, JAR_WIDTH, JAR_HEIGHT);

      marbleBodiesRef.current.forEach((body) => {
        const { position, circleRadius } = body;
        const color = body.render.fillStyle;

        ctx.save();
        ctx.translate(position.x, position.y);
        ctx.rotate(body.angle);

        const gradient = ctx.createRadialGradient(-circleRadius*0.3, -circleRadius*0.3, circleRadius*0.1, 0, 0, circleRadius);
        gradient.addColorStop(0, color);
        gradient.addColorStop(1, '#000000');

        ctx.beginPath();
        ctx.arc(0, 0, circleRadius, 0, 2 * Math.PI);
        ctx.fillStyle = gradient;
        ctx.fill();

        ctx.lineWidth = 1;
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
        ctx.stroke();

        ctx.beginPath();
        ctx.arc(-circleRadius * 0.4, -circleRadius * 0.4, circleRadius * 0.25, 0, 2 * Math.PI);
        ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
        ctx.fill();

        ctx.restore();
      });

      animationFrameId = requestAnimationFrame(renderLoop);
    };
    renderLoop();

    return () => {
      Matter.Runner.stop(runner);
      Matter.Engine.clear(engine);
      cancelAnimationFrame(animationFrameId);
      marbleBodiesRef.current = [];
    };
  }, [JAR_WIDTH, JAR_HEIGHT]);

  useEffect(() => {
    localStorage.setItem('teacherToolsMarbleJarCount', JSON.stringify(marbleCount));
    localStorage.setItem('teacherToolsMarbleJarTarget', JSON.stringify(target));
    localStorage.setItem('teacherToolsMarbleJarStyle', JSON.stringify(jarStyleId));

    const engine = engineRef.current;
    if (!engine) return;

    while (marbleBodiesRef.current.length < marbleCount) {
      const color = MARBLE_COLORS[marbleBodiesRef.current.length % MARBLE_COLORS.length];
      const newMarble = Matter.Bodies.circle(
        JAR_WIDTH / 2 + (Math.random() * 40 - 20), 
        -50, 
        MARBLE_RADIUS, 
        { 
          restitution: 0.7,
          friction: 0.02,
          density: 0.05,
          render: { fillStyle: color } 
        }
      );
      Matter.World.add(engine.world, newMarble);
      marbleBodiesRef.current.push(newMarble);
    }

    while (marbleBodiesRef.current.length > marbleCount) {
      const removedMarble = marbleBodiesRef.current.pop();
      Matter.World.remove(engine.world, removedMarble);
    }

    if (marbleCount >= target && !isRewarding && marbleCount > 0) {
      triggerReward();
    }
  }, [marbleCount, target, jarStyleId, JAR_WIDTH]);

  const addMarble = (xPos = JAR_WIDTH / 2) => {
    if (isRewarding) return;
    audioEngine.playTick(settings.soundTheme);

    const engine = engineRef.current;
    if (engine) {
       const color = MARBLE_COLORS[marbleCount % MARBLE_COLORS.length];
       const newMarble = Matter.Bodies.circle(
         xPos + (Math.random() * 10 - 5), 
         -50, 
         MARBLE_RADIUS, 
         { 
           restitution: 0.7,
           friction: 0.02,
           density: 0.05,
           render: { fillStyle: color } 
         }
       );
       Matter.World.add(engine.world, newMarble);
       marbleBodiesRef.current.push(newMarble);
    }

    setMarbleCount(prev => prev + 1);
  };

  const removeMarbleAtPoint = (x, y) => {
    if (isRewarding) return;
    const engine = engineRef.current;
    if (!engine) return;

    const bodies = marbleBodiesRef.current;
    const clickedBodies = Matter.Query.point(bodies, { x, y });

    if (clickedBodies.length > 0 && marbleCount > 0) {
      const clickedBody = clickedBodies[0];
      Matter.World.remove(engine.world, clickedBody);
      marbleBodiesRef.current = marbleBodiesRef.current.filter(b => b !== clickedBody);
      setMarbleCount(prev => prev - 1);
      audioEngine.playTick(settings.soundTheme);
    } else {
      addMarble(x);
    }
  };

  const resetJar = () => {
    setMarbleCount(0);
    setIsRewarding(false);
    audioEngine.playTick(settings.soundTheme);
  };

  const triggerReward = () => {
    setIsRewarding(true);
    audioEngine.playAlarm(settings.soundTheme);

    const end = Date.now() + 4 * 1000;
    (function frame() {
      confetti({ particleCount: 10, angle: 60, spread: 55, origin: { x: 0, y: 0.8 }, colors: MARBLE_COLORS });
      confetti({ particleCount: 10, angle: 120, spread: 55, origin: { x: 1, y: 0.8 }, colors: MARBLE_COLORS });
      if (Date.now() < end) requestAnimationFrame(frame);
    }());
  };

  useEffect(() => {
    return () => clearHeader();
  }, [clearHeader]);


  const handleMouseMove = (e) => {
    if (!jarContainerRef.current) return;
    const rect = jarContainerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const boundedX = Math.max(MARBLE_RADIUS, Math.min(x, JAR_WIDTH - MARBLE_RADIUS));
    setHoverX(boundedX);
  };

  const handleMouseLeave = () => {
    setHoverX(null);
  };

  const handleJarClick = (e) => {
    if (!jarContainerRef.current) return;
    const rect = jarContainerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    removeMarbleAtPoint(x, y);
  };

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 p-6 h-full overflow-hidden font-['Outfit'] select-none">


      {/* Main Display */}
      <div className="tool-stage group/display">
        <div className="tool-grid-bg" />

        <div className="relative flex flex-col items-center">
          {/* Drop Preview */}
          <div className="h-[50px] w-full relative mb-4 opacity-0 group-hover/display:opacity-100 transition-all duration-500 pointer-events-none">
             {hoverX !== null && !isRewarding && (
               <motion.div 
                 className="absolute top-0 w-12 h-12 rounded-full bg-white/40 shadow-2xl backdrop-blur-xl border-4 border-white/80 flex items-center justify-center overflow-hidden"
                 style={{ left: hoverX, transform: 'translateX(-50%)' }}
                 layoutId="drop-preview"
               >
                  <div className="w-full h-full bg-gradient-to-tr from-slate-200/50 to-transparent" />
               </motion.div>
             )}
          </div>

          {/* Glass Jar */}
          <div 
            ref={jarContainerRef}
            onClick={handleJarClick}
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            className="relative bg-white/10 backdrop-blur-[2px] rounded-b-[5rem] border-[10px] border-t-0 border-white/90 shadow-[0_50px_100px_-20px_rgba(0,0,0,0.1),inset_0_0_80px_rgba(255,255,255,0.5)] overflow-hidden cursor-pointer group/jar"
            style={{ width: JAR_WIDTH, height: JAR_HEIGHT }}
          >
             {/* Jar Rim */}
             <div className="absolute top-0 left-0 right-0 h-12 bg-white/30 border-b-4 border-white/40 z-20 pointer-events-none flex items-center justify-center">
                <div className="w-1/3 h-1.5 bg-white/20 rounded-full" />
             </div>

             <canvas 
               ref={canvasRef} 
               width={JAR_WIDTH} 
               height={JAR_HEIGHT} 
               className="w-full h-full absolute inset-0 z-10 pointer-events-none"
             />

             {/* Reflection Overlays */}
             <div className="absolute inset-0 pointer-events-none z-30 bg-gradient-to-tr from-white/10 via-transparent to-white/5" />
             <div className="absolute left-8 top-16 bottom-16 w-3 bg-white/10 rounded-full blur-[3px] pointer-events-none z-30 opacity-60" />
             <div className="absolute right-12 top-24 w-1.5 h-32 bg-white/20 rounded-full blur-[1px] pointer-events-none z-30 opacity-40 rotate-6" />
          </div>

          {/* Counter HUD */}
          <div className="tool-hero-stat-card mt-12 w-full max-w-[280px]">
            <div className="absolute inset-0 bg-indigo-500/10 rounded-[3rem] blur-2xl opacity-0 group-hover:opacity-100 transition-opacity" />
            <div className="flex items-center gap-2 mb-1 relative">
               <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse" />
               <span className="tool-header-stat-label">Accumulated</span>
            </div>
            <motion.span 
              key={marbleCount}
              initial={{ scale: 0.8, opacity: 0, y: 10 }}
              animate={{ scale: 1, opacity: 1, y: 0 }}
              className="text-7xl font-black text-white tabular-nums relative tracking-tighter"
            >
              {marbleCount}
            </motion.span>
            <div className="flex items-center gap-1.5 mt-2 bg-white/5 px-3 py-1 rounded-full border border-white/10">
               <span className="text-[9px] font-black text-slate-500 uppercase">Target:</span>
               <span className="text-[9px] font-black text-indigo-400 uppercase">{target}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Win Modal */}
      <AnimatePresence>
        {isRewarding && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-xl p-8"
          >
            <motion.div
              initial={{ scale: 0.5, y: 100 }}
              animate={{ scale: 1, y: 0 }}
              className="tool-overlay-card border-4 border-indigo-400 max-w-2xl"
            >
              <div className="relative">
                <div className="absolute -inset-10 bg-indigo-500 blur-3xl opacity-20 animate-pulse rounded-full" />
                <div className="tool-icon-container-indigo relative z-10 rotate-3">
                   <Trophy size={100} className="text-yellow-500 drop-shadow-lg" strokeWidth={1.5} />
                </div>
                <div className="absolute -top-4 -right-4 w-12 h-12 bg-emerald-400 rounded-full flex items-center justify-center text-white shadow-lg animate-bounce z-20">
                   <Sparkles size={24} />
                </div>
              </div>

              <div className="space-y-4">
                <h3 className="tool-title-hero Leading-none mb-3">Victory!</h3>
                <p className="tool-sub-label">The collective effort has achieved the objective. Reward sequence initiated.</p>
              </div>

              <button
                onClick={resetJar}
                className="group flex items-center gap-3 px-12 py-6 bg-slate-900 text-white rounded-[2.5rem] font-black uppercase tracking-widest text-sm hover:bg-indigo-600 transition-all shadow-xl shadow-indigo-100 active:scale-95"
              >
                <RotateCcw size={20} className="group-hover:rotate-180 transition-transform duration-700" /> Complete & Reset
              </button>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

    </div>
  );
