import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Play, 
  Pause, 
  Plus, 
  Minus, 
  Activity,
  Music,
  Zap,
  RotateCcw,
  Volume2,
  Settings2,
  Clock,
  Radio,
  Tally4,
  Target
} from 'lucide-react';
import { useSettings } from '../../contexts/SettingsContext';
