export const Metronome = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [bpm, setBpm] = useState(120);
  const [isPlaying, setIsPlaying] = useState(false);
  const [beat, setBeat] = useState(0);

  const audioCtxRef = useRef(null);
  const timerIDRef = useRef(null);
  const nextNoteTimeRef = useRef(0);
  const currentBeatRef = useRef(0);

  const scheduleAheadTime = 0.1;
  const lookahead = 25.0;

  useEffect(() => {
    if (!audioCtxRef.current) {
      audioCtxRef.current = new (window.AudioContext || window.webkitAudioContext)();
    }
    return () => {
      if (timerIDRef.current) clearTimeout(timerIDRef.current);
      if (audioCtxRef.current && audioCtxRef.current.state !== 'closed') {
         audioCtxRef.current.close();
      }
    };
  }, []);

  const nextNote = () => {
    const secondsPerBeat = 60.0 / bpm;
    nextNoteTimeRef.current += secondsPerBeat;
    currentBeatRef.current = (currentBeatRef.current + 1) % 4;
  };

  const playClick = (time, beatNumber) => {
    const isFirstBeat = beatNumber === 0;

    const osc = audioCtxRef.current.createOscillator();
    const gain = audioCtxRef.current.createGain();

    osc.connect(gain);
    gain.connect(audioCtxRef.current.destination);

    if (isFirstBeat) {
      osc.frequency.value = 1200;
    } else {
      osc.frequency.value = 800;
    }

    gain.gain.setValueAtTime(0.5, time);
    gain.gain.exponentialRampToValueAtTime(0.001, time + 0.1);

    osc.start(time);
    osc.stop(time + 0.1);

    setTimeout(() => {
      setBeat(beatNumber);
    }, (time - audioCtxRef.current.currentTime) * 1000);
  };

  const scheduler = () => {
    while (nextNoteTimeRef.current < audioCtxRef.current.currentTime + scheduleAheadTime) {
      playClick(nextNoteTimeRef.current, currentBeatRef.current);
      nextNote();
    }
    timerIDRef.current = setTimeout(scheduler, lookahead);
  };

  useEffect(() => {
    setOnReset(() => () => {
      setIsPlaying(false);
      setBpm(120);
    });
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    if (isPlaying) {
      if (audioCtxRef.current.state === 'suspended') {
        audioCtxRef.current.resume();
      }
      // Note: beat reset is now handled in the toggle function
      nextNoteTimeRef.current = audioCtxRef.current.currentTime + 0.05;
      scheduler();
    } else {
      if (timerIDRef.current) clearTimeout(timerIDRef.current);
    }
    return () => { if (timerIDRef.current) clearTimeout(timerIDRef.current); };
  }, [isPlaying, bpm]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <button
          onClick={() => { 
            const next = !isPlaying;
            if (next) {
              currentBeatRef.current = 0;
              setBeat(0);
            }
            setIsPlaying(next); 
            audioEngine.playTick(settings.soundTheme); 
          }}
          className={`flex items-center gap-3 px-10 py-2 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all active:scale-95 shadow-xl border-2 italic ${
            isPlaying 
              ? 'bg-rose-500 border-rose-400 text-white shadow-rose-900/20' 
              : 'bg-slate-900 border-slate-800 text-white shadow-slate-900/20 hover:bg-indigo-600 hover:border-indigo-500'
          }`}
        >
          {isPlaying ? <Pause size={14} fill="currentColor" strokeWidth={0} /> : <Play size={14} fill="currentColor" strokeWidth={0} className="ml-0.5" />}
          {isPlaying ? 'Halt Pulse' : 'Initiate Pulse'}
        </button>
      </div>
    );
  }, [isPlaying, settings.soundTheme]);

  return (
    <div className="tool-container w-full mx-auto space-y-8 h-full flex flex-col font-['Outfit'] select-none">

      <div className="flex flex-col lg:flex-row gap-8 flex-1 min-h-[600px] overflow-hidden">

        {/* Parameter Panel */}
        <div className="w-full lg:w-96 flex flex-col gap-6 shrink-0 h-full overflow-hidden">
          <div className="tool-sidebar-card flex-1 p-10">
            <div className="flex items-center gap-3 mb-10">
               <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400">
                  <Activity size={18} />
               </div>
               <h4 className="tool-sub-label mb-0">Rhythmic Spec</h4>
            </div>

            <div className="flex-1 space-y-10 overflow-y-auto pr-2 custom-scrollbar no-scrollbar">
               <div className="space-y-6">
                 <div className="flex justify-between items-center px-1">
                   <span className="tool-sub-label-indigo border-b-0 pb-0">Velocity Control</span>
                   <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest bg-indigo-50 px-3 py-1 rounded-xl italic">BPM</span>
                 </div>

                 <div className="bg-slate-50 p-10 rounded-[3rem] border-4 border-white shadow-inner flex flex-col items-center gap-8 group transition-all hover:bg-white hover:shadow-2xl">
                   <div className="text-8xl font-black text-slate-800 italic tabular-nums tracking-tighter leading-none drop-shadow-2xl">
                      {bpm}
                   </div>

                   <div className="flex items-center gap-6 w-full">
                     <button onClick={() => { setBpm(b => Math.max(30, b - 1)); audioEngine.playTick(settings.soundTheme); }} className="w-14 h-14 bg-white rounded-2xl shadow-md text-slate-300 hover:text-rose-500 transition-all active:scale-90 border-2 border-slate-50 flex items-center justify-center">
                       <Minus size={24} />
                     </button>
                     <input
                       type="range"
                       min="30" max="300"
                       value={bpm}
                       onChange={(e) => setBpm(Number(e.target.value))}
                       className="flex-1 accent-indigo-600 h-2 bg-slate-200 rounded-full appearance-none cursor-pointer"
                     />
                     <button onClick={() => { setBpm(b => Math.min(300, b + 1)); audioEngine.playTick(settings.soundTheme); }} className="w-14 h-14 bg-white rounded-2xl shadow-md text-slate-300 hover:text-emerald-500 transition-all active:scale-90 border-2 border-slate-50 flex items-center justify-center">
                       <Plus size={24} />
                     </button>
                   </div>
                 </div>
               </div>

               <div className="grid grid-cols-2 gap-4">
                  {[60, 120, 144, 200].map(v => (
                    <button 
                     key={v}
                     onClick={() => { setBpm(v); audioEngine.playTick(settings.soundTheme); }}
                     className={`p-6 rounded-[2rem] border-4 font-black text-xs transition-all active:scale-95 italic ${bpm === v ? 'bg-slate-900 border-slate-900 text-white shadow-2xl' : 'bg-white border-slate-50 text-slate-400 hover:border-indigo-600 hover:text-indigo-600'}`}
                    >
                      {v} <span className="opacity-30 ml-1">BPM</span>
                    </button>
                  ))}
               </div>
            </div>

            <div className="mt-10 pt-10 border-t border-slate-50">
               <div className="p-8 bg-slate-900 rounded-[3rem] shadow-2xl border border-slate-800 flex flex-col gap-6 overflow-hidden relative group">
                  <div className="tool-grid-bg-dark opacity-10" />
                  <div className="absolute inset-0 bg-indigo-500/5 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                  <div className="flex items-center gap-3 relative z-10">
                    <Clock size={18} className="text-indigo-400" />
                    <span className="tool-sub-label-indigo mb-0 border-b-0 pb-0">Temporal Protocol</span>
                  </div>
                  <p className="text-[11px] font-black text-white/40 leading-relaxed uppercase tracking-tighter italic relative z-10">
                    Adjust frequency for synchronized classroom performance. Precision audio synthesis active.
                  </p>
               </div>
            </div>
          </div>
        </div>

        {/* Visual Pulse Stage */}
        <div className="flex-1 tool-stage bg-white p-12 relative overflow-hidden flex flex-col items-center justify-center h-auto">
          <div className="tool-grid-bg opacity-30" />

          <div className="absolute top-10 left-10 flex items-center gap-4 opacity-20">
             <div className={`w-3 h-3 rounded-full shadow-[0_0_15px_rgba(99,102,241,1)] ${isPlaying ? 'bg-indigo-500 animate-pulse' : 'bg-slate-300'}`} />
             <span className="text-[10px] font-black text-slate-800 uppercase tracking-[0.6em] italic">Waveform active</span>
          </div>

          <div className="relative flex flex-col items-center gap-20 w-full max-w-4xl">
            {/* Main Visualizer */}
            <div className="relative w-[30rem] h-[30rem] flex items-center justify-center">
               {/* Rotating Rings */}
               <motion.div 
                 animate={{ rotate: isPlaying ? 360 : 0 }}
                 transition={{ duration: 60 / bpm, repeat: Infinity, ease: "linear" }}
                 className="absolute inset-0 border-8 border-dashed border-slate-100 rounded-full opacity-40"
               />
               <motion.div 
                 animate={{ rotate: isPlaying ? -360 : 0 }}
                 transition={{ duration: (60 / bpm) * 2, repeat: Infinity, ease: "linear" }}
                 className="absolute inset-12 border-4 border-slate-50 rounded-full opacity-20"
               />

               {/* The Pulse Central */}
               <AnimatePresence mode="popLayout">
                  <motion.div
                    key={beat}
                    initial={{ scale: 1, opacity: 1 }}
                    animate={isPlaying ? { 
                      scale: [1, 1.4, 1],
                      opacity: [1, 0.8, 1],
                      borderColor: beat === 0 ? ['#f43f5e', '#ef4444', '#f43f5e'] : ['#6366f1', '#4f46e5', '#6366f1']
