            </div>
          </div>
        )}
        {gameState !== 'menu' && (
          <button 
            onClick={() => setGameState('menu')}
            className="p-2 hover:bg-gray-100 rounded-xl transition-colors text-gray-400"
            title="Return to Menu"
          >
            <ArrowLeft size={20} />
          </button>
        )}
      </div>
    );
  }, [gameState, currentIndex, history, setHeaderActions]);

  return (
