import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { RefreshCcw, CheckCircle2, AlertCircle, Banknote, Info, RotateCcw } from 'lucide-react';
import confetti from 'canvas-confetti';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';
import { CURRENCIES } from './MoneyTool/moneyData';
import { formatCurrency } from '../../utils/format';

export const MoneyTool = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const [selectedCurrency, setSelectedCurrency] = useState('AUD');
  const [targetAmount, setTargetAmount] = useState(0);
  const [tableMoney, setTableMoney] = useState([]);
  const [isSuccess, setIsSuccess] = useState(false);

  const { settings } = useSettings();

  const currentCurrencyData = CURRENCIES[selectedCurrency];

  const generateTarget = () => {
    const steps = Math.floor(100 / 0.05);
    const randomStep = Math.floor(Math.random() * steps) + 1;
    const amount = Number((randomStep * 0.05).toFixed(2));
    setTargetAmount(amount);
    setTableMoney([]);
    setIsSuccess(false);
  };

  // Removed useEffect that was calling generateTarget()

  const currentTotal = Number((tableMoney.reduce((sum, item) => sum + item.value, 0)).toFixed(2));
  const difference = Number((currentTotal - targetAmount).toFixed(2));

  // Removed useEffect that was checking for success. 
  // Success is now handled in addMoney and removeMoney.

  const addMoney = (item) => {
    if (isSuccess) setIsSuccess(false);
    audioEngine.playTick(settings.soundTheme);
    const newTableMoney = [...tableMoney, { ...item, uniqueId: Math.random().toString() }];
    setTableMoney(newTableMoney);

    // Check for success immediately
    const newTotal = Number((newTableMoney.reduce((sum, i) => sum + i.value, 0)).toFixed(2));
    if (targetAmount > 0 && Number((newTotal - targetAmount).toFixed(2)) === 0) {
      setIsSuccess(true);
      audioEngine.playAlarm(settings.soundTheme);
      confetti({ particleCount: 100, spread: 70, origin: { y: 0.6 } });
    }
  };

  const removeMoney = (uniqueId) => {
    if (isSuccess) setIsSuccess(false);
    audioEngine.playTick(settings.soundTheme);
    const newTableMoney = tableMoney.filter(i => i.uniqueId !== uniqueId);
    setTableMoney(newTableMoney);

    // Check for success immediately
    const newTotal = Number((newTableMoney.reduce((sum, i) => sum + i.value, 0)).toFixed(2));
    if (targetAmount > 0 && Number((newTotal - targetAmount).toFixed(2)) === 0) {
      setIsSuccess(true);
      audioEngine.playAlarm(settings.soundTheme);
      confetti({ particleCount: 100, spread: 70, origin: { y: 0.6 } });
    }
  };

  useEffect(() => {
    setOnReset(() => () => {
      setTableMoney([]);
      setIsSuccess(false);
      generateTarget();
    });
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <select 
          value={selectedCurrency}
          onChange={(e) => {
            const next = e.target.value;
            setSelectedCurrency(next);
            // Update target amount immediately when currency changes
            const steps = Math.floor(100 / 0.05);
            const randomStep = Math.floor(Math.random() * steps) + 1;
            const amount = Number((randomStep * 0.05).toFixed(2));
            setTargetAmount(amount);
            setTableMoney([]);
            setIsSuccess(false);
          }}
          className="px-4 py-2 border-2 border-gray-100 rounded-xl font-bold text-gray-500 bg-white hover:border-indigo-100 focus:outline-none transition-all cursor-pointer text-[10px] uppercase tracking-widest"
        >
          <option value="AUD">🇦🇺 Australian ($)</option>
          <option value="CAD">🇨🇦 Canadian ($)</option>
          <option value="GBP">🇬🇧 UK (£)</option>
        </select>
        <div className="w-px h-6 bg-slate-200" />
        <button
          onClick={generateTarget}
          className="flex items-center gap-2 px-4 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-widest hover:border-indigo-100 hover:text-indigo-600 transition-all active:scale-95 shadow-sm"
        >
          <RefreshCcw size={14} /> New Amount
        </button>
      </div>
    );
  }, [selectedCurrency]);

  return (
    <div className="tool-container flex flex-col p-4 pt-2 pb-8 space-y-8 h-full">

      <div className="flex flex-col lg:flex-row gap-8 flex-1">

        {/* Left Side: Goal & Feedback */}
        <div className="w-full lg:w-1/3 flex flex-col gap-6">
          <div className="tool-card p-8 text-center space-y-4">
            <h3 className="text-gray-400 font-bold uppercase tracking-widest text-[10px]">Target Amount</h3>
            <div className="text-6xl font-black text-slate-800 tabular-nums tracking-tight italic">
              {formatCurrency(targetAmount, currentCurrencyData.symbol)}
            </div>
          </div>

          <div className="tool-card p-8 text-center space-y-4 flex-1 flex flex-col justify-center min-h-[200px]">
            <h3 className="text-gray-400 font-bold uppercase tracking-widest text-[10px]">On The Table</h3>
            <div className="text-5xl font-black text-indigo-600 tabular-nums tracking-tight italic">
              {formatCurrency(currentTotal, currentCurrencyData.symbol)}
            </div>

            <div className="h-16 flex items-center justify-center mt-4">
              {isSuccess ? (
                <div className="flex items-center gap-2 text-emerald-600 font-black text-xl animate-in zoom-in italic">
                  <CheckCircle2 size={28} /> EXACT MATCH!
                </div>
              ) : difference === 0 ? null : (
                <div className={`flex items-center gap-2 font-black text-[10px] uppercase tracking-widest px-4 py-3 rounded-2xl animate-in fade-in shadow-sm ${
                  difference > 0 ? 'bg-rose-50 text-rose-600 border border-rose-100' : 'bg-indigo-50 text-indigo-600 border border-indigo-100'
                }`}>
                  <AlertCircle size={16} />
                  {difference > 0 
                    ? `Overflow: ${formatCurrency(difference, currentCurrencyData.symbol)}`
                    : `Shortfall: ${formatCurrency(Math.abs(difference), currentCurrencyData.symbol)}`
                  }
                </div>
              )}
            </div>

            {isSuccess && (
              <button
                onClick={generateTarget}
                className="mt-4 w-full py-4 bg-slate-900 text-white font-black rounded-2xl hover:bg-indigo-600 transition-all shadow-xl shadow-slate-200 animate-in slide-in-from-bottom-2 uppercase tracking-widest text-xs"
              >
                Play Again
              </button>
            )}
          </div>
        </div>

        {/* Right Side: Table and Bank */}
        <div className="w-full lg:w-2/3 flex flex-col gap-6">

          {/* The Table */}
          <div className="bg-slate-50 p-12 rounded-[3.5rem] shadow-inner border-4 border-white min-h-[300px] relative overflow-hidden flex flex-col group">
            <div className="absolute top-8 left-8 flex items-center gap-2 opacity-20 group-hover:opacity-40 transition-opacity">
               <div className="w-2 h-2 rounded-full bg-slate-400" />
               <h3 className="text-slate-800 font-black uppercase tracking-widest text-xs italic">Surface Map</h3>
            </div>

            <div className="flex-1 mt-10">
              {tableMoney.length === 0 ? (
                <div className="w-full h-full flex flex-col items-center justify-center text-slate-300 gap-4">
                  <Banknote size={48} strokeWidth={1} />
                  <p className="font-bold text-lg uppercase tracking-widest">Deploy currency to surface</p>
                </div>
              ) : (
                <div className="flex flex-wrap gap-4 items-center justify-start content-start h-full">
                  <AnimatePresence>
                    {tableMoney.map((item) => {
                      const isNote = item.type === 'note';
                      const polyClipPath = item.isPoly ? (item.polyPoints || 'polygon(50% 0%, 75% 6.7%, 93.3% 25%, 100% 50%, 93.3% 75%, 75% 93.3%, 50% 100%, 25% 93.3%, 6.7% 75%, 0% 50%, 6.7% 25%, 25% 6.7%)') : 'none';
                      return (
                        <motion.button
                          key={item.uniqueId}
                          layout
                          initial={{ opacity: 0, scale: 0.5, y: -20 }}
                          animate={{ opacity: 1, scale: 1, y: 0 }}
                          exit={{ opacity: 0, scale: 0.5, y: 20 }}
                          whileHover={{ scale: 1.1, rotate: 2 }}
                          whileTap={{ scale: 0.9 }}
                          onClick={() => removeMoney(item.uniqueId)}
                          className={`relative flex items-center justify-center font-black shadow-lg border-2 overflow-hidden ${item.color} ${item.sizeClass} ${
                            isNote ? 'rounded-md' : 'rounded-full'
                          } hover:ring-4 hover:ring-rose-400 transition-all cursor-pointer`}
                          style={{ clipPath: polyClipPath }}
                        >
                          {isNote && (
                            <div className="absolute inset-0 opacity-20 pointer-events-none">
                              <div className="w-4 h-4 rounded-full border-2 border-black absolute top-1 left-1"></div>
                              <div className="w-4 h-4 rounded-full border-2 border-black absolute bottom-1 right-1"></div>
                            </div>
                          )}
                          {item.isBimetallic && (
                            <div className={`absolute inset-0 m-auto w-[65%] h-[65%] rounded-full ${item.innerColor} pointer-events-none`}></div>
                          )}
                          <span className="relative z-10">{item.label}</span>
                        </motion.button>
                      );
                    })}
                  </AnimatePresence>
                </div>
              )}
            </div>
          </div>

          {/* The Bank */}
          <div className="tool-card p-10 space-y-10">
            <div className="flex items-center gap-4 justify-center">
               <div className="h-px flex-1 bg-slate-50" />
               <h3 className="text-gray-300 font-black uppercase tracking-[0.4em] text-[10px]">Vault Access</h3>
               <div className="h-px flex-1 bg-slate-50" />
            </div>

            <div className="space-y-8">
              {/* Notes Row */}
              <div className="flex flex-wrap justify-center gap-4">
                {currentCurrencyData.items.filter(i => i.type === 'note').map((item) => (
                  <motion.button
                    key={item.id}
                    layout
                    whileHover={{ scale: 1.05, y: -5 }}
                    whileTap={{ scale: 0.95 }}
                    onClick={() => addMoney(item)}
                    className={`relative flex items-center justify-center font-black shadow-xl border-2 overflow-hidden ${item.color} ${item.sizeClass} rounded-md cursor-pointer transition-shadow hover:shadow-indigo-500/20`}
                  >
                    <div className="absolute inset-0 opacity-20 pointer-events-none">
                      <div className="w-4 h-4 rounded-full border-2 border-black absolute top-1 left-1"></div>
                      <div className="w-4 h-4 rounded-full border-2 border-black absolute bottom-1 right-1"></div>
                    </div>
                    <span className="relative z-10">{item.label}</span>
                  </motion.button>
                ))}
              </div>

              {/* Coins Row */}
              <div className="flex flex-wrap justify-center gap-4">
                {currentCurrencyData.items.filter(i => i.type === 'coin').map((item) => {
                  const polyClipPath = item.isPoly ? (item.polyPoints || 'polygon(50% 0%, 75% 6.7%, 93.3% 25%, 100% 50%, 93.3% 75%, 75% 93.3%, 50% 100%, 25% 93.3%, 6.7% 75%, 0% 50%, 6.7% 25%, 25% 6.7%)') : 'none';
                  return (
                    <motion.button
                      key={item.id}
                      layout
                      whileHover={{ scale: 1.1, y: -5 }}
                      whileTap={{ scale: 0.9 }}
                      onClick={() => addMoney(item)}
                      className={`relative flex items-center justify-center font-black shadow-xl border-2 overflow-hidden ${item.color} ${item.sizeClass} rounded-full cursor-pointer transition-shadow hover:shadow-indigo-500/20`}
                      style={{ clipPath: polyClipPath }}
                    >
                      {item.isBimetallic && (
                        <div className={`absolute inset-0 m-auto w-[65%] h-[65%] rounded-full ${item.innerColor} pointer-events-none`}></div>
                      )}
                      <span className="relative z-10">{item.label}</span>
                    </motion.button>
                  );
                })}
              </div>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
