        <div className="w-px h-6 bg-slate-200" />

        <select 
          value={selectedClassId} 
          onChange={(e) => setSelectedClassId(e.target.value)} 
          className="px-6 py-2 bg-white border-2 border-slate-100 text-slate-600 rounded-xl font-black text-[10px] uppercase tracking-widest outline-none transition-all cursor-pointer hover:border-indigo-100 italic"
        >
