        >
          {isSpinning ? <RotateCcw size={14} className="animate-spin" /> : <Play size={14} fill="currentColor" />}
          {isSpinning ? 'Selecting...' : 'Pick Name'}
        </button>
      </div>
    );
  }, [mode, selectedClassId, isSpinning, validNames.length, settings.soundTheme]);

  const wheelFontSize = Math.max(10, Math.min(24, 280 / Math.max(1, validNames.length)));

  return (
