                    <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic">Selection Pool v5.2</span>
                 </div>
              </div>
              <div className="flex items-center gap-2">
                 <button onClick={() => { setLocalNames(shuffle(validNames)); audioEngine.playTick(settings.soundTheme); }} className="w-10 h-10 flex items-center justify-center text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all" title="Shuffle"><Shuffle size={18} /></button>
                 <button onClick={() => { setLocalNames([...validNames].sort((a, b) => a.localeCompare(b))); audioEngine.playTick(settings.soundTheme); }} className="w-10 h-10 flex items-center justify-center text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all" title="Sort"><SortAsc size={18} /></button>
              </div>
           </div>

           <div className="flex-1 min-h-0 mb-10 relative group">
              <textarea 
                value={localNames.join('\n')} 
                onChange={(e) => setLocalNames(e.target.value.split('\n'))} 
                className="w-full h-full p-8 bg-slate-50 border-4 border-white focus:border-indigo-100 focus:bg-white rounded-[3rem] text-[15px] font-bold text-slate-700 transition-all outline-none resize-none custom-scrollbar shadow-inner italic" 
                placeholder="One name per line..." 
              />
              <div className="absolute top-8 right-8 pointer-events-none opacity-10">
                 <Terminal size={32} className="text-slate-900" />
