import React, { useEffect, useRef, useState } from 'react';
import Matter from 'matter-js';
import { Zap, RotateCcw, Settings2, Info, Activity, Scaling, X, Play, Pause, Monitor, Database, Target, MousePointer2 } from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';
import { motion, AnimatePresence } from 'framer-motion';

const CANVAS_WIDTH = 800;
const CANVAS_HEIGHT = 500;
const BALL_RADIUS = 30;
const STRING_LENGTH = 250;
const NUM_BALLS = 5;

const NewtonsCradle = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const containerRef = useRef(null);
  const engineRef = useRef(null);
  const requestRef = useRef(null);
  const [balls, setBalls] = useState([]);
  const [selectedBallIndex, setSelectedBallIndex] = useState(null);
  const [masses, setMasses] = useState(new Array(NUM_BALLS).fill(1));
  const [showConfig, setShowConfig] = useState(true);

  useEffect(() => {
    const engine = Matter.Engine.create();
    engine.gravity.y = 1.5;
    engineRef.current = engine;

    const world = engine.world;
    const newBalls = [];
    const constraints = [];

    const startX = CANVAS_WIDTH / 2 - (NUM_BALLS - 1) * BALL_RADIUS;

    for (let i = 0; i < NUM_BALLS; i++) {
      const x = startX + i * BALL_RADIUS * 2;
      const y = 350;

      const ball = Matter.Bodies.circle(x, y, BALL_RADIUS, {
        restitution: 1.0,
        friction: 0,
        frictionAir: 0.001,
        slop: 0,
        label: `ball-${i}`,
        mass: masses[i],
        render: {
          fillStyle: '#e2e8f0'
        }
      });

      const anchor = { x: x, y: 100 };
      const constraint = Matter.Constraint.create({
        pointA: anchor,
        bodyB: ball,
        stiffness: 1,
        length: STRING_LENGTH,
        render: {
          strokeStyle: '#64748b',
          lineWidth: 1
        }
      });

      newBalls.push(ball);
      constraints.push(constraint);
    }

    const mouse = Matter.Mouse.create(containerRef.current);
    const mouseConstraint = Matter.MouseConstraint.create(engine, {
      mouse: mouse,
      constraint: {
        stiffness: 0.2,
        render: {
          visible: false
        }
      }
    });

    Matter.World.add(world, [...newBalls, ...constraints, mouseConstraint]);

    const update = () => {
      Matter.Engine.update(engine, 1000 / 60);

      const currentBalls = newBalls.map((b, i) => ({
        id: b.id,
        index: i,
        x: b.position.x,
        y: b.position.y,
        angle: b.angle,
        anchorX: startX + i * BALL_RADIUS * 2,
        anchorY: 100
      }));

      setBalls(currentBalls);
      requestRef.current = requestAnimationFrame(update);
    };

    requestRef.current = requestAnimationFrame(update);

    return () => {
      cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
  }, []);

  useEffect(() => {
    if (engineRef.current) {
      const bodies = Matter.Composite.allBodies(engineRef.current.world);
      masses.forEach((m, i) => {
        const body = bodies.find(b => b.label === `ball-${i}`);
        if (body) {
          Matter.Body.setMass(body, m);
        }
      });
    }
  }, [masses]);

  const handleReset = () => {
    if (engineRef.current) {
      const bodies = Matter.Composite.allBodies(engineRef.current.world);
      const startX = CANVAS_WIDTH / 2 - (NUM_BALLS - 1) * BALL_RADIUS;

      bodies.forEach((body) => {
        if (body.label && body.label.startsWith('ball-')) {
          const i = parseInt(body.label.split('-')[1]);
          const x = startX + i * BALL_RADIUS * 2;
          const y = 100 + STRING_LENGTH;
          Matter.Body.setPosition(body, { x, y });
          Matter.Body.setVelocity(body, { x: 0, y: 0 });
          Matter.Body.setAngle(body, 0);
          Matter.Body.setAngularVelocity(body, 0);
        }
      });
      audioEngine.playTick(settings.soundTheme);
    }
  };

  const updateMass = (index, value) => {
    const newMasses = [...masses];
    newMasses[index] = parseFloat(value);
    setMasses(newMasses);
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    setOnReset(() => handleReset);
    return () => clearHeader();
  }, [clearHeader, setOnReset, settings.soundTheme]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <button
          onClick={() => { setShowConfig(!showConfig); audioEngine.playTick(settings.soundTheme); }}
          className={`flex items-center gap-2 px-8 py-2 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all active:scale-95 shadow-lg italic ${
            showConfig 
              ? 'bg-slate-900 text-white shadow-slate-200' 
              : 'bg-white text-slate-400 border-2 border-slate-100 hover:border-indigo-100 hover:text-indigo-600'
          }`}
        >
          {showConfig ? <X size={14} /> : <Settings2 size={14} />} Config Mass
        </button>
      </div>
    );
  }, [showConfig, settings.soundTheme, setHeaderActions]);

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      {/* Simulation Stage */}
      <div className="flex-1 tool-stage p-0 relative overflow-hidden bg-white border-none rounded-[4rem] group/stage flex items-center justify-center">
        <div className="tool-grid-bg opacity-30" />

        {/* Decorative HUD Elements */}
        <div className="absolute top-12 left-12 flex flex-col gap-6 z-20">
           <div className="flex items-center gap-4 px-8 py-4 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border-4 border-white/60 shadow-xl group/hud hover:border-indigo-100 transition-all">
              <div className="w-3 h-3 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_20px_rgba(79,70,229,1)]" />
              <div className="flex flex-col">
                 <span className="text-[11px] font-black text-slate-800 uppercase tracking-[0.6em] italic leading-none mb-1">Momentum Simulator</span>
                 <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.4em] italic leading-none">Status: Continuous Cycle</span>
              </div>
           </div>
        </div>

        <div 
          ref={containerRef}
          className="w-full h-full flex flex-col items-center pt-24 relative z-10"
        >
          {/* Frame Support */}
          <div className="w-[450px] h-12 bg-slate-950 rounded-[2.5rem] border-8 border-slate-900 shadow-[0_48px_96px_-24px_rgba(0,0,0,0.5)] z-20 flex items-center justify-center relative overflow-hidden">
             <div className="w-[400px] h-1.5 bg-white/10 rounded-full" />
             <div className="absolute inset-0 bg-gradient-to-tr from-white/5 to-transparent pointer-events-none" />
             <div className="absolute -left-12 -top-12 w-24 h-24 bg-white/5 rounded-full blur-2xl" />
          </div>

          <svg width={CANVAS_WIDTH} height={CANVAS_HEIGHT} className="relative z-10 overflow-visible cursor-crosshair">
            <defs>
              <radialGradient id="ballGradient" cx="30%" cy="30%" r="70%">
                <stop offset="0%" stopColor="#f8fafc" />
                <stop offset="50%" stopColor="#94a3b8" />
                <stop offset="100%" stopColor="#475569" />
              </radialGradient>
              <radialGradient id="heavyBallGradient" cx="30%" cy="30%" r="70%">
                <stop offset="0%" stopColor="#fff7ed" />
                <stop offset="50%" stopColor="#fb923c" />
                <stop offset="100%" stopColor="#ea580c" />
              </radialGradient>
              <filter id="ball-glow" x="-20%" y="-20%" width="140%" height="140%">
                 <feGaussianBlur stdDeviation="6" result="blur" />
                 <feComposite in="SourceGraphic" in2="blur" operator="over" />
              </filter>
            </defs>

            {/* Strings */}
            {balls.map((ball) => (
              <line
                key={`string-${ball.index}`}
                x1={ball.anchorX}
                y1={ball.anchorY}
                x2={ball.x}
                y2={ball.y}
                stroke="#cbd5e1"
                strokeWidth="3"
                strokeLinecap="round"
                opacity={0.6}
              />
            ))}

            {/* Balls */}
            {balls.map((ball) => {
              const mass = masses[ball.index];
              const isHeavy = mass > 1.5;
              const isLight = mass < 0.5;

              return (
                <g 
                  key={`ball-group-${ball.index}`} 
                  transform={`translate(${ball.x}, ${ball.y})`}
                  className="group/ball"
                  onClick={(e) => {
                    e.stopPropagation();
                    setSelectedBallIndex(ball.index);
                    setShowConfig(true);
                    audioEngine.playTick(settings.soundTheme);
                  }}
                >
                  <circle
                    r={BALL_RADIUS}
                    fill={isHeavy ? "url(#heavyBallGradient)" : "url(#ballGradient)"}
                    className="transition-all duration-300 drop-shadow-2xl"
                    stroke={selectedBallIndex === ball.index ? "#6366f1" : "rgba(255,255,255,0.2)"}
                    strokeWidth={selectedBallIndex === ball.index ? "6" : "2"}
                    style={{ filter: selectedBallIndex === ball.index ? 'url(#ball-glow)' : 'none' }}
                  />
                  {/* Chrome reflection */}
                  <ellipse
                    cx={-BALL_RADIUS * 0.3}
                    cy={-BALL_RADIUS * 0.3}
                    rx={BALL_RADIUS * 0.45}
                    ry={BALL_RADIUS * 0.3}
                    fill="white"
                    fillOpacity="0.4"
                    transform={`rotate(-45)`}
                  />
                  {(isHeavy || isLight) && (
                    <text
                      y="5"
                      textAnchor="middle"
                      fill="white"
                      fontSize="11"
                      fontWeight="900"
                      className="pointer-events-none uppercase tracking-tighter italic"
                      style={{ filter: 'drop-shadow(0 2px 4px rgba(0,0,0,0.4))' }}
                    >
                      {mass.toFixed(1)}k
                    </text>
                  )}
                </g>
              );
            })}
          </svg>
        </div>

        {/* Interaction Guide */}
        <div className="absolute bottom-12 right-12 flex items-center gap-6 z-20 pointer-events-none opacity-40 italic">
           <div className="text-right">
              <p className="text-[11px] font-black uppercase tracking-[0.6em]">Manual Extraction</p>
              <p className="text-[11px] font-black uppercase tracking-[0.4em] mt-1">Drag spheres to initialize cycle</p>
           </div>
           <div className="w-12 h-12 rounded-2xl bg-white/50 border-2 border-white flex items-center justify-center shadow-inner">
              <MousePointer2 size={24} className="text-slate-400" />
           </div>
        </div>
      </div>

      {/* Physics Sidebar */}
      <AnimatePresence>
        {showConfig && (
          <motion.div
            initial={{ opacity: 0, width: 0 }}
            animate={{ opacity: 1, width: 420 }}
            exit={{ opacity: 0, width: 0 }}
            className="flex flex-col gap-6 overflow-hidden shrink-0"
          >
            <div className="tool-sidebar-card flex-1 p-10 flex flex-col">
              <div className="flex items-center justify-between mb-10 shrink-0">
                 <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 border-4 border-white shadow-inner">
                       <Database size={24} />
                    </div>
                    <div className="flex flex-col">
                       <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Mass Matrix</h4>
                       <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic">Node Energy Values</span>
                    </div>
                 </div>
                 <button onClick={() => { setShowConfig(false); audioEngine.playTick(settings.soundTheme); }} className="w-10 h-10 flex items-center justify-center text-slate-300 hover:text-slate-600 hover:bg-slate-50 rounded-2xl transition-all">
                    <X size={20} />
                 </button>
              </div>

              <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar no-scrollbar space-y-4">
                <AnimatePresence initial={false}>
                  {masses.map((mass, i) => (
                    <motion.div 
                      key={i} 
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      className={`p-6 rounded-[2.5rem] border-4 transition-all duration-300 italic ${selectedBallIndex === i ? 'bg-indigo-50/40 border-indigo-100 shadow-xl' : 'bg-slate-50 border-white hover:border-slate-100'}`}
                      onMouseEnter={() => setSelectedBallIndex(i)}
                    >
                      <div className="flex justify-between items-center mb-5">
                        <div className="flex items-center gap-3">
                           <div className={`w-3 h-3 rounded-full ${mass > 1.5 ? 'bg-orange-500 animate-pulse' : 'bg-indigo-500'}`} />
                           <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Sphere Node #{i + 1}</span>
                        </div>
                        <div className="flex items-center gap-1">
                          <span className="text-2xl font-black text-slate-800 tabular-nums tracking-tighter leading-none">{mass.toFixed(1)}</span>
                          <span className="text-[11px] font-black text-slate-300 uppercase mt-1">kg</span>
                        </div>
                      </div>
                      <input
                        type="range" min="0.1" max="5" step="0.1" value={mass}
                        onChange={(e) => updateMass(i, e.target.value)}
