import React, { useState, useMemo, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  RotateCcw, 
  Eye, 
  EyeOff, 
  Settings2,
  MoveRight,
  Hash,
  Activity,
  Box,
  Sliders,
  Sparkles,
  MapPin,
  MoveHorizontal,
  Target,
  Zap,
  Info
} from 'lucide-react';
