export const NumberLine = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [range, setRange] = useState({ start: 0, end: 20 });
  const [step, setStep] = useState(1);
  const [showLabels, setShowLabels] = useState(true);
  const [pins, setPins] = useState([]); // { value: number, color: string }
  const [jumps, setJumps] = useState([]); // { start: number, end: number, color: string }
  const [dragStart, setDragStart] = useState(null); // { value: number, x: number }
  const [hoverValue, setHoverValue] = useState(null);
  const svgRef = useRef(null);

  const colors = [
    '#6366f1', // indigo
    '#10b981', // green
    '#f59e0b', // amber
    '#ef4444', // red
    '#a855f7', // violet
  ];

  const resetAll = () => {
    setPins([]);
    setJumps([]);
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    setOnReset(() => resetAll);
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <button
        onClick={resetAll}
        className="flex items-center gap-2 px-6 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:border-rose-100 hover:text-rose-600 transition-all active:scale-95 shadow-sm italic"
      >
        <RotateCcw size={14} /> Clear Axis
      </button>
    );
  }, [pins, jumps, settings.soundTheme]);

  const markers = useMemo(() => {
    const m = [];
    const start = parseFloat(range.start) || 0;
    const end = parseFloat(range.end) || 0;
    const count = (end - start) / step;
    if (count > 200 || isNaN(count)) return []; // Safety limit
    for (let i = start; i <= end; i += step) {
      m.push(parseFloat(i.toFixed(2)));
    }
    return m;
  }, [range.start, range.end, step]);

  const togglePin = (val) => {
    setPins(prev => {
      const existing = prev.find(p => Math.abs(p.value - val) < step / 2);
      if (existing) {
        audioEngine.playTick(settings.soundTheme);
        return prev.filter(p => p !== existing);
      }
      audioEngine.playTick(settings.soundTheme);
      return [...prev, { value: val, color: colors[prev.length % colors.length] }];
    });
  };

  const addJump = (s, e) => {
    if (s === e) return;
    setJumps([...jumps, { start: s, end: e, color: colors[jumps.length % colors.length] }]);
    audioEngine.playTick(settings.soundTheme);
  };

  const getValueFromX = (svgX) => {
    const start = parseFloat(range.start) || 0;
    const end = parseFloat(range.end) || 0;
    const totalWidth = width - 2 * padding;
    const progress = (svgX - padding) / totalWidth;
    const rawVal = start + progress * (end - start);
    const snapped = Math.round((rawVal - start) / step) * step + start;
    return parseFloat(snapped.toFixed(2));
  };

  const getSvgPoint = (e) => {
    const svg = svgRef.current;
    if (!svg) return { x: 0, y: 0 };
    const pt = svg.createSVGPoint();
    pt.x = e.clientX;
    pt.y = e.clientY;
    return pt.matrixTransform(svg.getScreenCTM().inverse());
  };

  const handleMouseDown = (e) => {
    const pt = getSvgPoint(e);
    const val = getValueFromX(pt.x);
    const start = parseFloat(range.start) || 0;
    const end = parseFloat(range.end) || 0;
    if (val >= start && val <= end) {
      setDragStart({ value: val, x: pt.x });
    }
  };

  const handleMouseMove = (e) => {
    const pt = getSvgPoint(e);
    const val = getValueFromX(pt.x);
    const start = parseFloat(range.start) || 0;
    const end = parseFloat(range.end) || 0;
    if (val >= start && val <= end) {
      setHoverValue(val);
    } else {
      setHoverValue(null);
    }
  };

  const handleMouseUp = (e) => {
    if (!dragStart) return;
    const pt = getSvgPoint(e);
    const endVal = getValueFromX(pt.x);
    const start = parseFloat(range.start) || 0;
    const end = parseFloat(range.end) || 0;

    if (Math.abs(pt.x - dragStart.x) < 5) {
      togglePin(dragStart.value);
    } else if (endVal >= start && endVal <= end) {
      addJump(dragStart.value, endVal);
    }

    setDragStart(null);
  };

  const width = 1200;
  const height = 400;
  const padding = 80;
  const lineY = height / 2 + 50;

  const getX = (val) => {
    const start = parseFloat(range.start) || 0;
    const end = parseFloat(range.end) || 0;
    const totalRange = end - start;
    if (totalRange <= 0) return padding + (width - 2 * padding) / 2;
    const progress = (val - start) / totalRange;
    return padding + progress * (width - 2 * padding);
  };

  return (
    <div className="tool-container w-full mx-auto space-y-8 h-full flex flex-col font-['Outfit'] select-none">

      <div className="flex flex-col lg:flex-row gap-8 flex-1 min-h-[600px] overflow-hidden">
        {/* Configuration Hub */}
        <div className="w-full lg:w-96 flex flex-col gap-6 shrink-0 h-full overflow-hidden">
          <div className="tool-sidebar-card flex-1 p-10">
            <div className="flex items-center gap-3 mb-10">
               <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400">
                  <Sliders size={18} />
               </div>
               <h4 className="tool-sub-label mb-0">Axis Config</h4>
            </div>

            <div className="flex-1 space-y-10 overflow-y-auto pr-2 custom-scrollbar no-scrollbar">
               <div className="space-y-4">
                 <label className="tool-sub-label-indigo border-b-0 pb-0 ml-1">Sequence Range</label>
                 <div className="grid grid-cols-2 gap-4">
                   <div className="bg-slate-50 p-6 rounded-[2rem] border-4 border-white shadow-inner focus-within:border-indigo-100 transition-all">
                     <span className="text-[10px] font-black text-slate-300 uppercase block mb-2 italic">Origin</span>
                     <input 
                       type="number" 
                       value={range.start}
                       onChange={(e) => {
                         const val = e.target.value;
                         if (val === '-' || val === '') {
                           setRange(prev => ({ ...prev, start: val }));
                         } else {
                           const numVal = Number(val);
                           setRange(prev => ({ start: numVal, end: Math.max(numVal, parseFloat(prev.end) || 0) }));
                         }
                       }}
                       className="w-full bg-transparent border-none outline-none font-black text-2xl text-slate-800 tabular-nums italic"
                     />
                   </div>
                   <div className="bg-slate-50 p-6 rounded-[2rem] border-4 border-white shadow-inner focus-within:border-indigo-100 transition-all">
                     <span className="text-[10px] font-black text-slate-300 uppercase block mb-2 italic">Terminal</span>
                     <input 
                       type="number" 
                       value={range.end}
                       onChange={(e) => {
                         const val = e.target.value;
                         if (val === '-' || val === '') {
                           setRange(prev => ({ ...prev, end: val }));
                         } else {
                           const numVal = Number(val);
                           setRange(prev => ({ start: Math.min(numVal, parseFloat(prev.start) || 0), end: numVal }));
                         }
                       }}
                       className="w-full bg-transparent border-none outline-none font-black text-2xl text-slate-800 tabular-nums italic"
                     />
                   </div>
                 </div>
               </div>

               <div className="space-y-6">
                 <label className="tool-sub-label-indigo border-b-0 pb-0 ml-1">Increment Step</label>
                 <div className="bg-slate-50 p-8 rounded-[3rem] border-4 border-white shadow-inner focus-within:border-indigo-100 transition-all flex flex-col gap-6 items-center">
                   <div className="text-5xl font-black text-indigo-600 italic tabular-nums leading-none">{step}</div>
                   <input 
                     type="range" 
                     min="0.1" max="5" step="0.1" 
                     value={step}
                     onChange={(e) => setStep(parseFloat(e.target.value))}
                     className="w-full accent-indigo-600 h-2 bg-slate-200 rounded-full appearance-none cursor-pointer"
                   />
                 </div>
               </div>
            </div>

            <div className="mt-10 pt-10 border-t border-slate-50">
               <div className="p-8 bg-slate-900 rounded-[3rem] shadow-2xl border border-slate-800 flex flex-col items-center gap-6 text-center group overflow-hidden relative">
                  <div className="tool-grid-bg-dark opacity-10" />
                  <div className="absolute inset-0 bg-indigo-500/5 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                  <div className="flex items-center gap-3 relative z-10">
                    <Hash size={18} className="text-indigo-400" />
                    <span className="tool-sub-label-indigo mb-0 border-b-0 pb-0">Axis Magnitude</span>
                  </div>
                  <h3 className="text-6xl font-black text-white italic tracking-tighter leading-none relative z-10 tabular-nums">{(parseFloat(range.end) || 0) - (parseFloat(range.start) || 0)}</h3>
               </div>
            </div>
          </div>
        </div>

        {/* Simulation Stage */}
        <div className="flex-1 tool-stage bg-white p-12 relative overflow-hidden flex flex-col h-auto">
          <div className="tool-grid-bg opacity-30" />

          <div className="absolute top-10 left-10 flex items-center gap-4 opacity-20">
             <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-indigo-500">
                <MoveHorizontal size={20} />
             </div>
             <div className="flex flex-col">
                <span className="text-[10px] font-black uppercase tracking-[0.6em] italic text-slate-800 leading-none mb-1">Linear Sequence Lab</span>
                <span className="text-[10px] font-black uppercase tracking-[0.4em] italic text-slate-400">Axis Protocol v2.4</span>
             </div>
          </div>

          <div className="flex-1 flex flex-col justify-center min-h-0">
            <svg 
              ref={svgRef}
              viewBox={`0 0 ${width} ${height}`} 
              onMouseDown={handleMouseDown}
              onMouseMove={handleMouseMove}
              onMouseUp={handleMouseUp}
              onMouseLeave={() => { setHoverValue(null); setDragStart(null); }}
              className="w-full h-full cursor-crosshair touch-none select-none drop-shadow-2xl relative z-10"
              preserveAspectRatio="xMidYMid meet"
            >
              <defs>
                <linearGradient id="axisGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                  <stop offset="0%" stopColor="#1e293b" stopOpacity="0.2" />
                  <stop offset="10%" stopColor="#1e293b" />
                  <stop offset="90%" stopColor="#1e293b" />
                  <stop offset="100%" stopColor="#1e293b" stopOpacity="0.2" />
                </linearGradient>
                <filter id="glow">
                   <feGaussianBlur stdDeviation="2" result="coloredBlur"/>
                   <feMerge>
                      <feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/>
                   </feMerge>
                </filter>
              </defs>

              {/* Main Line */}
              <line 
                x1={padding} y1={lineY} x2={width - padding} y2={lineY} 
                stroke="url(#axisGradient)" strokeWidth="8" strokeLinecap="round" 
              />

              {/* Markers */}
              {markers.map((val) => {
                const x = getX(val);
                const isWhole = Number.isInteger(val);
                const isHovered = hoverValue === val;
                const isDragOrigin = dragStart?.value === val;

                return (
                  <g key={val} className="transition-all duration-300">
                    <line 
                      x1={x} y1={lineY - (isWhole ? 25 : 12)} x2={x} y2={lineY + (isWhole ? 25 : 12)} 
                      stroke={isHovered || isDragOrigin ? "#6366f1" : "#e2e8f0"} 
                      strokeWidth={isHovered || isDragOrigin ? "8" : (isWhole ? "4" : "2")} 
                      className="transition-all"
                    />
                    {showLabels && isWhole && (
                      <text 
                        x={x} y={lineY + 70} 
                        textAnchor="middle" 
                        className={`font-black tracking-tighter select-none pointer-events-none transition-all duration-500 italic ${
                          isHovered || isDragOrigin ? 'fill-indigo-600 scale-125' : 'fill-slate-300'
                        }`}
                        style={{ fontSize: '32px', filter: isHovered || isDragOrigin ? 'url(#glow)' : 'none' }}
                      >
                        {val}
                      </text>
                    )}
                    <rect x={x - 25} y={lineY - 60} width={50} height={120} fill="transparent" className="cursor-pointer" />
                  </g>
                );
              })}

              {/* Jumps */}
              <AnimatePresence>
                {jumps.map((jump, i) => {
                  const x1 = getX(jump.start);
                  const x2 = getX(jump.end);
                  const radius = Math.abs(x2 - x1) / 2;
                  const centerX = (x1 + x2) / 2;
                  const isPositive = jump.end > jump.start;
                  const pathHeight = radius * 0.7;
                  const path = `M ${x1} ${lineY} A ${radius} ${pathHeight} 0 0 ${isPositive ? 1 : 0} ${x2} ${lineY}`;

                  return (
                    <motion.g
                      key={`jump-${i}`}
                      initial={{ opacity: 0, pathLength: 0 }}
                      animate={{ opacity: 1, pathLength: 1 }}
                      exit={{ opacity: 0 }}
                      className="group/jump cursor-pointer"
                      onClick={(e) => { e.stopPropagation(); setJumps(jumps.filter((_, idx) => idx !== i)); audioEngine.playTick(settings.soundTheme); }}
                    >
                      <path d={path} fill="none" stroke={jump.color} strokeWidth="8" strokeLinecap="round" className="opacity-20 group-hover:opacity-40 transition-opacity" />
                      <motion.path 
                        d={path} fill="none" stroke={jump.color} strokeWidth="8" strokeLinecap="round" strokeDasharray="12 8"
                        animate={{ strokeDashoffset: isPositive ? [-100, 0] : [0, -100] }}
                        transition={{ repeat: Infinity, duration: 2, ease: "linear" }}
                      />
                      <path 
                        d={isPositive ? `M ${x2 - 15} ${lineY - 15} L ${x2} ${lineY} L ${x2 - 15} ${lineY + 15}` : `M ${x2 + 15} ${lineY - 15} L ${x2} ${lineY} L ${x2 + 15} ${lineY + 15}`}
                        fill="none" stroke={jump.color} strokeWidth="8" strokeLinecap="round"
                      />
                      <g className="opacity-0 group-hover:opacity-100 transition-all duration-300">
                        <rect x={centerX - 40} y={lineY - pathHeight - 60} width={80} height={50} rx="20" fill="white" stroke={jump.color} strokeWidth="4" shadow="0 20px 40px rgba(0,0,0,0.2)" />
                        <text x={centerX} y={lineY - pathHeight - 24} textAnchor="middle" className="font-black tabular-nums italic" style={{ fill: jump.color, fontSize: '28px' }}>
                          {isPositive ? '+' : ''}{parseFloat((jump.end - jump.start).toFixed(2))}
                        </text>
                      </g>
                    </motion.g>
                  );
                })}
              </AnimatePresence>

              {/* Pins */}
              <AnimatePresence>
                {pins.map((pin) => {
                  const x = getX(pin.value);
                  return (
                    <motion.g
                      key={`pin-${pin.value}`}
                      initial={{ opacity: 0, y: -40 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -40 }}
                      className="cursor-pointer group/pin"
                      onMouseDown={(e) => e.stopPropagation()}
                      onClick={(e) => { e.stopPropagation(); togglePin(pin.value); }}
                    >
                      <circle cx={x} cy={lineY} r="12" fill={pin.color} className="group-hover:fill-rose-500 transition-colors shadow-2xl" />
                      <line x1={x} y1={lineY} x2={x} y2={lineY - 120} stroke={pin.color} strokeWidth="8" strokeLinecap="round" className="group-hover:stroke-rose-500 transition-colors" />
                      <circle cx={x} cy={lineY - 130} r="32" fill={pin.color} className="group-hover:fill-rose-500 transition-colors shadow-2xl" />
                      <text x={x} y={lineY - 120} textAnchor="middle" className="font-black fill-white pointer-events-none tabular-nums italic leading-none" style={{ fontSize: '24px' }}>
                        {pin.value}
                      </text>
                    </motion.g>
                  );
                })}
              </AnimatePresence>
            </svg>
          </div>

          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-10">
             <div className="flex items-center gap-6">
                <div className="w-12 h-12 rounded-2xl bg-white shadow-xl border-4 border-slate-50 flex items-center justify-center text-indigo-500">
                   <Target size={24} />
                </div>
                <div className="flex flex-col">
                   <span className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-300 italic">Origin Vector</span>
                   <span className="text-xl font-black text-slate-800 italic tabular-nums">{range.start}</span>
                </div>
             </div>
             <div className="w-px h-10 bg-slate-100" />
             <div className="flex items-center gap-6">
                <div className="w-12 h-12 rounded-2xl bg-white shadow-xl border-4 border-slate-50 flex items-center justify-center text-indigo-500">
                   <Zap size={24} />
                </div>
                <div className="flex flex-col">
                   <span className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-300 italic">Terminal Node</span>
                   <span className="text-xl font-black text-slate-800 italic tabular-nums">{range.end}</span>
                </div>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

