import React, { useState, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Play, RotateCcw, Loader, History, Settings, BarChart3, Calculator, Trash2, Sliders, Target, Zap, Activity, Info, Monitor, Database, Terminal, MousePointer2 } from 'lucide-react';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';
import { useLocalStorage } from '../../hooks/useLocalStorage';
import { downloadCSV } from '../../utils/export';
import { ToolAnalytics } from '../ToolAnalytics';

export const NumberSpinner = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const [min, setMin] = useState(1);
  const [max, setMax] = useState(10);
  const [result, setResult] = useState(null);
  const [isSpinning, setIsSpinning] = useState(false);
  const [rotation, setRotation] = useState(0);
  const [history, setHistory] = useLocalStorage('number_spinner_history', []);
  const [targetNumber, setTargetNumber] = useState(null);

  const numSegments = Math.max(1, max - min + 1);
  const numbers = useMemo(() => Array.from({ length: numSegments }, (_, i) => min + i), [min, max]);
  const segmentAngle = 360 / numSegments;

  const resetStats = () => {
    setHistory([]);
    setResult(null);
    setRotation(0);
    audioEngine.playTick(settings.soundTheme);
  };

  const spin = () => {
    if (isSpinning) return;
    if (min >= max) return;
    if (max - min > 100) return;

    setIsSpinning(true);
    setResult(null);

    const winningIndex = Math.floor(Math.random() * numbers.length);
    const winningNumber = numbers[winningIndex];

    const extraFullSpins = Math.floor(5 + Math.random() * 3) * 360;
    const segmentCenter = (winningIndex + 0.5) * segmentAngle;
    const randomOffset = (Math.random() - 0.5) * (segmentAngle * 0.7);

    const resetRotation = 360 - (rotation % 360);
    const targetFromZero = 360 - segmentCenter;

    const nextRotation = rotation + extraFullSpins + resetRotation + targetFromZero - randomOffset;
    setRotation(nextRotation);
    setTargetNumber(winningNumber);

    if (settings.soundTheme !== 'none') {
      let ticks = 0;
      const tickInterval = setInterval(() => {
        audioEngine.playTick(settings.soundTheme);
        ticks++;
        if (ticks > 25) clearInterval(tickInterval);
      }, 150);
    }
  };

  const handleDownload = () => {
    downloadCSV(history, 'spinner_results.csv');
  };

  const frequencies = history.reduce((acc, curr) => {
    acc[curr.value] = (acc[curr.value] || 0) + 1;
    return acc;
  }, {});

  const chartData = useMemo(() => {
    return {
      labels: numbers.map(String),
      series: numbers.map(num => frequencies[num] || 0)
    };
  }, [numbers, frequencies]);

  const chartOptions = useMemo(() => {
    return {
      distributeSeries: true,
      axisY: {
        onlyInteger: true,
        offset: 20
      },
      axisX: {
        offset: 30
      },
      height: '160px',
      chartPadding: {
        top: 15,
        right: 15,
        bottom: 5,
        left: 5
      }
    };
  }, []);

  useEffect(() => {
    setOnReset(() => resetStats);
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <button
          onClick={spin}
          disabled={isSpinning || min >= max}
          className={`flex items-center gap-2 px-8 py-2 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all active:scale-95 shadow-lg italic ${isSpinning ? 'bg-slate-50 text-slate-200' : 'bg-slate-950 text-white shadow-indigo-200'}`}
        >
          {isSpinning ? <Loader size={14} className="animate-spin" /> : <Play size={14} fill="currentColor" strokeWidth={0} className="ml-0.5" />}
          {isSpinning ? 'Accelerating...' : 'Spin Resolver'}
        </button>
        <div className="w-px h-6 bg-slate-200" />
        <button
          onClick={resetStats}
          disabled={isSpinning}
          className="flex items-center gap-2 px-8 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:border-rose-100 hover:text-rose-600 transition-all active:scale-95 shadow-sm italic"
        >
          <Trash2 size={14} /> Clear Log
        </button>
      </div>
    );
  }, [isSpinning, min, max, settings.soundTheme]);

