import React, { useState, useRef, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Zap, 
  Clock, 
  RotateCcw, 
  AlertTriangle, 
  Play, 
  Activity, 
  TrendingUp, 
  Target, 
  Monitor, 
  Terminal,
  Database,
  Timer
} from 'lucide-react';
import { LineChart } from 'chartist';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';
import 'chartist/dist/index.css';

export const ReactionTime = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const [status, setStatus] = useState('idle'); // 'idle', 'waiting', 'ready', 'result'
  const [startTime, setStartTime] = useState(0);
  const [lastResult, setLastResult] = useState(null); // number or 'failed'
  const [history, setHistory] = useState(() => {
    const saved = localStorage.getItem('teacherToolsReactionTime');
    return saved ? JSON.parse(saved) : [];
  });
  const timeoutRef = useRef(null);
  const chartRef = useRef(null);
  const chartInstance = useRef(null);

  useEffect(() => {
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      if (chartInstance.current) chartInstance.current.detach();
      clearHeader();
    };
  }, [clearHeader]);

  const updateChart = useCallback(() => {
    const validAttempts = history.filter(h => !h.failed);
    if (validAttempts.length > 1 && chartRef.current) {
      const data = {
        labels: validAttempts.map((_, i) => i + 1),
        series: [validAttempts.map(h => h.ms)]
      };

      const options = {
        fullWidth: true,
        chartPadding: { top: 20, right: 40, bottom: 20, left: 20 },
        low: 0,
        showArea: true,
        axisX: { showGrid: false, showLabel: false },
        axisY: { 
          labelInterpolationFnc: (value) => `${value}ms`,
          scaleMinSpace: 40
        }
      };

      if (!chartInstance.current) {
        chartInstance.current = new LineChart(chartRef.current, data, options);
      } else {
        chartInstance.current.update(data);
      }
    }
  }, [history]);

  useEffect(() => {
    localStorage.setItem('teacherToolsReactionTime', JSON.stringify(history));
    updateChart();
  }, [history, updateChart]);

  useEffect(() => {
    setOnReset(() => () => {
        setHistory([]);
        setStatus('idle');
        setLastResult(null);
        audioEngine.playTick(settings.soundTheme);
    });
  }, [setOnReset, settings.soundTheme]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <button 
          onClick={() => { setHistory([]); setStatus('idle'); setLastResult(null); audioEngine.playTick(settings.soundTheme); }}
          className="flex items-center gap-2 px-8 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:border-rose-100 hover:text-rose-600 transition-all active:scale-95 shadow-sm italic"
          disabled={history.length === 0}
        >
          <RotateCcw size={14} /> Purge Telemetry
        </button>
      </div>
    );
  }, [history.length, setHeaderActions, settings.soundTheme]);


  const handleStart = () => {
    setStatus('waiting');
    setLastResult(null);
    audioEngine.playTick(settings.soundTheme);
    const delay = Math.floor(Math.random() * 5000) + 2000;
    timeoutRef.current = setTimeout(() => {
      setStatus('ready');
      setStartTime(Date.now());
      audioEngine.playReady(settings.soundTheme);
    }, delay);
  };

  const handleClick = () => {
    if (status === 'idle') {
      handleStart();
    } else if (status === 'waiting') {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      const newHistory = [...history, { attempt: history.length + 1, ms: null, failed: true }];
      setHistory(newHistory);
      setLastResult('failed');
      setStatus('result');
      audioEngine.playTick(settings.soundTheme);
    } else if (status === 'ready') {
      const endTime = Date.now();
      const reactionTime = endTime - startTime;
      const newHistory = [...history, { attempt: history.length + 1, ms: reactionTime, failed: false }];
      setHistory(newHistory);
      setLastResult(reactionTime);
      setStatus('result');
      audioEngine.playSuccess(settings.soundTheme);
    } else if (status === 'result') {
      handleStart();
    }
  };

  const validAttempts = history.filter(h => !h.failed);
  const average = validAttempts.length > 0 
    ? Math.round(validAttempts.reduce((acc, curr) => acc + curr.ms, 0) / validAttempts.length)
    : 0;
  const best = validAttempts.length > 0
    ? Math.min(...validAttempts.map(h => h.ms))
    : 0;
  const worst = validAttempts.length > 0
    ? Math.max(...validAttempts.map(h => h.ms))
    : 0;

  const getButtonConfig = () => {
    switch(status) {
      case 'idle': return { bg: 'bg-slate-950', icon: <Play size={120} className="text-white" />, text: 'Engage System', subtext: 'Click to initialize sync' };
      case 'waiting': return { bg: 'bg-rose-600', icon: <Activity size={120} className="text-white animate-pulse" />, text: 'Stabilizing...', subtext: 'Wait for temporal signal' };
      case 'ready': return { bg: 'bg-emerald-500', icon: <Zap size={120} className="text-white animate-bounce" />, text: 'EXECUTE', subtext: 'IMMEDIATE RESPONSE REQUIRED' };
      case 'result': return { 
        bg: lastResult === 'failed' ? 'bg-rose-700' : 'bg-slate-900', 
        icon: lastResult === 'failed' ? <AlertTriangle size={120} className="text-white" /> : <Timer size={120} className="text-indigo-400" />, 
        text: lastResult === 'failed' ? 'SYNCHRONIZATION FAILURE' : `${lastResult}ms`, 
        subtext: 'RE-INITIALIZE PROTOCOL' 
      };
      default: return { bg: 'bg-slate-500', icon: null, text: '', subtext: '' };
    }
  };

  const btnConfig = getButtonConfig();

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      {/* Primary Interaction Stage */}
      <div className="flex-1 flex flex-col gap-6">
        <button
          onClick={handleClick}
          className={`flex-1 rounded-[4rem] border-8 border-white shadow-2xl transition-all duration-500 flex flex-col items-center justify-center text-white gap-12 relative overflow-hidden group ${btnConfig.bg}`}
        >
          <div className="tool-grid-bg-dark opacity-10" />
          <div className="absolute inset-0 bg-white/5 opacity-0 group-hover:opacity-100 transition-opacity" />

          <AnimatePresence mode="wait">
             <motion.div 
               key={status}
               initial={{ scale: 0.8, opacity: 0 }}
               animate={{ scale: 1, opacity: 1 }}
               exit={{ scale: 1.2, opacity: 0 }}
               className="relative z-10 drop-shadow-2xl"
             >
                {btnConfig.icon}
             </motion.div>
          </AnimatePresence>

          <div className="text-center relative z-10 px-12">
            <motion.h3 
              key={btnConfig.text}
              initial={{ y: 20, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              className="text-8xl font-black tracking-tighter uppercase italic mb-4 leading-none"
            >
               {btnConfig.text}
            </motion.h3>
            <p className="text-[14px] font-black text-white/40 uppercase tracking-[0.6em] italic">{btnConfig.subtext}</p>
          </div>

          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-4 text-white/20">
             <Monitor size={24} />
             <div className="w-48 h-1 bg-white/5 rounded-full overflow-hidden">
                <motion.div 
                  className="h-full bg-white/40"
                  animate={status === 'waiting' ? { width: ['0%', '100%'], opacity: [0.5, 1, 0.5] } : { width: '0%' }}
                  transition={status === 'waiting' ? { duration: 5, repeat: Infinity } : {}}
                />
             </div>
          </div>
        </button>
      </div>

      {/* Telemetry Sidebar */}
      <div className="w-full lg:w-[480px] shrink-0 flex flex-col gap-6 overflow-hidden">
        <div className="tool-sidebar-card flex-1 p-12 flex flex-col gap-10">
           <div className="flex items-center gap-4 mb-2 shrink-0">
              <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400 border-4 border-white shadow-inner">
                 <Database size={24} />
              </div>
              <div className="flex flex-col">
                 <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Signal Analysis</h4>
                 <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic">Live Telemetry Stream</span>
              </div>
           </div>

           <div className="grid grid-cols-3 gap-6 shrink-0">
              <div className="tool-header-stat p-8 rounded-[2.5rem] bg-slate-50 border-4 border-white shadow-xl flex flex-col items-center gap-2 group italic">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1 group-hover:text-indigo-400 transition-colors">Average</p>
                 <p className="text-3xl font-black text-slate-800 tabular-nums tracking-tighter leading-none">{average ? `${average}` : '---'}<span className="text-[10px] ml-1">ms</span></p>
              </div>
              <div className="tool-header-stat p-8 rounded-[2.5rem] bg-emerald-50 border-4 border-emerald-100 shadow-xl flex flex-col items-center gap-2 group italic">
                 <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest leading-none mb-1 group-hover:text-emerald-400 transition-colors">Peak</p>
                 <p className="text-3xl font-black text-emerald-800 tabular-nums tracking-tighter leading-none">{best ? `${best}` : '---'}<span className="text-[10px] ml-1">ms</span></p>
              </div>
              <div className="tool-header-stat p-8 rounded-[2.5rem] bg-rose-50 border-4 border-rose-100 shadow-xl flex flex-col items-center gap-2 group italic">
                 <p className="text-[10px] font-black text-rose-600 uppercase tracking-widest leading-none mb-1 group-hover:text-rose-400 transition-colors">Trough</p>
                 <p className="text-3xl font-black text-rose-800 tabular-nums tracking-tighter leading-none">{worst ? `${worst}` : '---'}<span className="text-[10px] ml-1">ms</span></p>
              </div>
           </div>

           <div className="flex-1 flex flex-col gap-10 min-h-0">
              <div className="shrink-0 space-y-6">
                <div className="flex items-center justify-between">
                   <h3 className="text-[12px] font-black text-slate-400 uppercase tracking-[0.4em] italic leading-none">Telemetry Graph</h3>
                   <TrendingUp size={16} className="text-indigo-500" />
                </div>
                <div className="h-[220px] w-full bg-slate-50 rounded-[3rem] border-4 border-white shadow-inner p-8 relative overflow-hidden flex items-center justify-center">
                   <div className="tool-grid-bg opacity-20" />
                   {validAttempts.length > 1 ? (
                     <div ref={chartRef} className="ct-chart h-full w-full custom-chartist" />
                   ) : (
                     <div className="text-center px-10 space-y-4">
                        <div className="w-12 h-12 rounded-full bg-slate-200 flex items-center justify-center mx-auto opacity-40">
                           <Activity size={24} />
                        </div>
                        <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest leading-relaxed">Insufficient Data Stream (Min: 2 Nodes)</p>
                     </div>
                   )}
                </div>
              </div>

              <div className="flex-1 flex flex-col min-h-0">
                <div className="flex items-center justify-between mb-6 shrink-0">
                   <h3 className="text-[12px] font-black text-slate-400 uppercase tracking-[0.4em] italic leading-none">Activity Log</h3>
                   <Terminal size={16} className="text-slate-300" />
                </div>
                <div className="flex-1 overflow-y-auto space-y-4 pr-4 custom-scrollbar no-scrollbar">
                  <AnimatePresence initial={false}>
                    {history.length === 0 ? (
                      <div className="h-full flex items-center justify-center text-slate-300 italic text-[11px] font-black uppercase tracking-widest p-12 text-center">
                        Awaiting Manual Synchronization Engagements
                      </div>
                    ) : (
