      { id: '1', name: 'Standard Protocol', words: ['SYNTHESIS', 'MANIFEST', 'ENIGMA', 'CHRONOS'] }
    ];
  });

  const [selectedListId, setSelectedListId] = useState(lists[0]?.id || '');
  const [isAddingList, setIsAddingList] = useState(false);
  const [editingListId, setEditingListId] = useState(null);
  const [newListTitle, setNewListTitle] = useState('');
  const [wordsInput, setWordsInput] = useState('');

  const [queue, setQueue] = useState([]);
  const [currentWord, setCurrentWord] = useState('');
  const [revealedIndices, setRevealedIndices] = useState([]);
  const [isAutoRevealing, setIsAutoRevealing] = useState(false);
  const [revealSpeed, setRevealSpeed] = useState(1500); // ms

  useEffect(() => {
    localStorage.setItem('spelling_lists', JSON.stringify(lists));
  }, [lists]);

  const saveList = () => {
    if (!newListTitle.trim() || !wordsInput.trim()) return;
    const newWords = wordsInput.split('\n').map(w => w.trim().toUpperCase()).filter(w => w.length > 0);
    if (newWords.length === 0) return;

    if (editingListId) {
      setLists(prev => prev.map(l => l.id === editingListId ? { ...l, name: newListTitle.trim(), words: newWords } : l));
    } else {
      const newList = {
        id: Date.now().toString(),
        name: newListTitle.trim(),
        words: newWords
      };
      setLists(prev => [...prev, newList]);
      setSelectedListId(newList.id);
    }

    setNewListTitle('');
    setWordsInput('');
    setIsAddingList(false);
    setEditingListId(null);
    audioEngine.playTick(settings.soundTheme);
  };

  const editList = (list, e) => {
    e.stopPropagation();
    setEditingListId(list.id);
    setNewListTitle(list.name);
    setWordsInput(list.words.join('\n'));
    setIsAddingList(true);
    audioEngine.playTick(settings.soundTheme);
  };

  const deleteList = (id, e) => {
    e.stopPropagation();
    if (lists.length <= 1) return;
    setLists(prev => prev.filter(l => l.id !== id));
    if (selectedListId === id) setSelectedListId(lists.find(l => l.id !== id).id);
    audioEngine.playTick(settings.soundTheme);
  };

  const startNextWord = useCallback((remainingQueue) => {
    const nextQueue = remainingQueue || queue;
    if (nextQueue.length === 0) {
      const list = lists.find(l => l.id === selectedListId);
      const shuffled = [...list.words].sort(() => Math.random() - 0.5);
      setQueue(shuffled.slice(1));
      setCurrentWord(shuffled[0]);
    } else {
      setCurrentWord(nextQueue[0]);
      setQueue(nextQueue.slice(1));
    }
    setRevealedIndices([]);
    setIsAutoRevealing(false);
    audioEngine.playTick(settings.soundTheme);
  }, [lists, queue, selectedListId, settings.soundTheme]);

  const startGame = () => {
    const list = lists.find(l => l.id === selectedListId);
    if (!list || list.words.length === 0) return;

    const shuffled = [...list.words].sort(() => Math.random() - 0.5);
    setCurrentWord(shuffled[0]);
    setQueue(shuffled.slice(1));
    setRevealedIndices([]);
    setStatus('playing');
    setIsAutoRevealing(false);
    audioEngine.playTick(settings.soundTheme);
  };

  const revealOneLetter = useCallback(() => {
    if (!currentWord) return;

    const unrevealed = [];
    for (let i = 0; i < currentWord.length; i++) {
      if (!revealedIndices.includes(i)) unrevealed.push(i);
    }

    if (unrevealed.length > 0) {
      const randomIndex = unrevealed[Math.floor(Math.random() * unrevealed.length)];
      setRevealedIndices(prev => [...prev, randomIndex]);
      audioEngine.playTick(settings.soundTheme);

      if (unrevealed.length === 1) {
        setIsAutoRevealing(false);
        confetti({
          particleCount: 50,
          spread: 60,
          origin: { y: 0.7 }
        });
      }
    }
  }, [currentWord, revealedIndices, settings.soundTheme]);

  useEffect(() => {
    setOnReset(() => () => setStatus('setup'));
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    let timer;
    if (isAutoRevealing) {
      timer = setInterval(() => {
        revealOneLetter();
      }, revealSpeed);
    }
    return () => clearInterval(timer);
  }, [isAutoRevealing, revealOneLetter, revealSpeed]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        {status === 'playing' && (
           <>
            <div className="flex bg-slate-100 p-1 rounded-2xl border-2 border-transparent">
               {[500, 1500, 3000].map(speed => (
                 <button
                   key={speed}
                   onClick={() => { setRevealSpeed(speed); audioEngine.playTick(settings.soundTheme); }}
                   className={`px-5 py-2 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all ${revealSpeed === speed ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                 >
                   {speed === 500 ? 'FAST' : speed === 1500 ? 'NORM' : 'SLOW'}
                 </button>
               ))}
            </div>
            <div className="w-px h-6 bg-slate-200" />
            <button 
              onClick={() => { setStatus('setup'); audioEngine.playTick(settings.soundTheme); }}
              className="flex items-center gap-2 px-6 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:border-rose-100 hover:text-rose-600 transition-all active:scale-95 shadow-sm"
            >
              <RotateCcw size={14} /> Global Reset
            </button>
           </>
        )}
      </div>
    );
  }, [status, revealSpeed, settings.soundTheme]);

  return (
    <div className="tool-container flex flex-col gap-6 h-full font-['Outfit'] select-none">
      <AnimatePresence mode="wait">
        {status === 'setup' ? (
