            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95 }}
            className="flex-1 flex flex-col gap-8 min-h-0"
          >
            <div className="flex flex-col lg:flex-row gap-8 flex-1 min-h-0">
