               {/* Stage Area */}
               <div className="flex-1 tool-card bg-slate-900 border-none p-12 flex flex-col items-center justify-center relative overflow-hidden shadow-2xl group">
                  <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#6366f1 2px, transparent 2px)', backgroundSize: '48px 48px' }} />

                  <div className="relative z-10 flex flex-col items-center gap-12 text-center">
                     <div className="w-40 h-40 bg-white/5 rounded-[4rem] border border-white/10 flex items-center justify-center text-indigo-400 shadow-inner group-hover:scale-110 transition-transform duration-700">
                        <Sparkles size={80} strokeWidth={1} />
                     </div>
                     <div className="space-y-3">
                        <h2 className="text-6xl font-black text-white italic tracking-tighter uppercase">Enigma Reveal</h2>
                        <p className="text-[10px] font-black text-white/20 uppercase tracking-[0.5em]">Linguistic Synthesis Protocol</p>
