                         {isRevealed && <div className="absolute inset-0 bg-gradient-to-br from-white/20 to-transparent pointer-events-none rounded-[3rem]" />}
                       </motion.div>
                     );
                   })}
                </div>

                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-4 text-slate-300">
                   <Target size={16} />
                   <span className="text-[10px] font-black uppercase tracking-[0.4em]">Target Synthesis: {currentWord.length} Units</span>
                </div>
             </div>

             {/* Dynamic Control Dock */}
             <div className="w-full max-w-5xl p-8 bg-slate-900 rounded-[4rem] shadow-2xl flex flex-col md:flex-row items-center gap-10 text-white relative overflow-hidden group">
                <div className="absolute -right-10 -bottom-10 opacity-5 group-hover:scale-110 transition-transform duration-1000">
                   <Activity size={160} strokeWidth={1} />
                </div>

                <div className="flex-1 flex flex-col gap-4 relative z-10 w-full">
                   <div className="flex items-center justify-between">
                      <div className="flex items-center gap-3">
                         <Timer size={16} className="text-indigo-400" />
                         <span className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-400">Synthesis Tempo</span>
                      </div>
                      <span className="text-sm font-black tabular-nums italic text-indigo-400">{(revealSpeed / 1000).toFixed(1)}s</span>
                   </div>
                   <input 
                     type="range" 
                     min="500" 
                     max="3000" 
                     step="500"
                     value={revealSpeed}
                     onChange={(e) => setRevealSpeed(Number(e.target.value))}
                     className="w-full accent-indigo-500 h-2 bg-white/10 rounded-full appearance-none cursor-pointer"
                   />
                </div>

                <div className="flex items-center gap-6 relative z-10">
                   <button
                    onClick={() => { setIsAutoRevealing(!isAutoRevealing); audioEngine.playTick(settings.soundTheme); }}
                    className={`w-24 h-24 rounded-[2rem] transition-all shadow-xl flex flex-col items-center justify-center gap-1 active:scale-90 ${
                      isAutoRevealing ? 'bg-amber-500 text-white shadow-amber-500/20' : 'bg-indigo-600 text-white shadow-indigo-600/20 hover:bg-indigo-700'
                    }`}
                  >
                    {isAutoRevealing ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
                    <span className="text-[9px] font-black uppercase tracking-widest">{isAutoRevealing ? 'PAUSE' : 'AUTO'}</span>
                  </button>

                  <button
                    onClick={revealOneLetter}
                    disabled={revealedIndices.length === currentWord.length}
                    className="w-24 h-24 bg-white/5 hover:bg-white/10 rounded-[2rem] transition-all border-2 border-white/10 flex flex-col items-center justify-center gap-1 active:scale-95 disabled:opacity-20"
                  >
                    <Eye size={32} />
                    <span className="text-[9px] font-black uppercase tracking-widest">PULSE</span>
                  </button>

                  <button
                    onClick={() => startNextWord()}
                    className="w-24 h-24 bg-white/5 hover:bg-white/10 rounded-[2rem] transition-all border-2 border-white/10 flex flex-col items-center justify-center gap-1 active:scale-95"
                  >
                    <SkipForward size={32} />
                    <span className="text-[9px] font-black uppercase tracking-widest">NEXT</span>
                  </button>

                  <div className="w-px h-16 bg-white/10 mx-2" />

                  <button
                    onClick={() => { setStatus('setup'); audioEngine.playTick(settings.soundTheme); }}
                    className="w-20 h-20 bg-rose-500/10 hover:bg-rose-500/20 text-rose-500 rounded-2xl transition-all border border-rose-500/20 flex items-center justify-center"
                  >
                    <RotateCcw size={28} />
                  </button>
                </div>
             </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

