                    <Infinity size={20} />
                  </div>
                  <div className="flex flex-col items-start">
                    <span className="text-[9px] font-black opacity-60 uppercase tracking-widest">Source Mode</span>
                    <span className="text-xs font-black uppercase tracking-tight">{isGeneratorMode ? 'Emitter Active' : 'Single Placement'}</span>
                  </div>
               </button>

               <div className="grid grid-cols-3 gap-3">
                  {MATERIALS.filter(m => m.id !== 12).map(mat => (
                    <button
                      key={mat.id}
                      onClick={() => setSelectedMaterial(mat.id)}
                      className={`group flex flex-col items-center gap-2 p-3 rounded-2xl transition-all duration-300 border-2 ${selectedMaterial === mat.id ? 'bg-white border-indigo-600 shadow-xl scale-105 z-10' : 'bg-slate-50 border-transparent hover:bg-white hover:border-slate-200 opacity-60 hover:opacity-100'}`}
