  const generateCommand = useCallback(() => {
    const isSimon = Math.random() > (difficulty === 'Hard' ? 0.2 : 0.3);
    const command = COMMANDS[Math.floor(Math.random() * COMMANDS.length)];

    setCurrentCommand({
      isSimon,
      text: command.text,
      icon: command.icon,
      id: command.id
    });
    setTimer(100);
    setFeedback(null);
