    if (gameState !== 'playing' || feedback) return;

    const isCorrect = (currentCommand.isSimon && actionId === currentCommand.id) || 
                     (!currentCommand.isSimon && actionId === null);

    if (isCorrect) {
      const newScore = score + 1;
