                localStorage.setItem('simonSaysHighScore', newScore.toString());
              }
              setFeedback({ isCorrect: true, message: 'CORRECT INHIBITION' });
              setTimeout(generateCommand, 600);
              return 100;
            }
          }
          return prev - speed;
        });
      }, 50);
    }
