import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Volume2, VolumeX, Mic, MicOff, Settings2, AlertTriangle, ShieldAlert, ShieldCheck, Activity, BellRing, Target, Volume1, Sparkles } from 'lucide-react';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';

export const SoundLevel = () => {
  const { settings } = useSettings();
  const { setHeaderActions, clearHeader } = useHeader();

  const [volume, setVolume] = useState(0);
  const [threshold, setThreshold] = useState(60);
  const [isMonitoring, setIsMonitoring] = useState(false);
  const [permissionError, setPermissionError] = useState(null);

  const audioContextRef = useRef(null);
  const analyserRef = useRef(null);
  const streamRef = useRef(null);
  const animationRef = useRef(null);
  const lastVolumeRef = useRef(0);
  const thresholdRef = useRef(threshold);
  const volumeBuffer = useRef([]); 
  const [avgVolume, setAvgVolume] = useState(0);

  useEffect(() => {
    thresholdRef.current = threshold;
  }, [threshold]);

  const startMonitoring = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const AudioContext = window.AudioContext || window.webkitAudioContext;
      audioContextRef.current = new AudioContext();

      const source = audioContextRef.current.createMediaStreamSource(stream);
      analyserRef.current = audioContextRef.current.createAnalyser();
      analyserRef.current.fftSize = 256;
      analyserRef.current.smoothingTimeConstant = 0.8;

      source.connect(analyserRef.current);

      setIsMonitoring(true);
      setPermissionError(null);
      updateVolume();
    } catch (err) {
      console.warn('Microphone access issue:', err);
      if (err.name === 'NotFoundError' || err.name === 'DevicesNotFoundError') {
        setPermissionError('Hardware not found: Connection error or hardware absence.');
      } else if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setPermissionError('Protocol Error: OS/Browser has withheld microphone permissions.');
      } else {
        setPermissionError('System synthesis error: Connection to auditory hardware failed.');
      }
    }
  };

  const stopMonitoring = () => {
    if (animationRef.current) cancelAnimationFrame(animationRef.current);
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
    }
    setIsMonitoring(false);
    setVolume(0);
    setAvgVolume(0);
    lastVolumeRef.current = 0;
    volumeBuffer.current = [];
  };

  const updateVolume = () => {
    if (!analyserRef.current) return;

    const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
    analyserRef.current.getByteFrequencyData(dataArray);

    let sum = 0;
    for (let i = 0; i < dataArray.length; i++) {
      sum += dataArray[i];
    }
    const average = sum / dataArray.length;
    const currentFrameVolume = Math.min(100, Math.round((average / 128) * 100));

    const alpha = 0.15; 
    const smoothedVolume = (currentFrameVolume * alpha) + (lastVolumeRef.current * (1 - alpha));
    lastVolumeRef.current = smoothedVolume;

    volumeBuffer.current.push(smoothedVolume);
    if (volumeBuffer.current.length > 120) {
      volumeBuffer.current.shift();
    }
    const currentRollingAvg = volumeBuffer.current.reduce((a, b) => a + b, 0) / volumeBuffer.current.length;

    setVolume(Math.round(smoothedVolume));
    setAvgVolume(Math.round(currentRollingAvg));

    animationRef.current = requestAnimationFrame(updateVolume);
  };

  useEffect(() => {
    return () => {
      stopMonitoring();
      clearHeader();
    };
  }, [clearHeader]);

  useEffect(() => {
    setHeaderActions(null);
  }, [setHeaderActions]);

  const getStatus = () => {
    if (volume >= threshold) return 'danger';
    if (avgVolume >= threshold * 0.8) return 'warning';
    return 'ok';
  };

  const [isDragging, setIsDragging] = useState(false);

  useEffect(() => {
    const handleGlobalMouseMove = (e) => {
      if (!isDragging) return;
      const gauge = document.querySelector('.gauge-svg');
      if (!gauge) return;
      const rect = gauge.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      let angle = Math.atan2(e.clientY - centerY, e.clientX - centerX) * (180 / Math.PI) + 90;
      angle = (angle + 360) % 360;
      const newThreshold = Math.max(5, Math.min(100, Math.round(angle / 3.6)));
      setThreshold(newThreshold);
    };

    const handleGlobalMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleGlobalMouseMove);
      window.addEventListener('mouseup', handleGlobalMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleGlobalMouseMove);
      window.removeEventListener('mouseup', handleGlobalMouseUp);
    };
  }, [isDragging]);

  const status = getStatus();

  return (
    <div className="tool-container flex flex-col gap-8 p-6 h-full overflow-hidden font-['Outfit'] select-none">

      {permissionError ? (
        <div className="tool-card flex flex-col items-center justify-center p-20 text-center gap-10 bg-white border-4 border-slate-50 shadow-indigo-900/5">
          <div className="w-32 h-32 bg-rose-50 text-rose-500 rounded-[3rem] shadow-inner flex items-center justify-center">
            <AlertTriangle size={60} strokeWidth={1} />
          </div>
          <div className="space-y-4">
            <h3 className="text-3xl font-black text-slate-800 uppercase tracking-tighter">Auditory Link Failure</h3>
            <p className="text-slate-400 max-w-sm text-sm uppercase tracking-widest font-bold leading-relaxed">{permissionError}</p>
          </div>
          <button
            onClick={startMonitoring}
            className="flex items-center gap-3 px-10 py-5 bg-slate-900 text-white rounded-[2rem] font-black uppercase tracking-widest text-xs hover:bg-rose-600 transition-all shadow-xl shadow-slate-100 active:scale-95"
          >
            <RefreshCw size={18} /> Re-Initialize Hardware
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-8 items-stretch h-full">

          {/* Main Visualizer Area */}
          <div className={`tool-card p-12 flex flex-col items-center justify-center relative overflow-hidden bg-white border-4 border-slate-50 shadow-indigo-900/5 ${isDragging ? 'cursor-grabbing' : ''}`}>
            <div className="absolute inset-0 bg-[#f8fafc]/30 -z-10" style={{ backgroundImage: 'radial-gradient(#e2e8f0 1.5px, transparent 1.5px)', backgroundSize: '48px 48px' }} />

            <AnimatePresence>
              {status === 'danger' && (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="absolute inset-0 bg-rose-600/5 backdrop-blur-[2px] animate-pulse pointer-events-none"
                />
              )}
            </AnimatePresence>

            <div className="absolute top-10 flex items-center gap-2">
               <Sparkles size={16} className="text-indigo-400 animate-pulse" />
               <span className="text-[10px] font-black text-slate-300 uppercase tracking-[0.4em]">Atmospheric Audio Analysis</span>
            </div>

            <div className="relative w-full max-w-md aspect-square flex items-center justify-center group">
              <div className="absolute -inset-10 border-2 border-dashed border-slate-100 rounded-full group-hover:border-indigo-100 group-hover:rotate-6 transition-all duration-1000 pointer-events-none" />

              <svg className="absolute inset-0 w-full h-full gauge-svg drop-shadow-xl" viewBox="0 0 100 100">
                <circle cx="50" cy="50" r="45" fill="none" stroke="#f1f5f9" strokeWidth="8" />

                {/* Rolling Avg Indicator */}
                <circle
                  cx="50" cy="50" r="45" fill="none" stroke="#e2e8f0" strokeWidth="4"
                  strokeDasharray="282.7" strokeDashoffset={282.7 - (282.7 * avgVolume) / 100}
                  className="transition-all duration-300 -rotate-90 origin-center opacity-50"
                />

                {/* Main Volume Progress */}
                <motion.circle
                  cx="50" cy="50" r="45" fill="none"
                  stroke={status === 'danger' ? '#f43f5e' : status === 'warning' ? '#f59e0b' : '#10b981'}
                  strokeWidth="8" strokeDasharray="282.7"
                  animate={{ strokeDashoffset: 282.7 - (282.7 * volume) / 100 }}
                  transition={{ type: 'spring', damping: 20, stiffness: 60 }}
                  className="-rotate-90 origin-center drop-shadow-md"
                />

                {/* Threshold Marker / Handle */}
                <g 
                  className="threshold-handle cursor-grab active:cursor-grabbing transition-transform duration-200"
                  transform={`rotate(${(threshold * 3.6)}, 50, 50)`}
                  onMouseDown={(e) => { e.preventDefault(); setIsDragging(true); }}
                >
                  <line x1="50" y1="2" x2="50" y2="10" stroke="#6366f1" strokeWidth="3" strokeLinecap="round" />
                  <circle cx="50" cy="3" r="4" fill="#6366f1" className="shadow-lg" />
                  <circle cx="50" cy="3" r="8" fill="#6366f1" fillOpacity="0.1" />
                </g>
              </svg>

              <div className="relative z-10 flex flex-col items-center gap-8 bg-white rounded-full w-2/3 h-2/3 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1),inset_0_0_40px_rgba(255,255,255,1)] border-4 border-white flex items-center justify-center">
                <motion.div
                  animate={{ scale: status === 'danger' ? [1, 1.15, 1] : 1 }}
                  transition={{ repeat: Infinity, duration: 0.5 }}
                  className={`p-8 rounded-[2.5rem] shadow-xl ${
                    status === 'danger' ? 'bg-rose-50 text-rose-600 shadow-rose-100' : 
                    status === 'warning' ? 'bg-amber-50 text-amber-600 shadow-amber-100' : 
                    'bg-emerald-50 text-emerald-600 shadow-emerald-100'
                  }`}
                >
                  {status === 'danger' ? <ShieldAlert size={64} strokeWidth={1.5} /> : 
                   status === 'warning' ? <AlertTriangle size={64} strokeWidth={1.5} /> : 
                   <ShieldCheck size={64} strokeWidth={1.5} />}
                </motion.div>

                <div className="text-center">
                  <h3 className={`text-7xl font-black tabular-nums leading-none tracking-tighter italic ${
                    status === 'danger' ? 'text-rose-600' : 
                    status === 'warning' ? 'text-amber-600' : 
                    'text-slate-800'
                  }`}>
                    {status === 'danger' ? 'CRITICAL' : status === 'warning' ? 'ELEVATED' : volume}
                  </h3>
                  <div className="flex flex-col gap-1 mt-4">
                    <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">
                      Decibel Saturation
                    </p>
                  </div>
                </div>
              </div>
            </div>

            {!isMonitoring && (
              <div className="absolute inset-0 bg-white/40 backdrop-blur-xl flex items-center justify-center z-20">
                <div className="text-center space-y-6">
                  <div className="w-24 h-24 bg-white rounded-[2rem] shadow-2xl flex items-center justify-center mx-auto text-slate-300 border-2 border-slate-50 rotate-3">
                    <VolumeX size={40} />
                  </div>
                  <div className="space-y-1">
                    <p className="font-black uppercase tracking-[0.4em] text-slate-400 text-[10px]">Spectrum Offline</p>
                    <p className="font-bold text-slate-300 text-[10px] uppercase tracking-widest italic">Monitoring sequence inactive</p>
                  </div>
                  <button
                    onClick={startMonitoring}
                    className="flex items-center gap-3 px-10 py-5 bg-indigo-600 text-white rounded-[2rem] font-black uppercase tracking-widest text-xs hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 active:scale-95"
                  >
                    <Mic size={18} /> Initialize Monitor
                  </button>
                </div>
              </div>
            )}
          </div>

        </div>
      )}

    </div>
  );
};

