import React, { useState, useEffect, useRef, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ArrowDownUp, Info, Settings2, RotateCcw, ArrowDown, ArrowUp, 
  Beaker, Anchor, Droplets, FlaskConical, Scale, Maximize2,
  ChevronRight, ShieldCheck, AlertCircle, TrendingUp, Weight, X, Eye, EyeOff,
  Activity, Monitor, Database
} from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';

// Constants
const LAB_WIDTH = 800;
const LAB_HEIGHT = 600;
const SPRING_TOP_Y = 100;
const GRAVITY = 9.8;

const SCALES = [
  { id: '1n', name: 'Precision Scale', maxForce: 1, k: 0.01, color: '#fbbf24', precision: 2, label: 'Micro' },
  { id: '5n', name: 'Standard Scale', maxForce: 5, k: 0.05, color: '#10b981', precision: 1, label: 'Standard' },
  { id: '10n', name: 'Industrial Scale', maxForce: 10, k: 0.1, color: '#3b82f6', precision: 1, label: 'Heavy' },
];

const WEIGHTS = [
  { id: '10g', name: '10g', mass: 0.01, emoji: '🔘', size: 40 },
  { id: '50g', name: '50g', mass: 0.05, emoji: '🟢', size: 50 },
  { id: '100g', name: '100g', mass: 0.1, emoji: '🔵', size: 60 },
  { id: '200g', name: '200g', mass: 0.2, emoji: '🔴', size: 70 },
  { id: '500g', name: '500g', mass: 0.5, emoji: '🧱', size: 85 },
  { id: '1kg', name: '1kg', mass: 1.0, emoji: '⚖️', size: 100 },
];

export const SpringScales = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();
  const weightIdCounter = useRef(0);

  const [selectedScale, setSelectedScale] = useState(SCALES[1]);
  const [attachedWeights, setAttachedWeights] = useState([]);
  const [showForces, setShowForces] = useState(true);
  const [isBroken, setIsBroken] = useState(false);

  const [extension, setExtension] = useState(0);
  const [velocity, setVelocity] = useState(0);

  const totalMass = useMemo(() => 
    attachedWeights.reduce((sum, w) => sum + w.mass, 0),
  [attachedWeights]);

  const totalForce = totalMass * GRAVITY;

  useEffect(() => {
    if (totalForce > selectedScale.maxForce + 0.1 && !isBroken) {
      setIsBroken(true);
      setVelocity(20);
      audioEngine.playAlarm(settings.soundTheme);
    }
  }, [totalForce, selectedScale, isBroken, settings.soundTheme]);

  const resetLab = () => {
    setAttachedWeights([]);
    setExtension(0);
    setVelocity(0);
    setIsBroken(false);
    audioEngine.playTick(settings.soundTheme);
  };

  const addWeight = (weight) => {
    if (isBroken || attachedWeights.length >= 4) return;
    const id = `w-${weightIdCounter.current++}`;
    setAttachedWeights(prev => [...prev, { ...weight, instanceId: id }]);
    audioEngine.playTick(settings.soundTheme);
  };

  const removeWeight = (instanceId) => {
    if (isBroken) return;
    setAttachedWeights(prev => prev.filter(w => w.instanceId !== instanceId));
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    let animationFrame;
    const step = () => {
      if (isBroken) {
        setExtension(prev => Math.min(prev + velocity, 500));
        setVelocity(v => v + 0.5);
        return;
      }
      const m = totalMass > 0 ? totalMass : 0.01; 
      const F_gravity = totalMass * GRAVITY;
      const targetExtension = (F_gravity / selectedScale.maxForce) * 200; 
      setExtension(prev => {
        const stiffness = 0.15;
        const damping = 0.85;
        const diff = targetExtension - prev;
        const accel = diff * stiffness;
        setVelocity(v => {
          const newV = (v + accel) * damping;
          return Math.abs(newV) < 0.01 ? 0 : newV;
        });
        const next = prev + velocity;
        return Math.abs(next - targetExtension) < 0.1 && Math.abs(velocity) < 0.1 ? targetExtension : next;
      });
      animationFrame = requestAnimationFrame(step);
    };
    animationFrame = requestAnimationFrame(step);
    return () => cancelAnimationFrame(animationFrame);
  }, [totalMass, selectedScale, velocity, isBroken]);

  useEffect(() => {
    setOnReset(() => resetLab);
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <button
          onClick={() => { setShowForces(!showForces); audioEngine.playTick(settings.soundTheme); }}
          disabled={isBroken}
          className={`flex items-center gap-2 px-8 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95 shadow-lg italic ${isBroken ? 'bg-slate-50 text-slate-200 cursor-not-allowed' : showForces ? 'bg-indigo-600 text-white shadow-indigo-200' : 'bg-white border-2 border-slate-100 text-slate-400 hover:border-indigo-100'}`}
        >
          {showForces ? <EyeOff size={14} /> : <Eye size={14} />} {showForces ? 'Hide Vectors' : 'Show Vectors'}
        </button>
        <div className="w-px h-6 bg-slate-200" />
        <button
          onClick={resetLab}
