import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Flag, 
  ListOrdered, 
  Volume2, 
  VolumeX, 
  Download,
  TimerReset,
  Settings2,
  Trash2,
  Settings,
  TrendingUp,
  Activity,
  Info,
  ShieldCheck,
  AlertCircle,
  Leaf,
  Cpu,
  Sliders,
  Flame,
  Zap
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import HistoryPanel from '../shared/HistoryPanel';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';
import { useLocalStorage } from '../../hooks/useLocalStorage';
import { formatStopwatchTime } from '../../utils/format';
import { downloadCSV } from '../../utils/export';

export const StopWatch = () => {
  const [time, setTime] = useState(0);
  const [isRunning, setIsRunning] = useState(false);
  const [laps, setLaps] = useState([]);
  const [isMuted, setIsMuted] = useLocalStorage('teacherToolsStopwatchMuted', false);
  const [tickSound, setTickSound] = useLocalStorage('teacherToolsStopwatchTickSound', 'classic');
  const { 
    setHasConfig, 
    isConfigOpen, 
    setIsConfigOpen, 
    setOnConfigToggle, 
    setOnReset,
    clearHeader 
  } = useHeader();
  const lastTickRef = useRef(0);

  const reset = useCallback(() => {
    setIsRunning(false);
    setTime(0);
    lastTickRef.current = 0;
    setIsMuted(false);
    setTickSound('classic');
  }, [setIsMuted, setTickSound]);

  useEffect(() => {
    setHasConfig(true);
    setOnConfigToggle(() => () => setIsConfigOpen(prev => !prev));
    setOnReset(() => reset);
    return () => clearHeader();
  }, [setIsConfigOpen, setHasConfig, setOnConfigToggle, setOnReset, clearHeader, reset]);

  useEffect(() => {
    let intervalId;
    if (isRunning) {
      intervalId = setInterval(() => {
        setTime((prev) => {
          const newTime = prev + 10;
          if (Math.floor(newTime / 1000) > lastTickRef.current) {
            if (!isMuted) audioEngine.playTick(tickSound);
            lastTickRef.current = Math.floor(newTime / 1000);
          }
          return newTime;
        });
      }, 10);
    }
    return () => clearInterval(intervalId);
  }, [isRunning, tickSound, isMuted]);

  const toggle = () => {
    setIsRunning(!isRunning);
    audioEngine.playTick(tickSound);
    if (!isRunning) {
      lastTickRef.current = Math.floor(time / 1000);
    }
  };


  const clearLaps = () => {
    setLaps([]);
    audioEngine.playTick(tickSound);
  };

  const addLap = () => {
    if (time === 0) return;
    const lastLapTime = laps.length > 0 ? laps[0].total : 0;
    const lapTime = time - lastLapTime;
    setLaps([{ id: Date.now(), lap: lapTime, total: time }, ...laps]);
    audioEngine.playTick(tickSound);
  };

  const handleDownload = () => {
    if (laps.length === 0) return;
    downloadCSV(laps.map((l, i) => ({
      'Lap Number': laps.length - i,
      'Lap Time (ms)': l.lap,
      'Total Time (ms)': l.total,
      'Formatted Lap': formatStopwatchTime(l.lap),
      'Formatted Total': formatStopwatchTime(l.total)
    })), `precision_chronos_data_${new Date().toISOString().slice(0,10)}.csv`);
    audioEngine.playTick(tickSound);
  };

  const soundThemes = ['classic', 'digital', 'soft', 'bubbly', 'chime', 'synth', 'beep', 'siren'];

  return (
    <div className="tool-container flex flex-col lg:flex-row-reverse gap-8 h-full font-['Outfit'] select-none">

      {/* Parameters Sidebar */}
      <div className="w-full lg:w-[320px] flex flex-col gap-4 shrink-0 h-full overflow-hidden">
        {/* Lap History Card */}
        <HistoryPanel
          title="Lap History"
          items={laps}
          onClear={clearLaps}
          onDownload={handleDownload}
          emptyMessage="No Data"
          renderItem={(lap, index) => (
            <motion.div
              key={lap.id}
              layout
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              className="p-3 bg-slate-50 border border-slate-100 rounded-2xl flex justify-between items-center group transition-all"
            >
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 bg-white border border-slate-100 rounded-xl flex items-center justify-center font-black text-xs text-indigo-600 shadow-sm">
                  {laps.length - index}
                </div>
                <div className="flex flex-col">
                  <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Laptime</span>
                  <span className="text-sm font-black text-slate-900 tabular-nums">+{formatStopwatchTime(lap.lap)}</span>
                </div>
              </div>
              <div className="text-right">
                <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1 block">Total</span>
                <p className="text-lg font-black text-indigo-600 tabular-nums tracking-tighter leading-none">{formatStopwatchTime(lap.total)}</p>
              </div>
            </motion.div>
          )}
        />

        {/* Config Sidebar Card */}
        <AnimatePresence>
          {isConfigOpen && (
            <motion.div 
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              className="overflow-hidden shrink-0"
            >
              <div className="tool-sidebar-card-flush p-0 space-y-0">
                <div className="tool-history-header">
                  <div className="flex items-center gap-2">
                    <Settings2 size={16} className="text-indigo-400" />
                    <h4 className="mb-0">Audio Config</h4>
                  </div>
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={() => setIsMuted(!isMuted)} 
                      className="tool-history-button"
                    >
                      {isMuted ? <VolumeX size={14} /> : <Volume2 size={14} />}
                    </button>
                  </div>
                </div>

                <div className="p-4 space-y-4">
                  <div className="grid grid-cols-4 gap-1.5">
                    {soundThemes.map(theme => (
                      <button
                        key={theme}
                        onClick={() => {
                          setTickSound(theme);
                          audioEngine.playTick(theme);
                        }}
                        className={`py-1.5 rounded-lg text-[7px] font-black uppercase tracking-tighter transition-all border-2 ${
                          tickSound === theme 
                            ? 'bg-indigo-600 border-indigo-500 text-white shadow-md' 
                            : 'bg-slate-50 border-white text-slate-400 hover:text-indigo-600'
                        }`}
                      >
                        {theme}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Main Chronometer Stage */}
      <div className="flex-1 tool-stage p-0 relative overflow-hidden bg-white border-none rounded-[4rem] group/stage flex flex-col items-center justify-center">
        <div className="tool-grid-bg opacity-30" />

        <div className="relative z-10 flex flex-col items-center gap-24 py-20 w-full max-w-4xl">
            <div className="w-full max-w-xl px-8 h-24 md:h-32 rounded-[2rem] border-4 border-slate-50 transition-all duration-500 relative group overflow-hidden flex items-center justify-center shadow-lg bg-white">
              <div className="tool-grid-bg opacity-10" />
              <div className="absolute inset-0 bg-indigo-500/5 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

              <div className="relative z-10 flex items-center gap-2 md:gap-4 scale-95 md:scale-110">
                <div className="flex items-center gap-2 md:gap-3">
                  {/* Minutes */}
                  <div className="relative flex flex-col items-center">
                    <div className="text-6xl md:text-8xl font-black tabular-nums tracking-tighter leading-none italic text-blue-600 drop-shadow-[0_0_15px_rgba(37,99,235,0.3)]">
                      {Math.floor(time / 60000).toString().padStart(2, '0')}
                    </div>
                  </div>

                  <div className="flex flex-col gap-1.5 opacity-10">
                    <div className="w-1.5 h-1.5 rounded-full bg-slate-900" />
                    <div className="w-1.5 h-1.5 rounded-full bg-slate-900" />
                  </div>

                  {/* Seconds */}
                  <div className="relative flex flex-col items-center">
                    <div className="text-6xl md:text-8xl font-black tabular-nums tracking-tighter leading-none italic text-red-500 drop-shadow-[0_0_10px_rgba(239,68,68,0.3)]">
                      {Math.floor((time % 60000) / 1000).toString().padStart(2, '0')}
                    </div>
                  </div>
                </div>

                <div className="flex flex-col gap-1.5 opacity-10">
                  <div className="w-1.5 h-1.5 rounded-full bg-slate-900" />
                  <div className="w-1.5 h-1.5 rounded-full bg-slate-900" />
                </div>

                {/* Centiseconds */}
                <div className="relative flex flex-col items-center">
                  <div className="text-4xl md:text-5xl font-black tabular-nums tracking-tighter leading-none italic text-slate-400">
                    {Math.floor((time % 1000) / 10).toString().padStart(2, '0')}
                  </div>
                </div>
              </div>
            </div>

           <div className="flex items-center gap-12 scale-110">
              <button
                onClick={addLap}
                disabled={!isRunning && time === 0}
                className="w-32 h-32 flex flex-col items-center justify-center gap-2 bg-white border-8 border-slate-100 rounded-[3.5rem] text-slate-300 hover:text-indigo-600 hover:border-indigo-100 transition-all group/lap shadow-xl active:scale-90"
              >
                <Flag size={36} className="group-hover/lap:-rotate-12 transition-all" />
                <span className="text-[11px] font-black uppercase tracking-widest italic">Lap</span>
              </button>

              <button
                onClick={toggle}
                className={`w-48 h-48 rounded-[5rem] flex items-center justify-center transition-all shadow-[0_64px_128px_-32px_rgba(0,0,0,0.4)] active:scale-95 border-[16px] ${
                  isRunning 
                    ? 'bg-rose-500 text-white border-rose-400/50 shadow-rose-900/50 hover:bg-rose-600' 
                    : 'bg-slate-950 text-white border-slate-800 shadow-slate-900/50 hover:bg-indigo-600'
                }`}
              >
                {isRunning ? (
                  <Pause size={80} fill="currentColor" strokeWidth={0} />
                ) : (
                  <Play size={80} fill="currentColor" className="ml-4" strokeWidth={0} />
                )}
              </button>

              <button
                onClick={reset}
                className="w-32 h-32 flex flex-col items-center justify-center gap-2 bg-white border-8 border-slate-100 rounded-[3.5rem] text-slate-300 hover:text-rose-600 hover:border-rose-100 transition-all group/reset shadow-xl active:scale-90"
              >
                <RotateCcw size={36} className="group-hover/reset:rotate-180 transition-all duration-1000" />
                <span className="text-[11px] font-black uppercase tracking-widest italic">Purge</span>
              </button>
           </div>
        </div>
      </div>
    </div>
  );
};

export default StopWatch;

