              </div>
           </div>

           <div className="tool-card-dark p-5 flex flex-col gap-4 shadow-xl overflow-hidden relative group">
              <div className="absolute -right-8 -bottom-8 opacity-10 rotate-12 group-hover:rotate-0 transition-transform duration-700">
                 <Brain size={120} />
              </div>
              <div className="flex items-center gap-2 font-black uppercase text-[10px] tracking-widest opacity-60">
                <Sparkles size={14} className="text-amber-400" /> Pro Tip
              </div>
              <p className="text-[11px] font-bold text-slate-300 leading-relaxed relative z-10">
                On Easy and Medium, conflicting cells are marked with red to help you learn the patterns. Hard mode is for true masters!
              </p>
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  TrendingUp, 
  Plus, 
  Trash2, 
  Settings2, 
  RotateCcw,
  Calculator,
  MousePointer2,
  X,
  Target,
  Hash,
  Activity,
  Sparkles,
  Maximize2,
  ChevronRight,
  Monitor,
  Terminal,
  Database
} from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';
import { Parser } from 'expr-eval';

const parser = new Parser();

const prepareFormula = (f) => {
  return f
    .replace(/(\d)([a-z])/gi, '$1*$2') // 2x -> 2*x
    .replace(/\)\(/g, ')*(')           // (x+1)(x+2) -> (x+1)*(x+2)
    .replace(/([a-z])\(/gi, '$1*(')     // x(x+1) -> x*(x+1)
    .replace(/\)([\d])/g, ')*$1');      // (x+1)2 -> (x+1)*2
};

const getRandomColor = () => `hsl(${Math.random() * 360}, 75%, 50%)`;

export const TeacherMath = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [elements, setElements] = useState([
    { id: 1, raw: '(2, 3)', color: '#6366f1' },
    { id: 2, raw: '(-4, 1)', color: '#ec4899' },
    { id: 3, raw: 'x', color: '#10b981' },
    { id: 'initial-empty', raw: '', color: getRandomColor() }
  ]);

  const [gridConfig, setGridConfig] = useState({
    range: 10,
    step: 1,
    showLabels: true
  });

  const [showConfig, setShowConfig] = useState(false);

  const svgRef = useRef(null);
  const size = 1000;
  const padding = 60;
  const innerSize = size - padding * 2;
  const center = size / 2;
  const scale = innerSize / (gridConfig.range * 2);

  const toSvgX = (cartX) => center + cartX * scale;
  const toSvgY = (cartY) => center - cartY * scale;
  const toCartX = (svgX) => (svgX - center) / scale;
  const toCartY = (svgY) => (center - svgY) / scale;

  const parsedElements = useMemo(() => {
    let pointCount = 0;
    return elements.map(el => {
      const clean = el.raw.trim();
      if (!clean) return { ...el, type: 'empty' };

      const pointMatch = clean.match(/^\s*\((-?\d*\.?\d+)\s*,\s*(-?\d*\.?\d+)\)\s*$/);
      if (pointMatch) {
        const label = String.fromCharCode(65 + (pointCount % 26));
        pointCount++;
        return {
          ...el,
          type: 'point',
          x: parseFloat(pointMatch[1]),
          y: parseFloat(pointMatch[2]),
          label
        };
      }

      try {
        let f = clean;
        if (f.toLowerCase().startsWith('y=') || f.toLowerCase().startsWith('y =')) {
          f = f.substring(f.indexOf('=') + 1).trim();
        }

        const prepared = prepareFormula(f);
        const compiled = parser.parse(prepared);
        compiled.evaluate({ x: 0 }); 
        return { ...el, type: 'formula', formula: f, compiled, displayFormula: `y = ${f}` };
      } catch (err) {
        return { ...el, type: 'error', error: 'Invalid format' };
      }
    });
  }, [elements]);

  const handleSvgClick = (e) => {
    const rect = svgRef.current.getBoundingClientRect();
    const scaleX = size / rect.width;
    const scaleY = size / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    const cartX = Math.round(toCartX(x) * 2) / 2;
    const cartY = Math.round(toCartY(y) * 2) / 2;

    if (Math.abs(cartX) <= gridConfig.range && Math.abs(cartY) <= gridConfig.range) {
      const newPoint = {
        id: Date.now(),
        raw: `(${cartX}, ${cartY})`,
        color: getRandomColor()
      };
      const newElements = [...elements];
      newElements.splice(newElements.length - 1, 0, newPoint);
      setElements(newElements);
      audioEngine.playTick(settings.soundTheme);
    }
  };

  const updateElement = (id, newRaw) => {
    setElements(prev => {
      const index = prev.findIndex(e => e.id === id);
      const newElements = [...prev];
      newElements[index] = { ...newElements[index], raw: newRaw };
      if (index === prev.length - 1 && newRaw.trim() !== '') {
        newElements.push({ id: Date.now(), raw: '', color: getRandomColor() });
      }
      return newElements;
    });
  };

  const removeElement = (id) => {
    if (elements.length <= 1) {
      setElements([{ id: Date.now(), raw: '', color: getRandomColor() }]);
      return;
    }
    setElements(elements.filter(e => e.id !== id));
    audioEngine.playTick(settings.soundTheme);
  };

  const renderGrid = () => {
    const lines = [];
    const range = gridConfig.range;
    const step = gridConfig.step;

    for (let i = -range; i <= range; i += step) {
      const pos = toSvgX(i);
      const isAxis = i === 0;
      lines.push(
        <line key={`v-${i}`} x1={pos} y1={padding} x2={pos} y2={size - padding} stroke={isAxis ? '#1e293b' : '#f1f5f9'} strokeWidth={isAxis ? 4 : 2} strokeOpacity={isAxis ? 1 : 0.5} />
      );
      const yPos = toSvgY(i);
      lines.push(
        <line key={`h-${i}`} x1={padding} y1={yPos} x2={size - padding} y2={yPos} stroke={isAxis ? '#1e293b' : '#f1f5f9'} strokeWidth={isAxis ? 4 : 2} strokeOpacity={isAxis ? 1 : 0.5} />
      );

      if (gridConfig.showLabels && i !== 0) {
        lines.push(<text key={`xl-${i}`} x={pos} y={center + 24} textAnchor="middle" className="text-[12px] font-black fill-slate-300 tabular-nums">{i}</text>);
        lines.push(<text key={`yl-${i}`} x={center - 24} y={yPos + 5} textAnchor="end" className="text-[12px] font-black fill-slate-300 tabular-nums">{i}</text>);
      }
    }
    lines.push(<text key="origin" x={center - 15} y={center + 24} textAnchor="end" className="text-[12px] font-black fill-slate-400">0</text>);
    return lines;
  };

  const renderFormulaPath = (compiled) => {
    try {
      const points = [];
      const range = gridConfig.range;
      const step = range / 100;
      for (let x = -range; x <= range; x += step) {
        const y = compiled.evaluate({ x });
        if (Math.abs(y) > range * 5) continue;
        points.push(`${toSvgX(x)},${toSvgY(y)}`);
      }
      return points.join(' ');
    } catch (e) { return ''; }
  };

  useEffect(() => {
    setOnReset(() => () => {
      setElements([{ id: Date.now(), raw: '', color: getRandomColor() }]);
      audioEngine.playTick(settings.soundTheme);
    });
    return () => clearHeader();
  }, [clearHeader, setOnReset, settings.soundTheme]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <button
          onClick={() => { setShowConfig(!showConfig); audioEngine.playTick(settings.soundTheme); }}
          className={`flex items-center gap-2 px-8 py-2 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] transition-all active:scale-95 shadow-lg italic ${
            showConfig 
              ? 'bg-slate-900 text-white shadow-slate-200' 
              : 'bg-white text-slate-400 border-2 border-slate-100 hover:border-indigo-100 hover:text-indigo-600'
          }`}
        >
          {showConfig ? <X size={14} /> : <Settings2 size={14} />} Config Axis
        </button>
      </div>
    );
  }, [showConfig, settings.soundTheme, setHeaderActions]);

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      {/* Equation Sidebar */}
      <div className="w-full lg:w-[420px] flex flex-col gap-6 shrink-0 h-full overflow-hidden">
        <div className="tool-sidebar-card flex-1 p-10 flex flex-col">
           <div className="flex items-center justify-between mb-10 shrink-0">
              <div className="flex items-center gap-3">
                 <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 border border-slate-100">
                    <Terminal size={18} />
                 </div>
                 <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Synthesis Console</h4>
              </div>
              <button 
                onClick={() => { setElements([{ id: Date.now(), raw: '', color: getRandomColor() }]); audioEngine.playTick(settings.soundTheme); }} 
                className="p-3 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-all"
              >
                <Trash2 size={18} />
              </button>
           </div>

           <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar no-scrollbar space-y-4">
              <AnimatePresence initial={false}>
                {elements.map((element, index) => {
                  const parsed = parsedElements[index];
                  const isInvalid = parsed.type === 'error';
                  const isPoint = parsed.type === 'point';
                  const isFormula = parsed.type === 'formula';

                  return (
                    <motion.div
                      key={element.id}
                      initial={{ opacity: 0, x: -20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, scale: 0.9 }}
                      className={`p-6 rounded-[2.5rem] border-4 transition-all flex flex-col gap-4 italic ${isInvalid ? 'border-rose-100 bg-rose-50/20' : 'border-slate-50 bg-white focus-within:border-indigo-100 focus-within:shadow-2xl'}`}
                    >
                      <div className="flex items-center gap-6">
                        <div className="w-12 h-12 rounded-2xl shadow-inner shrink-0 flex items-center justify-center text-white font-black" style={{ backgroundColor: element.raw.trim() ? element.color : '#f1f5f9' }}>
                           {isPoint ? <Target size={20} /> : isFormula ? <TrendingUp size={20} /> : <Calculator size={20} className="opacity-20" />}
                        </div>
                        <div className="flex-1 min-w-0">
                           <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] leading-none mb-2">{isPoint ? 'Coordinate Node' : isFormula ? 'Linear Logic' : 'Awaiting Matrix'}</p>
                           <input
                             type="text"
                             value={element.raw}
                             onChange={(e) => updateElement(element.id, e.target.value)}
                             onKeyDown={(e) => e.key === 'Enter' && e.currentTarget.blur()}
                             placeholder={index === elements.length - 1 ? "Initialize node..." : "y = mx + b or (x, y)"}
                             className="w-full bg-transparent border-none focus:ring-0 text-xl font-black font-mono text-slate-700 placeholder:text-slate-200 p-0 leading-none"
                           />
                        </div>
                        {index < elements.length - 1 && (
                          <button onClick={() => removeElement(element.id)} className="w-10 h-10 flex items-center justify-center text-slate-200 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all shrink-0">
                            <X size={20} />
                          </button>
                        )}
                      </div>
                      {isInvalid && element.raw.trim() && (
                        <div className="flex items-center gap-3 px-2 border-t border-rose-100 pt-3">
                           <div className="w-1.5 h-1.5 rounded-full bg-rose-500 animate-pulse" />
                           <p className="text-[9px] text-rose-500 font-black uppercase tracking-[0.2em]">Invalid Data Stream Pattern</p>
                        </div>
                      )}
                    </motion.div>
                  );
                })}
              </AnimatePresence>
           </div>

           <div className="mt-10 pt-10 border-t border-slate-50 shrink-0 space-y-6">
              <div className="p-8 bg-slate-900 rounded-[3rem] shadow-[0_50px_100px_-20px_rgba(0,0,0,0.3)] border-4 border-slate-800 relative group overflow-hidden">
                 <div className="tool-grid-bg-dark opacity-10" />
                 <div className="absolute inset-0 bg-indigo-500/10 blur-3xl opacity-0 group-hover:opacity-100 transition-opacity" />

                 <div className="relative z-10 flex flex-col gap-4">
                    <div className="flex items-center justify-between">
                       <span className="text-[10px] font-black text-white/30 uppercase tracking-[0.4em] italic leading-none">Manifest Count</span>
                       <span className="text-3xl font-black text-white italic tabular-nums tracking-tighter leading-none">{elements.filter(e => e.raw.trim()).length}</span>
                    </div>
                    <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                       <motion.div 
                        className="h-full bg-indigo-500 shadow-[0_0_12px_rgba(99,102,241,1)]"
                        initial={false}
                        animate={{ width: `${(elements.filter(e => e.raw.trim()).length / 10) * 100}%` }}
                       />
                    </div>
                 </div>
              </div>

              <div className="flex items-center gap-4 group">
                 <div className="w-10 h-10 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-300 group-hover:bg-indigo-50 group-hover:text-indigo-400 transition-all shadow-sm">
                    <Database size={18} />
                 </div>
                 <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Matrix Reference</span>
                    <span className="text-[11px] font-bold text-slate-300 italic uppercase">Syntax: (x, y) or y=x</span>
                 </div>
              </div>
           </div>
        </div>
      </div>

      {/* Main Axis Stage */}
      <div className="flex-1 tool-stage p-0 relative overflow-hidden bg-white border-none rounded-[4rem] group/stage flex items-center justify-center">
        <div className="tool-grid-bg opacity-30" />

        {/* Decorative Grid */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-[0.03] group-hover/stage:opacity-[0.05] transition-opacity duration-1000">
           <Monitor size={600} className="text-slate-900" strokeWidth={0.05} />
        </div>

        {/* HUD Controls Overlay */}
        <div className="absolute top-12 left-12 flex flex-col gap-6 z-20">
           <div className="flex items-center gap-4 px-8 py-4 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border-4 border-white/60 shadow-xl group/hud hover:border-indigo-100 transition-all">
              <div className="w-3 h-3 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_20px_rgba(79,70,229,1)]" />
              <div className="flex flex-col">
                 <span className="text-[11px] font-black text-slate-800 uppercase tracking-[0.6em] italic leading-none mb-1">Observation Plane</span>
                 <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.4em] italic leading-none">Resolution: ±{gridConfig.range} Units</span>
              </div>
           </div>
        </div>

        <AnimatePresence>
          {showConfig && (
            <motion.div 
              initial={{ opacity: 0, scale: 0.9, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9, y: 20 }}
              className="absolute bottom-12 left-12 right-12 z-[30] flex items-center gap-12 bg-slate-900/95 backdrop-blur-3xl px-16 py-10 rounded-[4rem] border-4 border-slate-800 shadow-[0_80px_160px_-40px_rgba(0,0,0,0.8)]"
            >
              <div className="flex flex-col gap-6 flex-1">
                <div className="flex items-center justify-between">
                  <span className="text-[12px] font-black text-indigo-400 uppercase tracking-[0.4em] italic flex items-center gap-3 leading-none"><Maximize2 size={18} /> Axis Resolution</span>
                  <span className="text-2xl font-black text-white tabular-nums italic tracking-tighter leading-none">±{gridConfig.range}</span>
                </div>
                <div className="flex items-center gap-10">
                  <span className="text-[10px] font-black text-white/20 italic tracking-widest leading-none">05</span>
                  <div className="flex-1 relative flex items-center">
                    <input 
                      type="range" 
                      min="5" max="50" step="5" 
                      value={gridConfig.range} 
                      onChange={(e) => setGridConfig({ ...gridConfig, range: parseInt(e.target.value) })} 
                      className="w-full accent-indigo-500 h-2 bg-white/10 rounded-full appearance-none cursor-pointer" 
                    />
                  </div>
                  <span className="text-[10px] font-black text-white/20 italic tracking-widest leading-none">50</span>
                </div>
              </div>

              <div className="w-px h-24 bg-white/10" />

              <div className="flex items-center gap-10">
                <div className="flex flex-col gap-2">
                   <span className="text-[11px] font-black text-white/40 uppercase tracking-[0.4em] italic leading-none">Telemetry</span>
                   <p className="text-[10px] text-white/20 font-black uppercase tracking-widest leading-none italic">Display Numeric Tags</p>
                </div>
                <button 
                  onClick={() => { setGridConfig({ ...gridConfig, showLabels: !gridConfig.showLabels }); audioEngine.playTick(settings.soundTheme); }} 
                  className={`w-16 h-10 rounded-full relative transition-all border-4 ${gridConfig.showLabels ? 'bg-indigo-600 border-indigo-400/50' : 'bg-white/10 border-white/5'}`}
                >
                  <motion.div 
                    animate={{ left: gridConfig.showLabels ? '28px' : '4px' }}
                    className="absolute top-1 w-6 h-6 bg-white rounded-full shadow-2xl" 
                  />
                </button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        <div className="w-full max-w-[950px] aspect-square flex items-center justify-center p-12">
           <svg 
            ref={svgRef}
            viewBox={`0 0 ${size} ${size}`}
            className="w-full h-full cursor-crosshair select-none drop-shadow-[0_48px_96px_rgba(0,0,0,0.1)]"
            onClick={handleSvgClick}
          >
            <defs>
              <filter id="plot-glow" x="-20%" y="-20%" width="140%" height="140%">
                 <feGaussianBlur stdDeviation="6" result="coloredBlur"/>
                 <feMerge>
                    <feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/>
                 </feMerge>
              </filter>
            </defs>

            {renderGrid()}

            {parsedElements.map(el => {
              if (el.type === 'formula') {
                const pathData = renderFormulaPath(el.compiled);
                if (!pathData) return null;
                return (
                  <motion.polyline
                    key={`svg-f-${el.id}`}
                    initial={{ pathLength: 0, opacity: 0 }}
                    animate={{ pathLength: 1, opacity: 1 }}
                    transition={{ duration: 1.5, ease: "easeInOut" }}
                    points={pathData}
                    stroke={el.color}
                    strokeWidth="10"
                    fill="none"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    style={{ filter: 'url(#plot-glow)' }}
                  />
                );
              }
              if (el.type === 'point') {
                return (
                  <motion.g
                    key={`svg-p-${el.id}`}
                    initial={{ scale: 0 }}
                    animate={{ scale: 1, x: toSvgX(el.x), y: toSvgY(el.y) }}
                    transition={{ type: 'spring', damping: 12 }}
                  >
                    <circle r="14" fill={el.color} stroke="white" strokeWidth="5" style={{ filter: 'url(#plot-glow)' }} />
                    <text y="-40" textAnchor="middle" className="text-[24px] font-black fill-slate-800 uppercase tracking-tighter italic" style={{ pointerEvents: 'none' }}>
                      {el.label} ({el.x}, {el.y})
                    </text>
                  </motion.g>
                );
              }
              return null;
            })}
          </svg>
        </div>

        {/* Interaction Guide */}
        <div className="absolute bottom-12 right-12 flex items-center gap-6 z-20 pointer-events-none opacity-40 italic">
           <div className="text-right">
              <p className="text-[11px] font-black uppercase tracking-[0.6em]">Manual Node Deployment</p>
              <p className="text-[11px] font-black uppercase tracking-[0.4em] mt-1">Tap stage to extract coordinates</p>
           </div>
           <div className="w-12 h-12 rounded-2xl bg-white/50 border-2 border-white flex items-center justify-center shadow-inner">
              <MousePointer2 size={24} className="text-slate-400" />
           </div>
        </div>
      </div>
    </div>
  );
};

export default TeacherMath;

