import React, { useState, useEffect, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Thermometer, Zap, RotateCcw, Info, Hand, Play, Maximize2, TrendingUp, Activity, FlaskConical, X } from 'lucide-react';
import { LineChart } from 'chartist';
import 'chartist/dist/index.css';
import { useHeader } from '../../contexts/HeaderContext';

const PARTICLE_SPACING = 20;

export const ThermalConduction = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const canvasRef = useRef(null);
  const chartRef = useRef(null);
  const chartInstance = useRef(null);

  const createParticles = (energy, rows, cols) => {
    const particles = [];
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        particles.push({ r, c, energy });
      }
    }
    return particles;
  };

  const [blocks, setBlocks] = useState([
    { id: 1, label: 'A', rows: 10, cols: 10, x: 100, y: 100, particles: createParticles(100, 10, 10), isDragging: false, color: '#ef4444' },
    { id: 2, label: 'B', rows: 20, cols: 5, x: 450, y: 100, particles: createParticles(10, 20, 5), isDragging: false, color: '#3b82f6' },
    { id: 3, label: 'C', rows: 5, cols: 20, x: 100, y: 550, particles: createParticles(10, 5, 20), isDragging: false, color: '#10b981' },
  ]);
  const [history, setHistory] = useState([]);

  const blocksRef = useRef(blocks);
  const dragOffset = useRef({ x: 0, y: 0 });
  const draggedBlockId = useRef(null);
  const requestRef = useRef();

  const getAvgEnergy = (block) => {
    if (!block.particles.length) return 0;
    return block.particles.reduce((acc, p) => acc + p.energy, 0) / block.particles.length;
  };

  // Update state for UI and history
  useEffect(() => {
    const timer = setInterval(() => {
      setBlocks([...blocksRef.current]);
    }, 50);

    const historyTimer = setInterval(() => {
      setHistory(prev => {
        if (blocksRef.current.length < 3) return prev;
        const entry = {
          time: prev.length,
          A: getAvgEnergy(blocksRef.current[0]),
          B: getAvgEnergy(blocksRef.current[1]),
          C: getAvgEnergy(blocksRef.current[2]),
        };
        return [...prev, entry].slice(-50);
      });
    }, 500);

    return () => {
      clearInterval(timer);
      clearInterval(historyTimer);
    };
  }, []);

  // Update Chart
  useEffect(() => {
    if (history.length > 1 && chartRef.current) {
      const data = {
        labels: history.map(h => h.time),
        series: [
          history.map(h => h.A),
          history.map(h => h.B),
          history.map(h => h.C),
        ]
      };

      const options = {
        showPoint: false,
        lineSmooth: true,
        axisX: { showGrid: false, showLabel: false },
        axisY: { low: 0, high: 100, showGrid: true },
        fullWidth: true,
        chartPadding: { right: 10, left: 0, top: 0, bottom: 0 }
      };

      if (!chartInstance.current) {
        chartInstance.current = new LineChart(chartRef.current, data, options);
      } else {
        chartInstance.current.update(data);
      }
    }
  }, [history]);

  // Color interpolation
  const getColor = (energy) => {
    const r = Math.min(255, Math.floor((energy / 100) * 255));
    const b = Math.min(255, Math.floor((1 - energy / 100) * 255));
    const g = 50;
    return `rgb(${r}, ${g}, ${b})`;
  };

  const animate = useCallback((time) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const currentBlocks = blocksRef.current;

    // 1. Heat Transfer Logic (Internal Conduction)
    currentBlocks.forEach(block => {
      for (let i = 0; i < block.particles.length; i++) {
        for (let j = i + 1; j < block.particles.length; j++) {
          const p1 = block.particles[i];
          const p2 = block.particles[j];
          const dist = Math.abs(p1.r - p2.r) + Math.abs(p1.c - p2.c);
          if (dist === 1) { // Adjacency
            const transfer = (p1.energy - p2.energy) * 0.05;
            p1.energy -= transfer;
            p2.energy += transfer;
          }
        }
      }
    });

    // 2. Heat Transfer Logic (External Conduction between blocks)
    for (let i = 0; i < currentBlocks.length; i++) {
      for (let j = i + 1; j < currentBlocks.length; j++) {
        const b1 = currentBlocks[i];
        const b2 = currentBlocks[j];

        const b1w = b1.cols * PARTICLE_SPACING;
        const b1h = b1.rows * PARTICLE_SPACING;
        const b2w = b2.cols * PARTICLE_SPACING;
        const b2h = b2.rows * PARTICLE_SPACING;

        // Check for rough collision
        if (Math.abs(b1.x + b1w/2 - (b2.x + b2w/2)) < (b1w + b2w)/2 + 20 && 
            Math.abs(b1.y + b1h/2 - (b2.y + b2h/2)) < (b1h + b2h)/2 + 20) {
          b1.particles.forEach(p1 => {
            const p1x = b1.x + p1.c * PARTICLE_SPACING;
            const p1y = b1.y + p1.r * PARTICLE_SPACING;

            b2.particles.forEach(p2 => {
              const p2x = b2.x + p2.c * PARTICLE_SPACING;
              const p2y = b2.y + p2.r * PARTICLE_SPACING;

              const dx = p1x - p2x;
              const dy = p1y - p2y;
              if (dx*dx + dy*dy < PARTICLE_SPACING * PARTICLE_SPACING * 1.5) {
                const transfer = (p1.energy - p2.energy) * 0.01;
                p1.energy -= transfer;
                p2.energy += transfer;
              }
            });
          });
        }
      }
    }

    // 3. Render Blocks
    currentBlocks.forEach(block => {
      const { x, y, label, particles, rows, cols } = block;
      const w = cols * PARTICLE_SPACING;
      const h = rows * PARTICLE_SPACING;

      // Draw Particles
      particles.forEach(p => {
        const energy = p.energy;
        const color = getColor(energy);
        const vibrationAmp = (energy / 100) * 4;
        const vibrationSpeed = 0.01 * energy;

        const px = x + p.c * PARTICLE_SPACING + PARTICLE_SPACING/2;
        const py = y + p.r * PARTICLE_SPACING + PARTICLE_SPACING/2;

        const ox = Math.sin(time * vibrationSpeed + p.r + p.c) * vibrationAmp;
        const oy = Math.cos(time * vibrationSpeed * 0.9 + p.r * p.c) * vibrationAmp;

        ctx.beginPath();
        ctx.arc(px + ox, py + oy, 6, 0, Math.PI * 2);
        ctx.fillStyle = color;
        ctx.shadowBlur = energy / 5;
        ctx.shadowColor = color;
        ctx.fill();
        ctx.shadowBlur = 0;

        ctx.beginPath();
        ctx.arc(px + ox - 2, py + oy - 2, 2, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,255,255,0.3)';
        ctx.fill();
      });

      // Draw Rough Outline
      ctx.strokeStyle = 'rgba(255,255,255,0.4)';
      ctx.lineWidth = 2;
      ctx.lineJoin = 'round';

      const jitter = () => (Math.random() - 0.5) * 3; // eslint-disable-line react-hooks/purity
      ctx.beginPath();
      ctx.moveTo(x + jitter(), y + jitter());
      ctx.lineTo(x + w + jitter(), y + jitter());
      ctx.lineTo(x + w + jitter(), y + h + jitter());
      ctx.lineTo(x + jitter(), y + h + jitter());
      ctx.closePath();
      ctx.stroke();

      // Label
      ctx.font = '900 24px Outfit, system-ui, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillStyle = 'rgba(255,255,255,0.8)';
      ctx.fillText(label, x + w/2, y + h/2 + 8);

      if (block.isDragging) {
        ctx.strokeStyle = 'rgba(255,255,255,0.8)';
        ctx.setLineDash([5, 5]);
        ctx.strokeRect(x - 5, y - 5, w + 10, h + 10);
        ctx.setLineDash([]);
      }
    });

    requestRef.current = requestAnimationFrame(animate);
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    const handleResize = () => {
      canvas.width = canvas.parentElement.clientWidth;
      canvas.height = canvas.parentElement.clientHeight;
    };
    window.addEventListener('resize', handleResize);
    handleResize();

    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      window.removeEventListener('resize', handleResize);
    };
  }, [animate]);

  const handleMouseDown = (e) => {
    const rect = canvasRef.current.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;

    const hit = [...blocksRef.current].reverse().find(b => {
      const w = b.cols * PARTICLE_SPACING;
      const h = b.rows * PARTICLE_SPACING;
      return mx >= b.x && mx <= b.x + w && my >= b.y && my <= b.y + h;
    });

    if (hit) {
      draggedBlockId.current = hit.id;
      dragOffset.current = { x: mx - hit.x, y: my - hit.y };
      const newBlocks = blocksRef.current.map(b => 
        b.id === hit.id ? { ...b, isDragging: true } : b
      );
      blocksRef.current = newBlocks;
      setBlocks(newBlocks);
    }
  };

  const handleMouseMove = (e) => {
    if (draggedBlockId.current === null) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;

    const newBlocks = blocksRef.current.map(b => {
      if (b.id === draggedBlockId.current) {
        return { 
          ...b, 
          x: mx - dragOffset.current.x, 
          y: my - dragOffset.current.y 
        };
      }
      return b;
    });
    blocksRef.current = newBlocks;
    setBlocks(newBlocks);
  };

  const handleMouseUp = () => {
    if (draggedBlockId.current === null) return;
    const newBlocks = blocksRef.current.map(b => ({ ...b, isDragging: false }));
    blocksRef.current = newBlocks;
    setBlocks(newBlocks);
    draggedBlockId.current = null;
  };

  const reset = useCallback(() => {
    const initial = [
      { id: 1, label: 'A', rows: 10, cols: 10, x: 100, y: 100, particles: createParticles(100, 10, 10), isDragging: false, color: '#ef4444' },
      { id: 2, label: 'B', rows: 20, cols: 5, x: 450, y: 100, particles: createParticles(10, 20, 5), isDragging: false, color: '#3b82f6' },
      { id: 3, label: 'C', rows: 5, cols: 20, x: 100, y: 550, particles: createParticles(10, 5, 20), isDragging: false, color: '#10b981' },
    ];
    blocksRef.current = initial;
    setBlocks(initial);
  }, []);

  useEffect(() => {
    setOnReset(() => reset);
    return () => clearHeader();
  }, [clearHeader, setOnReset, reset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <div className="hidden md:flex items-center gap-6 px-4 py-2 bg-slate-50 border-2 border-slate-100 rounded-xl">
           <div className="flex items-center gap-2">
              <div className="w-2.5 h-2.5 rounded-full bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.5)] animate-pulse" />
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Excited</span>
           </div>
           <div className="flex items-center gap-2">
              <div className="w-2.5 h-2.5 rounded-full bg-blue-500" />
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Stable</span>
           </div>
        </div>
        <button
          onClick={reset}
          className="flex items-center gap-2 px-4 py-2 bg-white border-2 border-slate-100 text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-widest hover:border-rose-100 hover:text-rose-600 transition-all active:scale-95 shadow-sm"
        >
          <RotateCcw size={14} /> Reset Lab
        </button>
      </div>
    );
  }, [setHeaderActions, reset]);

  return (
    <div className="tool-container flex flex-col gap-6 p-6 flex-1 overflow-hidden font-['Outfit'] select-none">

      <div className="flex-1 flex flex-col lg:flex-row gap-6 min-h-0 overflow-hidden">
        {/* Lab Area */}
        <div className="flex-[2.5] flex flex-col gap-6 min-h-0 min-w-0">
          <div 
            className="flex-1 tool-card bg-[#0f172a] p-0 relative overflow-hidden border-4 border-slate-800 shadow-indigo-900/10 cursor-grab active:cursor-grabbing group"
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
          >
            <canvas ref={canvasRef} className="w-full h-full" />

            <div className="absolute top-8 left-8 flex items-center gap-3 bg-black/40 backdrop-blur-md px-5 py-2.5 rounded-2xl border border-white/5 opacity-0 group-hover:opacity-100 transition-all duration-500 pointer-events-none translate-y-2 group-hover:translate-y-0">
               <Hand size={16} className="text-amber-400" />
               <span className="text-[10px] font-black text-white/80 uppercase tracking-widest">Connect blocks to conduct</span>
            </div>

            <div className="absolute bottom-8 right-8">
               <div className="bg-black/40 backdrop-blur-md px-5 py-3 rounded-[2rem] border border-white/5 flex items-center gap-4">
                  <div className="flex flex-col items-end">
                    <span className="text-[9px] font-black text-white/40 uppercase tracking-widest">System Entropy</span>
                    <span className="text-xs font-black text-white/90 tracking-tighter">Thermal Kinetic Model</span>
                  </div>
                  <div className="w-px h-8 bg-white/10" />
                  <Activity size={20} className="text-rose-500 animate-pulse" />
               </div>
            </div>
          </div>

          <div className="tool-card bg-white p-8 flex flex-col gap-8">
            <div className="flex items-center gap-3">
               <div className="w-10 h-10 rounded-xl bg-rose-50 flex items-center justify-center text-rose-500">
                  <Activity size={20} />
               </div>
               <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Kinetic Energy Matrix</h3>
            </div>
            <div className="grid grid-cols-3 gap-6">
              {blocks.map((block) => (
                <div key={block.id} className="space-y-3">
                  <div className="flex justify-between items-end px-1">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Matrix {block.label}</span>
                    <span className="text-lg font-black text-slate-800 tabular-nums italic">{Math.round(getAvgEnergy(block))}°</span>
                  </div>
                  <div className="h-4 bg-slate-50 rounded-full overflow-hidden p-1 border border-slate-100">
                    <motion.div 
                      className="h-full rounded-full shadow-lg"
                      initial={false}
                      animate={{ 
                        width: `${getAvgEnergy(block)}%`,
                        backgroundColor: getColor(getAvgEnergy(block)),
                        boxShadow: `0 0 10px ${getColor(getAvgEnergy(block))}44`
                      }}
                      transition={{ type: 'spring', bounce: 0, duration: 0.1 }}
                    />
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Sidebar Controls */}
        <div className="flex-1 flex flex-col gap-6 overflow-y-auto custom-scrollbar">
          <div className="tool-card bg-white p-8 flex flex-col gap-8">
            <div className="flex items-center gap-3">
               <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center text-amber-500">
                  <TrendingUp size={20} />
               </div>
               <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">Thermal Trends</h3>
            </div>
            <div className="h-48 w-full bg-slate-50 rounded-[2rem] border-2 border-slate-100 p-4 relative overflow-hidden">
               {history.length > 1 ? (
                 <div ref={chartRef} className="ct-chart h-full w-full custom-thermal-chart" />
               ) : (
                 <div className="h-full flex flex-col items-center justify-center gap-3 opacity-30">
                    <Activity size={32} className="text-slate-400" />
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic">Monitoring contact...</span>
                 </div>
               )}
            </div>
            <div className="flex justify-center gap-6">
               {['A', 'B', 'C'].map((label, i) => (
                 <div key={label} className="flex items-center gap-2">
                    <div className={`w-3 h-1 rounded-full ct-series-color-${i}`} />
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Block {label}</span>
                 </div>
               ))}
            </div>
          </div>

          <div className="tool-card bg-indigo-900 p-8 text-white flex flex-col gap-6 relative overflow-hidden group">
             <div className="absolute -right-12 -top-12 opacity-5 group-hover:rotate-12 transition-transform duration-1000">
                <FlaskConical size={200} />
             </div>
             <div className="flex items-center gap-3 relative z-10">
                <Info size={18} className="text-indigo-200" />
                <h3 className="text-lg font-black uppercase tracking-tight italic">Thermodynamics</h3>
             </div>
             <div className="space-y-4 relative z-10">
                <div className="bg-white/5 rounded-2xl p-5 border border-white/5 backdrop-blur-sm">
                   <h4 className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-2">Conduction Mechanism</h4>
                   <p className="text-[11px] font-medium text-indigo-50/70 leading-relaxed">
                      Energy transfers via physical collision between particles. High-energy atoms vibrate more violently, bumping neighbors and spreading kinetic heat.
                   </p>
                </div>
                <div className="bg-white/5 rounded-2xl p-5 border border-white/5 backdrop-blur-sm">
                   <h4 className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-2">Thermal Equilibrium</h4>
                   <p className="text-[11px] font-medium text-indigo-50/70 leading-relaxed">
                      Systems naturally drift towards a state where net energy transfer is zero—a uniform temperature across all connected matter.
                   </p>
                </div>
             </div>
          </div>
        </div>
      </div>
      <style dangerouslySetInnerHTML={{ __html: `
        .custom-thermal-chart .ct-series-a .ct-line { stroke: #ef4444; stroke-width: 4px; stroke-linecap: round; }
        .custom-thermal-chart .ct-series-b .ct-line { stroke: #3b82f6; stroke-width: 4px; stroke-linecap: round; }
        .custom-thermal-chart .ct-series-c .ct-line { stroke: #10b981; stroke-width: 4px; stroke-linecap: round; }
        .ct-series-color-0 { background-color: #ef4444; }
        .ct-series-color-1 { background-color: #3b82f6; }
        .ct-series-color-2 { background-color: #10b981; }
        .ct-grid { stroke: rgba(0,0,0,0.03); stroke-dasharray: 0; }
        .ct-label { color: #94a3b8; font-weight: 800; font-size: 9px; font-family: 'Outfit'; text-transform: uppercase; }
      `}} />
    </div>
  );
};

