import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  CheckCircle2, 
  XCircle, 
  Calculator, 
  Info, 
  RotateCcw,
  Sparkles,
  Zap,
  Activity,
  Award,
  Target,
  Hash,
  ChevronRight,
  Monitor,
  Layout,
  MousePointer2,
  TrendingUp,
  Grid
} from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';
import { useSettings } from '../../contexts/SettingsContext';
import { audioEngine } from '../../utils/audio';

export const TimesTable = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [selectedRows, setSelectedRows] = useState([2, 3, 4, 5, 10]);
  const [cellStates, setCellStates] = useState(() => {
    const saved = localStorage.getItem('teacherToolsTimesTableMastery');
    return saved ? JSON.parse(saved) : {};
  });
  const [sessionCount, setSessionCount] = useState(1);
  const [currentQuestion, setCurrentQuestion] = useState(null);
  const [userInput, setUserInput] = useState('');
  const [feedback, setFeedback] = useState(null);

  const inputRef = useRef(null);

  const drawNextQuestion = (rowsToConsider = selectedRows, states = cellStates) => {
    if (rowsToConsider.length === 0) {
      setCurrentQuestion(null);
      return;
    }

    let candidates = [];
    rowsToConsider.forEach(row => {
      for (let col = 1; col <= 12; col++) {
        const key = `${row}x${col}`;
        const state = states[key] || 'white';
        let weight = 0;

        if (state === 'orange') weight = 5;
        else if (state === 'white') weight = 3;
        else if (state === 'light-green') weight = 2;
        else if (state === 'dark-green') weight = 1;

        for (let w = 0; w < weight; w++) {
          candidates.push({ row, col, key });
        }
      }
    });

    if (candidates.length > 0) {
      const selected = candidates[Math.floor(Math.random() * candidates.length)];
      if (Math.random() > 0.5) {
        setCurrentQuestion({ a: selected.row, b: selected.col, row: selected.row, col: selected.col, key: selected.key });
      } else {
        setCurrentQuestion({ a: selected.col, b: selected.row, row: selected.row, col: selected.col, key: selected.key });
      }
    } else {
      setCurrentQuestion(null);
    }
  };

  useEffect(() => {
    if (!currentQuestion && selectedRows.length > 0) {
      drawNextQuestion(selectedRows, cellStates);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('teacherToolsTimesTableMastery', JSON.stringify(cellStates));
  }, [cellStates]);

  useEffect(() => {
    setOnReset(() => () => {
        setCellStates({});
        setSessionCount(1);
        setFeedback(null);
        audioEngine.playTick(settings.soundTheme);
    });
    return () => clearHeader();
  }, [clearHeader, setOnReset, settings.soundTheme]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        <button
          onClick={() => { setCellStates({}); setSessionCount(1); setFeedback(null); audioEngine.playTick(settings.soundTheme); }}
          className="flex items-center gap-2 px-8 py-2 bg-white text-slate-400 rounded-xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-rose-50 hover:text-rose-600 transition-all active:scale-95 border-2 border-slate-100 hover:border-rose-100 shadow-sm italic"
        >
          <RotateCcw size={14} /> Global Wipe
        </button>
      </div>
    );
  }, [settings.soundTheme, setHeaderActions]);

  const toggleRow = (num) => {
    let newRows;
    if (selectedRows.includes(num)) {
      newRows = selectedRows.filter(n => n !== num);
    } else {
      newRows = [...selectedRows, num].sort((a, b) => a - b);
    }
    setSelectedRows(newRows);
    audioEngine.playTick(settings.soundTheme);

    if (currentQuestion && !newRows.includes(currentQuestion.row)) {
      drawNextQuestion(newRows, cellStates);
      setFeedback(null);
    } else if (!currentQuestion && newRows.length > 0) {
      drawNextQuestion(newRows, cellStates);
    }

    setTimeout(() => inputRef.current?.focus(), 100);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!userInput.trim() || !currentQuestion) return;

    const answer = parseInt(userInput, 10);
    const correctAnswer = currentQuestion.a * currentQuestion.b;
    const key = currentQuestion.key;
    const currentState = cellStates[key] || 'white';

    let newState = currentState;

    if (answer === correctAnswer) {
      audioEngine.playTick(settings.soundTheme);
      setFeedback({ type: 'success', msg: 'Correct!', timestamp: Date.now() });

      if (currentState === 'white' || currentState === 'orange') newState = 'light-green';
      else if (currentState === 'light-green') newState = 'dark-green';
      else if (currentState === 'dark-green') newState = 'dark-green';

    } else {
      audioEngine.playTick(settings.soundTheme);
      setFeedback({ type: 'error', msg: `${currentQuestion.a} × ${currentQuestion.b} = ${correctAnswer}`, timestamp: Date.now() });
      newState = 'orange';
    }

    const nextCellStates = { ...cellStates, [key]: newState };
    setCellStates(nextCellStates);
    setSessionCount(prev => prev + 1);
    setUserInput('');
    drawNextQuestion(selectedRows, nextCellStates);

    setTimeout(() => inputRef.current?.focus(), 100);
  };

  const gridNumbers = Array.from({ length: 12 }, (_, i) => i + 1);

  const getCellColor = (state) => {
    if (state === 'white' || !state) return 'bg-white border-slate-100 shadow-sm';
    if (state === 'orange') return 'bg-orange-500 border-orange-400 shadow-[0_0_15px_rgba(249,115,22,0.4)]';
    if (state === 'light-green') return 'bg-emerald-400 border-emerald-300 shadow-[0_0_15px_rgba(16,185,129,0.4)]';
    if (state === 'dark-green') return 'bg-emerald-700 border-emerald-600 shadow-[0_0_15px_rgba(4,120,87,0.6)]';
    return 'bg-white border-slate-100';
  };

  return (
    <div className="tool-container flex flex-col lg:flex-row gap-8 h-full font-['Outfit'] select-none">

      {/* Arithmetic Logic Sidebar */}
      <div className="w-full lg:w-[420px] flex flex-col gap-6 shrink-0 h-full overflow-hidden">
        <div className="tool-sidebar-card flex-1 p-10 flex flex-col">
           <div className="flex items-center justify-between mb-10 shrink-0">
              <div className="flex items-center gap-3">
                 <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 border border-slate-100">
                    <Grid size={18} />
                 </div>
                 <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Mastery Matrix</h4>
              </div>
           </div>

           <div className="flex-1 flex flex-col items-center justify-center w-full min-h-0">
             <div className="space-y-1.5 w-fit">
                {/* Header Row */}
                <div className="flex gap-1.5 items-center mb-2">
                   <div className="w-10 h-8 flex-shrink-0" />
                   {gridNumbers.map(col => (
                     <div key={col} className="w-7 h-7 flex items-center justify-center font-black text-slate-300 text-[10px] italic tabular-nums">
                        {col}
                     </div>
                   ))}
                </div>

                {gridNumbers.map(row => {
                  const isSelected = selectedRows.includes(row);
                  return (
                    <div key={row} className="flex gap-1.5 items-center">
                       <button
                         onClick={() => toggleRow(row)}
                         className={`w-10 h-8 rounded-xl flex items-center justify-center font-black text-[12px] transition-all border-2 italic ${
                           isSelected 
                             ? 'bg-slate-900 text-white border-slate-900 shadow-xl scale-110 z-10'
                             : 'bg-slate-50 text-slate-400 border-transparent hover:bg-white hover:border-indigo-100'
                         }`}
                       >
                         {row}
                       </button>
                       {gridNumbers.map(col => {
                         const state = cellStates[`${row}x${col}`];
                         return (
                           <div 
                             key={`${row}x${col}`} 
                             className={`w-7 h-7 rounded-lg border-2 transition-all duration-700 ${getCellColor(state)}`}
                             title={`${row} × ${col}`}
                           />
                         )
                       })}
                    </div>
                  )
                })}
             </div>
           </div>

           <div className="mt-10 pt-10 border-t border-slate-50 shrink-0 space-y-8">
              <div className="grid grid-cols-2 gap-4">
                 <div className="flex items-center gap-3">
                    <div className="w-5 h-5 bg-white border-2 border-slate-100 rounded-lg shadow-sm" />
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic">Stable</span>
                 </div>
                 <div className="flex items-center gap-3">
                    <div className="w-5 h-5 bg-orange-500 border-2 border-orange-400 rounded-lg" />
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic">Critical</span>
                 </div>
                 <div className="flex items-center gap-3">
                    <div className="w-5 h-5 bg-emerald-400 border-2 border-emerald-300 rounded-lg" />
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic">Optimal</span>
                 </div>
                 <div className="flex items-center gap-3">
                    <div className="w-5 h-5 bg-emerald-700 border-2 border-emerald-600 rounded-lg" />
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic">Mastered</span>
                 </div>
              </div>

              <div className="flex items-center gap-4 group">
                 <div className="w-10 h-10 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-300 group-hover:bg-indigo-50 group-hover:text-indigo-400 transition-all shadow-sm">
                    <TrendingUp size={18} />
                 </div>
                 <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Adaptive Learning</span>
                    <span className="text-[11px] font-bold text-slate-300 italic uppercase">Prioritizing weak nodes</span>
                 </div>
              </div>
           </div>
        </div>
      </div>

      {/* Main Flashcard Stage */}
      <div className="flex-1 tool-stage p-0 relative overflow-hidden bg-white border-none rounded-[4rem] group/stage flex items-center justify-center">
        <div className="tool-grid-bg opacity-30" />

        {/* Decorative Grid */}
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-[0.03] group-hover/stage:opacity-[0.05] transition-opacity duration-1000">
           <Calculator size={600} className="text-slate-900" strokeWidth={0.05} />
        </div>

        {/* HUD Stats */}
        <div className="absolute top-12 left-12 flex flex-col gap-6 z-20">
           <div className="flex items-center gap-4 px-8 py-4 bg-white/40 backdrop-blur-3xl rounded-[2.5rem] border-4 border-white/60 shadow-xl group/hud hover:border-indigo-100 transition-all">
              <div className="w-3 h-3 rounded-full bg-indigo-500 animate-pulse shadow-[0_0_20px_rgba(79,70,229,1)]" />
              <div className="flex flex-col">
                 <span className="text-[11px] font-black text-slate-800 uppercase tracking-[0.6em] italic leading-none mb-1">Calculation Cycle</span>
                 <span className="text-[9px] font-black text-slate-400 uppercase tracking-[0.4em] italic leading-none">Iteration {sessionCount}</span>
              </div>
           </div>
        </div>

        <div className="w-full max-w-4xl p-12 lg:p-24 relative z-10 flex flex-col items-center">
          {selectedRows.length === 0 ? (
             <div className="text-center space-y-8 max-w-md animate-in fade-in zoom-in-95 duration-500">
                <div className="w-32 h-32 rounded-[4rem] bg-slate-50 flex items-center justify-center text-slate-200 border-4 border-white shadow-inner mx-auto group-hover:rotate-12 transition-transform">
                   <Target size={64} strokeWidth={1} />
                </div>
                <div className="space-y-3">
                   <h3 className="text-4xl font-black text-slate-300 uppercase tracking-tighter italic">No Active Nodes</h3>
                   <p className="text-[12px] font-black text-slate-400 uppercase tracking-[0.4em] italic leading-relaxed">Select arithmetic streams in the mastery matrix to begin calculations.</p>
                </div>
             </div>
          ) : currentQuestion ? (
            <div className="w-full flex flex-col items-center gap-16 animate-in slide-in-from-bottom-12 duration-700">
              <div className="text-center space-y-8">
                <motion.div
                  key={`${currentQuestion.a}-${currentQuestion.b}`}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="text-[10rem] lg:text-[14rem] leading-none font-black text-slate-900 tracking-tighter tabular-nums italic drop-shadow-2xl whitespace-nowrap"
                >
                  {currentQuestion.a} <span className="text-indigo-600">×</span> {currentQuestion.b}
                </motion.div>

                <form onSubmit={handleSubmit} className="w-full max-w-xl mx-auto relative group/form">
                  <input
                    ref={inputRef}
                    type="number"
                    value={userInput}
                    onChange={(e) => setUserInput(e.target.value)}
                    className="w-full text-center text-[10rem] font-black p-12 bg-slate-50/50 border-8 border-white rounded-[5rem] focus:ring-[32px] focus:ring-indigo-500/5 focus:border-indigo-500 transition-all tabular-nums shadow-inner placeholder:text-slate-100 italic leading-none"
                    placeholder="?"
                    autoFocus
                  />
                  <div className="absolute right-12 top-1/2 -translate-y-1/2 opacity-0 group-focus-within/form:opacity-20 transition-opacity">
                     <Hash size={64} className="text-indigo-600" />
                  </div>
                  <button type="submit" className="hidden">Submit</button>
                </form>
              </div>

              <div className="h-32 w-full flex items-center justify-center">
                <AnimatePresence mode="wait">
                  {feedback && (
                    <motion.div 
                      key={`${feedback.msg}-${feedback.timestamp}`}
                      initial={{ opacity: 0, scale: 0.8, y: 20 }}
                      animate={{ opacity: 1, scale: 1, y: 0 }}
                      exit={{ opacity: 0, scale: 1.2, y: -20 }}
                      className={`px-16 py-8 rounded-[4rem] flex items-center gap-8 shadow-[0_64px_128px_-32px_rgba(0,0,0,0.1)] border-4 transition-all ${
                        feedback.type === 'success' 
                          ? 'bg-emerald-50 text-emerald-700 border-emerald-200 shadow-emerald-500/10' 
                          : 'bg-rose-50 text-rose-700 border-rose-200 shadow-rose-500/10'
                      }`}
                    >
                      {feedback.type === 'success' ? <CheckCircle2 size={48} className="text-emerald-500" /> : <XCircle size={48} className="text-rose-500" />}
                      <span className="font-black text-5xl italic tracking-tighter leading-none">{feedback.msg}</span>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </div>
          ) : null}
        </div>

        {/* Interaction Guide */}
        <div className="absolute bottom-12 right-12 flex items-center gap-6 z-20 pointer-events-none opacity-40 italic">
           <div className="text-right">
              <p className="text-[11px] font-black uppercase tracking-[0.6em]">Submit Solution</p>
              <p className="text-[11px] font-black uppercase tracking-[0.4em] mt-1">Press Enter to resolve node</p>
           </div>
           <div className="w-12 h-12 rounded-2xl bg-white/50 border-2 border-white flex items-center justify-center shadow-inner">
              <MousePointer2 size={24} className="text-slate-400" />
           </div>
        </div>
      </div>

    </div>
  );
};

export default TimesTable;

