import React, { useState, useEffect, useMemo, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Trophy, 
  Users, 
  Play, 
  RotateCcw,
  Trash2, 
  Plus, 
  Shuffle, 
  List as ListIcon, 
  Settings, 
  X,
  Shield, 
  TrendingUp, 
  Check, 
  MousePointer2, 
  ChevronUp,
  ChevronDown, 
  Maximize2, 
  UserPlus, 
  Info, 
  Star, 
  History,
  ChevronLeft, 
  ChevronRight,
  Activity,
  Zap,
  Target,
  Layout,
  Crown
} from 'lucide-react';
import { useLocalStorage } from '../../hooks/useLocalStorage';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';
import { audioEngine } from '../../utils/audio';
import { shuffle } from '../../utils/random';

const K_FACTOR = 32;
const BASE_RATING = 1200;

const EloManager = ({ participants, eloRatings, setEloRatings, eloHistory, setEloHistory }) => {
  const [selectedWinner, setSelectedWinner] = useState('');
  const [editingMatchId, setEditingMatchId] = useState(null);
  const [currentPage, setCurrentPage] = useState(1);
  const { settings } = useSettings();
  const itemsPerPage = 8;
  const matchIdCounter = useRef(Date.now());

  const recalculateAll = (history) => {
    const newRatings = {};
    participants.forEach(p => newRatings[p] = 1200);

    const processedHistory = [...history].reverse().map(m => {
      if (!m.winner || !m.loser) return m;

      const rW = newRatings[m.winner] || BASE_RATING;
      const rL = newRatings[m.loser] || BASE_RATING;

      const eW = 1 / (1 + Math.pow(10, (rL - rW) / 400));
      const eL = 1 / (1 + Math.pow(10, (rW - rL) / 400));

      const nW = Math.round(rW + K_FACTOR * (1 - eW));
      const nL = Math.round(rL + K_FACTOR * (0 - eL));

      newRatings[m.winner] = nW;
      newRatings[m.loser] = nL;

      return {
        ...m,
        winnerOld: rW,
        winnerNew: nW,
        loserOld: rL,
        loserNew: nL
      };
    });

    setEloRatings(newRatings);
    setEloHistory(processedHistory.reverse());
  };

  const recordMatch = (winner, loser) => {
    if (!winner || !loser || winner === loser) return;

    const rW = eloRatings[winner] || BASE_RATING;
    const rL = eloRatings[loser] || BASE_RATING;

    const eW = 1 / (1 + Math.pow(10, (rL - rW) / 400));
    const eL = 1 / (1 + Math.pow(10, (rW - rL) / 400));

    const nW = Math.round(rW + K_FACTOR * (1 - eW));
    const nL = Math.round(rL + K_FACTOR * (0 - eL));

    setEloRatings(prev => ({ ...prev, [winner]: nW, [loser]: nL }));

    const match = {
      id: matchIdCounter.current++,
      winner,
      loser,
      winnerOld: rW,
      winnerNew: nW,
      loserOld: rL,
      loserNew: nL,
      date: new Date().toISOString()
    };
    setEloHistory([match, ...eloHistory]);
    audioEngine.playAlarm(settings.soundTheme);
  };

  const handleStudentClick = (student) => {
    audioEngine.playTick(settings.soundTheme);
    if (editingMatchId) {
      const match = eloHistory.find(m => m.id === editingMatchId);
      if (!match) return;

      let newHistory;
      if (match.winner === student) {
        newHistory = eloHistory.map(m => m.id === editingMatchId ? { ...m, winner: null } : m);
      } else if (match.loser === student) {
        newHistory = eloHistory.map(m => m.id === editingMatchId ? { ...m, loser: null } : m);
      } else if (!match.winner) {
        newHistory = eloHistory.map(m => m.id === editingMatchId ? { ...m, winner: student } : m);
      } else if (!match.loser) {
        newHistory = eloHistory.map(m => m.id === editingMatchId ? { ...m, loser: student } : m);
      } else {
        return;
      }

      recalculateAll(newHistory);
      const updatedMatch = newHistory.find(m => m.id === editingMatchId);
      if (updatedMatch.winner && updatedMatch.loser) setEditingMatchId(null);
      return;
    }

    if (!selectedWinner) {
      setSelectedWinner(student);
    } else if (selectedWinner === student) {
      setSelectedWinner('');
    } else {
      recordMatch(selectedWinner, student);
      setSelectedWinner('');
    }
  };

  const deleteMatch = (id) => {
    const newHistory = eloHistory.filter(m => m.id !== id);
    recalculateAll(newHistory);
    setEditingMatchId(null);
    audioEngine.playTick(settings.soundTheme);
  };

  const sortedParticipants = [...participants].sort((a, b) => (eloRatings[b] || 1200) - (eloRatings[a] || 1200));
  const totalPages = Math.ceil(eloHistory.length / itemsPerPage);
  const currentHistory = eloHistory.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-full min-h-0">
      {/* Rankings Board */}
      <div className="flex-1 tool-card bg-white border-4 border-slate-50 p-8 flex flex-col gap-8 min-h-0">
        <div className="flex items-center justify-between">
           <div className="flex items-center gap-3">
              <div className="w-12 h-12 rounded-2xl bg-indigo-50 flex items-center justify-center text-indigo-600 shadow-sm border border-indigo-100">
                 <Trophy size={24} />
              </div>
              <div className="flex flex-col">
                 <h3 className="text-xl font-black text-slate-800 uppercase tracking-tight">Apex Leaderboard</h3>
                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Skill-Based Tier Synthesis</span>
              </div>
           </div>
           <div className="flex items-center gap-4">
              <div className="flex flex-col items-end">
                 <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Total Active</span>
                 <span className="text-sm font-black text-slate-800 tabular-nums">{participants.length} Candidates</span>
              </div>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 overflow-y-auto pr-2 custom-scrollbar no-scrollbar pb-8">
           {sortedParticipants.map((p, i) => {
             const isWinner = eloHistory.find(m => m.id === editingMatchId)?.winner === p;
             const isLoser = eloHistory.find(m => m.id === editingMatchId)?.loser === p;
             const isSelected = selectedWinner === p || isWinner || isLoser;
             const rating = eloRatings[p] || 1200;
             const rank = i + 1;

             return (
               <button 
                 key={p} 
                 onClick={() => handleStudentClick(p)}
                 className={`group flex items-center gap-4 p-5 rounded-[2rem] border-2 transition-all duration-300 relative overflow-hidden ${
                   isWinner ? 'bg-emerald-500 border-emerald-500 text-white shadow-xl' :
                   isLoser ? 'bg-rose-500 border-rose-500 text-white shadow-xl' :
                   selectedWinner === p ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl' :
                   'bg-white border-slate-50 hover:border-indigo-100 hover:shadow-2xl hover:shadow-indigo-50'
                 }`}
               >
                 <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-xs font-black shadow-inner transition-colors ${
                   isSelected ? 'bg-white/20 border-white/20 text-white' : 
                   (rank === 1 ? 'bg-amber-100 text-amber-600' : 'bg-slate-50 text-slate-300')
                 }`}>
                   {rank}
                 </div>
                 <div className="flex flex-col items-start truncate flex-1">
                    <span className="text-[10px] font-black uppercase tracking-widest opacity-60">Competitor</span>
                    <span className="font-black text-sm uppercase tracking-tighter truncate w-full text-left">{p}</span>
                 </div>
                 <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black uppercase tracking-widest opacity-60">Rating</span>
                    <span className="font-black text-lg tabular-nums tracking-tighter italic">{rating}</span>
                 </div>
               </button>
             );
           })}
        </div>
      </div>

      {/* History & Controls Sidebar */}
      <div className="w-full lg:w-96 flex flex-col gap-6 min-h-0">
        <div className="tool-card p-8 bg-slate-900 border-none text-white flex flex-col gap-8 flex-1 min-h-0 overflow-hidden shadow-2xl">
           <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                 <History size={20} className="text-indigo-400" />
                 <h4 className="text-sm font-black uppercase tracking-widest text-indigo-400">Match Stream</h4>
              </div>
              <div className="px-3 py-1 bg-white/10 rounded-full text-[10px] font-black tabular-nums">
                 {eloHistory.length} Matches
              </div>
           </div>

           <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar no-scrollbar">
              <AnimatePresence mode="popLayout">
                {currentHistory.map(m => {
                  const isEditing = editingMatchId === m.id;
                  return (
                    <motion.div 
                      key={m.id}
                      layout
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      className={`p-5 rounded-3xl border-2 transition-all group relative cursor-pointer ${
                        isEditing ? 'bg-white/10 border-indigo-500 shadow-xl' : 'bg-white/5 border-transparent hover:bg-white/[0.08]'
                      }`}
                      onClick={() => { if (!isEditing) { setEditingMatchId(m.id); setSelectedWinner(''); } }}
                    >
                       <div className="flex items-center justify-between gap-3 mb-4">
                          <div className={`flex-1 text-center p-2 rounded-xl text-[10px] font-black uppercase truncate transition-all ${m.winner ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' : 'bg-white/10 text-white/20 border-white/5 animate-pulse'}`}>
                             {m.winner || 'PENDING'}
                          </div>
                          <Zap size={14} className="text-white/20" />
                          <div className={`flex-1 text-center p-2 rounded-xl text-[10px] font-black uppercase truncate transition-all ${m.loser ? 'bg-rose-500/20 text-rose-400 border border-rose-500/30' : 'bg-white/10 text-white/20 border-white/5 animate-pulse'}`}>
                             {m.loser || 'PENDING'}
                          </div>
                       </div>

                       <div className="flex items-center justify-between">
                          <span className="text-[10px] font-black text-white/30 uppercase tracking-widest italic">
                             {new Date(m.date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                          </span>
                          <div className="flex items-center gap-4">
                             {isEditing ? (
                               <div className="flex gap-3">
                                  <button onClick={(e) => { e.stopPropagation(); deleteMatch(m.id); }} className="text-rose-400 hover:scale-110 transition-transform"><Trash2 size={16} /></button>
                                  <button onClick={(e) => { e.stopPropagation(); setEditingMatchId(null); }} className="text-white/40 hover:scale-110 transition-transform"><X size={16} /></button>
                               </div>
                             ) : (
                               <div className="flex items-center gap-2">
                                  <span className="text-[10px] font-black text-emerald-400">+{m.winnerNew - m.winnerOld}</span>
                                  <span className="text-[10px] font-black text-rose-400">{m.loserNew - m.loserOld}</span>
                               </div>
                             )}
                          </div>
                       </div>
                    </motion.div>
                  );
                })}
              </AnimatePresence>
           </div>

           {totalPages > 1 && (
             <div className="flex items-center justify-between pt-4 border-t border-white/10">
                <button onClick={() => setCurrentPage(p => Math.max(1, p-1))} disabled={currentPage === 1} className="p-2 hover:bg-white/10 rounded-xl transition-all disabled:opacity-20"><ChevronLeft size={16} /></button>
                <span className="text-[10px] font-black text-white/40 uppercase tracking-[0.3em]">Page {currentPage} of {totalPages}</span>
                <button onClick={() => setCurrentPage(p => Math.min(totalPages, p+1))} disabled={currentPage === totalPages} className="p-2 hover:bg-white/10 rounded-xl transition-all disabled:opacity-20"><ChevronRight size={16} /></button>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

const ChampionNode = ({ winner }) => (
  <div className="flex flex-col items-center gap-6 mb-12">
    <div className="relative">
      <AnimatePresence mode="wait">
        {winner ? (
          <motion.div
            key="champion"
            initial={{ scale: 0, rotate: -20 }}
            animate={{ scale: 1, rotate: 0 }}
            className="w-32 h-32 rounded-[3rem] bg-slate-900 border-[8px] border-amber-400 flex items-center justify-center text-amber-400 shadow-[0_30px_60px_-10px_rgba(251,191,36,0.5)] z-20"
          >
            <Crown size={64} fill="currentColor" strokeWidth={1} />
            <motion.div 
              animate={{ rotate: 360 }}
              transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
              className="absolute inset-[-12px] border-4 border-dashed border-amber-400/30 rounded-[3.5rem] pointer-events-none"
            />
          </motion.div>
        ) : (
          <div className="w-32 h-32 rounded-[3rem] bg-slate-50 border-[8px] border-slate-100 flex items-center justify-center text-slate-100">
             <Trophy size={64} strokeWidth={1} />
          </div>
        )}
      </AnimatePresence>
    </div>
    <div className="text-center space-y-2">
       <span className="text-[10px] font-black text-slate-300 uppercase tracking-[0.5em]">Tournament Champion</span>
       <h2 className="text-4xl font-black text-slate-900 uppercase tracking-tighter italic">
          {winner || "Awaiting Final"}
       </h2>
    </div>
  </div>
);

const MatchNode = ({ match, onSelectWinner, mirrored = false, isCenter = false, round }) => {
  const { settings } = useSettings();
  const hasWinner = !!match.winner;

  return (
    <div className={`relative flex items-center ${mirrored ? 'flex-row-reverse' : ''}`}>
      <div className={`flex flex-col gap-2 p-2 bg-white rounded-3xl border-2 transition-all duration-500 min-w-[200px] shadow-sm hover:shadow-xl hover:-translate-y-1 ${hasWinner ? 'border-indigo-100' : 'border-slate-50'}`}>
        {match.participants.map((player, i) => {
          const isWinner = match.winner === player;
          const isLoser = match.winner && player && match.winner !== player;
          const isEmpty = !player;

          return (
            <button
              key={i}
              onClick={() => player && onSelectWinner(match.id, player)}
              disabled={isEmpty || hasWinner}
              className={`group flex items-center justify-between p-3 rounded-2xl transition-all border-2 ${
                isWinner ? 'bg-emerald-500 border-emerald-400 text-white shadow-lg' :
                isLoser ? 'bg-slate-50 border-transparent text-slate-300 opacity-60' :
                isEmpty ? 'bg-slate-50/50 border-dashed border-slate-200 text-slate-200' :
                'bg-white border-transparent text-slate-700 hover:border-indigo-200 hover:bg-indigo-50/50'
              }`}
            >
              <div className="flex items-center gap-3 truncate">
                 <div className={`w-6 h-6 rounded-lg flex items-center justify-center text-[10px] font-black ${isWinner ? 'bg-white/20 text-white' : 'bg-slate-100 text-slate-300'}`}>
                    {match.seeds?.[i] || '?'}
                 </div>
                 <span className="font-black text-[11px] uppercase tracking-widest truncate">{player || "TBD"}</span>
              </div>
              {isWinner && <Check size={14} strokeWidth={4} />}
            </button>
          );
        })}
      </div>

      {/* Connection Lines */}
      {!isCenter && (
        <div className={`w-10 h-px bg-slate-200 relative ${mirrored ? 'mr-0' : 'ml-0'}`}>
           <div className={`absolute w-3 h-3 rounded-full bg-slate-200 -top-1.5 ${mirrored ? '-left-1.5' : '-right-1.5'}`} />
        </div>
      )}
    </div>
  );
};

export const Tournaments = () => {
  const { settings } = useSettings();
  const { setHeaderActions, setHasConfig, setOnConfigToggle, setOnReset, clearHeader } = useHeader();
  const [tournaments, setTournaments] = useLocalStorage('tournaments_list', []);
  const [activeTournamentId, setActiveTournamentId] = useLocalStorage('active_tournament_id', null);

  const [step, setStep] = useState('setup');
  const [tournamentType, setTournamentType] = useState('single');
  const [bracketSize, setBracketSize] = useState(16);
  const [selectedClassId, setSelectedClassId] = useState(settings.classes[0]?.id || '');
  const [zoom, setZoom] = useState(0.8);
  const [minZoom, setMinZoom] = useState(0.2);
  const bracketRef = useRef(null);
  const tournamentIdCounter = useRef(Date.now());

  const activeTournament = useMemo(() =>
    tournaments.find(t => t.id === activeTournamentId),
    [tournaments, activeTournamentId]
  );

  useEffect(() => {
    if (activeTournament) {
      setTournamentType(activeTournament.type);
      setBracketSize(activeTournament.bracketSize || 16);
      setSelectedClassId(activeTournament.classId || '');
      setStep(activeTournament.step || 'setup');
    } else {
      setStep('setup');
    }
  }, [activeTournamentId]);

  useEffect(() => {
    if (step === 'active' && bracketRef.current && containerRef.current && tournamentType !== 'elo') {
      const updateZoom = () => {
        const containerWidth = containerRef.current.clientWidth - 100;
        const containerHeight = containerRef.current.clientHeight - 100;
        const bracketWidth = bracketRef.current.scrollWidth;
        const bracketHeight = bracketRef.current.scrollHeight;

        if (bracketWidth > 0 && bracketHeight > 0) {
          const fitZoom = Math.min(1.5, containerWidth / bracketWidth, containerHeight / bracketHeight);
          setMinZoom(fitZoom);
          setZoom(fitZoom);
        }
      };
      setTimeout(updateZoom, 300);
    }
  }, [step, activeTournamentId, activeTournament?.data?.numRounds, tournamentType]);

  const addTournament = () => {
    let nextNum = 1;
    while (tournaments.map(t => t.name).includes(`Tournament ${nextNum}`)) nextNum++;
    const newTournament = {
      id: (tournamentIdCounter.current++).toString(),
      name: `Tournament ${nextNum}`,
      type: 'single',
      step: 'setup',
      participants: [],
      bracketSize: 16,
      data: null,
      classId: settings.classes[0]?.id || ''
    };
    setTournaments([...tournaments, newTournament]);
    setActiveTournamentId(newTournament.id);
    audioEngine.playTick(settings.soundTheme);
  };

  const generateSingleElimination = (players) => {
    const n = players.length;
    const numRounds = Math.ceil(Math.log2(n));
    const bracketSize = Math.pow(2, numRounds);
    let matches = [];
    for (let r = 0; r < numRounds; r++) {
      const matchesInRound = bracketSize / Math.pow(2, r + 1);
      for (let i = 0; i < matchesInRound; i++) {
        let side = r === numRounds - 1 ? 'center' : (i < matchesInRound / 2 ? 'left' : 'right');
        matches.push({
          id: `m-${r}-${i}`, round: r, participants: [null, null], seeds: [null, null],
          winner: null, nextMatchId: r === numRounds - 1 ? null : `m-${r + 1}-${Math.floor(i / 2)}`,
          position: i, side
        });
      }
    }
    const round0Matches = matches.filter(m => m.round === 0);
    for (let i = 0; i < bracketSize; i++) {
      const player = players[i] || null;
      const matchIndex = Math.floor(i / 2);
      const slotIndex = i % 2;
      round0Matches[matchIndex].participants[slotIndex] = player;
      round0Matches[matchIndex].seeds[slotIndex] = player ? i + 1 : null;
    }
    round0Matches.forEach(match => {
      if (match.participants[0] && !match.participants[1]) match.winner = match.participants[0];
      else if (!match.participants[0] && match.participants[1]) match.winner = match.participants[1];
    });
    let changed = true;
    while (changed) {
      changed = false;
      matches.forEach(match => {
        if (match.winner && match.nextMatchId) {
          const nextMatch = matches.find(m => m.id === match.nextMatchId);
          if (!nextMatch) return;
          if (nextMatch.participants[match.position % 2] !== match.winner) {
            nextMatch.participants[match.position % 2] = match.winner;
            changed = true;
          }
        }
      });
    }
    return { type: 'single', participants: players, matches, numRounds, bracketSize };
  };

  const handleSelectWinner = (matchId, winnerName) => {
    audioEngine.playTick(settings.soundTheme);
    setTournaments(prev => prev.map(t => {
      if (t.id !== activeTournamentId) return t;
      const newMatches = JSON.parse(JSON.stringify(t.data.matches));
      const match = newMatches.find(m => m.id === matchId);
      if (!match) return t;
      match.winner = winnerName;
      if (match.nextMatchId) {
        const nextMatch = newMatches.find(m => m.id === match.nextMatchId);
        if (nextMatch) nextMatch.participants[match.position % 2] = winnerName;
      }
      return { ...t, data: { ...t.data, matches: newMatches } };
    }));
  };

  const resetTournament = () => {
    if (window.confirm('Reset all match results?')) {
      setTournaments(prev => prev.map(t => {
        if (t.id !== activeTournamentId) return t;
        if (t.type === 'elo') return { ...t, eloRatings: {}, eloHistory: [] };
        const newMatches = t.data.matches.map(match => {
          const m = { ...match, winner: null };
          if (m.round > 0) m.participants = [null, null];
          return m;
        });
        return { ...t, data: { ...t.data, matches: newMatches } };
      }));
      audioEngine.playTick(settings.soundTheme);
    }
  };

  useEffect(() => {
    setHasConfig(true);
    setOnConfigToggle(() => () => {
      const next = step === 'setup' ? 'active' : 'setup';
      setStep(next);
      setTournaments(prev => prev.map(t => t.id === activeTournamentId ? { ...t, step: next } : t));
    });
    setOnReset(() => resetTournament);
    return () => clearHeader();
  }, [clearHeader, setHasConfig, setOnConfigToggle, setOnReset, step, activeTournamentId]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-4">
        {step === 'active' && tournamentType !== 'elo' && (
          <div className="flex items-center gap-2 bg-slate-50 px-4 py-1.5 rounded-xl border-2 border-transparent shadow-sm">
            <Maximize2 size={14} className="text-slate-400" />
            <input type="range" min={minZoom} max="1.5" step="0.01" value={zoom} onChange={(e) => setZoom(parseFloat(e.target.value))} className="w-16 accent-indigo-600 h-1.5 bg-slate-200 rounded-full appearance-none cursor-pointer" />
          </div>
        )}
        <select value={activeTournamentId || ''} onChange={(e) => e.target.value === 'new' ? addTournament() : setActiveTournamentId(e.target.value)} className="px-4 py-2 bg-white border-2 border-slate-100 rounded-xl font-black text-[10px] text-slate-600 outline-none hover:border-indigo-100 transition-all uppercase tracking-widest shadow-sm">
          <option value="" disabled>Active Session</option>
          {tournaments.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
          <option value="new" className="text-indigo-600 font-black">+ Create New</option>
        </select>
      </div>
    );
  }, [activeTournamentId, tournaments, step, zoom, minZoom, tournamentType]);

  const initiateTournament = () => {
    const selectedClass = settings.classes.find(c => c.id === selectedClassId);
    if (!selectedClass || !selectedClass.students.length) return;
    audioEngine.playTick(settings.soundTheme);
    const shuffled = shuffle([...selectedClass.students]);
    setTournaments(prev => prev.map(t => {
      if (t.id !== activeTournamentId) return t;
      if (tournamentType === 'elo') return { ...t, step: 'active', type: 'elo', participants: shuffled, eloRatings: {}, eloHistory: [] };
      return { ...t, step: 'active', type: tournamentType, data: generateSingleElimination(shuffled) };
    }));
  };

  return (
    <div className="tool-container flex flex-col gap-6 p-6 h-full overflow-hidden font-['Outfit'] select-none">
      {!activeTournament ? (
        <div className="flex-1 flex flex-col items-center justify-center gap-12 bg-white tool-card border-4 border-slate-50 relative overflow-hidden">
           <div className="absolute inset-0 bg-[#f8fafc]/50 -z-10" style={{ backgroundImage: 'radial-gradient(#e2e8f0 2px, transparent 2px)', backgroundSize: '48px 48px' }} />
           <div className="w-40 h-40 rounded-[4rem] bg-indigo-50 flex items-center justify-center text-indigo-200 border-4 border-indigo-100 shadow-inner">
              <Trophy size={80} strokeWidth={1} />
           </div>
           <div className="text-center space-y-4">
              <h2 className="text-4xl font-black text-slate-800 uppercase tracking-tighter italic">Apex Arena Registry</h2>
              <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.4em]">Select an existing session or initiate a new bracket</p>
           </div>
           <button onClick={addTournament} className="px-12 py-5 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-indigo-900/20 hover:bg-indigo-600 transition-all hover:scale-105 active:scale-95">
              Initialize Protocol
           </button>
        </div>
      ) : step === 'setup' ? (
        <div className="flex-1 flex flex-col lg:flex-row gap-8 min-h-0">
          <div className="w-full lg:w-96 flex flex-col gap-6">
            <div className="tool-card p-8 bg-white border-4 border-slate-50 shadow-indigo-900/5 flex flex-col gap-10">
               <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400"><Settings size={18} /></div>
                  <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight italic">Arena Config</h4>
               </div>

               <div className="space-y-6">
                  <div className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Combat Format</label>
                     <div className="grid grid-cols-1 gap-2">
                        {['single', 'elo'].map(type => (
                          <button key={type} onClick={() => setTournamentType(type)} className={`p-5 rounded-3xl border-2 font-black text-xs transition-all flex items-center justify-between ${tournamentType === type ? 'bg-slate-900 border-slate-900 text-white shadow-xl' : 'bg-slate-50 border-transparent text-slate-400 hover:bg-white hover:border-slate-100'}`}>
                             <div className="flex items-center gap-3">
                                {type === 'single' ? <Layout size={16} /> : <TrendingUp size={16} />}
                                <span className="uppercase tracking-widest">{type === 'single' ? 'Single Elimination' : 'Elo Rating System'}</span>
                             </div>
                             {tournamentType === type && <Check size={14} />}
                          </button>
                        ))}
                     </div>
                  </div>

                  <div className="space-y-3">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Class Roster</label>
                     <select value={selectedClassId} onChange={(e) => setSelectedClassId(e.target.value)} className="w-full p-5 bg-slate-50 border-2 border-transparent rounded-3xl text-sm font-black text-slate-800 outline-none focus:bg-white focus:border-indigo-100 transition-all uppercase tracking-widest shadow-inner">
                        {settings.classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                     </select>
                  </div>
               </div>

               <button onClick={initiateTournament} className="w-full py-6 bg-indigo-600 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all hover:scale-[1.02] active:scale-95 flex items-center justify-center gap-3">
                  <Play size={16} fill="currentColor" /> Deploy Arena
               </button>
            </div>
          </div>

          <div className="flex-1 tool-card bg-white border-4 border-slate-50 p-8 flex flex-col gap-6 relative overflow-hidden group">
             <div className="absolute inset-0 bg-[#f8fafc]/30 -z-10" style={{ backgroundImage: 'radial-gradient(#e2e8f0 1.5px, transparent 1.5px)', backgroundSize: '48px 48px' }} />
             <div className="flex items-center justify-between border-b border-slate-50 pb-6">
                <div className="flex items-center gap-3">
                   <Users size={18} className="text-slate-400" />
                   <h3 className="font-black text-slate-800 uppercase tracking-tight">Deployment Roster</h3>
                </div>
                <span className="px-4 py-1.5 bg-indigo-50 rounded-full text-[10px] font-black text-indigo-600 uppercase tracking-widest">
                   {settings.classes.find(c => c.id === selectedClassId)?.students.length || 0} Candidates
                </span>
             </div>
             <div className="flex-1 grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-3 overflow-y-auto pr-2 custom-scrollbar no-scrollbar">
                {(settings.classes.find(c => c.id === selectedClassId)?.students || []).map((s, i) => (
                  <div key={i} className="p-4 bg-slate-50 rounded-2xl border-2 border-transparent hover:border-indigo-100 hover:bg-white transition-all group/item flex items-center gap-3">
                     <div className="w-8 h-8 rounded-lg bg-white border border-slate-100 flex items-center justify-center text-[10px] font-black text-slate-300 group-hover/item:text-indigo-400 transition-colors">{i+1}</div>
                     <span className="text-xs font-bold text-slate-700 uppercase tracking-tight truncate">{s}</span>
                  </div>
                ))}
             </div>
          </div>
        </div>
      ) : (
        <div className="flex-1 flex flex-col min-h-0">
           {tournamentType === 'elo' ? (
             <EloManager 
              participants={activeTournament.participants}
              eloRatings={activeTournament.eloRatings || {}}
              setEloRatings={(r) => setTournaments(prev => prev.map(t => t.id === activeTournamentId ? { ...t, eloRatings: typeof r === 'function' ? r(t.eloRatings || {}) : r } : t))}
              eloHistory={activeTournament.eloHistory || []}
              setEloHistory={(h) => setTournaments(prev => prev.map(t => t.id === activeTournamentId ? { ...t, eloHistory: typeof h === 'function' ? h(t.eloHistory || []) : h } : t))}
             />
           ) : (
             <div ref={containerRef} className="flex-1 overflow-auto bg-slate-50/50 rounded-[3rem] border-4 border-slate-100/50 relative">
               <motion.div 
                 ref={bracketRef} 
                 style={{ scale: zoom, transformOrigin: 'top left' }} 
                 className="p-32 transition-all duration-300 ease-out inline-flex flex-col items-center min-w-full min-h-full"
               >
                 <ChampionNode winner={activeTournament.data?.matches?.find(m => m.side === 'center')?.winner} />

                 <div className="flex gap-0 min-w-max items-center justify-center">
                    {/* Left Brackets */}
                    {Array.from({ length: Math.max(0, (activeTournament.data?.numRounds || 1) - 1) }).map((_, rIdx) => (
                      <div key={`L-${rIdx}`} className="flex flex-col h-full min-h-[600px] justify-center">
                        <span className="text-center text-[9px] font-black text-slate-300 uppercase tracking-[0.3em] mb-4">Round {rIdx + 1}</span>
                        <div className="flex-1 flex flex-col justify-around">
                          {activeTournament.data?.matches?.filter(m => m.round === rIdx && m.side === 'left').map(m => (
                            <div key={m.id} className="px-12 py-8 relative"><MatchNode match={m} onSelectWinner={handleSelectWinner} round={rIdx} /></div>
                          ))}
                        </div>
                      </div>
                    ))}

                    {/* Center Final */}
                    <div className="flex flex-col items-center justify-center px-16 relative min-h-[600px]">
                       <span className="text-center text-[10px] font-black text-indigo-500 uppercase tracking-[0.5em] mb-6">Grand Final</span>
                       {activeTournament.data?.matches?.filter(m => m.side === 'center').map(m => (
                         <MatchNode key={m.id} match={m} onSelectWinner={handleSelectWinner} isCenter round={activeTournament.data.numRounds - 1} />
                       ))}
                    </div>

                    {/* Right Brackets */}
                    {Array.from({ length: Math.max(0, (activeTournament.data?.numRounds || 1) - 1) }).reverse().map((_, revIdx, arr) => {
                      const rIdx = arr.length - 1 - revIdx;
                      return (
                        <div key={`R-${rIdx}`} className="flex flex-col h-full min-h-[600px] justify-center">
                          <span className="text-center text-[9px] font-black text-slate-300 uppercase tracking-[0.3em] mb-4">Round {rIdx + 1}</span>
                          <div className="flex-1 flex flex-col justify-around">
                            {activeTournament.data?.matches?.filter(m => m.round === rIdx && m.side === 'right').map(m => (
                              <div key={m.id} className="px-12 py-8 relative"><MatchNode match={m} onSelectWinner={handleSelectWinner} mirrored round={rIdx} /></div>
                            ))}
                          </div>
                        </div>
                      );
                    })}
                 </div>
               </motion.div>
             </div>
           )}
        </div>
      )}

    </div>
  );
};

