import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Trash2, Delete, Volume2, Sparkles, RefreshCcw, RotateCcw, ArrowLeft } from 'lucide-react';
import { useHeader } from '../../contexts/HeaderContext';

const PHONICS_DATA = {
  consonants: ['b', 'c', 'd', 'f', 'g', 'h', 'j', 'k', 'l', 'm', 'n', 'p', 'r', 's', 't', 'v', 'w', 'x', 'y', 'z'],
  vowels: ['a', 'e', 'i', 'o', 'u'],
  digraphs: ['sh', 'ch', 'th', 'ck', 'qu', 'ng', 'wh', 'ph', 'ee', 'oo', 'ai', 'ay', 'oa', 'oi', 'oy', 'ou', 'ow', 'au', 'aw', 'er', 'ir', 'ur', 'ar', 'or'],
  trigraphs: ['igh', 'air', 'ure', 'ear'],
  'split digraphs': ['a-e', 'e-e', 'i-e', 'o-e', 'u-e']
};

const CATEGORY_COLORS = {
  consonants: 'bg-blue-50 border-blue-200 text-blue-700',
  vowels: 'bg-rose-50 border-rose-200 text-rose-700',
  digraphs: 'bg-purple-50 border-purple-200 text-purple-700',
  trigraphs: 'bg-amber-50 border-amber-200 text-amber-700',
  'split digraphs': 'bg-emerald-50 border-emerald-200 text-emerald-700'
};

const PHONETIC_SOUNDS = {
  'b': 'buh', 'c': 'k', 'd': 'duh', 'f': 'fff', 'g': 'guh', 'h': 'huh', 'j': 'juh', 'k': 'k', 'l': 'lll', 'm': 'mmm', 'n': 'nnn', 'p': 'puh', 'r': 'rrr', 's': 'sss', 't': 'tuh', 'v': 'vvv', 'w': 'wuh', 'x': 'ks', 'y': 'yuh', 'z': 'zzz',
  'a': 'ah', 'e': 'eh', 'i': 'ih', 'o': 'o', 'u': 'uh',
  'sh': 'sh', 'ch': 'ch', 'th': 'th', 'ck': 'k', 'qu': 'kw', 'ng': 'ng', 'wh': 'w', 'ph': 'f', 'ee': 'ee', 'oo': 'oo', 'ai': 'ay', 'ay': 'ay', 'oa': 'oh', 'oi': 'oy', 'oy': 'oy', 'ou': 'ow', 'ow': 'ow', 'au': 'or', 'aw': 'or', 'er': 'er', 'ir': 'er', 'ur': 'er', 'ar': 'ar', 'or': 'or',
  'igh': 'ie', 'air': 'air', 'ure': 'your', 'ear': 'ear',
  'a-e': 'ay', 'e-e': 'ee', 'i-e': 'ie', 'o-e': 'oh', 'u-e': 'oo'
};

export const WordBuilder = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const [builtWord, setBuiltWord] = useState([]);
  const [activeIndex, setActiveIndex] = useState(-1);

  const speakPhoneme = (phoneme) => {
    window.speechSynthesis.cancel();
    const sound = PHONETIC_SOUNDS[phoneme] || phoneme.replace('-', '');
    const utterance = new SpeechSynthesisUtterance(sound);
    utterance.rate = 0.8;
    window.speechSynthesis.speak(utterance);
  };

  const addPhoneme = (phoneme, category) => {
    setBuiltWord([...builtWord, { id: Date.now() + Math.random(), value: phoneme, category }]);
    speakPhoneme(phoneme);
  };

  const removePhoneme = (id) => {
    setBuiltWord(builtWord.filter(p => p.id !== id));
  };

  const clearWord = () => setBuiltWord([]);
  const deleteLast = () => setBuiltWord(builtWord.slice(0, -1));

  const speakWord = () => {
    if (builtWord.length === 0) return;
    window.speechSynthesis.cancel();
    let currentIndex = 0;

    const speakNext = () => {
      if (currentIndex < builtWord.length) {
        setActiveIndex(currentIndex);
        const phoneme = builtWord[currentIndex].value;
        const sound = PHONETIC_SOUNDS[phoneme] || phoneme.replace('-', '');
        const utterance = new SpeechSynthesisUtterance(sound);
        utterance.rate = 0.7;

        utterance.onend = () => {
          currentIndex++;
          if (currentIndex < builtWord.length) {
            setTimeout(speakNext, 150);
          } else {
            setTimeout(() => setActiveIndex(-1), 150);
          }
        };
        utterance.onerror = () => setActiveIndex(-1);
        window.speechSynthesis.speak(utterance);
      }
    };
    speakNext();
  };

  useEffect(() => {
    setOnReset(() => clearWord);
    return () => clearHeader();
  }, [clearHeader, setOnReset]);

  useEffect(() => {
    setHeaderActions(
      <div className="flex items-center gap-2">
        <button
          onClick={speakWord}
          disabled={builtWord.length === 0}
          className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl font-black text-[11px] hover:bg-indigo-700 shadow-lg shadow-indigo-100 uppercase transition-all active:scale-95 disabled:opacity-30 disabled:shadow-none"
        >
          <Volume2 size={16} /> Sound Out
        </button>
        <button
          onClick={deleteLast}
          disabled={builtWord.length === 0}
          className="p-2 bg-slate-50 text-slate-600 rounded-xl hover:bg-amber-50 hover:text-amber-600 transition-all border-2 border-transparent hover:border-amber-100 disabled:opacity-30"
          title="Delete last"
        >
          <Delete size={20} />
        </button>
        <button
          onClick={clearWord}
          disabled={builtWord.length === 0}
          className="p-2 bg-slate-50 text-slate-600 rounded-xl hover:bg-rose-50 hover:text-rose-600 transition-all border-2 border-transparent hover:border-rose-100 disabled:opacity-30"
          title="Reset"
        >
          <RotateCcw size={20} />
        </button>
      </div>
    );
  }, [builtWord, activeIndex]);

  return (
    <div className="tool-container flex flex-col gap-6 h-full p-4 overflow-hidden">
      <div className="flex-1 flex flex-col gap-6 min-h-0">

        {/* Workspace Area */}
        <div className="tool-card flex-1 flex flex-col items-center justify-center p-8 bg-white border-4 border-dashed border-slate-100 relative min-h-[300px]">
          <div className="absolute top-6 left-1/2 -translate-x-1/2">
            <span className="text-[10px] font-black text-slate-300 uppercase tracking-[0.5em] select-none">Word Canvas</span>
          </div>

          <AnimatePresence mode="popLayout">
            {builtWord.length === 0 ? (
              <motion.div 
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
                className="flex flex-col items-center gap-4 text-slate-300"
              >
                <Sparkles size={48} className="opacity-20" />
                <p className="text-xl font-black italic tracking-tight">Select sounds to build a word</p>
              </motion.div>
            ) : (
              <div className="flex flex-wrap gap-4 justify-center">
                {builtWord.map((p, index) => (
                  <motion.button
                    key={p.id}
                    layout
                    initial={{ scale: 0.5, opacity: 0, y: 20 }}
                    animate={{ 
                      scale: index === activeIndex ? 1.1 : 1,
                      opacity: 1, 
                      y: 0,
                    }}
                    exit={{ scale: 0, opacity: 0, y: -20 }}
                    whileHover={{ scale: 1.05, y: -2 }}
                    whileTap={{ scale: 0.95 }}
                    onClick={() => removePhoneme(p.id)}
                    className={`
                      w-20 h-28 md:w-24 md:h-32 rounded-[2rem] flex items-center justify-center 
                      text-4xl md:text-5xl font-black border-b-8 shadow-xl
                      transition-all relative group
