import React, { useState, useCallback, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { HelpCircle, ChevronRight, History, Trophy, ThumbsDown, Users, Sparkles, RotateCcw } from 'lucide-react';
import { WYR_QUESTIONS } from '../../data/wouldYouRather';
import { audioEngine } from '../../utils/audio';
import { useSettings } from '../../contexts/SettingsContext';
import { useHeader } from '../../contexts/HeaderContext';

const YEAR_LEVELS = [
  { id: '1-3', label: 'Years 1 - 3', color: 'from-pink-400 to-rose-500', emoji: '🧸' },
  { id: '4-6', label: 'Years 4 - 6', color: 'from-orange-400 to-amber-500', emoji: '⚽' },
  { id: '7-9', label: 'Years 7 - 9', color: 'from-blue-400 to-indigo-500', emoji: '📚' },
  { id: '10-12', label: 'Years 10 - 12', color: 'from-purple-400 to-violet-500', emoji: '🎓' },
];

export const WouldYouRather = () => {
  const { setHeaderActions, setOnReset, clearHeader } = useHeader();
  const { settings } = useSettings();

  const [view, setView] = useState('selection'); // selection, game
  const [yearLevel, setYearLevel] = useState(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [history, setHistory] = useState([]);

  const resetGame = useCallback(() => {
    setView('selection');
    setYearLevel(null);
    setHistory([]);
    audioEngine.playTick(settings.soundTheme);
  }, [settings.soundTheme]);

  useEffect(() => {
    setOnReset(() => resetGame);
    return () => clearHeader();
  }, [clearHeader, setOnReset, resetGame]);

  const [questions, setQuestions] = useState([]);


  const currentPair = questions[currentIndex];

  const handleSelect = (choiceIndex) => {
    const winner = currentPair[choiceIndex];
    const loser = currentPair[1 - choiceIndex];

    setHistory(prev => [{ winner, loser, id: Date.now() }, ...prev].slice(0, 5));
    audioEngine.playTick(settings.soundTheme);

    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      setCurrentIndex(0);
    }
  };

  const startLevel = (levelId) => {
    const shuffled = [...WYR_QUESTIONS[levelId]].sort(() => Math.random() - 0.5);
    setQuestions(shuffled);
    setYearLevel(levelId);
    setView('game');
    setCurrentIndex(0);
    setHistory([]);
    audioEngine.playTick(settings.soundTheme);
  };

  useEffect(() => {
    if (view === 'game') {
      setHeaderActions(
        <div className="flex items-center gap-4">
          <button 
            onClick={resetGame}
            className="tool-header-button"
            title="Change Level"
          >
            <RotateCcw size={20} />
          </button>
          <div className="tool-header-stat">
            <div className="tool-header-stat-label">Current Level</div>
            <div className="tool-header-stat-value">
              {YEAR_LEVELS.find(l => l.id === yearLevel)?.label.split(' ')[1] || yearLevel}
            </div>
          </div>
          <div className="w-px h-6 bg-slate-200" />
          <div className="tool-header-stat-dark">
            <div className="tool-header-stat-label-indigo">Round</div>
            <div className="tool-header-stat-value-white">
              {currentIndex + 1}
            </div>
          </div>
        </div>
      );
    } else {
      setHeaderActions(null);
    }
  }, [view, currentIndex, yearLevel, setHeaderActions, resetGame]);

  return (
    <div className="tool-container flex flex-col gap-6 p-6 h-full overflow-hidden font-['Outfit'] select-none">

      <AnimatePresence mode="wait">
        {view === 'selection' ? (
          <motion.div 
            key="selection"
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 1.05 }}
            className="tool-stage"
          >
            <div className="tool-grid-bg" />

            <div className="text-center space-y-12 max-w-5xl w-full p-8">
              <div className="space-y-4">
                <div className="tool-icon-container-indigo">
                  <HelpCircle size={40} className="text-indigo-600" />
                </div>
                <h2 className="tool-title-hero">Dilemma Synthesis</h2>
                <p className="tool-sub-label">Decision Matrix Protocol v2.0</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {YEAR_LEVELS.map(level => (
                  <button
                    key={level.id}
                    onClick={() => startLevel(level.id)}
                    className={`group relative p-10 rounded-[3rem] bg-gradient-to-br ${level.color} text-white shadow-xl hover:scale-105 transition-all active:scale-95 flex flex-col items-center gap-6 text-center border-4 border-white/20`}
                  >
                    <span className="text-6xl group-hover:animate-bounce transition-all drop-shadow-lg">{level.emoji}</span>
                    <span className="text-2xl font-black tracking-tight">{level.label}</span>
                    <div className="absolute inset-0 bg-white opacity-0 group-hover:opacity-10 transition-opacity rounded-[3rem]" />
                  </button>
                ))}
              </div>
            </div>
          </motion.div>
        ) : (
          <motion.div 
            key="game"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="flex-1 flex flex-col lg:flex-row gap-8"
          >
            {/* History Sidebar */}
            <div className="w-full lg:w-80 flex flex-col gap-6">
              <div className="tool-sidebar-card">
                <div className="tool-grid-bg" />

                <div className="tool-label">
                  <History size={16} />
                  Sequence Log
                </div>

                <div className="flex-1 space-y-4 overflow-y-auto custom-scrollbar pr-2">
                  <AnimatePresence initial={false}>
                    {history.length === 0 ? (
                      <div className="h-full flex flex-col items-center justify-center text-slate-200 text-center gap-6 py-12">
                        <Sparkles size={64} strokeWidth={1} className="animate-pulse" />
                        <p className="text-[10px] font-black uppercase tracking-widest leading-relaxed">Awaiting user input for data generation</p>
                      </div>
                    ) : (
                      history.map((item, idx) => (
                        <motion.div
                          key={item.id}
                          initial={{ opacity: 0, x: -20 }}
                          animate={{ opacity: 1, x: 0 }}
                          className={`p-5 rounded-3xl border-2 transition-all ${idx === 0 ? 'bg-indigo-50 border-indigo-100 shadow-lg shadow-indigo-50/50' : 'bg-white border-slate-50 opacity-40'}`}
                        >
                          <div className="flex items-start gap-4">
                            <div className="p-2.5 bg-indigo-100 text-indigo-600 rounded-xl">
                              <Trophy size={16} />
                            </div>
                            <div className="flex-1">
                              <p className="text-[10px] font-black uppercase text-indigo-400 mb-1">Selected</p>
                              <p className="text-sm font-bold text-slate-700 leading-tight">{item.winner}</p>
                            </div>
                          </div>
                        </motion.div>
                      ))
                    )}
                  </AnimatePresence>
                </div>
              </div>
            </div>

            {/* Main Stage */}
            <div className="flex-1 flex flex-col gap-8">
              <div className="text-center space-y-3">
                <div className="flex justify-center">
                  <span className="px-6 py-2 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-[0.4em] shadow-sm">
                    {YEAR_LEVELS.find(l => l.id === yearLevel)?.label} • Cycle Protocol Active
                  </span>
                </div>
                <h3 className="text-5xl font-black text-slate-800 tracking-tighter italic uppercase">Critical Decision Path</h3>
              </div>

              <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-8 items-stretch">
                <AnimatePresence mode="wait">
                  <motion.button
                    key={`${currentIndex}-0`}
                    initial={{ opacity: 0, x: -100, rotate: -2 }}
                    animate={{ opacity: 1, x: 0, rotate: 0 }}
                    exit={{ opacity: 0, scale: 0.9, x: -150 }}
                    transition={{ type: 'spring', damping: 20 }}
                    onClick={() => handleSelect(0)}
                    className="group relative p-12 bg-white border-4 border-slate-50 rounded-[4rem] shadow-2xl hover:border-indigo-500 hover:scale-[1.02] transition-all flex flex-col items-center justify-center text-center gap-10 overflow-hidden active:scale-95"
                  >
                    <div className="absolute inset-0 bg-gradient-to-br from-transparent via-transparent to-indigo-50/50 group-hover:to-indigo-100/50 transition-all" />
                    <div className="p-8 bg-indigo-50 rounded-[2.5rem] text-indigo-600 group-hover:scale-110 transition-transform relative z-10 shadow-inner">
                      <Sparkles size={56} fill="currentColor" className="opacity-20" />
                    </div>
                    <p className="text-3xl font-black text-slate-800 leading-tight relative z-10 group-hover:text-indigo-600 transition-colors uppercase italic tracking-tighter">
                      {currentPair ? currentPair[0] : ""}
                    </p>
                    <div className="absolute bottom-8 right-8 opacity-0 group-hover:opacity-100 transition-opacity translate-x-4 group-hover:translate-x-0">
                      <ChevronRight size={40} className="text-indigo-400" />
                    </div>
                  </motion.button>

                  <motion.button
                    key={`${currentIndex}-1`}
                    initial={{ opacity: 0, x: 100, rotate: 2 }}
                    animate={{ opacity: 1, x: 0, rotate: 0 }}
                    exit={{ opacity: 0, scale: 0.9, x: 150 }}
                    transition={{ type: 'spring', damping: 20 }}
                    onClick={() => handleSelect(1)}
                    className="group relative p-12 bg-white border-4 border-slate-50 rounded-[4rem] shadow-2xl hover:border-rose-500 hover:scale-[1.02] transition-all flex flex-col items-center justify-center text-center gap-10 overflow-hidden active:scale-95"
                  >
                    <div className="absolute inset-0 bg-gradient-to-br from-transparent via-transparent to-rose-50/50 group-hover:to-rose-100/50 transition-all" />
                    <div className="p-8 bg-rose-50 rounded-[2.5rem] text-rose-600 group-hover:scale-110 transition-transform relative z-10 shadow-inner">
                      <Users size={56} fill="currentColor" className="opacity-20" />
                    </div>
                    <p className="text-3xl font-black text-slate-800 leading-tight relative z-10 group-hover:text-rose-600 transition-colors uppercase italic tracking-tighter">
                      {currentPair ? currentPair[1] : ""}
                    </p>
                    <div className="absolute bottom-8 right-8 opacity-0 group-hover:opacity-100 transition-opacity translate-x-4 group-hover:translate-x-0">
                      <ChevronRight size={40} className="text-rose-400" />
                    </div>
                  </motion.button>
                </AnimatePresence>
              </div>

              {/* Progress Indicator */}
              <div className="flex justify-center gap-2 pb-4">
                {Array.from({ length: Math.min(questions.length, 10) }).map((_, i) => (
                  <div 
                    key={i} 
                    className={`h-2 rounded-full transition-all duration-700 ${i === currentIndex % 10 ? 'w-12 bg-indigo-500 shadow-[0_0_15px_rgba(99,102,241,0.5)]' : 'w-3 bg-slate-200'}`}
                  />
                ))}
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

import React, { createContext, useContext, useState, useCallback } from 'react';

const HeaderContext = createContext();

export const HeaderProvider = ({ children }) => {
  const [headerActions, setHeaderActions] = useState(null);
  const [headerInfo, setHeaderInfo] = useState(null);
  const [helpContent, setHelpContent] = useState(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [hasConfig, setHasConfig] = useState(false);
  const [isConfigOpen, setIsConfigOpen] = useState(false);
  const [onConfigToggle, setOnConfigToggle] = useState(null);
  const [onReset, setOnReset] = useState(null);
  const [activeOverlay, setActiveOverlay] = useState(null); // 'info', 'help', 'settings', 'about'

  // Clear header state when navigating (handled via effect in tools or layout)
  const clearHeader = useCallback(() => {
    setHeaderActions(null);
    setHeaderInfo(null);
    setHelpContent(null);
    setIsFullscreen(false);
    setHasConfig(false);
    setIsConfigOpen(false);
    setOnConfigToggle(null);
    setOnReset(null);
    setActiveOverlay(null);
  }, []);

  return (
    <HeaderContext.Provider value={{ 
      headerActions, 
      setHeaderActions, 
      headerInfo, 
      setHeaderInfo,
      helpContent,
      setHelpContent,
      isFullscreen,
      setIsFullscreen,
      hasConfig,
      setHasConfig,
      isConfigOpen,
      setIsConfigOpen,
      onConfigToggle,
      setOnConfigToggle,
      onReset,
      setOnReset,
      activeOverlay,
      setActiveOverlay,
      clearHeader 
    }}>
      {children}
    </HeaderContext.Provider>
  );
};

export const useHeader = () => {
  const context = useContext(HeaderContext);
  if (!context) {
    throw new Error('useHeader must be used within a HeaderProvider');
  }
  return context;
};

import { createContext, useContext, useState, useEffect } from 'react';

const demoStudents = Array.from({ length: 28 }, (_, i) => `Student ${i + 1}`);

const defaultSettings = {
  theme: 'early-years', // 'early-years', 'primary', 'secondary', 'dark'
  soundTheme: 'classic', // 'none', 'classic', 'digital', 'soft', 'bubbly'
  selectedYear: 'All',
  classes: [{ id: 'class-demo', name: 'Demo', students: demoStudents }]
};

const SettingsContext = createContext();

export const useSettings = () => {
  return useContext(SettingsContext);
};

export const SettingsProvider = ({ children }) => {
  const [settings, setSettings] = useState(() => {
    const savedSettings = localStorage.getItem('teacherToolsSettings');
    if (savedSettings) {
      const parsed = JSON.parse(savedSettings);
      // Migrate old soundsEnabled to soundTheme
      if (parsed.soundsEnabled !== undefined && parsed.soundTheme === undefined) {
        parsed.soundTheme = parsed.soundsEnabled ? 'classic' : 'none';
        delete parsed.soundsEnabled;
      }
      
      // Ensure there's always at least one class
      if (!parsed.classes || parsed.classes.length === 0) {
        parsed.classes = [{ id: 'class-demo', name: 'Demo', students: demoStudents }];
      }
      
      return { ...defaultSettings, ...parsed };
    }
    return defaultSettings;
  });

  useEffect(() => {
    localStorage.setItem('teacherToolsSettings', JSON.stringify(settings));
    document.documentElement.setAttribute('data-theme', settings.theme);
  }, [settings]);

  const updateTheme = (theme) => setSettings(prev => ({ ...prev, theme }));
  const setSoundTheme = (soundTheme) => setSettings(prev => ({ ...prev, soundTheme }));

  const addClass = (newClass) => {
    setSettings(prev => ({
      ...prev,
      classes: [...prev.classes, newClass]
    }));
  };

  const updateClass = (updatedClass) => {
    setSettings(prev => ({
      ...prev,
      classes: prev.classes.map(c => c.id === updatedClass.id ? updatedClass : c)
    }));
  };

  const deleteClass = (classId) => {
    setSettings(prev => {
      const newClasses = prev.classes.filter(c => c.id !== classId);
      if (newClasses.length === 0) {
        newClasses.push({ id: 'class-demo', name: 'Demo', students: demoStudents });
      }
      return {
        ...prev,
        classes: newClasses
      };
    });
  };

  return (
    <SettingsContext.Provider value={{
      settings,
      updateTheme,
      setSoundTheme,
      addClass,
      updateClass,
      deleteClass,
      setSettings
    }}>
      {children}
    </SettingsContext.Provider>
  );
};
